import{_ as a,c as m,o as e,b as t}from"./app.a0ddd9de.js";const q='{"title":"\u0410\u0444\u043E\u0440\u0438\u0437\u043C 40-45","description":"","frontmatter":{"title":"\u0410\u0444\u043E\u0440\u0438\u0437\u043C 40-45","subtitle":"\u0428\u0438\u0432\u0430 \u0441\u0443\u0442\u0440\u0430 \u0432\u0438\u043C\u0430\u0440\u0448\u0438\u043D\u0438. \u0413\u043B\u0430\u0432\u0430 3.","tags":"vim-3","date":"2021-01-20T00:00:00.000Z"},"headers":[{"level":2,"title":"\u041A\u043E\u043D\u0435\u0446 \u0413\u043B\u0430\u0432\u044B III \u0438 \u0421\u0432\u044F\u0449\u0435\u043D\u043D\u043E\u0433\u043E \u041F\u0438\u0441\u0430\u043D\u0438\u044F","slug":"\u043A\u043E\u043D\u0435\u0446-\u0433n\u0430\u0432\u044B-iii-\u0438-\u0441\u0432\u044F\u0449\u0435\u043D\u043D\u043E\u0433\u043E-\u043F\u0438\u0441\u0430\u043D\u0438\u044F"}],"relativePath":"texts/shiva-sutra-vimarshini/3/40-45/index.md"}',i={},o=t(`<div class="stanza"><a href="#s3.40" id="s3.40" class="num">3.40</a><div class="sans"><p>\u092F\u0926\u093E \u0924\u094D\u0935\u092F\u092E\u0947\u0935\u093E\u0928\u094D\u0924\u0930\u0940\u0902 \u0924\u0941\u0930\u094D\u092F\u0926\u0936\u093E\u092E\u093E\u0924\u094D\u092E\u0924\u094D\u0935\u0947\u0928 \u0928 \u0935\u093F\u092E\u0943\u0936\u0924\u093F \u0924\u0926\u093E \u0926\u0947\u0939\u093E\u0926\u093F\u092A\u094D\u0930\u092E\u093E\u0924\u0943\u0924\u093E\u092D\u093E\u0935\u093E\u0926\u092A\u0942\u0930\u094D\u0923\u092E\u094D\u092E\u0928\u094D\u092F\u0924\u093E\u0924\u094D\u092E\u0915\u093E\u0923\u0935\u092E\u0932\u0930\u0942\u092A\u093E\u0924\u094D\u2014</p><blockquote><p><strong>\u0905\u092D\u093F\u0932\u093E\u0937\u093E\u0926\u094D\u092C\u0939\u093F\u0930\u094D\u0917\u0924\u093F\u0903 \u0938\u0902\u0935\u093E\u0939\u094D\u092F\u0938\u094D\u092F\u0965\u096A\u0966\u0965</strong></p></blockquote><p>\u0936\u0915\u094D\u0924\u093F\u091A\u0915\u094D\u0930\u093E\u0927\u093F\u0937\u094D\u0920\u093F\u0924\u0948\u0903 \u0915\u091E\u094D\u091A\u0941\u0915\u093E\u0928\u094D\u0924\u0903\u0915\u0930\u0923\u092C\u0939\u093F\u0937\u094D\u0915\u0930\u0923\u0924\u0928\u094D\u092E\u093E\u0924\u094D\u0930\u092D\u0942\u0924\u0948\u0903 \u0938\u0939 \u0938\u0902\u0935\u093E\u0939\u094D\u092F\u0924\u0947 \u092F\u094B\u0928\u0947\u0930\u094D\u092F\u094B\u0928\u094D\u092F\u0928\u094D\u0924\u0930\u0902 \u0928\u0940\u092F\u0924 \u0907\u0924\u093F \u0938\u0902\u0935\u093E\u0939\u094D\u092F\u0903 \u0915\u0930\u094D\u092E\u093E\u0924\u094D\u092E\u0930\u0942\u092A\u0903 \u092A\u0936\u0941\u0903 \u0924\u0938\u094D\u092F</p><blockquote><p>... \u0905\u092D\u093F\u0932\u093E\u0937\u094B \u092E\u0932\u094B\u093D\u0924\u094D\u0930 \u0924\u0941\u0964</p></blockquote><p>\u0907\u0924\u093F \u0936\u094D\u0930\u0940\u0938\u094D\u0935\u091A\u094D\u091B\u0928\u094D\u0926\u094B\u0915\u094D\u0924\u0928\u0940\u0924\u094D\u092F\u093E\u092A\u0942\u0930\u094D\u0923\u092E\u094D\u092E\u0928\u094D\u092F\u0924\u093E\u0924\u094D\u092E\u0915\u093E\u0935\u093F\u0926\u094D\u092F\u093E\u0916\u094D\u092F\u093E\u0923\u0935\u092E\u0932\u0930\u0942\u092A\u093E\u0926\u092D\u093F\u0932\u093E\u0937\u093E\u0926\u094D\u0927\u0947\u0924\u094B\u0930\u094D\u092C\u0939\u093F\u0930\u094D\u0917\u0924\u093F\u0930\u094D\u0935\u093F\u0937\u092F\u094B\u0928\u094D\u092E\u0941\u0916\u0924\u094D\u0935\u092E\u0947\u0935 \u092D\u0935\u0924\u093F \u0928 \u0924\u094D\u0935\u0928\u094D\u0924\u0930\u094D\u092E\u0941\u0916\u0930\u0942\u092A\u093E\u0935\u0939\u093F\u0924\u0924\u094D\u0935\u0902 \u091C\u093E\u0924\u0941\u091A\u093F\u0924\u094D\u0964 \u092F\u0926\u0941\u0915\u094D\u0924\u0902 \u0915\u093E\u0932\u093F\u0915\u093E\u0915\u094D\u0930\u092E\u0947</p><blockquote><p>\u092F\u0926\u0935\u093F\u0926\u094D\u092F\u093E\u0935\u0943\u0924\u0924\u092F\u093E \u0935\u093F\u0915\u0932\u094D\u092A\u0935\u093F\u0927\u093F\u092F\u094B\u0917\u0924\u0903\u0964<br> \u0936\u093F\u0935\u093E\u0926\u0940\u0928\u094D\u0928\u0948\u0935 \u091D\u091F\u093F\u0924\u093F \u0938\u092E\u0941\u0926\u094D\u092D\u093E\u0935\u092F\u0924\u0947\u0916\u093F\u0932\u093E\u0928\u094D\u0965<br> \u0924\u0924\u0903 \u0936\u0941\u092D\u093E\u0936\u0941\u092D\u093E \u092D\u093E\u0935\u093E \u0932\u0915\u094D\u0937\u094D\u092F\u0928\u094D\u0924\u0947 \u0924\u0926\u094D\u0935\u0936\u0924\u094D\u0935\u0924\u0903\u0964<br> \u0905\u0936\u0941\u092D\u0947\u092D\u094D\u092F\u0936\u094D\u091A \u092D\u093E\u0935\u0947\u092D\u094D\u092F\u0903 \u092A\u0930\u0902 \u0926\u0941\u0903\u0916\u0902 \u092A\u094D\u0930\u091C\u093E\u092F\u0924\u0947\u0965<br> \u0905\u0924\u0925\u094D\u092F\u093E\u0902 \u0915\u0932\u094D\u092A\u0928\u093E\u0902 \u0915\u0943\u0924\u094D\u0935\u093E \u092A\u091A\u094D\u092F\u0928\u094D\u0924\u0947 \u0928\u0930\u0915\u093E\u0926\u093F\u0937\u0941\u0964<br> \u0938\u094D\u0935\u094B\u0924\u094D\u0925\u0948\u0930\u094D\u0926\u094B\u0937\u0948\u0936\u094D\u091A \u0926\u0939\u094D\u092F\u0928\u094D\u0924\u0947 \u0935\u0947\u0923\u0935\u094B \u0935\u0939\u094D\u0928\u093F\u0928\u093E \u092F\u0925\u093E\u0965<br> \u092E\u093E\u092F\u093E\u092E\u092F\u0948\u0903 \u0938\u0926\u093E \u092D\u093E\u0935\u0948\u0930\u0935\u093F\u0926\u094D\u092F\u093E\u0902 \u092A\u0930\u093F\u092D\u0941\u091E\u094D\u091C\u0924\u0947\u0964<br> \u092E\u093E\u092F\u093E\u092E\u092F\u0940\u0902 \u0924\u0928\u0941\u0902 \u092F\u093E\u0928\u094D\u0924\u093F \u0924\u0947 \u091C\u0928\u093E\u0903 \u0915\u094D\u0932\u0947\u0936\u092D\u093E\u091C\u0928\u092E\u094D\u0965</p></blockquote><p>\u0907\u0924\u093F\u0965\u096A\u0966\u0965</p></div><hr><div class="trans"><p>Yad\u0101 tvayamev\u0101ntar\u012B\u1E41 turyada\u015B\u0101m\u0101tmatvena na vim\u1E5B\u015Bati tad\u0101 deh\u0101dipram\u0101t\u1E5Bt\u0101bh\u0101v\u0101dap\u016Br\u1E47ammanyat\u0101tmak\u0101\u1E47avamalar\u016Bp\u0101t\u2014</p><blockquote><p><strong>Abhil\u0101\u1E63\u0101dbahirgati\u1E25 sa\u1E41v\u0101hyasya||40||</strong></p></blockquote><p>\u015Aakticakr\u0101dhi\u1E63\u1E6Dhitai\u1E25 ka\xF1cuk\u0101nta\u1E25kara\u1E47abahi\u1E63kara\u1E47atanm\u0101trabh\u016Btai\u1E25 saha sa\u1E41v\u0101hyate yoneryonyantara\u1E41 n\u012Byata iti sa\u1E41v\u0101hya\u1E25 karm\u0101tmar\u016Bpa\u1E25 pa\u015Bu\u1E25 tasya</p><blockquote><p>... abhil\u0101\u1E63o malo&#39;tra tu|</p></blockquote><p>iti \u015Br\u012Bsvacchandoktan\u012Bty\u0101p\u016Br\u1E47ammanyat\u0101tmak\u0101vidy\u0101khy\u0101\u1E47avamalar\u016Bp\u0101dabhil\u0101\u1E63\u0101ddhetorbahirgatirvi\u1E63ayonmukhatvameva bhavati na tvantarmukhar\u016Bp\u0101vahitatva\u1E41 j\u0101tucit| Yadukta\u1E41 k\u0101lik\u0101krame</p><blockquote><p>Yadavidy\u0101v\u1E5Btatay\u0101 vikalpavidhiyogata\u1E25|<br> \u015Aiv\u0101d\u012Bnnaiva jha\u1E6Diti samudbh\u0101vayatekhil\u0101n||<br> Tata\u1E25 \u015Bubh\u0101\u015Bubh\u0101 bh\u0101v\u0101 lak\u1E63yante tadva\u015Batvata\u1E25|<br> A\u015Bubhebhya\u015Bca bh\u0101vebhya\u1E25 para\u1E41 du\u1E25kha\u1E41 praj\u0101yate||<br> Atathy\u0101\u1E41 kalpan\u0101\u1E41 k\u1E5Btv\u0101 pacyante narak\u0101di\u1E63u|<br> Svotthairdo\u1E63ai\u015Bca dahyante ve\u1E47avo vahnin\u0101 yath\u0101||<br> M\u0101y\u0101mayai\u1E25 sad\u0101 bh\u0101vairavidy\u0101\u1E41 paribhu\xF1jate|<br> M\u0101y\u0101may\u012B\u1E41 tanu\u1E41 y\u0101nti te jan\u0101\u1E25 kle\u015Babh\u0101janam||</p></blockquote><p>iti||40||</p></div><hr><p>\u041D\u043E <em>(tu)</em> \u043A\u043E\u0433\u0434\u0430 <em>(tad\u0101)</em> \u044D\u0442\u043E\u0442 \u0441\u0430\u043C\u044B\u0439 [Yog\u012B] <em>(ayam eva)</em> \u043D\u0435 \u043E\u0441\u043E\u0437\u043D\u0430\u0435\u0442 <em>(na vim\u1E5B\u015Bati)</em> \u0432\u043D\u0443\u0442\u0440\u0435\u043D\u043D\u0435\u0435 <em>(\u0101ntar\u012Bm)</em> \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435 <em>(da\u015B\u0101m)</em> Turya <em>(turya)</em> \u043A\u0430\u043A \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435 \u0421\u0430\u043C\u043E\u0441\u0442\u0438 <em>(\u0101tmatvena)</em>, \u0442\u043E\u0433\u0434\u0430 <em>(tad\u0101)</em> \u0438\u0437-\u0437\u0430 \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u044F <em>(bh\u0101v\u0101t)</em>, \u0441\u043E\u0441\u0442\u043E\u044F\u0449\u0435\u0433\u043E \u0438\u0437 \u0100\u1E47avamala --\u0438\u0437\u043D\u0430\u0447\u0430\u043B\u044C\u043D\u043E\u0433\u043E \u0437\u0430\u0433\u0440\u044F\u0437\u043D\u0435\u043D\u0438\u044F-- <em>(\u0101\u1E47ava-mala)</em>, \u0445\u0430\u0440\u0430\u043A\u0442\u0435\u0440\u0438\u0437\u0443\u0435\u043C\u043E\u0433\u043E <em>(\u0101tmaka)</em> \u043F\u043E\u043D\u044F\u0442\u0438\u0435\u043C <em>(manyat\u0101)</em> \u043D\u0435\u0441\u043E\u0432\u0435\u0440\u0448\u0435\u043D\u0441\u0442\u0432\u0430 \u0438 \u043D\u0435\u043F\u043E\u043B\u043D\u043E\u0442\u044B <em>(ap\u016Br\u1E47am)</em><sup>1</sup>\u2014\u0432 \u043A\u043E\u0442\u043E\u0440\u043E\u043C \u0442\u0435\u043B\u043E <em>(deha)</em>, \u0442.\u0435. --\u0442\u0435\u043B\u043E, \u044D\u0433\u043E \u0438 \u0442.\u0434.-- <em>(\u0101di)</em> [\u0440\u0430\u0441\u0441\u043C\u0430\u0442\u0440\u0438\u0432\u0430\u0435\u0442\u0441\u044F \u043A\u0430\u043A] \u0432\u043E\u0441\u043F\u0440\u0438\u043D\u0438\u043C\u0430\u044E\u0449\u0438\u0439, \u0438\u043B\u0438 \u043F\u043E\u0437\u043D\u0430\u044E\u0449\u0438\u0439 <em>(pram\u0101t\u1E5Bt\u0101)</em>, \u0438\u043C\u0435\u0435\u043C:</p><blockquote><p><strong>\u0418\u0437-\u0437\u0430 \u0436\u0435\u043B\u0430\u043D\u0438\u044F, \u043E\u0441\u043D\u043E\u0432\u0430\u043D\u043D\u043E\u0433\u043E \u043D\u0430 \u0447\u0443\u0432\u0441\u0442\u0432\u0435 \u0436\u0430\u0436\u0434\u044B <em>(abhil\u0101\u1E63\u0101t)</em>, \u043F\u0440\u043E\u0438\u0441\u0445\u043E\u0434\u0438\u0442 \u0443\u0441\u0442\u0440\u0435\u043C\u043B\u0435\u043D\u0438\u0435 \u0432\u043E\u0432\u043D\u0435 <em>(bahirgati\u1E25)</em> \u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u043D\u043E\u0433\u043E \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u0430 <em>(sa\u1E41v\u0101hyasya)</em>, [\u043A\u043E\u0442\u043E\u0440\u043E\u0435 \u0442\u0430\u043A\u0438\u043C \u043E\u0431\u0440\u0430\u0437\u043E\u043C, \u0441\u0442\u0430\u043D\u043E\u0432\u0438\u0442\u0441\u044F \u0436\u0435\u0440\u0442\u0432\u043E\u0439 \u043A\u043E\u043B\u0435\u0441\u0430 Sa\u1E41s\u0101ra, \u0438\u043B\u0438 \u0422\u0440\u0430\u043D\u0441\u043C\u0438\u0433\u0440\u0430\u0446\u0438\u0438 \u043E\u0442 \u043E\u0434\u043D\u043E\u0439 \u0444\u043E\u0440\u043C\u044B \u0436\u0438\u0437\u043D\u0438 \u043A \u0434\u0440\u0443\u0433\u043E\u0439]||40||</strong></p></blockquote><p>&quot;Sa\u1E41v\u0101hya&quot; <em>(sa\u1E41v\u0101hya\u1E25)</em> [\u2014 \u044D\u0442\u043E] \u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u043D\u043E\u0435 \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u043E <em>(pa\u015Bu\u1E25)</em>, \u0432\u043E\u0432\u043B\u0435\u0447\u0435\u043D\u043D\u043E\u0435 <em>(\u0101tma-r\u016Bpa\u1E25)</em> \u0432 \u0434\u0435\u0439\u0441\u0442\u0432\u0438\u044F <em>(karma)</em>, [\u043A\u0442\u043E] &quot;\u0432\u043C\u0435\u0441\u0442\u0435 \u0441 <em>(saha)</em> Ka\xF1cuka-s --\u043D\u043E\u0436\u043D\u0430\u043C\u0438 \u041D\u0435\u0432\u0435\u0434\u0435\u043D\u0438\u044F--, \u0432\u043D\u0443\u0442\u0440\u0435\u043D\u043D\u0438\u043C [\u043F\u0441\u0438\u0445\u0438\u0447\u0435\u0441\u043A\u0438\u043C] \u043E\u0440\u0433\u0430\u043D\u043E\u043C --\u0441\u043E\u0441\u0442\u043E\u044F\u0449\u0438\u043C \u0438\u0437 \u0438\u043D\u0442\u0435\u043B\u043B\u0435\u043A\u0442\u0430, \u044D\u0433\u043E \u0438 \u0443\u043C\u0430--, \u0432\u043D\u0435\u0448\u043D\u0438\u043C\u0438 \u043E\u0440\u0433\u0430\u043D\u0430\u043C\u0438 --\u0441\u0432\u044F\u0437\u0430\u043D\u043D\u044B\u043C\u0438 \u0441 \u0421\u0438\u043B\u043E\u0439 \u0432\u043E\u0441\u043F\u0440\u0438\u044F\u0442\u0438\u044F \u0438 \u0434\u0435\u0439\u0441\u0442\u0432\u0438\u044F--, \u0442\u043E\u043D\u043A\u0438\u043C\u0438 \u0438 \u0433\u0440\u0443\u0431\u044B\u043C\u0438 \u044D\u043B\u0435\u043C\u0435\u043D\u0442\u0430\u043C\u0438 <em>(ka\xF1cuka-anta\u1E25kara\u1E47a-bahi\u1E63kara\u1E47a-tanm\u0101tra-bh\u016Btai\u1E25)</em>, \u043A\u043E\u0442\u043E\u0440\u044B\u0435 \u043A\u043E\u043D\u0442\u0440\u043E\u043B\u0438\u0440\u0443\u044E\u0442\u0441\u044F <em>(adhi\u1E63\u1E6Dhitai\u1E25)</em> \u0433\u0440\u0443\u043F\u043F\u043E\u0439 <em>(cakra)</em> \u0441\u0438\u043B <em>(\u015Bakti)</em><sup>2</sup>, \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u043D\u0430\u043F\u0440\u0430\u0432\u043B\u044F\u0435\u043C\u044B\u043C <em>(sa\u1E41v\u0101hyate)</em> [\u0438\u043B\u0438] \u0432\u0435\u0434\u043E\u043C\u044B\u043C <em>(n\u012Byate)</em> \u043E\u0442 \u043E\u0434\u043D\u043E\u0439 \u0444\u043E\u0440\u043C\u044B \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u043E\u0432\u0430\u043D\u0438\u044F <em>(yone\u1E25)</em> \u043A \u0434\u0440\u0443\u0433\u043E\u0439 <em>(antaram)</em> \u0444\u043E\u0440\u043C\u0435 \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u043E\u0432\u0430\u043D\u0438\u044F <em>(yoni... iti)</em>&quot;. \u0412 \u0441\u043B\u0443\u0447\u0430\u0435 \u044D\u0442\u043E\u0433\u043E [\u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u043D\u043E\u0433\u043E \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u0430] <em>(tasya)</em>, \u0441\u043E\u0433\u043B\u0430\u0441\u043D\u043E \u0442\u043E\u043C\u0443, \u0447\u0442\u043E \u0431\u044B\u043B\u043E \u0443\u043F\u043E\u043C\u044F\u043D\u0443\u0442\u043E <em>(ukta-n\u012Bty\u0101)</em> \u0432 \u0434\u043E\u0441\u0442\u043E\u0447\u0442\u0438\u043C\u043E\u043C Svacchandatantra <em>(\u015Br\u012B-svacchanda)</em> [\u0441\u043B\u0435\u0434\u0443\u044E\u0449\u0438\u043C \u043E\u0431\u0440\u0430\u0437\u043E\u043C:]</p><blockquote><p>&quot;... \u0432 \u044D\u0442\u043E\u043C \u0441\u043B\u0443\u0447\u0430\u0435 <em>(atra tu)</em>, \u0436\u0435\u043B\u0430\u043D\u0438\u0435 <em>(abhil\u0101\u1E63a\u1E25)</em> [\u2014 \u044D\u0442\u043E] \u043C\u0430\u043B\u0430, \u0438\u043B\u0438 \u0437\u0430\u0433\u0440\u044F\u0437\u043D\u0435\u043D\u0438\u0435 <em>(mala\u1E25... iti)</em>&quot;|</p></blockquote><p>\u0438\u043C\u0435\u0435\u0442 \u043C\u0435\u0441\u0442\u043E \u0443\u0441\u0442\u0440\u0435\u043C\u043B\u0435\u043D\u0438\u0435 \u0432\u043E \u0432\u043D\u0435 <em>(bahirgati\u1E25)</em> \u0438\u0437-\u0437\u0430 <em>(heto\u1E25)</em> abhil\u0101\u1E63a --\u0436\u0435\u043B\u0430\u043D\u0438\u044F, \u043E\u0441\u043D\u043E\u0432\u0430\u043D\u043D\u043E\u0433\u043E \u043D\u0430 \u0447\u0443\u0432\u0441\u0442\u0432\u0435 \u0436\u0430\u0436\u0434\u044B-- <em>(abhil\u0101\u1E63\u0101t)</em> \u0432 \u0444\u043E\u0440\u043C\u0435 <em>(r\u016Bp\u0101t)</em> \u0100\u1E47avamala <em>(\u0101\u1E47ava-mala)</em>, [\u0442\u0430\u043A\u0436\u0435] \u0438\u0437\u0432\u0435\u0441\u0442\u043D\u043E\u043C \u043A\u0430\u043A <em>(\u0101khya)</em> Avidy\u0101, \u0438\u043B\u0438 \u041D\u0435\u0432\u0435\u0434\u0435\u043D\u0438\u0435 <em>(avidy\u0101)</em>, \u0441\u043E\u0441\u0442\u043E\u044F\u0449\u0435\u043C \u0438\u0437 <em>(\u0101tmaka)</em> \u043F\u043E\u043D\u044F\u0442\u0438\u044F <em>(manyat\u0101)</em> \u043D\u0435\u0441\u043E\u0432\u0435\u0440\u0448\u0435\u043D\u0441\u0442\u0432\u0430 \u0438 \u043D\u0435\u043F\u043E\u043B\u043D\u043E\u0442\u044B <em>(ap\u016Br\u1E47am)</em>. [\u042D\u043A\u0441\u0442\u0440\u0430\u0432\u0435\u0440\u0441\u0438\u044F] \u2014 \u044D\u0442\u043E <em>(bhavati)</em> \u043E\u0440\u0438\u0435\u043D\u0442\u0430\u0446\u0438\u044F \u0442\u043E\u043B\u044C\u043A\u043E <em>(eva)</em> \u0432 \u043D\u0430\u043F\u0440\u0430\u0432\u043B\u0435\u043D\u0438\u0438 --\u0442.\u0435. \u0438\u043D\u0442\u0435\u0440\u0435\u0441-- <em>(unmukhatvam)</em> \u043E\u0431\u044A\u0435\u043A\u0442\u043E\u0432 <em>(vi\u1E63aya)</em>, [\u0438] \u043F\u043E\u043B\u043D\u043E\u0441\u0442\u044C\u044E \u043E\u0442\u0441\u0443\u0442\u0441\u0442\u0432\u0443\u0435\u0442 <em>(na tu... j\u0101tucid)</em> \u0432\u043D\u0438\u043C\u0430\u0442\u0435\u043B\u044C\u043D\u043E\u0441\u0442\u044C <em>(avahitatvam)</em> \u043A \u0432\u043D\u0443\u0442\u0440\u0435\u043D\u043D\u0435\u0439 <em>(antarmukha)</em> \u043F\u0440\u0438\u0440\u043E\u0434\u0435 <em>(r\u016Bpa)</em>|</p><p>\u0422\u043E \u0436\u0435 <em>(yad)</em> \u0431\u044B\u043B\u043E \u043F\u0440\u043E\u0432\u043E\u0437\u0433\u043B\u0430\u0448\u0435\u043D\u043E <em>(uktam)</em> \u0432 K\u0101lik\u0101krama <em>(k\u0101lik\u0101krame)</em>:</p><blockquote><p>&quot;[\u0412 \u0441\u043B\u0443\u0447\u0430\u0435 \u043D\u0435\u0432\u0435\u0436\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0433\u043E \u0447\u0435\u043B\u043E\u0432\u0435\u043A\u0430,] \u043E\u0445\u0432\u0430\u0447\u0435\u043D\u043D\u043E\u0433\u043E, \u0438\u043B\u0438 \u043F\u043E\u043A\u0440\u044B\u0442\u043E\u0433\u043E <em>(\u0101v\u1E5Btatay\u0101)</em> \u043D\u0435\u0432\u0435\u0434\u0435\u043D\u0438\u0435\u043C <em>(avidy\u0101)</em> \u043E \u0422\u043E\u043C --\u0421\u0430\u043C\u043E\u0441\u0442\u0438-- <em>(yad)</em> [\u0438] \u0438\u0437-\u0437\u0430 <em>(yogatas)</em> \u0438\u0441\u043F\u043E\u043B\u044C\u0437\u043E\u0432\u0430\u043D\u0438\u044F, \u0438\u043B\u0438 \u043F\u0440\u0438\u043C\u0435\u043D\u0435\u043D\u0438\u044F <em>(vidhi)</em> \u043C\u044B\u0441\u043B\u0435\u0439 <em>(vikalpa)</em>, \u043E\u043D \u043D\u0435 \u0441\u0440\u0430\u0437\u0443 \u043E\u0441\u043E\u0437\u043D\u0430\u0435\u0442 <em>(na eva jha\u1E6Diti samudbh\u0101vayate)</em>, \u0447\u0442\u043E \u0432\u0441\u0435 [\u0442\u0430\u0442\u0442\u0432\u044B, \u0438\u043B\u0438 \u043A\u0430\u0442\u0435\u0433\u043E\u0440\u0438\u0438] <em>(akhil\u0101n)</em>, \u043D\u0430\u0447\u0438\u043D\u0430\u044F \u0441 <em>(\u0101d\u012Bn)</em> \u015Aiva <em>(\u015Biva)</em>, [\u044F\u0432\u043B\u044F\u044E\u0442\u0441\u044F \u0435\u0433\u043E \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0439 \u0441\u0443\u0449\u043D\u043E\u0441\u0442\u043D\u043E\u0439 \u043F\u0440\u0438\u0440\u043E\u0434\u043E\u0439, \u043F\u0440\u0435\u0434\u0441\u0442\u0430\u0432\u043B\u044F\u044E\u0449\u0435\u0439 \u0441\u043E\u0431\u043E\u0439 \u043A\u043E\u043C\u043F\u0430\u043A\u0442\u043D\u0443\u044E \u043C\u0430\u0441\u0441\u0443 \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u044F].</p></blockquote><blockquote><p>\u0417\u0430\u0442\u0435\u043C <em>(tatas)</em> \u043F\u043E\u044F\u0432\u043B\u044F\u044E\u0442\u0441\u044F <em>(lak\u1E63yante)</em> \u0445\u043E\u0440\u043E\u0448\u0438\u0435 \u0438 \u043F\u043B\u043E\u0445\u0438\u0435 <em>(\u015Bubha-a\u015Bubh\u0101\u1E25)</em> \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u044F <em>(bh\u0101v\u0101\u1E25)</em>; \u0438 <em>(ca)</em> \u043F\u043E\u0441\u043A\u043E\u043B\u044C\u043A\u0443 [\u0442\u0430\u043A\u043E\u0439 \u0447\u0435\u043B\u043E\u0432\u0435\u043A] \u043D\u0430\u0445\u043E\u0434\u0438\u0442\u0441\u044F \u043F\u043E\u0434 \u043A\u043E\u043D\u0442\u0440\u043E\u043B\u0435\u043C <em>(va\u015Batvata\u1E25)</em> \u0442\u043E\u0433\u043E [\u043D\u0435\u0432\u0435\u0434\u0435\u043D\u0438\u044F \u043E \u0441\u0432\u043E\u0435\u0439 \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0439 \u0421\u0430\u043C\u043E\u0441\u0442\u0438] <em>(tad)</em>, \u0432\u0435\u043B\u0438\u043A\u0430\u044F <em>(param)</em> \u0431\u043E\u043B\u044C <em>(du\u1E25kham)</em> \u043E\u0432\u043B\u0430\u0434\u0435\u0432\u0430\u0435\u0442 [\u0438\u043C] <em>(praj\u0101yate)</em> \u0438\u0437-\u0437\u0430 \u0432\u044B\u0448\u0435\u0443\u043F\u043E\u043C\u044F\u043D\u0443\u0442\u044B\u0445 \u043F\u043B\u043E\u0445\u0438\u0445 \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0439 <em>(a\u015Bubhebhya\u1E25... bh\u0101vebhya\u1E25)</em><sup>3</sup>.</p></blockquote><blockquote><p>\u041E\u0431\u043B\u0430\u0434\u0430\u044F <em>(k\u1E5Btv\u0101)</em> \u043B\u043E\u0436\u043D\u044B\u043C\u0438 <em>(atathy\u0101m)</em> \u0438\u0434\u0435\u044F\u043C\u0438 \u0438 \u0444\u0430\u043D\u0442\u0430\u0437\u0438\u044F\u043C\u0438 <em>(kalpan\u0101m)</em>, [\u0442\u0430\u043A\u0438\u0435 \u043D\u0435\u0432\u0435\u0436\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u044B\u0435 \u043B\u044E\u0434\u0438] \u043C\u0443\u0447\u0430\u044E\u0442\u0441\u044F <em>(pacyante)</em> \u0432 \u0430\u0434\u0443 <em>(naraka)</em>, \u0438 \u0442.\u0434. <em>(\u0101di\u1E63u)</em>, \u0438 <em>(ca)</em> \u0441\u0436\u0438\u0433\u0430\u044E\u0442\u0441\u044F <em>(dahyante)</em> \u0441\u0432\u043E\u0438\u043C\u0438 \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u044B\u043C\u0438 \u043D\u0435\u0434\u043E\u0441\u0442\u0430\u0442\u043A\u0430\u043C\u0438 \u0438 \u043F\u043E\u0440\u043E\u043A\u0430\u043C\u0438 <em>(sva-utthai\u1E25 do\u1E63ai\u1E25)</em>, \u0442\u0430\u043A\u0436\u0435 \u043A\u0430\u043A <em>(yath\u0101)</em> \u0431\u0430\u043C\u0431\u0443\u043A <em>(ve\u1E47ava\u1E25)</em> [\u0441\u0436\u0438\u0433\u0430\u0435\u0442\u0441\u044F \u0441\u0432\u043E\u0438\u043C \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u044B\u043C] \u043E\u0433\u043D\u0435\u043C <em>(vahnin\u0101)</em>.</p></blockquote><blockquote><p>\u0422\u0435 <em>(te)</em> \u043B\u044E\u0434\u0438 <em>(jan\u0101\u1E25)</em> \u0432\u0441\u0435\u0433\u0434\u0430 <em>(sad\u0101)</em> \u0441\u0442\u0440\u0430\u0434\u0430\u044E\u0442 \u043E\u0442 <em>(paribhu\xF1jate)</em> \u043D\u0435\u0432\u0435\u0434\u0435\u043D\u0438\u044F <em>(avidy\u0101m)</em> \u0438\u0437-\u0437\u0430 [\u0441\u0432\u043E\u0438\u0445 \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u044B\u0445] \u0438\u043B\u043B\u044E\u0437\u043E\u0440\u043D\u044B\u0445 \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0439 --\u041C\u0430\u0439\u0438\u0447\u0435\u0441\u043A\u0438\u0445 \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0439-- <em>(m\u0101y\u0101-mayai\u1E25... bh\u0101vai\u1E25)</em>; [\u0438 \u043A\u043E\u0433\u0434\u0430] \u043E\u043D\u0438 \u043F\u043E\u043B\u0443\u0447\u0430\u044E\u0442 \u0442\u0435\u043B\u043E <em>(tanum y\u0101nti)</em>, \u0441\u043E\u0442\u0432\u043E\u0440\u0435\u043D\u043D\u043E\u0435 \u041C\u0430\u0439\u0435\u0439 (M\u0101y\u0101) --\u0441\u0430\u043C\u0438\u043C \u0417\u0430\u0431\u043B\u0443\u0436\u0434\u0435\u043D\u0438\u0435\u043C-- <em>(m\u0101y\u0101-may\u012Bm)</em>, [\u043E\u043D\u0438 \u0441\u0442\u0430\u043D\u043E\u0432\u044F\u0442\u0441\u044F] \u0432\u043C\u0435\u0441\u0442\u0438\u043B\u0438\u0449\u0435\u043C <em>(bh\u0101janam)</em> \u043D\u0435\u0434\u0443\u0433\u043E\u0432 <em>(kle\u015Ba... iti)</em><sup>4</sup>&quot;</p></blockquote><p>||40||</p><hr><ol><li><p>\u0100\u1E47avamala \u2014 \u044D\u0442\u043E \u0438\u0437\u043D\u0430\u0447\u0430\u043B\u044C\u043D\u043E\u0435 \u0437\u0430\u0433\u0440\u044F\u0437\u043D\u0435\u043D\u0438\u0435 (\u043F\u0435\u0440\u0432\u043E\u0435 \u0438 \u0441\u0430\u043C\u043E\u0435 \u0441\u0438\u043B\u044C\u043D\u043E\u0435), \u043A\u043E\u0442\u043E\u0440\u043E\u0435 \u0437\u0430\u0441\u0442\u0430\u0432\u043B\u044F\u0435\u0442 \u0413\u043E\u0441\u043F\u043E\u0434\u0430 (\u0422\u0435\u0431\u044F!) \u0447\u0443\u0432\u0441\u0442\u0432\u043E\u0432\u0430\u0442\u044C, \u0447\u0442\u043E \u041E\u043D \u043D\u0435 \u0441\u043E\u0432\u0435\u0440\u0448\u0435\u043D\u0435\u043D \u0438 \u043D\u0435 \u043F\u043E\u043B\u043E\u043D. \u0427\u0435\u0440\u0435\u0437 \u0443\u0441\u0438\u043B\u0438\u044F \u0432\u044B \u043C\u043E\u0436\u0435\u0442\u0435 \u0443\u0434\u0430\u043B\u0438\u0442\u044C \u0432\u0441\u0435 \u0437\u0430\u0433\u0440\u044F\u0437\u043D\u0435\u043D\u0438\u044F, \u043A\u0440\u043E\u043C\u0435 \u0100\u1E47avamala. \u0415\u0451 \u0443\u0434\u0430\u043B\u0435\u043D\u0438\u0435 \u0432\u043E\u0437\u043C\u043E\u0436\u043D\u043E \u0442\u043E\u043B\u044C\u043A\u043E \u043F\u043E\u0441\u0440\u0435\u0434\u0441\u0442\u0432\u043E\u043C \u0415\u0433\u043E \u041C\u0438\u043B\u043E\u0441\u0442\u0438, \u0430 \u043D\u0435 \u043A\u0430\u043A\u0438\u0445 \u0431\u044B \u0442\u043E \u043D\u0438 \u0431\u044B\u043B\u043E \u0443\u0441\u0438\u043B\u0438\u0439. \u041F\u043E\u0434 \u0441\u043B\u043E\u0432\u043E\u043C &quot;\u0437\u0430\u0433\u0440\u044F\u0437\u043D\u0435\u043D\u0438\u0435/\u043D\u0435\u0447\u0438\u0441\u0442\u043E\u0442\u0430&quot;, \u043D\u0435 \u043F\u043E\u0434\u0440\u0430\u0437\u0443\u043C\u0435\u0432\u0430\u0435\u0442\u0441\u044F \u043D\u0438\u0447\u0435\u0433\u043E &quot;\u0430\u043C\u043E\u0440\u0430\u043B\u044C\u043D\u043E\u0433\u043E&quot;. \u0412 \u0422\u0440\u0438\u043A\u0435 \u0437\u0430\u0433\u0440\u044F\u0437\u043D\u0435\u043D\u0438\u0435/\u043D\u0435\u0447\u0438\u0441\u0442\u043E\u0442\u0430 \u043E\u0437\u043D\u0430\u0447\u0430\u0435\u0442 &quot;\u043E\u0442\u0441\u0443\u0442\u0441\u0442\u0432\u0438\u0435 \u0435\u0434\u0438\u043D\u0441\u0442\u0432\u0430&quot;, \u0430 \u0447\u0438\u0441\u0442\u043E\u0442\u0430 \u2014 &quot;\u043D\u0430\u043B\u0438\u0447\u0438\u0435 \u0435\u0434\u0438\u043D\u0441\u0442\u0432\u0430&quot;. \u0422\u0430\u043A\u0438\u043C \u043E\u0431\u0440\u0430\u0437\u043E\u043C, \u043C\u0430\u043B\u0430, \u0438\u043B\u0438 \u0437\u0430\u0433\u0440\u044F\u0437\u043D\u0435\u043D\u0438\u0435 \u2014 \u044D\u0442\u043E \u0442\u043E, \u0447\u0442\u043E \u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0438\u0432\u0430\u0435\u0442 \u0438 \u043F\u0440\u0438\u0432\u043E\u0434\u0438\u0442 \u0432 \u043A\u043E\u043D\u0446\u0435 \u043A\u043E\u043D\u0446\u043E\u0432 \u043A \u0434\u0432\u043E\u0439\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0441\u0442\u0438, \u0442.\u0435. \u043F\u0440\u0435\u043A\u0440\u0430\u0449\u0435\u043D\u0438\u044E \u0435\u0434\u0438\u043D\u0441\u0442\u0432\u0430.</p></li><li><p>\u041C\u0443\u0434\u0440\u0435\u0446 \u0443\u043F\u043E\u043C\u0438\u043D\u0430\u0435\u0442 \u0432\u0435\u0441\u044C \u0446\u0438\u043A\u043B \u0442\u0430\u0442\u0442\u0432 (\u043A\u0430\u0442\u0435\u0433\u043E\u0440\u0438\u0439 \u0443\u043D\u0438\u0432\u0435\u0440\u0441\u0430\u043B\u044C\u043D\u043E\u0433\u043E \u043F\u0440\u043E\u044F\u0432\u043B\u0435\u043D\u0438\u044F), \u043E\u0442 Ka\xF1cuka-s (\u0432\u043A\u043B\u044E\u0447\u0430\u044E\u0449\u0438\u0445 M\u0101y\u0101, \u0438\u0445 \u0438\u0441\u0442\u043E\u0447\u043D\u0438\u043A) \u0434\u043E \u043F\u043E\u0441\u043B\u0435\u0434\u043D\u0435\u0433\u043E \u0433\u0440\u0443\u0431\u043E\u0433\u043E \u044D\u043B\u0435\u043C\u0435\u043D\u0442\u0430.</p></li><li><p>\u042D\u0442\u0438 \u0434\u0432\u0435 \u0441\u0442\u0440\u043E\u0444\u044B \u0432 K\u0101lik\u0101krama \u0443\u0436\u0435 \u0431\u044B\u043B\u0438 \u043F\u0440\u043E\u0446\u0438\u0442\u0438\u0440\u043E\u0432\u0430\u043D\u044B K\u1E63emar\u0101ja, \u0430 \u0442\u0430\u043A\u0436\u0435 \u043F\u0435\u0440\u0435\u0432\u0435\u0434\u0435\u043D\u044B \u043C\u043D\u043E\u0439 \u0432 III, 35 \u044D\u0442\u043E\u0433\u043E \u041F\u0438\u0441\u0430\u043D\u0438\u044F. \u0422\u0435\u043C \u043D\u0435 \u043C\u0435\u043D\u0435\u0435, \u0441\u043B\u0435\u0434\u0443\u044E\u0449\u0438\u0435 \u0434\u0432\u0435 \u0441\u0442\u0440\u043E\u0444\u044B \u044F\u0432\u043B\u044F\u044E\u0442\u0441\u044F \u0441\u043E\u0432\u0435\u0440\u0448\u0435\u043D\u043D\u043E \u043D\u043E\u0432\u044B\u043C\u0438!</p></li><li><p>\u0421\u043E\u0433\u043B\u0430\u0441\u043D\u043E \u043C\u0443\u0434\u0440\u0435\u0446\u0443 Pata\xF1jali, \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u0443\u044E\u0442 \u043F\u044F\u0442\u044C \u0432\u0438\u0434\u043E\u0432 \u043D\u0435\u0434\u0443\u0433\u043E\u0432/\u0431\u043E\u043B\u0435\u0437\u043D\u0435\u0439. .</p></li></ol></div><div class="stanza"><a href="#s3.41" id="s3.41" class="num">3.41</a><div class="sans"><p>\u092F\u0926\u093E \u0924\u0941 \u092A\u093E\u0930\u092E\u0947\u0936\u0936\u0915\u094D\u0924\u093F\u092A\u093E\u0924\u0935\u0936\u094B\u0928\u094D\u092E\u093F\u0937\u093F\u0924\u0902 \u0938\u094D\u0935\u0902 \u0938\u094D\u0935\u092D\u093E\u0935\u092E\u0947\u0935 \u0935\u093F\u092E\u0943\u0936\u0924\u093F \u0924\u0926\u093E\u092D\u093F\u0932\u093E\u0937\u093E\u092D\u093E\u0935\u093E\u0928\u094D\u0928\u093E\u0938\u094D\u092F \u092C\u0939\u093F\u0930\u094D\u0917\u0924\u093F\u0930\u092A\u093F \u0924\u094D\u0935\u093E\u0924\u094D\u092E\u093E\u0930\u093E\u092E\u0924\u0948\u0935 \u0928\u093F\u0924\u094D\u092F\u092E\u093F\u0924\u094D\u092F\u093E\u0939\u2014</p><blockquote><p><strong>\u0924\u0926\u093E\u0930\u0942\u0922\u092A\u094D\u0930\u092E\u093F\u0924\u0947\u0938\u094D\u0924\u0924\u094D\u0915\u094D\u0937\u092F\u093E\u091C\u094D\u091C\u0940\u0935\u0938\u0919\u094D\u0915\u094D\u0937\u092F\u0903\u0965\u096A\u0967\u0965</strong></p></blockquote><p>\u0924\u0926\u093F\u0924\u093F \u092A\u0942\u0930\u094D\u0935\u0928\u093F\u0930\u094D\u0926\u093F\u0937\u094D\u091F\u0938\u0902\u0935\u0947\u0924\u094D\u0924\u094D\u0930\u093E\u0924\u094D\u092E\u0928\u093F \u0924\u0941\u0930\u094D\u092F\u092A\u0926 \u0906\u0930\u0942\u0922\u093E \u0924\u0926\u094D\u0935\u093F\u092E\u0930\u094D\u0936\u0928\u092A\u0930\u093E \u092A\u094D\u0930\u092E\u093F\u0924\u093F\u0903 \u0938\u0902\u0935\u093F\u0926\u094D\u092F\u0938\u094D\u092F \u092F\u094B\u0917\u093F\u0928\u0938\u094D\u0924\u0938\u094D\u092F\u0964 \u0924\u0926\u093F\u0924\u094D\u092F\u092D\u093F\u0932\u093E\u0937\u0915\u094D\u0937\u092F\u093E\u091C\u094D\u091C\u0940\u0935\u0938\u094D\u092F \u0938\u0902\u0935\u093E\u0939\u094D\u092F\u093E\u0924\u094D\u092E\u0928\u0903 \u092A\u0941\u0930\u094D\u092F\u0937\u094D\u091F\u0915\u092A\u094D\u0930\u092E\u093E\u0924\u0943\u092D\u093E\u0935\u0938\u094D\u092F \u0915\u094D\u0937\u092F\u0903 \u092A\u094D\u0930\u0936\u092E\u0936\u094D\u091A\u093F\u0924\u094D\u092A\u094D\u0930\u092E\u093E\u0924\u0943\u0924\u092F\u0948\u0935 \u0938\u094D\u092B\u0941\u0930\u0924\u0940\u0924\u094D\u092F\u0930\u094D\u0925\u0903\u0964 \u092F\u0926\u0941\u0915\u094D\u0924\u0902 \u0924\u0924\u094D\u0930\u0948\u0935</p><blockquote><p>\u092F\u0925\u093E \u0938\u094D\u0935\u092A\u094D\u0928\u093E\u0928\u0941\u092D\u0942\u0924\u093E\u0930\u094D\u0925\u093E\u0928\u094D\u092A\u094D\u0930\u092C\u0941\u0926\u094D\u0927\u094B \u0928\u0948\u0935 \u092A\u0936\u094D\u092F\u0924\u093F\u0964<br> \u0924\u0925\u093E \u092D\u093E\u0935\u0928\u092F\u093E \u092F\u094B\u0917\u0940 \u0938\u0902\u0938\u093E\u0930\u0902 \u0928\u0948\u0935 \u092A\u0936\u094D\u092F\u0924\u093F\u0965</p></blockquote><p>\u0907\u0924\u093F\u0964 \u0924\u0925\u093E</p><blockquote><p>\u0928\u093F\u0930\u0938\u094D\u092F \u0938\u0926\u0938\u0926\u094D\u0935\u0943\u0924\u094D\u0924\u0940\u0903 \u0938\u0902\u0936\u094D\u0930\u093F\u0924\u094D\u092F \u092A\u0926\u092E\u093E\u0928\u094D\u0924\u0930\u092E\u094D\u0964<br> \u0935\u093F\u0939\u093E\u092F \u0915\u0932\u094D\u092A\u0928\u093E\u091C\u093E\u0932\u092E\u0926\u094D\u0935\u0948\u0924\u0947\u0928 \u092A\u0930\u093E\u092A\u0930\u092E\u094D\u0965<br> \u092F\u0903 \u0938\u094D\u0935\u093E\u0924\u094D\u092E\u0928\u093F\u0930\u0924\u094B \u0928\u093F\u0924\u094D\u092F\u0902 \u0915\u093E\u0932\u0917\u094D\u0930\u093E\u0938\u0948\u0915\u0924\u0924\u094D\u092A\u0930\u0903\u0964<br> \u0915\u0948\u0935\u0932\u094D\u092F\u092A\u0926\u092D\u093E\u0917\u094D\u092F\u094B\u0917\u0940 \u0938 \u0928\u093F\u0930\u094D\u0935\u093E\u0923\u092A\u0926\u0902 \u0932\u092D\u0947\u0924\u094D\u0965</p></blockquote><p>\u0907\u0924\u093F\u0964 \u0915\u0948\u0935\u0932\u094D\u092F\u092A\u0926\u092D\u093E\u0917\u093F\u0924\u0940\u0928\u094D\u0926\u094D\u0930\u093F\u092F\u0924\u0928\u094D\u092E\u093E\u0924\u094D\u0930\u093E\u092D\u093F\u0930\u0938\u0902\u0935\u093E\u0939\u094D\u092F\u0903\u0965\u096A\u0967\u0965</p></div><hr><div class="trans"><p>Yad\u0101 tu p\u0101rame\u015Ba\u015Baktip\u0101tava\u015Bonmi\u1E63ita\u1E41 sva\u1E41 svabh\u0101vameva vim\u1E5B\u015Bati tad\u0101bhil\u0101\u1E63\u0101bh\u0101v\u0101nn\u0101sya bahirgatirapi tv\u0101tm\u0101r\u0101mataiva nityamity\u0101ha\u2014</p><blockquote><p><strong>Tad\u0101r\u016B\u1E0Dhapramitestatk\u1E63ay\u0101jj\u012Bvasa\u1E45k\u1E63aya\u1E25||41||</strong></p></blockquote><p>Taditi p\u016Brvanirdi\u1E63\u1E6Dasa\u1E41vettr\u0101tmani turyapada \u0101r\u016B\u1E0Dh\u0101 tadvimar\u015Banapar\u0101 pramiti\u1E25 sa\u1E41vidyasya yoginastasya| Tadityabhil\u0101\u1E63ak\u1E63ay\u0101jj\u012Bvasya sa\u1E41v\u0101hy\u0101tmana\u1E25 purya\u1E63\u1E6Dakapram\u0101t\u1E5Bbh\u0101vasya k\u1E63aya\u1E25 pra\u015Bama\u015Bcitpram\u0101t\u1E5Btayaiva sphurat\u012Btyartha\u1E25| Yadukta\u1E41 tatraiva</p><blockquote><p>Yath\u0101 svapn\u0101nubh\u016Bt\u0101rth\u0101nprabuddho naiva pa\u015Byati|<br> Tath\u0101 bh\u0101vanay\u0101 yog\u012B sa\u1E41s\u0101ra\u1E41 naiva pa\u015Byati||</p></blockquote><p>iti| Tath\u0101</p><blockquote><p>Nirasya sadasadv\u1E5Btt\u012B\u1E25 sa\u1E41\u015Britya padam\u0101ntaram|<br> Vih\u0101ya kalpan\u0101j\u0101lamadvaitena par\u0101param||<br> Ya\u1E25 sv\u0101tmanirato nitya\u1E41 k\u0101lagr\u0101saikatatpara\u1E25|<br> Kaivalyapadabh\u0101gyog\u012B sa nirv\u0101\u1E47apada\u1E41 labhet||</p></blockquote><p>iti| Kaivalyapadabh\u0101git\u012Bndriyatanm\u0101tr\u0101bhirasa\u1E41v\u0101hya\u1E25||41||</p></div><hr><p>\u041E\u0434\u043D\u0430\u043A\u043E <em>(tu)</em>, \u043A\u043E\u0433\u0434\u0430 <em>(yad\u0101)</em> [Yog\u012B] \u043E\u0441\u043E\u0437\u043D\u0430\u0451\u0442 <em>(vim\u1E5B\u015Bati)</em> \u0441\u0432\u043E\u044E \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u0443\u044E <em>(svam)</em> \u0441\u0443\u0449\u043D\u043E\u0441\u0442\u043D\u0443\u044E \u043F\u0440\u0438\u0440\u043E\u0434\u0443 <em>(sva-bh\u0101vam eva)</em>, \u043F\u0440\u043E\u044F\u0432\u043B\u0435\u043D\u043D\u0443\u044E <em>(unmi\u1E63ita)</em> \u0438\u0437-\u0437\u0430 \u043D\u0438\u0441\u0445\u043E\u0436\u0434\u0435\u043D\u0438\u044F \u041C\u0438\u043B\u043E\u0441\u0442\u0438 --\u0442.\u0435. \u043D\u0438\u0441\u0445\u043E\u0436\u0434\u0435\u043D\u0438\u044F \u0421\u0438\u043B\u044B-- <em>(\u015Bakti-p\u0101ta)</em> \u0412\u044B\u0441\u0448\u0435\u0433\u043E \u0413\u043E\u0441\u043F\u043E\u0434\u0430 <em>(p\u0101rame\u015Ba)</em>, \u0442\u043E\u0433\u0434\u0430 <em>(tad\u0101)</em>, \u0438\u0437-\u0437\u0430 \u043E\u0442\u0441\u0443\u0442\u0441\u0442\u0432\u0438\u044F <em>(abh\u0101v\u0101t)</em> abhil\u0101\u1E63a, \u0438\u043B\u0438 \u0436\u0435\u043B\u0430\u043D\u0438\u044F, \u043E\u0441\u043D\u043E\u0432\u0430\u043D\u043D\u043E\u0433\u043E \u043D\u0430 \u0447\u0443\u0432\u0441\u0442\u0432\u0435 \u0436\u0430\u0436\u0434\u044B <em>(abhil\u0101\u1E63a)</em>, \u043D\u0435\u0442 \u043D\u0430\u043F\u0440\u0430\u0432\u043B\u0435\u043D\u043D\u043E\u0441\u0442\u0438 \u0432\u043E\u0432\u043D\u0435 <em>(na... bahirgati\u1E25)</em> \u0432 \u044D\u0442\u043E\u043C \u0441\u043B\u0443\u0447\u0430\u0435 <em>(asya)</em>, \u043D\u043E \u0441\u043A\u043E\u0440\u0435\u0435 <em>(api tu)</em> \u043D\u0435\u043F\u0440\u0435\u043A\u0440\u0430\u0449\u0430\u044E\u0449\u0435\u0435\u0441\u044F <em>(nityam)</em> \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435 \u0440\u0430\u0434\u043E\u0441\u0442\u0438 <em>(\u0101r\u0101mat\u0101)</em> (\u043F\u0440\u0435\u0431\u044B\u0432\u0430\u043D\u0438\u044F) \u0432 \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0439 \u0421\u0430\u043C\u043E\u0441\u0442\u0438 <em>(\u0101tma)</em>. [\u015Aiva] \u0441\u043A\u0430\u0437\u0430\u043B <em>(\u0101ha)</em> \u0442\u0430\u043A <em>(iti)</em> [\u0432 \u0441\u043B\u0435\u0434\u0443\u044E\u0449\u0435\u043C \u0430\u0444\u043E\u0440\u0438\u0437\u043C\u0435]\u2014</p><blockquote><p><strong>[\u041E\u0434\u043D\u0430\u043A\u043E,] \u0432 \u0441\u043B\u0443\u0447\u0430\u0435 [\u0432\u0435\u043B\u0438\u043A\u043E\u0433\u043E Yog\u012B], \u0447\u044C\u044F \u043E\u0441\u043E\u0437\u043D\u0430\u043D\u043D\u043E\u0441\u0442\u044C <em>(pramite\u1E25)</em> \u0443\u043A\u043E\u0440\u0435\u043D\u0435\u043D\u0430 <em>(\u0101r\u016B\u1E0Dha)</em> \u0432 \u0422\u043E\u043C --\u0432 \u0447\u0435\u0442\u0432\u0435\u0440\u0442\u043E\u043C \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0438, \u0438\u043B\u0438 Turya-- <em>(tad)</em>, \u043F\u0440\u0438 \u0438\u0437\u0431\u0430\u0432\u043B\u0435\u043D\u0438\u0438 <em>(k\u1E63ay\u0101t)</em> \u043E\u0442 \u0442\u043E\u0433\u043E [\u0436\u0435\u043B\u0430\u043D\u0438\u044F] --\u0441\u043C. \u0430\u0444\u043E\u0440\u0438\u0437\u043C 40</strong></p></blockquote><p>;;; sans-- <em>(tad)</em> [\u0442\u0430\u043A\u0436\u0435] \u043F\u043E\u043B\u043D\u043E\u0441\u0442\u044C\u044E \u0443\u0441\u0442\u0440\u0430\u043D\u044F\u0435\u0442\u0441\u044F <em>(sa\u1E45k\u1E63aya\u1E25)</em> [\u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435] \u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u043D\u043E\u0433\u043E \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u0430 <em>(j\u012Bva)</em>||41||</p><p>[\u041F\u0435\u0440\u0432\u043E\u0435] &quot;tad&quot; <em>(tad iti)</em> [\u043E\u0437\u043D\u0430\u0447\u0430\u0435\u0442] \u0432 \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0438 <em>(pade)</em> Turya <em>(turya)</em>, \u0447\u044C\u044F \u043F\u0440\u0438\u0440\u043E\u0434\u0430 <em>(\u0101tmani)</em> \u2014 [\u0412\u044B\u0441\u0448\u0438\u0439] \u041F\u043E\u0437\u043D\u0430\u044E\u0449\u0438\u0439 <em>(sa\u1E41vett\u1E5B)</em>, \u0447\u0442\u043E \u0431\u044B\u043B\u043E \u0432\u044B\u0440\u0430\u0436\u0435\u043D\u043E <em>(nirdi\u1E63\u1E6Da)</em> \u0440\u0430\u043D\u0435\u0435 <em>(p\u016Brva)</em> --\u0432 III, 32--. [\u0421\u043B\u043E\u0432\u043E] \u0101r\u016B\u1E0Dha --\u0443\u043A\u043E\u0440\u0435\u043D\u0435\u043D\u043D\u044B\u0439-- <em>(\u0101r\u016B\u1E0Dh\u0101)</em> [\u043E\u0437\u043D\u0430\u0447\u0430\u0435\u0442] \u043F\u043E\u0441\u0432\u044F\u0449\u0451\u043D\u043D\u044B\u0439 <em>(par\u0101)</em> \u0432\u043E\u0441\u043F\u0440\u0438\u044F\u0442\u0438\u044E \u0438 \u043E\u0441\u043E\u0437\u043D\u0430\u043D\u0438\u044E <em>(vimar\u015Bana)</em> \u0442\u043E\u0439 [Turya] <em>(tad)</em>. [\u0418 pramite\u1E25 \u043E\u0437\u043D\u0430\u0447\u0430\u0435\u0442] \u0432 \u0441\u043B\u0443\u0447\u0430\u0435 \u0442\u043E\u0433\u043E Yog\u012B <em>(yogina\u1E25 tasya)</em>, \u0447\u044C\u044F <em>(yasya)</em> pramiti <em>(pramiti\u1E25)</em>, [\u0438\u043B\u0438] \u043E\u0441\u043E\u0437\u043D\u0430\u043D\u043D\u043E\u0441\u0442\u044C <em>(sa\u1E41vid)</em> --\u0442\u043E\u0433\u0434\u0430, \u043F\u0435\u0440\u0432\u043E\u0435 \u0432\u044B\u0440\u0430\u0436\u0435\u043D\u0438\u0435 &quot;Tad\u0101r\u016B\u1E0Dhapramite\u1E25&quot; \u0432 \u0430\u0444\u043E\u0440\u0438\u0437\u043C\u0435 \u043E\u0437\u043D\u0430\u0447\u0430\u0435\u0442 &quot;\u0412 \u0441\u043B\u0443\u0447\u0430\u0435 \u0442\u043E\u0433\u043E Yog\u012B, \u0447\u044C\u044F \u043E\u0441\u043E\u0437\u043D\u0430\u043D\u043D\u043E\u0441\u0442\u044C \u0443\u043A\u043E\u0440\u0435\u043D\u0435\u043D\u0430 \u0432 \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0438 Turya, \u0442.\u0435. \u043E\u0441\u043E\u0437\u043D\u0430\u043D\u043D\u043E\u0441\u0442\u044C \u043F\u043E\u0441\u0432\u044F\u0449\u0435\u043D\u0430 \u0432\u043E\u0441\u043F\u0440\u0438\u044F\u0442\u0438\u044E \u0438 \u0440\u0435\u0430\u043B\u0438\u0437\u0430\u0446\u0438\u0438 \u0442\u043E\u0433\u043E \u0427\u0435\u0442\u0432\u0435\u0440\u0442\u043E\u0433\u043E \u0421\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u044F, \u043A\u043E\u0442\u043E\u0440\u043E\u0435 \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u0412\u044B\u0441\u0448\u0438\u043C \u041F\u043E\u0437\u043D\u0430\u044E\u0449\u0438\u043C&quot;--|</p><p>[\u0412\u0442\u043E\u0440\u043E\u0435] &quot;tad&quot; <em>(tad)</em> [\u043E\u0437\u043D\u0430\u0447\u0430\u0435\u0442 \u0436\u0435\u043B\u0430\u043D\u0438\u0435, \u043E\u0441\u043D\u043E\u0432\u0430\u043D\u043D\u043E\u0435 \u043D\u0430 \u0447\u0443\u0432\u0441\u0442\u0432\u0435 \u0436\u0430\u0436\u0434\u044B. \u0421\u043B\u0435\u0434\u043E\u0432\u0430\u0442\u0435\u043B\u044C\u043D\u043E, \u0432\u044B\u0440\u0430\u0436\u0435\u043D\u0438\u0435 &quot;tatk\u1E63ay\u0101t&quot; \u043E\u0437\u043D\u0430\u0447\u0430\u0435\u0442] \u043F\u0440\u0438 \u0438\u0437\u0431\u0430\u0432\u043B\u0435\u043D\u0438\u0438 <em>(k\u1E63ay\u0101t)</em> \u043E\u0442 \u0436\u0435\u043B\u0430\u043D\u0438\u044F, \u043E\u0441\u043D\u043E\u0432\u0430\u043D\u043D\u043E\u0433\u043E \u043D\u0430 \u0447\u0443\u0432\u0441\u0442\u0432\u0435 \u0436\u0430\u0436\u0434\u044B <em>(abhil\u0101\u1E63a)</em>. [\u041D\u0430\u043A\u043E\u043D\u0435\u0446, \u0432\u044B\u0440\u0430\u0436\u0435\u043D\u0438\u0435 &quot;j\u012Bvasa\u1E45k\u1E63aya\u1E25&quot; \u043E\u0437\u043D\u0430\u0447\u0430\u0435\u0442 \u043F\u043E\u043B\u043D\u043E\u0435] \u0443\u0441\u0442\u0440\u0430\u043D\u0435\u043D\u0438\u0435 <em>(k\u1E63aya\u1E25)</em>, [\u0438\u043B\u0438] \u043F\u0440\u0435\u043A\u0440\u0430\u0449\u0435\u043D\u0438\u0435 <em>(pra\u015Bama\u1E25)</em> (\u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u044F) j\u012Bva <em>(j\u012Bvasya)</em>, [\u0438\u043B\u0438] \u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u043D\u043E\u0433\u043E \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u0430 <em>(sa\u1E41v\u0101hya-\u0101tmana\u1E25)</em>, \u0442.\u0435. \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u044F <em>(bh\u0101vasya)</em>, \u0432 \u043A\u043E\u0442\u043E\u0440\u043E\u043C \u0442\u043E\u043D\u043A\u043E\u0435 \u0442\u0435\u043B\u043E --\u0441\u0444\u043E\u0440\u043C\u0438\u0440\u043E\u0432\u0430\u043D\u043D\u043E\u0435 \u0438\u0437 \u0438\u043D\u0442\u0435\u043B\u043B\u0435\u043A\u0442\u0430, \u044D\u0433\u043E, \u0443\u043C\u0430 \u0438 \u0442\u043E\u043D\u043A\u0438\u0445 \u044D\u043B\u0435\u043C\u0435\u043D\u0442\u043E\u0432-- <em>(purya\u1E63\u1E6Daka)</em> [\u0441\u0447\u0438\u0442\u0430\u0435\u0442\u0441\u044F][\u0440\u0435\u0430\u043B\u044C\u043D\u044B\u043C] \u0432\u043E\u0441\u043F\u0440\u0438\u043D\u0438\u043C\u0430\u044E\u0449\u0438\u043C <em>(pram\u0101t\u1E5B)</em>. [\u0412 \u0434\u0432\u0443\u0445 \u0441\u043B\u043E\u0432\u0430\u0445, \u0442\u0430\u043A\u043E\u0439 \u0432\u0435\u043B\u0438\u043A\u0438\u0439 Yog\u012B] \u0441\u0438\u044F\u0435\u0442 <em>(sphurati)</em> \u043A\u0430\u043A [\u043D\u0430\u0434\u0435\u043B\u0435\u043D\u043D\u044B\u0439] \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435\u043C \u0412\u043E\u0441\u043F\u0440\u0438\u043D\u0438\u043C\u0430\u044E\u0449\u0435\u0433\u043E, \u043A\u043E\u0442\u043E\u0440\u044B\u0439 \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F [\u0447\u0438\u0441\u0442\u044B\u043C] \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u0435\u043C <em>(cit-pram\u0101t\u1E5Btay\u0101 eva)</em> --\u043E\u0447\u0435\u0432\u0438\u0434\u043D\u043E, \u043E\u043D \u0441\u0438\u044F\u0435\u0442 \u043A\u0430\u043A \u0412\u044B\u0441\u0448\u0438\u0439 \u0413\u043E\u0441\u043F\u043E\u0434\u044C--. \u0422\u0430\u043A\u043E\u0432\u043E \u0437\u043D\u0430\u0447\u0435\u043D\u0438\u0435 <em>(iti artha\u1E25)</em>|</p><p>\u042D\u0442\u043E <em>(yad)</em> \u0431\u044B\u043B\u043E \u0437\u0430\u044F\u0432\u043B\u0435\u043D\u043E <em>(uktam)</em> \u0432 \u0442\u043E\u0439 \u0441\u0430\u043C\u043E\u0439 [\u043A\u043D\u0438\u0433\u0435] <em>(tatra eva)</em> --\u0432 K\u0101lik\u0101krama--:</p><blockquote><p>&quot;\u0422\u0430\u043A\u0436\u0435 \u043A\u0430\u043A <em>(yath\u0101)</em> \u0442\u043E\u0442, \u043A\u0442\u043E \u043F\u0440\u043E\u0431\u0443\u0436\u0434\u0435\u043D <em>(prabuddha\u1E25)</em>, \u043D\u0435 <em>(na eva)</em> \u0432\u0438\u0434\u0438\u0442 <em>(pa\u015Byati)</em> \u043E\u0431\u044A\u0435\u043A\u0442\u043E\u0432 <em>(arth\u0101n)</em>, \u0432\u043E\u0441\u043F\u0440\u0438\u043D\u0438\u043C\u0430\u0435\u043C\u044B\u0445 <em>(anubh\u016Bta)</em> \u0432\u043E \u0441\u043D\u0435 <em>(svapna)</em>, \u0442\u0430\u043A \u0438 <em>(tath\u0101)</em> Yog\u012B <em>(yog\u012B)</em>, \u0441\u043E\u0437\u0435\u0440\u0446\u0430\u044F [\u0441\u0432\u043E\u044E \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u0443\u044E \u0421\u0430\u043C\u043E\u0441\u0442\u044C] <em>(bh\u0101vanay\u0101)</em>, \u043D\u0435 <em>(na eva)</em> \u0432\u0438\u0434\u0438\u0442 <em>(pa\u015Byati)</em> \u043C\u0438\u0440 [\u043A\u0430\u043A \u043C\u0438\u0440, \u043D\u043E \u043A\u0430\u043A \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u0435] <em>(sa\u1E41s\u0101ram... iti)</em><sup>1</sup>&quot;||</p></blockquote><p>\u0411\u043E\u043B\u0435\u0435 \u0442\u043E\u0433\u043E <em>(tath\u0101)</em>:</p><blockquote><p>&quot;\u041E\u0442\u0432\u0435\u0440\u0433\u043D\u0443\u0432 <em>(nirasya)</em> \u0441\u043F\u043E\u0441\u043E\u0431\u044B <em>(v\u1E5Btt\u012B\u1E25)</em> \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u043E\u0432\u0430\u043D\u0438\u044F \u0438 \u043D\u0435\u0441\u0443\u0449\u0435\u0441\u0442\u0432\u043E\u0432\u0430\u043D\u0438\u044F [\u0442\u0430\u043A\u0438\u0435 \u043A\u0430\u043A \u0433\u043E\u043B\u0443\u0431\u043E\u0439, \u043D\u0430\u0441\u043B\u0430\u0436\u0434\u0435\u043D\u0438\u0435 \u0438 \u043F\u0440.] <em>(sat-asat)</em>, \u043F\u0440\u0438\u0431\u0435\u0433\u043D\u0443\u0432 \u043A <em>(sa\u1E41\u015Britya)</em> \u0432\u043D\u0443\u0442\u0440\u0435\u043D\u043D\u0435\u043C\u0443 \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u044E --\u0442.\u0435. \u043A \u0421\u0430\u043C\u043E\u0441\u0442\u0438, \u043D\u0430\u0445\u043E\u0434\u044F\u0449\u0435\u0439\u0441\u044F \u043C\u0435\u0436\u0434\u0443 \u0442\u0435\u043C, \u0447\u0442\u043E \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u0443\u0435\u0442 \u0438 \u043D\u0435 \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u0443\u0435\u0442-- <em>(padam \u0101ntaram)</em> [\u0438] \u043E\u0442\u043A\u0430\u0437\u044B\u0432\u0430\u044F\u0441\u044C \u043E\u0442 <em>(vih\u0101ya)</em> \u043C\u043D\u043E\u0433\u043E\u0447\u0438\u0441\u043B\u0435\u043D\u043D\u044B\u0445 <em>(j\u0101lam)</em> \u0444\u0430\u043D\u0442\u0430\u0437\u0438\u0439 <em>(kalpan\u0101)</em>, [\u0442\u0430\u043A\u0438\u0445 \u043A\u0430\u043A] \u043D\u0435\u043F\u043E\u0445\u043E\u0436\u0438\u0439 \u0438 \u043F\u043E\u0445\u043E\u0436\u0438\u0439 <em>(para-aparam)</em> \u043F\u043E\u0441\u0440\u0435\u0434\u0441\u0442\u0432\u043E\u043C \u043D\u0435\u0434\u0432\u043E\u0439\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0441\u0442\u0438 <em>(advaitena)</em>, Yog\u012B <em>(yog\u012B)</em>, \u043A\u0442\u043E <em>(ya\u1E25)</em> \u0432\u0441\u0435\u0433\u0434\u0430 \u043F\u0440\u0435\u0434\u0430\u043D <em>(nirata\u1E25)</em> \u0441\u0432\u043E\u0435\u0439 \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0439 <em>(sva)</em> \u0421\u0430\u043C\u043E\u0441\u0442\u0438 <em>(\u0101tma)</em>, \u0438\u0441\u043A\u043B\u044E\u0447\u0438\u0442\u0435\u043B\u044C\u043D\u043E <em>(eka)</em> \u043D\u0430\u043C\u0435\u0440\u0435\u043D <em>(tatpara\u1E25)</em> \u043F\u043E\u0433\u043B\u043E\u0442\u0438\u0442\u044C <em>(gr\u0101sa)</em> \u0441\u043C\u0435\u0440\u0442\u044C <em>(k\u0101la)</em> [\u0438] \u043F\u043E\u0441\u0432\u044F\u0449\u0435\u043D <em>(bh\u0101k)</em> \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u044E <em>(pada)</em> Kaivalya, \u0438\u043B\u0438 \u0418\u0437\u043E\u043B\u044F\u0446\u0438\u0438 <em>(kaivalya)</em>, \u0434\u043E\u0441\u0442\u0438\u0433\u0430\u0435\u0442 <em>(sa\u1E25... labhet)</em> \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u044F <em>(padam)</em> Nirv\u0101\u1E47a <em>(nirv\u0101\u1E47a... iti)</em><sup>2</sup>&quot;||</p></blockquote><p>[\u0412\u044B\u0440\u0430\u0436\u0435\u043D\u0438\u0435] &quot;Kaivalyapadabh\u0101k&quot; <em>(kaivalya-pada-bh\u0101k iti)</em> [\u043E\u0437\u043D\u0430\u0447\u0430\u0435\u0442] \u0442\u043E\u0433\u043E, \u043A\u0442\u043E \u043D\u0435 \u0432\u0435\u0434\u043E\u043C <em>(asa\u1E41v\u0101hya\u1E25)</em> [\u0441\u0432\u043E\u0438\u043C\u0438] Indriya-s \u0438 Tanm\u0101tra-s <em>(indriya-tanm\u0101tr\u0101bhi\u1E25)</em><sup>3</sup>||41||</p><hr><ol><li><p>\u041F\u043E\u0434\u043E\u0431\u043D\u043E \u0442\u043E\u043C\u0443, \u043A\u0430\u043A \u0447\u0435\u043B\u043E\u0432\u0435\u043A \u043D\u0435 \u0432\u0438\u0434\u0438\u0442 \u043F\u0440\u0438 \u043F\u0440\u043E\u0431\u0443\u0436\u0434\u0435\u043D\u0438\u0438 \u043E\u0431\u044A\u0435\u043A\u0442\u044B, \u043A\u043E\u0442\u043E\u0440\u044B\u0435 \u043F\u0440\u043E\u044F\u0432\u0438\u043B\u0438\u0441\u044C \u0432\u043E \u0441\u043D\u0435, \u0442\u0430\u043A \u0438 \u0432\u0435\u043B\u0438\u043A\u0438\u0439 Yog\u012B, \u0431\u043B\u0430\u0433\u043E\u0434\u0430\u0440\u044F \u0441\u043E\u0432\u0435\u0440\u0448\u0435\u043D\u0441\u0442\u0432\u0443 \u0435\u0433\u043E \u0441\u043E\u0437\u0435\u0440\u0446\u0430\u043D\u0438\u044F, \u0432\u043E\u0441\u043F\u0440\u0438\u043D\u0438\u043C\u0430\u0435\u0442 \u0432\u0441\u0435\u043B\u0435\u043D\u043D\u0443\u044E \u0442\u043E\u043B\u044C\u043A\u043E \u043A\u0430\u043A \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u0435, \u0430 \u043D\u0435 \u043A\u0430\u043A \u043D\u0435\u0447\u0442\u043E, \u043F\u043E\u043B\u043D\u043E\u0435 \u0434\u0432\u043E\u0439\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0441\u0442\u0438. \u0427\u0435\u043B\u043E\u0432\u0435\u043A \u0432\u0438\u0434\u0438\u0442 \u0434\u0432\u043E\u0439\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0441\u0442\u044C \u0432 \u043C\u0438\u0440\u0435, \u0442\u043E\u043B\u044C\u043A\u043E \u043A\u043E\u0433\u0434\u0430 \u043E\u043D \u2014 sa\u1E41s\u0101r\u012B, \u0442\u043E \u0435\u0441\u0442\u044C \u0442\u043E\u0442, \u043A\u0442\u043E \u0441\u0432\u044F\u0437\u0430\u043D \u0441 \u0442\u0440\u0430\u043D\u0441\u043C\u0438\u0433\u0440\u0430\u0446\u0438\u043E\u043D\u043D\u044B\u043C \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u043E\u0432\u0430\u043D\u0438\u0435\u043C (Sa\u1E41s\u0101ra) \u0438\u0437-\u0437\u0430 \u0100\u1E47avamala. \u0421\u043B\u043E\u0432\u043E sa\u1E41s\u0101r\u012B \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u0441\u0438\u043D\u043E\u043D\u0438\u043C\u043E\u043C \u0441 sa\u1E41v\u0101hya, \u0438\u043B\u0438 j\u012Bva (\u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u043D\u044B\u043C \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u043E\u043C). \u041A\u043E\u0433\u0434\u0430 \u041C\u0438\u043B\u043E\u0441\u0442\u044C \u0413\u043E\u0441\u043F\u043E\u0434\u0430 \u043D\u0438\u0441\u0445\u043E\u0434\u0438\u0442 \u043D\u0430 \u043D\u0435\u0433\u043E, \u0100\u1E47avamala \u0443\u0434\u0430\u043B\u044F\u0435\u0442\u0441\u044F \u0438 \u0435\u0433\u043E \u0441\u043E\u0437\u0435\u0440\u0446\u0430\u043D\u0438\u0435 \u0421\u0430\u043C\u043E\u0441\u0442\u0438 \u0441\u0442\u0430\u043D\u043E\u0432\u0438\u0442\u0441\u044F \u0431\u0435\u0437\u0443\u043F\u0440\u0435\u0447\u043D\u044B\u043C. \u0422\u043E\u0433\u0434\u0430, \u043C\u0438\u0440 \u0431\u043E\u043B\u044C\u0448\u0435 \u043D\u0435 \u0440\u0430\u0441\u0441\u043C\u0430\u0442\u0440\u0438\u0432\u0430\u0435\u0442\u0441\u044F \u043A\u0430\u043A \u043C\u0438\u0440, \u0430 \u043A\u0430\u043A \u0447\u0438\u0441\u0442\u043E\u0435 \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u0435. \u0422\u0430\u043A\u043E\u0432 \u043A\u043E\u043C\u043C\u0435\u043D\u0442\u0430\u0440\u0438\u0439.</p></li><li><p>\u0422\u0435\u0440\u043C\u0438\u043D Nirv\u0101\u1E47a \u043D\u0435 \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u0442\u0440\u0430\u043A\u0442\u043E\u0432\u0430\u0442\u044C \u0437\u0434\u0435\u0441\u044C \u043A\u0430\u043A \u0432 \u0411\u0443\u0434\u0434\u0438\u0437\u043C\u0435. \u0412 \u0422\u0440\u0438\u043A\u0435 \u043E\u043D \u043E\u0437\u043D\u0430\u0447\u0430\u0435\u0442 &quot;\u015Aiva\u015Baktis\u0101marasya&quot;. \u0421\u043B\u043E\u0432\u043E &quot;s\u0101marasya&quot; \u043E\u0437\u043D\u0430\u0447\u0430\u0435\u0442 &quot;\u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435, \u043E\u0442\u043D\u043E\u0441\u044F\u0449\u0435\u0435\u0441\u044F \u043A samarasa&quot;. \u041F\u043E\u0441\u043A\u043E\u043B\u044C\u043A\u0443 &quot;samarasa&quot; \u043E\u0437\u043D\u0430\u0447\u0430\u0435\u0442 &quot;\u0438\u043C\u0435\u0442\u044C \u043E\u0434\u0438\u043D\u0430\u043A\u043E\u0432\u044B\u0439 \u0432\u043A\u0443\u0441, \u0438\u043B\u0438 \u0430\u0440\u043E\u043C\u0430\u0442&quot;, \u015Aiva\u015Baktis\u0101marasya \u043E\u0437\u043D\u0430\u0447\u0430\u0435\u0442, \u0431\u0443\u043A\u0432\u0430\u043B\u044C\u043D\u043E, \u0442\u043E &quot;\u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435, \u0433\u0434\u0435 \u015Aiva \u0438 \u015Aakti \u0438\u043C\u0435\u044E\u0442 \u043E\u0434\u0438\u043D\u0430\u043A\u043E\u0432\u044B\u0439 \u0432\u043A\u0443\u0441 \u0438\u043B\u0438 \u0430\u0440\u043E\u043C\u0430\u0442&quot;. \u0422\u0435\u043F\u0435\u0440\u044C, \u0447\u0442\u043E\u0431\u044B \u0431\u044B\u0442\u044C \u043C\u0435\u043D\u0435\u0435 \u0431\u0443\u043A\u0432\u0430\u043B\u044C\u043D\u044B\u043C \u0438 \u0431\u043E\u043B\u0435\u0435 &quot;\u0444\u0438\u043B\u043E\u0441\u043E\u0444\u0441\u043A\u0438\u043C&quot;, \u015Aiva\u015Baktis\u0101marasya \u2014 \u044D\u0442\u043E \u043D\u0435\u0434\u0438\u0444\u0444\u0435\u0440\u0435\u043D\u0446\u0438\u0438\u0440\u043E\u0432\u0430\u043D\u043D\u043E\u0435 \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435, \u0432 \u043A\u043E\u0442\u043E\u0440\u043E\u043C \u0434\u0432\u043E\u0439\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0441\u0442\u044C \u0432 \u0444\u043E\u0440\u043C\u0435 \u015Aiva-\u015Aakti (\u0421\u0443\u0431\u044A\u0435\u043A\u0442-\u043E\u0431\u044A\u0435\u043A\u0442) \u043F\u043E\u043B\u043D\u043E\u0441\u0442\u044C\u044E \u043F\u0440\u0435\u043A\u0440\u0430\u0449\u0430\u0435\u0442\u0441\u044F.</p></li><li><p>Kaivalya, \u0438\u043B\u0438 \u0418\u0437\u043E\u043B\u044F\u0446\u0438\u044F \u0432 \u0422\u0440\u0438\u043A\u0435 \u043D\u0435 \u0438\u043D\u0442\u0435\u0440\u043F\u0440\u0435\u0442\u0438\u0440\u0443\u0435\u0442\u0441\u044F \u0442\u0430\u043A, \u043A\u0430\u043A \u0432 \u0441\u0438\u0441\u0442\u0435\u043C\u0435, \u043D\u0430\u0437\u044B\u0432\u0430\u0435\u043C\u043E\u0439 S\u0101\u1E45khya-yoga, \u0430 \u0438\u043C\u0435\u043D\u043D\u043E \u043A\u0430\u043A \u0418\u0437\u043E\u043B\u044F\u0446\u0438\u044F \u043E\u0442 Prak\u1E5Bti, \u043D\u043E \u043A\u0430\u043A \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435, \u0432 \u043A\u043E\u0442\u043E\u0440\u043E\u043C \u0447\u0435\u043B\u043E\u0432\u0435\u043A \u0431\u043E\u043B\u044C\u0448\u0435 \u043D\u0435 \u043D\u0430\u0445\u043E\u0434\u0438\u0442\u0441\u044F \u043F\u043E\u0434 \u0432\u043B\u0438\u044F\u043D\u0438\u0435\u043C \u0441\u0432\u043E\u0438\u0445 \u0421\u0438\u043B \u0432\u043E\u0441\u043F\u0440\u0438\u044F\u0442\u0438\u044F/\u0434\u0435\u0439\u0441\u0442\u0432\u0438\u044F (J\xF1\u0101nendriya-s \u0438 Karmendriya-s) \u0438 \u0442\u043E\u043D\u043A\u0438\u0445 \u044D\u043B\u0435\u043C\u0435\u043D\u0442\u043E\u0432 (Tanm\u0101tra-s). \u0418\u043C\u0435\u043D\u043D\u043E \u0432 \u044D\u0442\u043E\u043C \u0441\u043C\u044B\u0441\u043B\u0435 \u0442\u0430\u043A\u043E\u0439 Yog\u012B \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F Kaivalyapadabh\u0101k (&quot;bh\u0101k&quot; \u2014 \u0418\u043C\u0435\u043D\u0438\u0442\u0435\u043B\u044C\u043D\u044B\u0439 \u043F\u0430\u0434\u0435\u0436, \u0435\u0434.\u0447. \u043E\u0442 &quot;bh\u0101j&quot;). \u041E\u043D \u2014 \u043D\u0435 \u043F\u0440\u043E\u0441\u0442\u043E sa\u1E41v\u0101hya (\u0442.\u0435. \u0431\u044B\u0442\u044C \u043D\u043E\u0441\u0438\u0442\u0435\u043B\u0435\u043C), \u0438\u043B\u0438 \u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u043D\u043E\u0435 \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u043E, \u043A\u043E\u0442\u043E\u0440\u043E\u0435 \u0432\u0441\u0435 \u0432\u0440\u0435\u043C\u044F \u0432\u0435\u0434\u043E\u043C\u043E \u0441\u0432\u043E\u0438\u043C\u0438 \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u044B\u043C\u0438 Indriya-s \u0438 Tanm\u0101tra-s.</p></li></ol></div><div class="stanza"><a href="#s3.42" id="s3.42" class="num">3.42</a><div class="sans"><p>\u0928\u0928\u094D\u0935\u0947\u0935\u0902 \u091C\u0940\u0935\u0938\u0919\u094D\u0915\u094D\u0937\u092F\u0947 \u0938\u0924\u094D\u092F\u0938\u094D\u092F \u0926\u0947\u0939\u092A\u093E\u0924\u0903 \u092A\u094D\u0930\u093E\u092A\u094D\u0924\u094B \u0928 \u091A\u093E\u0938\u094C \u0938\u0941\u092A\u094D\u0930\u092C\u0941\u0926\u094D\u0927\u0938\u094D\u092F\u093E\u092A\u093F \u0926\u0947\u0939\u093F\u0928\u0903 \u0938\u0926\u094D\u092F \u090F\u0935 \u0926\u0943\u0936\u094D\u092F\u0924\u0947 \u0924\u0924\u094D\u0915\u0925\u092E\u092F\u0902 \u0924\u0926\u093E\u0930\u0942\u0922\u092A\u094D\u0930\u092E\u093F\u0924\u093F\u0930\u093F\u0924\u094D\u092F\u093E\u0936\u0919\u094D\u0915\u094D\u092F\u093E\u0939\u2014</p><blockquote><p><strong>\u092D\u0942\u0924\u0915\u091E\u094D\u091A\u0941\u0915\u0940 \u0924\u0926\u093E \u0935\u093F\u092E\u0941\u0915\u094D\u0924\u094B \u092D\u0942\u092F\u0903 \u092A\u0924\u093F\u0938\u092E\u0903 \u092A\u0930\u0903\u0965\u096A\u0968\u0965</strong></p></blockquote><p>\u0924\u0926\u0947\u0924\u094D\u092F\u092D\u093F\u0932\u093E\u0937\u0915\u094D\u0937\u092F\u093E\u091C\u094D\u091C\u0940\u0935\u0938\u0919\u094D\u0915\u094D\u0937\u092F\u0947 \u092A\u0941\u0930\u094D\u092F\u0937\u094D\u091F\u0915\u092A\u094D\u0930\u092E\u093E\u0924\u0943\u0924\u093E\u092D\u093F\u092E\u093E\u0928\u0935\u093F\u0917\u0932\u0928\u0947 \u0938\u0924\u094D\u092F\u092F\u0902 \u092D\u0942\u0924\u0915\u091E\u094D\u091A\u0941\u0915\u0940 \u0936\u0930\u0940\u0930\u093E\u0930\u092E\u094D\u092D\u0940\u0923\u093F \u092D\u0942\u0924\u093E\u0928\u093F \u0915\u091E\u094D\u091A\u0941\u0915\u092E\u093F\u0935 \u0935\u094D\u092F\u0924\u093F\u0930\u093F\u0915\u094D\u0924\u0902 \u092A\u094D\u0930\u093E\u0935\u0930\u0923\u092E\u093F\u0935 \u0928 \u0924\u094D\u0935\u0939\u0928\u094D\u0924\u093E\u092A\u0926\u0938\u094D\u092A\u0930\u094D\u0936\u0940\u0928\u093F \u092F\u0938\u094D\u092F \u0924\u0925\u093E\u092D\u0942\u0924\u0903 \u0938\u0928\u094D \u0935\u093F\u092E\u0941\u0915\u094D\u0924\u094B \u0928\u093F\u0930\u094D\u0935\u093E\u0923\u092D\u093E\u0917\u094D\u092F\u0924\u094B \u092D\u0942\u092F\u094B \u092C\u093E\u0939\u0941\u0932\u094D\u092F\u0947\u0928 \u092A\u0924\u093F\u0938\u092E\u0903 \u091A\u093F\u0926\u094D\u0918\u0928\u092A\u093E\u0930\u092E\u0947\u0936\u094D\u0935\u0930\u0938\u094D\u0935\u0930\u0942\u092A\u093E\u0935\u093F\u0937\u094D\u091F\u0938\u094D\u0924\u0924 \u090F\u0935 \u092A\u0930\u0903 \u092A\u0942\u0930\u094D\u0923\u0903 \u0936\u0930\u0940\u0930\u0935\u0943\u0924\u094D\u0924\u093F\u0930\u094D\u0935\u094D\u0930\u0924\u092E\u094D (\u0969-\u0968\u096C) \u0907\u0924\u094D\u092F\u0941\u0915\u094D\u0924\u0938\u0942\u0924\u094D\u0930\u093E\u0930\u094D\u0925\u0928\u0940\u0924\u094D\u092F\u093E \u0926\u0932\u0915\u0932\u094D\u092A\u0947 \u0926\u0947\u0939\u093E\u0926\u094C \u0938\u094D\u0925\u093F\u0924\u094B\u093D\u092A\u093F \u0928 \u0924\u0924\u094D\u092A\u094D\u0930\u092E\u093E\u0924\u0943\u0924\u093E\u0938\u0902\u0938\u094D\u0915\u093E\u0930\u0947\u0923\u093E\u092A\u093F \u0938\u094D\u092A\u0943\u0937\u094D\u091F\u0903\u0964 \u0924\u0926\u0941\u0915\u094D\u0924\u0902 \u0936\u094D\u0930\u0940\u0915\u0941\u0932\u0930\u0924\u094D\u0928\u092E\u093E\u0932\u093E\u092F\u093E\u0902</p><blockquote><p>\u092F\u0926\u093E \u0917\u0941\u0930\u0941\u0935\u0930\u0903 \u0938\u092E\u094D\u092F\u0915\u094D \u0915\u0925\u092F\u0947\u0924\u094D\u0924\u0928\u094D\u0928 \u0938\u0902\u0936\u092F\u0903\u0964<br> \u092E\u0941\u0915\u094D\u0924\u0938\u094D\u0924\u0947\u0928\u0948\u0935 \u0915\u093E\u0932\u0947\u0928 \u092F\u0928\u094D\u0924\u094D\u0930\u0938\u094D\u0924\u093F\u0937\u094D\u0920\u0924\u093F \u0915\u0947\u0935\u0932\u092E\u094D\u0965<br> \u0915\u093F\u0902 \u092A\u0941\u0928\u0936\u094D\u091A\u0948\u0915\u0924\u093E\u0928\u0938\u094D\u0924\u0941 \u092A\u0930\u0947 \u092C\u094D\u0930\u0939\u094D\u092E\u0923\u093F \u092F\u0903 \u0938\u0941\u0927\u0940\u0903\u0964<br> \u0915\u094D\u0937\u0923\u092E\u093E\u0924\u094D\u0930\u0938\u094D\u0925\u093F\u0924\u094B \u092F\u094B\u0917\u0940 \u0938 \u092E\u0941\u0915\u094D\u0924\u094B \u092E\u094B\u091A\u092F\u0947\u0924\u094D\u092A\u094D\u0930\u091C\u093E\u0903\u0965</p></blockquote><p>\u0907\u0924\u093F\u0964 \u0936\u094D\u0930\u0940\u092E\u0943\u0924\u094D\u092F\u0941\u091C\u093F\u0924\u094D\u092F\u092A\u093F</p><blockquote><p>\u0928\u093F\u092E\u0947\u0937\u094B\u0928\u094D\u092E\u0947\u0937\u092E\u093E\u0924\u094D\u0930\u0947\u0923 \u092F\u0926\u093F \u091A\u0948\u0935\u094B\u092A\u0932\u092D\u094D\u092F\u0924\u0947\u0964<br> \u0924\u0924\u0903 \u092A\u094D\u0930\u092D\u0943\u0924\u093F \u092E\u0941\u0915\u094D\u0924\u094B\u093D\u0938\u094C \u0928 \u092A\u0941\u0928\u0930\u094D\u091C\u0928\u094D\u092E \u091A\u093E\u092A\u094D\u0928\u0941\u092F\u093E\u0924\u094D\u0965</p></blockquote><p>\u0907\u0924\u093F\u0964 \u0915\u0941\u0932\u0938\u093E\u0930\u0947\u093D\u092A\u093F</p><blockquote><p>\u0905\u0939\u094B \u0924\u0924\u094D\u0924\u094D\u0935\u0938\u094D\u092F \u092E\u093E\u0939\u093E\u0924\u094D\u092E\u094D\u092F\u0902 \u091C\u094D\u091E\u093E\u0924\u092E\u093E\u0924\u094D\u0930\u0938\u094D\u092F \u0938\u0941\u0928\u094D\u0926\u0930\u093F\u0964<br> \u0936\u094D\u0930\u094B\u0924\u094D\u0930\u093E\u0928\u094D\u0924\u0930\u0902 \u0924\u0941 \u0938\u092E\u094D\u092A\u094D\u0930\u093E\u092A\u094D\u0924\u0947 \u0924\u0924\u094D\u0915\u094D\u0937\u0923\u093E\u0926\u0947\u0935 \u092E\u0941\u091A\u094D\u092F\u0924\u0947\u0965</p></blockquote><p>\u0907\u0924\u093F\u0965\u096A\u0968\u0965</p></div><hr><div class="trans"><p>Nanveva\u1E41 j\u012Bvasa\u1E45k\u1E63aye satyasya dehap\u0101ta\u1E25 pr\u0101pto na c\u0101sau suprabuddhasy\u0101pi dehina\u1E25 sadya eva d\u1E5B\u015Byate tatkathamaya\u1E41 tad\u0101r\u016B\u1E0Dhapramitirity\u0101\u015Ba\u1E45ky\u0101ha\u2014</p><blockquote><p><strong>Bh\u016Btaka\xF1cuk\u012B tad\u0101 vimukto bh\u016Bya\u1E25 patisama\u1E25 para\u1E25||42||</strong></p></blockquote><p>Tadetyabhil\u0101\u1E63ak\u1E63ay\u0101jj\u012Bvasa\u1E45k\u1E63aye purya\u1E63\u1E6Dakapram\u0101t\u1E5Bt\u0101bhim\u0101navigalane satyaya\u1E41 bh\u016Btaka\xF1cuk\u012B \u015Bar\u012Br\u0101rambh\u012B\u1E47i bh\u016Bt\u0101ni ka\xF1cukamiva vyatirikta\u1E41 pr\u0101vara\u1E47amiva na tvahant\u0101padaspar\u015B\u012Bni yasya tath\u0101bh\u016Bta\u1E25 san vimukto nirv\u0101\u1E47abh\u0101gyato bh\u016Byo b\u0101hulyena patisama\u1E25 cidghanap\u0101rame\u015Bvarasvar\u016Bp\u0101vi\u1E63\u1E6Dastata eva para\u1E25 p\u016Br\u1E47a\u1E25 \u015Bar\u012Brav\u1E5Bttirvratam (3-26) ityuktas\u016Btr\u0101rthan\u012Bty\u0101 dalakalpe deh\u0101dau sthito&#39;pi na tatpram\u0101t\u1E5Bt\u0101sa\u1E41sk\u0101re\u1E47\u0101pi sp\u1E5B\u1E63\u1E6Da\u1E25| Tadukta\u1E41 \u015Br\u012Bkularatnam\u0101l\u0101y\u0101\u1E41</p><blockquote><p>Yad\u0101 guruvara\u1E25 samyak kathayettanna sa\u1E41\u015Baya\u1E25|<br> Muktastenaiva k\u0101lena yantrasti\u1E63\u1E6Dhati kevalam||<br> Ki\u1E41 puna\u015Bcaikat\u0101nastu pare brahma\u1E47i ya\u1E25 sudh\u012B\u1E25|<br> K\u1E63a\u1E47am\u0101trasthito yog\u012B sa mukto mocayetpraj\u0101\u1E25||</p></blockquote><p>iti| \u015Ar\u012Bm\u1E5Btyujityapi</p><blockquote><p>Nime\u1E63onme\u1E63am\u0101tre\u1E47a yadi caivopalabhyate|<br> Tata\u1E25 prabh\u1E5Bti mukto&#39;sau na punarjanma c\u0101pnuy\u0101t||</p></blockquote><p>iti| Kulas\u0101re&#39;pi</p><blockquote><p>Aho tattvasya m\u0101h\u0101tmya\u1E41 j\xF1\u0101tam\u0101trasya sundari|<br> \u015Arotr\u0101ntara\u1E41 tu sampr\u0101pte tatk\u1E63a\u1E47\u0101deva mucyate||</p></blockquote><p>iti||42||</p></div><hr><p>\u0412\u043E\u0437\u0440\u0430\u0436\u0435\u043D\u0438\u0435 <em>(nanu)</em>!: &quot;\u0422\u0430\u043A <em>(evam)</em>, \u043A\u043E\u0433\u0434\u0430 \u0438\u043C\u0435\u0435\u0442 \u043C\u0435\u0441\u0442\u043E \u043F\u043E\u043B\u043D\u043E\u0435 \u0443\u0441\u0442\u0440\u0430\u043D\u0435\u043D\u0438\u0435 [\u0443\u0441\u043B\u043E\u0432\u0438\u0439] \u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u043D\u043E\u0433\u043E \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u0430 <em>(j\u012Bva-sa\u1E45k\u1E63aye sati)</em>, \u0435\u0433\u043E <em>(asya)</em> \u0442\u0435\u043B\u043E \u0443\u043C\u0438\u0440\u0430\u0435\u0442 [\u0442\u0430\u043A\u0436\u0435] ----\u0431\u0443\u043A\u0432. \u0434\u043E\u0441\u0442\u0438\u0433\u0430\u0435\u0442\u0441\u044F \u0441\u043C\u0435\u0440\u0442\u044C \u0442\u0435\u043B\u0430; \u0442.\u0435. \u0442\u0435\u043B\u043E \u0443\u043C\u0438\u0440\u0430\u0435\u0442-- <em>(deha-p\u0101ta\u1E25 pr\u0101pta\u1E25)</em>, \u043D\u043E <em>(ca)</em> \u044D\u0442\u043E --\u0430 \u0438\u043C\u0435\u043D\u043D\u043E, \u0443\u043C\u0438\u0440\u0430\u043D\u0438\u0435 \u0438\u043B\u0438 \u0441\u043C\u0435\u0440\u0442\u044C \u0442\u0435\u043B\u0430-- <em>(asau)</em> \u043D\u0435 <em>(na)</em> \u043D\u0430\u0431\u043B\u044E\u0434\u0430\u0435\u0442\u0441\u044F <em>(d\u1E5B\u015Byate)</em> \u043D\u0435\u043F\u043E\u0441\u0440\u0435\u0434\u0441\u0442\u0432\u0435\u043D\u043D\u043E <em>(sadyas eva)</em> \u0432 \u0441\u043B\u0443\u0447\u0430\u0435 \u043F\u043E\u043B\u043D\u043E\u0441\u0442\u044C\u044E \u043F\u0440\u043E\u0431\u0443\u0436\u0434\u0435\u043D\u043D\u043E\u0433\u043E <em>(suprabuddhasya api)</em> [Yog\u012B], \u043A\u043E\u0442\u043E\u0440\u044B\u0439 \u0438\u043C\u0435\u0435\u0442 \u0442\u0435\u043B\u043E <em>(dehina\u1E25)</em> --\u0434\u0440\u0443\u0433\u0438\u043C\u0438 \u0441\u043B\u043E\u0432\u0430\u043C\u0438, \u043E\u043D \u0434\u043E\u0441\u0442\u0438\u0433 \u043E\u043A\u043E\u043D\u0447\u0430\u0442\u0435\u043B\u044C\u043D\u043E\u0433\u043E \u041E\u0441\u0432\u043E\u0431\u043E\u0436\u0434\u0435\u043D\u0438\u044F, \u043D\u043E \u0435\u0433\u043E \u0442\u0435\u043B\u043E \u0435\u0449\u0435 \u043D\u0435 \u0443\u043C\u0435\u0440\u043B\u043E--. \u041F\u043E\u0442\u043E\u043C\u0443 <em>(tad)</em>, \u043A\u0430\u043A <em>(katham)</em> \u043E\u043D <em>(ayam)</em> [\u0441\u0443\u0449\u0435\u0441\u0442\u0432\u0443\u0435\u0442], \u0447\u044C\u044F \u043E\u0441\u043E\u0437\u043D\u0430\u043D\u043D\u043E\u0441\u0442\u044C <em>(pramiti\u1E25)</em> \u0443\u043A\u043E\u0440\u0435\u043D\u0435\u043D\u0430 <em>(\u0101r\u016B\u1E0Dha)</em> \u0432 \u0422\u043E\u043C --\u0432 Turya-- <em>(tad)</em>? --\u043A\u0430\u043A \u043E\u043D \u043C\u043E\u0436\u0435\u0442 \u0431\u044B\u0442\u044C \u043F\u043E\u043B\u043D\u043E\u0441\u0442\u044C\u044E \u043E\u0441\u0432\u043E\u0431\u043E\u0436\u0434\u0435\u043D\u043D\u044B\u043C \u0438 \u0432 \u0442\u043E \u0436\u0435 \u0441\u0430\u043C\u043E\u0435 \u0432\u0440\u0435\u043C\u044F \u043E\u0441\u0442\u0430\u0432\u0430\u0442\u044C\u0441\u044F \u0432 \u0441\u0432\u043E\u0435\u043C \u0442\u0435\u043B\u0435?--&quot;. \u0412\u043E\u0437\u0440\u0430\u0436\u0430\u044F \u043F\u0440\u043E\u0442\u0438\u0432 \u044D\u0442\u043E\u0433\u043E <em>(iti-\u0101\u015Ba\u1E45kya)</em>, [\u015Aiva] \u0441\u043A\u0430\u0437\u0430\u043B <em>(\u0101ha)</em>\u2014</p><blockquote><p><strong>\u0417\u0430\u0442\u0435\u043C, [\u043A\u043E\u0433\u0434\u0430 \u0436\u0435\u043B\u0430\u043D\u0438\u0435 \u043E\u043A\u043E\u043D\u0447\u0430\u0442\u0435\u043B\u044C\u043D\u043E \u0438\u0441\u0447\u0435\u0437\u0430\u0435\u0442] <em>(tad\u0101)</em>, [\u0442\u043E\u0433\u0434\u0430 Yog\u012B \u0438\u0441\u043F\u043E\u043B\u044C\u0437\u0443\u0435\u0442 \u0442\u0435\u043B\u043E, \u0441\u043E\u0441\u0442\u043E\u044F\u0449\u0435\u0435 \u0438\u0437] \u0433\u0440\u0443\u0431\u044B\u0445 \u044D\u043B\u0435\u043C\u0435\u043D\u0442\u043E\u0432 <em>(bh\u016Bta)</em> \u043A\u0430\u043A \u043E\u0431\u043E\u043B\u043E\u0447\u043A\u0443 <em>(ka\xF1cuk\u012B)</em>; [\u0438 \u0431\u0443\u0434\u0443\u0447\u0438] \u043F\u043E\u043B\u043D\u043E\u0441\u0442\u044C\u044E \u043E\u0441\u0432\u043E\u0431\u043E\u0436\u0434\u0435\u043D\u043D\u044B\u043C <em>(vimukta\u1E25)</em>, [\u043F\u043E\u0441\u043A\u043E\u043B\u044C\u043A\u0443 \u043E\u043D] \u0432 \u0432\u044B\u0441\u0448\u0435\u0439 \u0441\u0442\u0435\u043F\u0435\u043D\u0438 <em>(bh\u016Byas)</em> \u043F\u043E\u0434\u043E\u0431\u0435\u043D <em>(sama\u1E25)</em> \u0413\u043E\u0441\u043F\u043E\u0434\u0443 [\u015Aiva] <em>(pati)</em>, [\u043E\u043D] \u0441\u043E\u0432\u0435\u0440\u0448\u0435\u043D\u0435\u043D \u0438 \u043F\u043E\u043B\u043E\u043D <em>(para\u1E25)</em>||42||</strong></p></blockquote><p>&quot;Tad\u0101&quot; --\u0422\u043E\u0433\u0434\u0430-- <em>(tad\u0101 iti)</em>, \u0442.\u0435. \u043F\u0440\u0438 \u0443\u0441\u0442\u0440\u0430\u043D\u0435\u043D\u0438\u0438 <em>(k\u1E63ay\u0101t)</em> abhil\u0101\u1E63a, \u0438\u043B\u0438 \u0436\u0435\u043B\u0430\u043D\u0438\u044F, \u043E\u0441\u043D\u043E\u0432\u0430\u043D\u043D\u043E\u0433\u043E \u043D\u0430 \u0447\u0443\u0432\u0441\u0442\u0432\u0435 \u0436\u0430\u0436\u0434\u044B <em>(abhil\u0101\u1E63a)</em>, \u043A\u043E\u0433\u0434\u0430 \u043F\u0440\u043E\u0438\u0441\u0445\u043E\u0434\u0438\u0442 \u043F\u043E\u043B\u043D\u043E\u0435 \u0443\u0434\u0430\u043B\u0435\u043D\u0438\u0435 <em>(sa\u1E45k\u1E63aye)</em> [\u0443\u0441\u043B\u043E\u0432\u0438\u044F] \u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u043D\u043E\u0433\u043E \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u0430 <em>(j\u012Bva)</em> \u2014\u043A\u043E\u0433\u0434\u0430 \u0438\u0441\u0447\u0435\u0437\u0430\u0435\u0442 <em>(vigalane sati)</em> \u043F\u043E\u043D\u044F\u0442\u0438\u0435 <em>(abhim\u0101na)</em>, \u0447\u0442\u043E \u0442\u043E\u043D\u043A\u043E\u0435 \u0442\u0435\u043B\u043E --\u0438\u043D\u0442\u0435\u043B\u043B\u0435\u043A\u0442, \u044D\u0433\u043E \u0438 \u0442\u043E\u043D\u043A\u0438\u0435 \u044D\u043B\u0435\u043C\u0435\u043D\u0442\u044B-- <em>(purya\u1E63\u1E6Daka)</em> \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F [\u0440\u0435\u0430\u043B\u044C\u043D\u044B\u043C] \u0432\u043E\u0441\u043F\u0440\u0438\u043D\u0438\u043C\u0430\u044E\u0449\u0438\u043C <em>(pram\u0101t\u1E5Bt\u0101)</em>\u2014, \u043E\u043D --\u0432\u0435\u043B\u0438\u043A\u0438\u0439 Yog\u012B-- <em>(ayam)</em> [\u0441\u0442\u0430\u043D\u043E\u0432\u0438\u0442\u0441\u044F] bh\u016Btaka\xF1cuk\u012B <em>(bh\u016Bta-ka\xF1cuk\u012B)</em>, [\u0438\u043B\u0438] \u0442\u0435\u043C, \u0447\u044C\u0438 <em>(yasya)</em> \u0433\u0440\u0443\u0431\u044B\u0435 \u044D\u043B\u0435\u043C\u0435\u043D\u0442\u044B --\u043F\u0440\u043E\u0441\u0442\u0440\u0430\u043D\u0441\u0442\u0432\u043E, \u0432\u043E\u0437\u0434\u0443\u0445, \u043E\u0433\u043E\u043D\u044C, \u0432\u043E\u0434\u0430 \u0438 \u0437\u0435\u043C\u043B\u044F-- <em>(bh\u016Bt\u0101ni)</em>, \u0444\u043E\u0440\u043C\u0438\u0440\u0443\u044E\u0449\u0438\u0435 <em>(\u0101rambh\u012B\u1E47i)</em> [\u0435\u0433\u043E] \u0442\u0435\u043B\u043E <em>(\u015Bar\u012Bra)</em>, \u043F\u043E\u0434\u043E\u0431\u043D\u044B <em>(iva... iva)</em> Ka\xF1cuka <em>(ka\xF1cukam)</em>, [\u0438\u043B\u0438] \u0440\u0430\u0437\u0434\u0435\u043B\u044F\u044E\u0449\u0435\u0439 <em>(vyatiriktam)</em> \u043E\u0431\u043E\u043B\u043E\u0447\u043A\u0435 <em>(pr\u0101vara\u1E47am)</em>, [\u0438] \u043D\u0435 <em>(na tu)</em> \u0437\u0430\u0442\u0440\u0430\u0433\u0438\u0432\u0430\u044E\u0442 <em>(spar\u015B\u012Bni)</em> \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435 <em>(pada)</em> &quot;\u042F \u0435\u0441\u0442\u044C&quot; <em>(ahant\u0101)</em>. \u0422\u043E\u0442, \u043A\u0442\u043E \u043F\u043E\u0434\u043E\u0431\u0435\u043D \u044D\u0442\u043E\u043C\u0443 <em>(tath\u0101bh\u016Bta\u1E25 san)</em> [\u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F] \u043F\u043E\u043B\u043D\u043E\u0441\u0442\u044C\u044E \u043E\u0441\u0432\u043E\u0431\u043E\u0436\u0434\u0435\u043D\u043D\u044B\u043C <em>(vimukta\u1E25)</em> [\u0438] \u043D\u0430\u0441\u043B\u0430\u0436\u0434\u0430\u0435\u0442\u0441\u044F Nirv\u0101\u1E47a <em>(nirv\u0101\u1E47a-bh\u0101k)</em><sup>1</sup></p><p>. [\u0418,] \u043F\u043E\u0441\u043A\u043E\u043B\u044C\u043A\u0443 <em>(yatas)</em> [\u043E\u043D] \u0432 \u0432\u044B\u0441\u0448\u0435\u0439 \u0441\u0442\u0435\u043F\u0435\u043D\u0438 <em>(bh\u016Byas)</em>, [\u0438\u043B\u0438] \u043F\u043E \u0431\u043E\u043B\u044C\u0448\u0435\u0439 \u0447\u0430\u0441\u0442\u0438 <em>(b\u0101hulyena)</em> \u0440\u0430\u0432\u0435\u043D <em>(sama\u1E25)</em> \u0413\u043E\u0441\u043F\u043E\u0434\u0443 [\u015Aiva] <em>(pati)</em>, [\u0442\u043E \u0435\u0441\u0442\u044C, \u0442\u0430\u043A \u043A\u0430\u043A \u043E\u043D] \u0432\u043E\u0448\u0435\u043B \u0432 <em>(\u0101vi\u1E63\u1E6Da\u1E25)</em> \u0441\u0443\u0449\u043D\u043E\u0441\u0442\u043D\u0443\u044E \u043F\u0440\u0438\u0440\u043E\u0434\u0443 <em>(sva-r\u016Bpa)</em> \u0412\u044B\u0441\u0448\u0435\u0433\u043E \u0413\u043E\u0441\u043F\u043E\u0434\u0430 <em>(p\u0101rame\u015Bvara)</em>, \u044F\u0432\u043B\u044F\u044E\u0449\u0435\u0433\u043E\u0441\u044F \u043A\u043E\u043C\u043F\u0430\u043A\u0442\u043D\u043E\u0439 \u043C\u0430\u0441\u0441\u043E\u0439 <em>(ghana)</em> \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u044F <em>(cit)</em>, \u0441\u043B\u0435\u0434\u043E\u0432\u0430\u0442\u0435\u043B\u044C\u043D\u043E <em>(tatas eva)</em> [\u043E\u043D \u0435\u0441\u0442\u044C] para <em>(para\u1E25)</em>, [\u0438\u043B\u0438] \u0441\u043E\u0432\u0435\u0440\u0448\u0435\u043D\u043D\u044B\u0439 \u0438 \u043F\u043E\u043B\u043D\u044B\u0439 <em>(p\u016Br\u1E47a\u1E25)</em>. &quot;\u041F\u0440\u0435\u0431\u044B\u0432\u0430\u043D\u0438\u0435 <em>(v\u1E5Btti\u1E25)</em> \u0432 \u0442\u0435\u043B\u0435 <em>(\u015Bar\u012Bra)</em> [\u2014 \u044D\u0442\u043E \u0435\u0433\u043E] \u043E\u0431\u0435\u0442 <em>(vratam)</em>, [\u0442\u043E \u0435\u0441\u0442\u044C \u043E\u043D \u0441\u043E\u0445\u0440\u0430\u043D\u044F\u0435\u0442 \u0444\u0438\u0437\u0438\u0447\u0435\u0441\u043A\u0443\u044E \u0444\u043E\u0440\u043C\u0443 \u0438\u0437-\u0437\u0430 \u0441\u0432\u043E\u0435\u0433\u043E \u0431\u0435\u0437\u043C\u0435\u0440\u043D\u043E\u0433\u043E \u0441\u043E\u0441\u0442\u0440\u0430\u0434\u0430\u043D\u0438\u044F \u043A \u0447\u0435\u043B\u043E\u0432\u0435\u0447\u0435\u0441\u0442\u0432\u0443; \u044D\u0442\u043E \u043F\u043E \u0438\u0441\u0442\u0438\u043D\u0435 \u0431\u043B\u0430\u0433\u043E\u0447\u0435\u0441\u0442\u0438\u0432\u044B\u0439 \u043F\u043E\u0441\u0442\u0443\u043F\u043E\u043A \u0441 \u0435\u0433\u043E \u0441\u0442\u043E\u0440\u043E\u043D\u044B]. (III, 26) [\u043D\u0430\u0441\u0442\u043E\u044F\u0449\u0435\u0433\u043E \u041F\u0438\u0441\u0430\u043D\u0438\u044F] <em>(3-26 iti)</em>&quot;; \u0432 \u0441\u043E\u043E\u0442\u0432\u0435\u0442\u0441\u0442\u0432\u0438\u0438 \u0441\u043E \u0437\u043D\u0430\u0447\u0435\u043D\u0438\u0435\u043C <em>(artha-n\u012Bty\u0101)</em> \u0432\u044B\u0448\u0435\u0443\u043F\u043E\u043C\u044F\u043D\u0443\u0442\u043E\u0433\u043E <em>(uktam)</em> \u0430\u0444\u043E\u0440\u0438\u0437\u043C\u0430 <em>(s\u016Btra)</em>, \u0434\u0430\u0436\u0435 \u0435\u0441\u043B\u0438 <em>(api)</em> \u043E\u043D \u043D\u0430\u0445\u043E\u0434\u0438\u0442\u0441\u044F <em>(sthita\u1E25)</em> \u0432 \u0442\u0435\u043B\u0435 \u0438 \u0442.\u0434. <em>(deha-\u0101dau)</em>, \u043A\u0430\u043A [\u0435\u0441\u043B\u0438 \u0431\u044B \u044D\u0442\u043E \u0431\u044B\u043B\u0438] <em>(kalpe)</em> \u043D\u043E\u0436\u043D\u044B \u043C\u0435\u0447\u0430 <em>(dala)</em> --\u043D\u0435\u0441\u043C\u043E\u0442\u0440\u044F \u043D\u0430 \u0442\u043E, \u0447\u0442\u043E \u043E\u043D\u0438 \u043F\u043B\u043E\u0442\u043D\u043E \u0437\u0430\u043A\u0440\u044B\u0432\u0430\u044E\u0442 \u043C\u0435\u0447, \u043E\u043D\u0438 \u0432\u0441\u0435\u0433\u0434\u0430 \u043E\u0442\u0434\u0435\u043B\u0435\u043D\u044B \u043E\u0442 \u0441\u0430\u043C\u043E\u0433\u043E \u043C\u0435\u0447\u0430--, \u043E\u043D \u043D\u0435 \u0437\u0430\u0442\u0440\u043E\u043D\u0443\u0442 <em>(na... sp\u1E5B\u1E63\u1E6Da\u1E25)</em> \u0434\u0430\u0436\u0435 <em>(api)</em> \u043E\u0441\u0442\u0430\u0442\u043E\u0447\u043D\u044B\u043C\u0438 \u0432\u043F\u0435\u0447\u0430\u0442\u043B\u0435\u043D\u0438\u044F\u043C\u0438 <em>(sa\u1E41sk\u0101re\u1E47a)</em> [\u043F\u043E\u043D\u044F\u0442\u0438\u044F \u0442\u043E\u0433\u043E, \u0447\u0442\u043E] \u044D\u0442\u043E --\u0442\u0435\u043B\u043E \u0438 \u043F\u0440.-- <em>(tad)</em> \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F [\u0440\u0435\u0430\u043B\u044C\u043D\u044B\u043C] \u0432\u043E\u0441\u043F\u0440\u0438\u043D\u0438\u043C\u0430\u044E\u0449\u0438\u043C, \u0438\u043B\u0438 \u043F\u043E\u0437\u043D\u0430\u044E\u0449\u0438\u043C --\u0421\u0430\u043C\u043E\u0441\u0442\u044C\u044E-- <em>(pram\u0101t\u1E5Bt\u0101)</em><sup>2</sup> |</p><p>\u042D\u0442\u0430 \u0436\u0435 [\u0438\u0441\u0442\u0438\u043D\u0430] <em>(tad)</em> \u0431\u044B\u043B\u0430 [\u0442\u0430\u043A\u0436\u0435] \u0443\u043F\u043E\u043C\u044F\u043D\u0443\u0442\u0430 <em>(uktam)</em> \u0432 \u0443\u0432\u0430\u0436\u0430\u0435\u043C\u043E\u0439 Kularatnam\u0101l\u0101 <em>(\u015Br\u012B-kularatnam\u0101l\u0101y\u0101m)</em>:</p><blockquote><p>&quot;\u041A\u043E\u0433\u0434\u0430 <em>(yad\u0101)</em> \u0441\u0430\u043C\u044B\u0439 \u0432\u044B\u0434\u0430\u044E\u0449\u0438\u0439\u0441\u044F \u0441\u0440\u0435\u0434\u0438 <em>(vara\u1E25)</em> \u0434\u0443\u0445\u043E\u0432\u043D\u044B\u0445 \u0443\u0447\u0438\u0442\u0435\u043B\u0435\u0439 <em>(guru)</em> \u0433\u043E\u0432\u043E\u0440\u0438\u0442 \u043E <em>(kathayet)</em> \u0422\u043E\u043C --\u0411\u043E\u0433\u0435-- <em>(tad)</em> \u0432\u043E \u0432\u0441\u0435\u0439 \u0441\u0432\u043E\u0435\u0439 \u043F\u043E\u043B\u043D\u043E\u0442\u0435 <em>(samyak)</em>, \u043D\u0435\u0442 \u0441\u043E\u043C\u043D\u0435\u043D\u0438\u044F <em>(na sa\u1E41\u015Baya\u1E25)</em>, [\u0447\u0442\u043E \u0435\u0433\u043E \u0443\u0447\u0435\u043D\u0438\u043A] \u043E\u0431\u0440\u0435\u0442\u0430\u0435\u0442 \u043E\u0441\u0432\u043E\u0431\u043E\u0436\u0434\u0435\u043D\u0438\u0435 <em>(mukta\u1E25)</em> \u0432 \u0442\u043E\u0442 \u0441\u0430\u043C\u044B\u0439 \u043C\u043E\u043C\u0435\u043D\u0442 <em>(tena eva k\u0101lena)</em>, [\u0438 \u043F\u043E\u0441\u043B\u0435 \u044D\u0442\u043E\u0433\u043E \u0442\u0430\u043A\u043E\u0439 \u0443\u0447\u0435\u043D\u0438\u043A] \u043E\u0441\u0442\u0430\u0435\u0442\u0441\u044F <em>(ti\u1E63\u1E6Dhati)</em> [\u0432 \u0441\u0432\u043E\u0435\u043C \u0442\u0435\u043B\u0435] \u0442\u043E\u043B\u044C\u043A\u043E <em>(kevalam)</em> [\u043F\u043E\u0434\u043E\u0431\u043D\u043E] \u043C\u0430\u0448\u0438\u043D\u0435 <em>(yantra\u1E25)</em> --\u043E\u043D \u0431\u043E\u043B\u044C\u0448\u0435 \u043D\u0435 \u0441\u0447\u0438\u0442\u0430\u0435\u0442 \u0435\u0433\u043E \u0441\u0432\u043E\u0435\u0439 \u0440\u0435\u0430\u043B\u044C\u043D\u043E\u0439 \u0421\u0430\u043C\u043E\u0441\u0442\u044C\u044E--.</p></blockquote><blockquote><p>\u041A\u0430\u043A \u0434\u043E\u043B\u0433\u043E \u0442\u043E\u0442 <em>(kim punar ca)</em>, \u043A\u0442\u043E <em>(ya\u1E25)</em> \u043C\u0443\u0434\u0440\u044B\u0439 <em>(sudh\u012B\u1E25)</em>, \u043F\u043E\u043B\u043D\u043E\u0441\u0442\u044C\u044E \u0441\u043A\u043E\u043D\u0446\u0435\u043D\u0442\u0440\u0438\u0440\u043E\u0432\u0430\u043D <em>(ekat\u0101na\u1E25 tu)</em> \u043D\u0430 \u0412\u044B\u0441\u0448\u0435\u043C \u0411\u0440\u0430\u0445\u043C\u0435 --\u0410\u0431\u0441\u043E\u043B\u044E\u0442\u0435-- <em>(pare brahma\u1E47i)</em>? [\u0415\u0441\u043B\u0438 \u0442\u0430\u043A\u043E\u0439] Yog\u012B <em>(yog\u012B)</em> \u043E\u0441\u0442\u0430\u0451\u0442\u0441\u044F <em>(sthita\u1E25)</em> \u0434\u0430\u0436\u0435 \u043D\u0430 \u043C\u0433\u043D\u043E\u0432\u0435\u043D\u0438\u0435 <em>(k\u1E63a\u1E47a-m\u0101tra)</em> [\u0432 \u0412\u044B\u0441\u0448\u0435\u043C \u0411\u0440\u0430\u0445\u043C\u0430\u043D\u0435], \u043E\u043D \u0441\u0442\u0430\u043D\u043E\u0432\u0438\u0442\u0441\u044F \u043E\u0441\u0432\u043E\u0431\u043E\u0436\u0434\u0435\u043D\u043D\u044B\u043C <em>(sa\u1E25 mukta\u1E25)</em> [\u0438] \u043E\u0441\u0432\u043E\u0431\u043E\u0436\u0434\u0430\u0435\u0442 <em>(mocayet)</em> [\u0434\u0440\u0443\u0433\u0438\u0445] \u0441\u0443\u0449\u0435\u0441\u0442\u0432 <em>(praj\u0101\u1E25... iti)</em>&quot;||</p></blockquote><p>\u0412 \u043F\u043E\u0447\u0442\u0435\u043D\u043D\u043E\u043C M\u1E5Btyujit --\u0442\u0430\u043A\u0436\u0435 \u043D\u0430\u0437\u044B\u0432\u0430\u0435\u043C\u043E\u043C Netratantra-- <em>(\u015Br\u012B-m\u1E5Btyujiti)</em> [\u044D\u0442\u043E] \u0442\u0430\u043A\u0436\u0435 [\u0431\u044B\u043B\u043E \u0441\u043A\u0430\u0437\u0430\u043D\u043E] <em>(api)</em>:</p><blockquote><p>&quot;\u0418 \u0435\u0441\u043B\u0438 <em>(yadi ca eva)</em> [\u0412\u044B\u0441\u0448\u0438\u0439 \u0412\u0435\u0447\u043D\u044B\u0439 \u015Aiva] \u043E\u0441\u043E\u0437\u043D\u0430\u0435\u0442\u0441\u044F [\u043A\u0435\u043C-\u0442\u043E] <em>(upalabhyate)</em> \u0434\u0430\u0436\u0435 \u043D\u0430 \u0432\u0440\u0435\u043C\u044F \u043C\u043E\u0440\u0433\u0430\u043D\u0438\u044F <em>(nime\u1E63a-unme\u1E63a-m\u0101tre\u1E47a)</em>, \u0441 \u044D\u0442\u043E\u0433\u043E \u043C\u043E\u043C\u0435\u043D\u0442\u0430 <em>(tatas prabh\u1E5Bti)</em> \u044D\u0442\u043E\u0442 [\u0447\u0435\u043B\u043E\u0432\u0435\u043A] <em>(asau)</em> \u0441\u0442\u0430\u043D\u043E\u0432\u0438\u0442\u0441\u044F \u043E\u0441\u0432\u043E\u0431\u043E\u0436\u0434\u0435\u043D\u043D\u044B\u043C <em>(mukta\u1E25)</em> \u0438 <em>(ca)</em> \u043D\u0435 \u0440\u043E\u0436\u0434\u0430\u0435\u0442\u0441\u044F --\u0431\u0443\u043A\u0432. \u043D\u0435 \u043F\u043E\u043B\u0443\u0447\u0430\u0435\u0442 \u0440\u043E\u0436\u0434\u0435\u043D\u0438\u044F-- <em>(na... janma... \u0101pnuy\u0101t)</em> \u0432\u043D\u043E\u0432\u044C <em>(punar... iti)</em><sup>3</sup>&quot;||<br> [\u0421\u043C. VIII, 8 \u0432 Netratantra]</p></blockquote><p>\u0412 Kulas\u0101ra <em>(kulas\u0101re)</em> [\u044D\u0442\u043E] \u0442\u0430\u043A\u0436\u0435 [\u0431\u044B\u043B\u043E \u0443\u043F\u043E\u043C\u044F\u043D\u0443\u0442\u043E] <em>(api)</em>:</p><blockquote><p>&quot;\u0410\u0445 <em>(aho)</em>!, \u0432\u043E\u0437\u0432\u044B\u0448\u0435\u043D\u043D\u043E\u0435 \u043F\u043E\u043B\u043E\u0436\u0435\u043D\u0438\u0435 \u0438 \u0432\u0435\u043B\u0438\u0447\u0438\u0435 <em>(m\u0101h\u0101tmyam)</em> [\u0412\u044B\u0441\u0448\u0435\u0433\u043E] \u041F\u0440\u0438\u043D\u0446\u0438\u043F\u0430 <em>(tattvasya)</em> [\u0442\u0430\u043A\u043E\u0432\u043E,] \u041E \u043F\u0440\u0435\u043A\u0440\u0430\u0441\u043D\u0430\u044F <em>(sundari)</em>!, [\u0447\u0442\u043E] \u043A\u043E\u0433\u0434\u0430 \u041E\u043D \u043F\u0440\u043E\u0441\u0442\u043E <em>(m\u0101trasya)</em> \u0438\u0437\u0432\u0435\u0441\u0442\u0435\u043D [\u043A\u043E\u043C\u0443-\u0442\u043E] --\u0442\u043E\u043B\u044C\u043A\u043E \u0447\u0435\u0440\u0435\u0437 \u0435\u0433\u043E \u0438\u043D\u0442\u0435\u043B\u043B\u0435\u043A\u0442-- <em>(j\xF1\u0101ta)</em>, \u043F\u0440\u0438 \u0415\u0433\u043E \u043F\u0435\u0440\u0435\u0434\u0430\u0447\u0435 [\u0438\u043C] <em>(sampr\u0101pte)</em> \u0434\u0440\u0443\u0433\u043E\u0439 \u043B\u0438\u0447\u043D\u043E\u0441\u0442\u0438 --\u0442.\u0435. \u0434\u0440\u0443\u0433\u043E\u043C\u0443 \u0443\u0445\u0443-- <em>(\u015Brotra-antaram)</em>, [\u043F\u043E\u043B\u0443\u0447\u0438\u0432\u0448\u0438\u0439 \u0415\u0433\u043E] \u0441\u0442\u0430\u043D\u043E\u0432\u0438\u0442\u0441\u044F \u043E\u0441\u0432\u043E\u0431\u043E\u0436\u0434\u0435\u043D\u043D\u044B\u043C <em>(mucyate)</em> \u043D\u0435\u043C\u0435\u0434\u043B\u0435\u043D\u043D\u043E <em>(tatk\u1E63a\u1E47\u0101t eva... iti)</em>&quot;||</p></blockquote><p>||42||</p><hr><ol><li><p>\u042F \u0443\u0436\u0435 \u043E\u0431\u044A\u044F\u0441\u043D\u044F\u043B \u0437\u043D\u0430\u0447\u0435\u043D\u0438\u0435 &quot;Nirv\u0101\u1E47a&quot; \u0432 \u044D\u0442\u043E\u0439 \u0441\u0438\u0441\u0442\u0435\u043C\u0435 \u0432 .</p></li><li><p>\u041E\u043D \u043F\u0440\u0435\u0431\u044B\u0432\u0430\u0435\u0442 \u0432 \u0442\u0435\u043B\u0435, \u0438 \u0442.\u0434., \u043A\u0430\u043A \u043C\u0435\u0447 \u0432 \u043D\u043E\u0436\u043D\u0430\u0445. \u0422\u0435\u043C \u043D\u0435 \u043C\u0435\u043D\u0435\u0435, \u043E\u043D \u043D\u0438\u043A\u043E\u0433\u0434\u0430 \u043D\u0435 \u0441\u0447\u0438\u0442\u0430\u0435\u0442 \u0441\u0432\u043E\u0435 \u0442\u0435\u043B\u043E \u0441\u0432\u043E\u0435\u0439 \u043D\u0430\u0441\u0442\u043E\u044F\u0449\u0435\u0439 \u0421\u0430\u043C\u043E\u0441\u0442\u044C\u044E, \u0438\u043B\u0438 \u042F. \u041F\u043E\u0447\u0435\u043C\u0443? \u041F\u043E\u0442\u043E\u043C\u0443 \u0447\u0442\u043E \u0431\u0443\u0434\u0443\u0447\u0438 \u043F\u043E\u043B\u043D\u043E\u0441\u0442\u044C\u044E \u043E\u0442\u043E\u0436\u0434\u0435\u0441\u0442\u0432\u043B\u0435\u043D\u043D\u044B\u043C \u0441 \u0412\u044B\u0441\u0448\u0438\u043C \u0413\u043E\u0441\u043F\u043E\u0434\u043E\u043C, \u044F\u0432\u043B\u044F\u044E\u0449\u0438\u043C\u0441\u044F \u043A\u043E\u043C\u043F\u0430\u043A\u0442\u043D\u043E\u0439 \u043C\u0430\u0441\u0441\u043E\u0439 \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u044F, \u043E\u043D \u0432\u0441\u0435\u0433\u0434\u0430 \u043F\u043E\u0434\u043E\u0431\u0435\u043D \u0415\u043C\u0443: \u0430\u0431\u0441\u043E\u043B\u044E\u0442\u043D\u043E \u0441\u0432\u043E\u0431\u043E\u0434\u0435\u043D! \u041E\u0441\u0442\u0430\u043B\u044C\u043D\u044B\u0435 \u043B\u044E\u0434\u0438, \u043A\u043E\u0442\u043E\u0440\u044B\u0435 \u043F\u043E\u043B\u043D\u043E\u0441\u0442\u044C\u044E \u043E\u0442\u043E\u0436\u0434\u0435\u0441\u0442\u0432\u043B\u0435\u043D\u044B \u0441\u043E \u0441\u0432\u043E\u0438\u043C\u0438 \u0442\u0435\u043B\u0430\u043C\u0438 \u0438 \u0442.\u0434., \u0438 \u043D\u0430\u0445\u043E\u0434\u044F\u0442\u0441\u044F \u043F\u043E\u0434 \u043A\u043E\u043D\u0442\u0440\u043E\u043B\u0435\u043C \u0100\u1E47avamala, \u043D\u0435 \u0432 \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0438 \u043E\u0441\u043E\u0437\u043D\u0430\u0442\u044C \u0441\u0432\u043E\u044E \u0441\u0443\u0449\u043D\u043E\u0441\u0442\u043D\u0443\u044E \u043F\u0440\u0438\u0440\u043E\u0434\u0443. \u0414\u0440\u0443\u0433\u0438\u043C\u0438 \u0441\u043B\u043E\u0432\u0430\u043C\u0438, \u043E\u043D\u0438 \u043F\u043E \u0441\u0443\u0442\u0438 \u044F\u0432\u043B\u044F\u044E\u0442\u0441\u044F \u0413\u043E\u0441\u043F\u043E\u0434\u043E\u043C, \u043D\u043E \u043D\u0435 \u043E\u0441\u043E\u0437\u043D\u0430\u044E\u0442 \u0441\u0432\u043E\u044E \u0438\u0441\u0442\u0438\u043D\u043D\u0443\u044E \u0441\u0443\u0449\u043D\u043E\u0441\u0442\u044C \u0438 \u043E\u0448\u0438\u0431\u043E\u0447\u043D\u043E \u043F\u043E\u043B\u0430\u0433\u0430\u044E\u0442, \u0447\u0442\u043E \u043E\u043D\u0438 \u043D\u0435 \u0442\u0435, \u043A\u0435\u043C \u044F\u0432\u043B\u044F\u044E\u0442\u0441\u044F \u043D\u0430 \u0441\u0430\u043C\u043E\u043C \u0434\u0435\u043B\u0435!</p></li><li><p>\u0412 \u0435\u0433\u043E Netroddyota, K\u1E63emar\u0101ja \u043E\u0431\u044A\u044F\u0441\u043D\u044F\u0435\u0442, \u043F\u0440\u043E\u0441\u0442\u044B\u043C \u0441\u043F\u043E\u0441\u043E\u0431\u043E\u043C, \u0437\u043D\u0430\u0447\u0435\u043D\u0438\u0435 \u044D\u0442\u043E\u0439 \u0441\u0442\u0440\u043E\u0444\u044B \u0432 Netratantra. \u0412\u0435\u0441\u044C \u0435\u0433\u043E \u043A\u043E\u043C\u043C\u0435\u043D\u0442\u0430\u0440\u0438\u0439 \u0433\u043B\u0430\u0441\u0438\u0442: &quot; \u0915\u0947\u0928\u091A\u093F\u0926\u093F\u0924\u093F \u092E\u0927\u094D\u092F\u0947\u093D\u0927\u094D\u092F\u093E\u0939\u093E\u0930\u094D\u092F\u092E\u094D\u0964 \u0909\u092A\u0932\u092D\u094D\u092F\u0924\u0947 \u0938\u092E\u093E\u0935\u093F\u0936\u094D\u092F\u0924\u0947\u0964 \u0924\u0924\u0903\u092A\u094D\u0930\u092D\u0943\u0924\u093F \u0928 \u0924\u0941 \u0915\u093E\u0932\u093E\u0928\u094D\u0924\u0930\u0947\u0964 \u092E\u0941\u0915\u094D\u0924\u0903 \u0938\u094D\u0925\u093F\u0924\u0948\u0930\u092A\u093F \u0926\u0947\u0939\u092A\u094D\u0930\u093E\u0923\u0948\u0930\u0917\u0941\u0923\u0940\u0915\u0943\u0924\u0903\u0964 \u0928 \u091A \u0924\u0926\u094D\u0926\u0947\u0939\u0924\u094D\u092F\u093E\u0917\u0947 \u092A\u0941\u0928\u0930\u094D\u091C\u0928\u094D\u092E \u0926\u0947\u0939\u093E\u0928\u094D\u0924\u0930\u0938\u092E\u094D\u092C\u0928\u094D\u0927\u092E\u093E\u092A\u094D\u0928\u094B\u0924\u094D\u092F\u092A\u093F\u0924\u0941 \u092A\u0930\u092E\u0936\u093F\u0935 \u090F\u0935 \u092D\u0935\u0924\u093F\u0965 &quot; - &quot;Kenaciditi madhye&#39;dhy\u0101h\u0101ryam| Upalabhyate sam\u0101vi\u015Byate| Tata\u1E25prabh\u1E5Bti na tu k\u0101l\u0101ntare| Mukta\u1E25 sthitairapi dehapr\u0101\u1E47airagu\u1E47\u012Bk\u1E5Bta\u1E25| Na ca taddehaty\u0101ge punarjanma deh\u0101ntarasambandham\u0101pnotyapitu parama\u015Biva eva bhavati||&quot; - &quot;[\u0421\u043B\u043E\u0432\u043E] &#39;kenacid&#39; --&#39;\u043A\u0435\u043C-\u0442\u043E&#39;-- \u0434\u043E\u043B\u0436\u0435\u043D \u0431\u044B\u0442\u044C \u043F\u043E\u0441\u0442\u0430\u0432\u043B\u0435\u043D \u0432 \u0441\u0435\u0440\u0435\u0434\u0438\u043D\u0435 [\u0441\u0442\u0440\u043E\u0444\u044B \u0434\u043B\u044F \u0437\u0430\u0432\u0435\u0440\u0448\u0435\u043D\u0438\u044F \u0441\u043C\u044B\u0441\u043B\u0430] --\u0442.\u0435. \u0442\u0430\u043C \u0434\u043E\u043B\u0436\u0435\u043D \u0431\u044B\u0442\u044C &#39;\u043A\u0442\u043E-\u0442\u043E&#39;, \u043A\u0442\u043E \u0432\u044B\u043F\u043E\u043B\u043D\u044F\u0435\u0442 \u0442\u043E, \u0447\u0442\u043E \u0437\u0430\u044F\u0432\u043B\u0435\u043D\u043E \u0432 \u0441\u0442\u0440\u043E\u0444\u0435--. [\u0422\u0435\u0440\u043C\u0438\u043D] &#39;upalabhyate&#39; [\u043E\u0437\u043D\u0430\u0447\u0430\u0435\u0442] &#39;\u043F\u0440\u043E\u043D\u0438\u043A\u043D\u0443\u0442\u043E&#39; --\u0432 \u0441\u043C\u044B\u0441\u043B\u0435 &#39;\u043E\u0441\u043E\u0437\u043D\u0430\u0435\u0442\u0441\u044F&#39;; \u044D\u0442\u043E \u043E\u0442\u043D\u043E\u0441\u0438\u0442\u0441\u044F \u043A \u0412\u044B\u0441\u0448\u0435\u043C\u0443 \u0412\u0435\u0447\u043D\u043E\u043C\u0443 \u015Aiva... \u042F \u0437\u043D\u0430\u044E \u044D\u0442\u043E, \u043F\u043E\u0442\u043E\u043C\u0443 \u0447\u0442\u043E \u044F \u0447\u0438\u0442\u0430\u043B \u043F\u0440\u0435\u0434\u044B\u0434\u0443\u0449\u0443\u044E \u0441\u0442\u0440\u043E\u0444\u0443 \u0432 Netratantra--. [\u0412\u044B\u0440\u0430\u0436\u0435\u043D\u0438\u0435] &#39;Tata\u1E25prabh\u1E5Bti&#39;, \u0438\u043B\u0438 &#39;thenceforth&#39; [\u043E\u0437\u043D\u0430\u0447\u0430\u0435\u0442, \u0447\u0442\u043E] \u044D\u0442\u043E \u043D\u0435 \u0432 \u0434\u0440\u0443\u0433\u043E\u0435 \u0432\u0440\u0435\u043C\u044F, [\u0430 \u0441 \u044D\u0442\u043E\u0433\u043E \u043C\u043E\u043C\u0435\u043D\u0442\u0430] --\u0432\u044B \u0442\u0430\u043A\u0436\u0435 \u043C\u043E\u0436\u0435\u0442\u0435 \u0440\u0430\u0437\u0434\u0435\u043B\u0438\u0442\u044C \u0434\u0432\u0430 \u0441\u043B\u043E\u0432\u0430 \u0441\u043B\u0435\u0434\u0443\u044E\u0449\u0438\u043C \u043E\u0431\u0440\u0430\u0437\u043E\u043C: Tata\u1E25 prabh\u1E5Bti--. &#39;Mukta&#39;, \u0438\u043B\u0438 &#39;\u043E\u0441\u0432\u043E\u0431\u043E\u0436\u0434\u0435\u043D\u043D\u044B\u0439&#39; \u043E\u0442 \u0442\u0435\u043B\u0430 \u0438 \u0436\u0438\u0437\u043D\u0435\u043D\u043D\u044B\u0445 \u044D\u043D\u0435\u0440\u0433\u0438\u0439 \u0434\u0430\u0436\u0435 \u043A\u043E\u0433\u0434\u0430 \u043E\u043D\u0438 \u043F\u0440\u043E\u0434\u043E\u043B\u0436\u0430\u044E\u0442 \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u043E\u0432\u0430\u0442\u044C, \u0442.\u0435. \u043B\u0438\u0448\u0435\u043D\u044B \u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0438\u0432\u0430\u044E\u0449\u0438\u0445 \u0430\u0440\u0442\u0438\u0431\u0443\u0442\u043E\u0432, \u0438\u043B\u0438 \u043A\u0430\u0447\u0435\u0441\u0442\u0432. \u0418, \u043F\u043E\u0441\u043B\u0435 \u043E\u0441\u0442\u0430\u0432\u043B\u0435\u043D\u0438\u044F \u0442\u0435\u043B\u0430, \u043E\u043D \u043D\u0435 \u043F\u0435\u0440\u0435\u0440\u043E\u0436\u0434\u0430\u0435\u0442\u0441\u044F \u0432\u043D\u043E\u0432\u044C, \u0430 \u0438\u043C\u0435\u043D\u043D\u043E, \u043E\u043D \u043D\u0435 \u0432\u0445\u043E\u0434\u0438\u0442 \u0432 \u043A\u043E\u043D\u0442\u0430\u043A\u0442 \u0441 \u0434\u0440\u0443\u0433\u0438\u043C \u0442\u0435\u043B\u043E\u043C, \u0430, \u0432\u0435\u0440\u043D\u0435\u0435, \u0441\u0442\u0430\u043D\u043E\u0432\u0438\u0442\u0441\u044F \u0412\u044B\u0441\u0448\u0438\u043C \u015Aiva&quot;.</p></li></ol><p>\u0421 \u043F\u043E\u043C\u043E\u0449\u044C\u044E \u043C\u0443\u0434\u0440\u0435\u0446\u0430 K\u1E63emar\u0101ja, Netratantra \u043F\u043E\u043D\u0438\u043C\u0430\u0435\u0442\u0441\u044F \u043B\u0435\u0433\u0447\u0435, \u043D\u0435 \u0442\u0430\u043A \u043B\u0438?</p></div><div class="stanza"><a href="#s3.43" id="s3.43" class="num">3.43</a><div class="sans"><p>\u0928\u0928\u0941 \u092D\u0942\u0924\u0915\u091E\u094D\u091A\u0941\u0915\u093F\u0924\u094D\u0935\u092E\u092A\u094D\u092F\u0938\u094D\u092F \u0915\u0938\u094D\u092E\u093E\u0924\u094D\u0924\u0926\u0948\u0935 \u0928 \u0928\u093F\u0935\u0930\u094D\u0924\u0924 \u0907\u0924\u094D\u092F\u093E\u0939\u2014</p><blockquote><p><strong>\u0928\u0948\u0938\u0930\u094D\u0917\u093F\u0915\u0903 \u092A\u094D\u0930\u093E\u0923\u0938\u092E\u094D\u092C\u0928\u094D\u0927\u0903\u0965\u096A\u0969\u0965</strong></p></blockquote><p>\u0928\u093F\u0938\u0930\u094D\u0917\u093E\u0924\u094D\u0938\u094D\u0935\u093E\u0924\u0928\u094D\u0924\u094D\u0930\u094D\u092F\u093E\u0924\u094D\u092E\u0928\u0903 \u0938\u094D\u0935\u092D\u093E\u0935\u093E\u0926\u093E\u092F\u093E\u0924\u094B \u0928\u0948\u0938\u0930\u094D\u0917\u093F\u0915\u0903 \u092A\u094D\u0930\u093E\u0923\u0938\u092E\u094D\u092C\u0928\u094D\u0927\u0903 \u0938\u0902\u0935\u093F\u0924\u094D \u0915\u093F\u0932 \u092D\u0917\u0935\u0924\u0940 \u0935\u093F\u0936\u094D\u0935\u0935\u0948\u091A\u093F\u0924\u094D\u0930\u094D\u092F\u092E\u0935\u092C\u093F\u092D\u093E\u0938\u092F\u093F\u0937\u0941\u0903 \u0938\u0919\u094D\u0915\u094B\u091A\u093E\u0935\u092D\u093E\u0938\u092A\u0942\u0930\u094D\u0935\u0915\u0902 \u0938\u0919\u094D\u0915\u0941\u091A\u0926\u0936\u0947\u0937\u0935\u093F\u0936\u094D\u0935\u0938\u094D\u092B\u0941\u0930\u0924\u094D\u0924\u093E\u0924\u094D\u092E\u0915\u092A\u094D\u0930\u093E\u0923\u0928\u093E\u0930\u0942\u092A\u0917\u094D\u0930\u093E\u0939\u0915\u092D\u0942\u092E\u093F\u0915\u093E\u0902 \u0936\u094D\u0930\u093F\u0924\u094D\u0935\u093E \u0917\u094D\u0930\u093E\u0939\u094D\u092F\u0930\u0942\u092A\u091C\u0917\u0926\u093E\u092D\u093E\u0938\u093E\u0924\u094D\u092E\u0928\u093E \u0938\u094D\u092B\u0941\u0930\u0924\u0940\u0924\u093F \u0928\u0948\u0938\u0930\u094D\u0917\u093F\u0915\u0903 \u0938\u094D\u0935\u093E\u0924\u0928\u094D\u0924\u094D\u0930\u094D\u092F\u093E\u0924\u094D\u092A\u094D\u0930\u0925\u092E\u092E\u0941\u0926\u094D\u092D\u093E\u0938\u093F\u0924\u094B\u093D\u0938\u094D\u092F\u093E\u0903 \u092A\u094D\u0930\u093E\u0923\u0938\u092E\u094D\u092C\u0928\u094D\u0927\u0903\u0964 \u0924\u0925\u093E \u091A \u0936\u094D\u0930\u0940\u0935\u093E\u091C\u0938\u0928\u0947\u092F\u093E\u092F\u093E\u092E\u094D</p><blockquote><p>\u092F\u093E \u0938\u093E \u0936\u0915\u094D\u0924\u093F\u0903 \u092A\u0930\u093E \u0938\u0942\u0915\u094D\u0937\u094D\u092E\u093E \u0935\u094D\u092F\u093E\u092A\u093F\u0928\u0940 \u0928\u093F\u0930\u094D\u092E\u0932\u093E \u0936\u093F\u0935\u093E\u0964<br> \u0936\u0915\u094D\u0924\u093F\u091A\u0915\u094D\u0930\u0938\u094D\u092F \u091C\u0928\u0928\u0940 \u092A\u0930\u093E\u0928\u0928\u094D\u0926\u093E\u092E\u0943\u0924\u093E\u0924\u094D\u092E\u093F\u0915\u093E\u0965<br> \u092E\u0939\u093E\u0918\u094B\u0930\u0947\u0936\u094D\u0935\u0930\u0940 \u091A\u0923\u094D\u0921\u093E \u0938\u0943\u0937\u094D\u091F\u093F\u0938\u0902\u0939\u093E\u0930\u0915\u093E\u0930\u093F\u0915\u093E\u0964<br> \u0924\u094D\u0930\u093F\u0935\u0939\u0902 \u0924\u094D\u0930\u093F\u0935\u093F\u0927\u0902 \u0924\u094D\u0930\u093F\u0938\u094D\u0925\u0902 \u092C\u0932\u093E\u0924\u094D\u0915\u093E\u0932\u0902 \u092A\u094D\u0930\u0915\u0930\u094D\u0937\u0924\u093F\u0965</p></blockquote><p>\u0907\u0924\u093F \u0938\u0902\u0935\u093F\u0926 \u090F\u0935 \u092D\u0917\u0935\u0924\u094D\u092F\u093E\u0903 \u092A\u094D\u0930\u093E\u0923\u0915\u094D\u0930\u092E\u0947\u0923 \u0928\u093E\u0921\u093F\u0924\u094D\u0930\u092F\u0935\u093E\u0939\u093F\u0938\u094B\u092E\u0938\u0942\u0930\u094D\u092F\u0935\u0939\u094D\u0928\u094D\u092F\u093E\u0924\u094D\u092E\u093E\u0935\u0938\u094D\u0925\u093F\u0924\u093E\u0924\u0940\u0924\u093E\u0928\u093E\u0917\u0924\u0935\u0930\u094D\u0924\u092E\u093E\u0928\u0930\u0942\u092A\u092C\u093E\u0939\u094D\u092F\u0915\u093E\u0932\u094B\u0932\u094D\u0932\u093E\u0938\u0928\u0935\u093F\u0932\u093E\u092A\u0928\u0915\u093E\u0930\u093F\u0924\u094D\u0935\u092E\u0941\u0915\u094D\u0924\u092E\u094D\u0964 \u0924\u0926\u0941\u0915\u094D\u0924\u0902 \u0938\u094D\u0935\u091A\u094D\u091B\u0928\u094D\u0926\u0947\u093D\u092A\u093F</p><blockquote><p>\u092A\u094D\u0930\u093E\u0923\u093E\u092A\u093E\u0928\u092E\u092F\u0903 \u092A\u094D\u0930\u093E\u0923\u094B \u0935\u093F\u0938\u0930\u094D\u0917\u093E\u092A\u0942\u0930\u0923\u0902 \u092A\u094D\u0930\u0924\u093F\u0964<br> \u0928\u093F\u0924\u094D\u092F\u092E\u093E\u092A\u0942\u0930\u092F\u0928\u094D\u0928\u0947\u0935 \u092A\u094D\u0930\u093E\u0923\u093F\u0928\u093E\u092E\u0941\u0930\u0938\u093F \u0938\u094D\u0925\u093F\u0924\u0903\u0965</p></blockquote><p>\u0907\u0924\u093F\u0964 \u092A\u094D\u0930\u093E\u0923\u0938\u094D\u092F</p><blockquote><p>\u0939\u0915\u093E\u0930\u0938\u094D\u0924\u0941 \u0938\u094D\u092E\u0943\u0924\u0903 \u092A\u094D\u0930\u093E\u0923\u0903 \u0938\u094D\u0935\u092A\u094D\u0930\u0935\u0943\u0924\u094D\u0924\u094B \u0939\u0932\u093E\u0915\u0943\u0924\u093F\u0903\u0964</p></blockquote><p>\u0907\u0924\u094D\u092F\u0941\u0915\u094D\u0924\u0928\u0940\u0924\u094D\u092F\u093E \u0936\u094D\u0930\u0940\u0938\u094D\u0935\u091A\u094D\u091B\u0928\u094D\u0926\u092D\u091F\u094D\u091F\u093E\u0930\u0915\u0930\u0942\u092A\u092A\u094D\u0930\u093E\u0923\u092E\u092F\u0924\u094D\u0935\u093E\u0926\u094D\u0935\u093F\u0938\u0930\u094D\u0917\u093E\u092A\u0942\u0930\u0924\u092F\u093E \u0938\u0943\u0937\u094D\u091F\u093F\u0938\u0902\u0939\u093E\u0930\u0915\u093E\u0930\u093F\u0924\u094D\u0935\u092E\u092D\u093F\u0939\u093F\u0924\u092E\u093F\u0924\u093F \u092F\u0941\u0915\u094D\u0924\u092E\u0941\u0915\u094D\u0924\u0902 \u0928\u0948\u0938\u0930\u094D\u0917\u093F\u0915\u0903 \u092A\u094D\u0930\u093E\u0923\u0938\u092E\u094D\u092C\u0928\u094D\u0927 \u0907\u0924\u093F\u0964 \u0905\u0924 \u090F\u0935 \u0936\u094D\u0930\u0940\u092D\u091F\u094D\u091F\u0915\u0932\u094D\u0932\u091F\u0947\u0928 \u092A\u094D\u0930\u093E\u0923\u093E\u0916\u094D\u092F\u0928\u093F\u092E\u093F\u0924\u094D\u0924\u0926\u093E\u0930\u094D\u0922\u094D\u092F\u092E\u094D</p><blockquote><p>\u092A\u094D\u0930\u093E\u0915\u094D \u0938\u0902\u0935\u093F\u0924\u094D \u092A\u094D\u0930\u093E\u0923\u0947 \u092A\u0930\u093F\u0923\u0924\u093E\u0964</p></blockquote><p>\u0907\u0924\u093F \u0924\u0924\u094D\u0924\u094D\u0935\u093E\u0930\u094D\u0925\u091A\u093F\u0928\u094D\u0924\u093E\u092E\u0923\u093E\u0935\u0941\u0915\u094D\u0924\u092E\u094D\u0965\u096A\u0969\u0965</p></div><hr><div class="trans"><p>Nanu bh\u016Btaka\xF1cukitvamapyasya kasm\u0101ttadaiva na nivartata ity\u0101ha\u2014</p><blockquote><p><strong>Naisargika\u1E25 pr\u0101\u1E47asambandha\u1E25||43||</strong></p></blockquote><p>Nisarg\u0101tsv\u0101tantry\u0101tmana\u1E25 svabh\u0101v\u0101d\u0101y\u0101to naisargika\u1E25 pr\u0101\u1E47asambandha\u1E25 sa\u1E41vit kila bhagavat\u012B vi\u015Bvavaicitryamavabibh\u0101sayi\u1E63u\u1E25 sa\u1E45koc\u0101vabh\u0101sap\u016Brvaka\u1E41 sa\u1E45kucada\u015Be\u1E63avi\u015Bvasphuratt\u0101tmakapr\u0101\u1E47an\u0101r\u016Bpagr\u0101hakabh\u016Bmik\u0101\u1E41 \u015Britv\u0101 gr\u0101hyar\u016Bpajagad\u0101bh\u0101s\u0101tman\u0101 sphurat\u012Bti naisargika\u1E25 sv\u0101tantry\u0101tprathamamudbh\u0101sito&#39;sy\u0101\u1E25 pr\u0101\u1E47asambandha\u1E25| Tath\u0101 ca \u015Br\u012Bv\u0101jasaney\u0101y\u0101m</p><blockquote><p>Y\u0101 s\u0101 \u015Bakti\u1E25 par\u0101 s\u016Bk\u1E63m\u0101 vy\u0101pin\u012B nirmal\u0101 \u015Biv\u0101|<br> \u015Aakticakrasya janan\u012B par\u0101nand\u0101m\u1E5Bt\u0101tmik\u0101||<br> Mah\u0101ghore\u015Bvar\u012B ca\u1E47\u1E0D\u0101 s\u1E5B\u1E63\u1E6Disa\u1E41h\u0101rak\u0101rik\u0101|<br> Trivaha\u1E41 trividha\u1E41 tristha\u1E41 bal\u0101tk\u0101la\u1E41 prakar\u1E63ati||</p></blockquote><p>iti sa\u1E41vida eva bhagavaty\u0101\u1E25 pr\u0101\u1E47akrame\u1E47a n\u0101\u1E0Ditrayav\u0101hisomas\u016Bryavahny\u0101tm\u0101vasthit\u0101t\u012Bt\u0101n\u0101gatavartam\u0101nar\u016Bpab\u0101hyak\u0101loll\u0101sanavil\u0101panak\u0101ritvamuktam| Tadukta\u1E41 svacchande&#39;pi</p><blockquote><p>Pr\u0101\u1E47\u0101p\u0101namaya\u1E25 pr\u0101\u1E47o visarg\u0101p\u016Bra\u1E47a\u1E41 prati|<br> Nityam\u0101p\u016Brayanneva pr\u0101\u1E47in\u0101murasi sthita\u1E25||</p></blockquote><p>iti| Pr\u0101\u1E47asya</p><blockquote><p>Hak\u0101rastu sm\u1E5Bta\u1E25 pr\u0101\u1E47a\u1E25 svaprav\u1E5Btto hal\u0101k\u1E5Bti\u1E25|</p></blockquote><p>ityuktan\u012Bty\u0101 \u015Br\u012Bsvacchandabha\u1E6D\u1E6D\u0101rakar\u016Bpapr\u0101\u1E47amayatv\u0101dvisarg\u0101p\u016Bratay\u0101 s\u1E5B\u1E63\u1E6Disa\u1E41h\u0101rak\u0101ritvamabhihitamiti yuktamukta\u1E41 naisargika\u1E25 pr\u0101\u1E47asambandha iti| Ata eva \u015Br\u012Bbha\u1E6D\u1E6Dakalla\u1E6Dena pr\u0101\u1E47\u0101khyanimittad\u0101r\u1E0Dhyam</p><blockquote><p>Pr\u0101k sa\u1E41vit pr\u0101\u1E47e pari\u1E47at\u0101|</p></blockquote><p>iti tattv\u0101rthacint\u0101ma\u1E47\u0101vuktam||43||</p></div><hr><p>\u0412\u043E\u0437\u0440\u0430\u0436\u0435\u043D\u0438\u0435 <em>(nanu)</em>!: &quot;\u041F\u043E\u0447\u0435\u043C\u0443 <em>(kasm\u0101t)</em> \u043D\u0435 <em>(na)</em> \u0438\u0441\u0447\u0435\u0437\u0430\u0435\u0442 <em>(nivartate)</em> \u0435\u0433\u043E <em>(asya)</em> \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435 \u0438\u0441\u043F\u043E\u043B\u044C\u0437\u043E\u0432\u0430\u043D\u0438\u044F \u0433\u0440\u0443\u0431\u044B\u0445 \u044D\u043B\u0435\u043C\u0435\u043D\u0442\u043E\u0432, [\u0444\u043E\u0440\u043C\u0438\u0440\u0443\u044E\u0449\u0438\u0445 \u0435\u0433\u043E \u0442\u0435\u043B\u043E], \u0432 \u043A\u0430\u0447\u0435\u0441\u0442\u0432\u0435 \u043F\u043E\u043A\u0440\u043E\u0432\u0430 <em>(bh\u016Btaka\xF1cukitvam)</em> \u0434\u0430\u0436\u0435 <em>(api)</em> \u0442\u043E\u0433\u0434\u0430 <em>(tad\u0101 eva... iti)</em> --\u043A\u043E\u0433\u0434\u0430 Yog\u012B \u0434\u043E\u0441\u0442\u0438\u0433\u0430\u0435\u0442 \u043E\u043A\u043E\u043D\u0447\u0430\u0442\u0435\u043B\u044C\u043D\u043E\u0433\u043E \u041E\u0441\u0432\u043E\u0431\u043E\u0436\u0434\u0435\u043D\u0438\u044F--?&quot; [\u041E\u0442\u0432\u0435\u0447\u0430\u044F \u043D\u0430 \u0432\u043E\u0437\u0440\u0430\u0436\u0435\u043D\u0438\u0435, \u015Aiva] \u0441\u043A\u0430\u0437\u0430\u043B <em>(\u0101ha)</em>\u2014</p><blockquote><p><strong>\u0421\u0432\u044F\u0437\u044C, \u0438\u043B\u0438 \u0430\u0441\u0441\u043E\u0446\u0438\u0430\u0446\u0438\u044F <em>(sambandha\u1E25)</em> \u0436\u0438\u0437\u043D\u0435\u043D\u043D\u043E\u0439 \u044D\u043D\u0435\u0440\u0433\u0438\u0438 <em>(pr\u0101\u1E47a)</em> [\u0441 \u0442\u0435\u043B\u043E\u043C \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F] \u0435\u0441\u0442\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0439 <em>(naisargika\u1E25)</em>||43||</strong></p></blockquote><p>\u0421\u0432\u044F\u0437\u044C, \u0438\u043B\u0438 \u0430\u0441\u0441\u043E\u0446\u0438\u0430\u0446\u0438\u044F <em>(sambandha\u1E25)</em> \u0436\u0438\u0437\u043D\u0435\u043D\u043D\u043E\u0439 \u044D\u043D\u0435\u0440\u0433\u0438\u0438 <em>(pr\u0101\u1E47a)</em> [\u0441 \u0442\u0435\u043B\u043E\u043C \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F] \u0435\u0441\u0442\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0439 <em>(naisargika\u1E25)</em>, \u0430 \u0438\u043C\u0435\u043D\u043D\u043E, \u0438\u0441\u0445\u043E\u0434\u0438\u0442 <em>(\u0101y\u0101ta\u1E25)</em> \u043E\u0442 nisarga, \u0438\u043B\u0438 \u043F\u0440\u0438\u0440\u043E\u0434\u044B <em>(nisarg\u0101t)</em>, \u0447\u044C\u044F \u0441\u0443\u0449\u043D\u043E\u0441\u0442\u044C <em>(sva-bh\u0101v\u0101t)</em> \u2014 \u0410\u0431\u0441\u043E\u043B\u044E\u0442\u043D\u0430\u044F \u0421\u0432\u043E\u0431\u043E\u0434\u0430 [\u0412\u044B\u0441\u0448\u0435\u0433\u043E \u0413\u043E\u0441\u043F\u043E\u0434\u0430] <em>(sv\u0101tantrya-\u0101tmana\u1E25)</em>. \u0412\u043E\u0441\u0445\u0438\u0442\u0438\u0442\u0435\u043B\u044C\u043D\u043E\u0435 <em>(bhagavat\u012B)</em> \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u0435 <em>(sa\u1E41vid)</em> \u043F\u043E\u0438\u0441\u0442\u0438\u043D\u0435 <em>(kila)</em>, \u0436\u0435\u043B\u0430\u044E\u0449\u0435\u0435 \u043F\u0440\u043E\u044F\u0432\u043B\u0435\u043D\u0438\u044F <em>(avabibh\u0101sayi\u1E63u\u1E25)</em> \u043C\u043D\u043E\u0433\u043E\u043E\u0431\u0440\u0430\u0437\u0438\u044F <em>(vaicitryam)</em> \u0432\u043E \u0432\u0441\u0435\u043B\u0435\u043D\u043D\u043E\u0439 <em>(vi\u015Bva)</em>, \u0432\u043D\u0430\u0447\u0430\u043B\u0435 \u043F\u0440\u0438\u0431\u0435\u0433\u043D\u0443\u0432 \u043A <em>(p\u016Brvakam... \u015Britv\u0101)</em> \u043F\u0440\u043E\u044F\u0432\u043B\u0435\u043D\u0438\u044E <em>(avabh\u0101sa)</em> \u0441\u0436\u0430\u0442\u0438\u044F --\u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u0438\u044F-- <em>(sa\u1E45koca)</em>, \u0441\u0438\u044F\u0435\u0442 \u043D\u0430\u0440\u0443\u0436\u0443 \u043A\u0430\u043A <em>(\u0101bh\u0101sa-\u0101tman\u0101 sphurati)</em> \u043C\u0438\u0440 <em>(jagat)</em>, \u043A\u043E\u0442\u043E\u0440\u044B\u0439 \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F gr\u0101hya, \u0438\u043B\u0438 \u043F\u043E\u0437\u043D\u0430\u0432\u0430\u0435\u043C\u044B\u043C --\u0442.\u0435. \u0442\u0435\u043C, \u0447\u0442\u043E \u043C\u043E\u0436\u0435\u0442 \u0431\u044B\u0442\u044C \u043F\u043E\u0437\u043D\u0430\u043D\u043E \u0438\u043B\u0438 \u0432\u043E\u0441\u043F\u0440\u0438\u043D\u044F\u0442\u043E-- <em>(gr\u0101hya-r\u016Bpa)</em> \u043F\u043E\u0441\u0440\u0435\u0434\u0441\u0442\u0432\u043E\u043C \u043F\u0440\u0438\u043D\u044F\u0442\u0438\u044F <em>(\u015Britv\u0101)</em> \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u044F <em>(bh\u016Bmik\u0101m)</em> gr\u0101haka, \u0438\u043B\u0438 \u043F\u043E\u0437\u043D\u0430\u044E\u0449\u0435\u0433\u043E --\u0442.\u0435. \u0442\u043E\u0433\u043E, \u043A\u0442\u043E \u043F\u043E\u0437\u043D\u0430\u0435\u0442 \u0438 \u0432\u043E\u0441\u043F\u0440\u0438\u043D\u0438\u043C\u0430\u0435\u0442-- <em>(gr\u0101haka)</em>, \u043A\u0442\u043E \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u0444\u043E\u0440\u043C\u043E\u0439, \u043F\u0440\u0438\u043D\u044F\u0442\u043E\u0439 <em>(r\u016Bpa)</em> Pr\u0101\u1E47an\u0101 --\u0443\u043D\u0438\u0432\u0435\u0440\u0441\u0430\u043B\u044C\u043D\u043E\u0439 \u0436\u0438\u0437\u043D\u0435\u043D\u043D\u043E\u0439 \u044D\u043D\u0435\u0440\u0433\u0438\u0435\u0439-- <em>(pr\u0101\u1E47an\u0101)</em>, \u0447\u044C\u044F \u0441\u0443\u0449\u043D\u043E\u0441\u0442\u044C <em>(\u0101tmaka)</em> \u2014 Sphuratt\u0101, \u0438\u043B\u0438 \u043F\u0443\u043B\u044C\u0441\u0438\u0440\u0443\u044E\u0449\u0438\u0439 \u0421\u0432\u0435\u0442 \u0411\u043E\u0433\u0430, \u043F\u0440\u043E\u044F\u0432\u043B\u044F\u044E\u0449\u0435\u0433\u043E <em>(sphuratt\u0101)</em> \u0446\u0435\u043B\u0443\u044E <em>(a\u015Be\u1E63a)</em> \u0432\u0441\u0435\u043B\u0435\u043D\u043D\u0443\u044E <em>(vi\u015Bva)</em>, \u043D\u043E \u0432 \u0441\u0436\u0430\u0442\u043E\u0439, \u0438\u043B\u0438 \u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u043D\u043E\u0439 \u0444\u043E\u0440\u043C\u0435 <em>(sa\u1E45kucat)</em> --\u043F\u043E\u0441\u043A\u043E\u043B\u044C\u043A\u0443 \u044D\u0442\u043E\u0442 \u043F\u0443\u043B\u044C\u0441\u0438\u0440\u0443\u044E\u0449\u0438\u0439 \u0411\u043E\u0436\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u044B\u0439 \u0421\u0432\u0435\u0442, \u0432\u043E\u0441\u0445\u0438\u0442\u0438\u0442\u0435\u043B\u044C\u043D\u043E\u0435 \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u0435 \u0432\u043D\u0430\u0447\u0430\u043B\u0435 \u043F\u0440\u0438\u0431\u0435\u0433\u043B\u043E \u043A \u043F\u043E\u043C\u043E\u0449\u0438 sa\u1E45koca, \u0438\u043B\u0438 \u0441\u0436\u0430\u0442\u0438\u044F--. \u0422\u0430\u043A\u0438\u043C \u043E\u0431\u0440\u0430\u0437\u043E\u043C <em>(iti)</em>, \u0441\u0432\u044F\u0437\u044C, \u0438\u043B\u0438 \u0430\u0441\u0441\u043E\u0446\u0438\u0430\u0446\u0438\u044F <em>(sambandha\u1E25)</em> \u0436\u0438\u0437\u043D\u0435\u043D\u043D\u043E\u0439 \u044D\u043D\u0435\u0440\u0433\u0438\u0438 <em>(pr\u0101\u1E47a)</em> [\u0441 \u0442\u0435\u043B\u043E\u043C \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F] \u0435\u0441\u0442\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0439 <em>(naisargika\u1E25)</em>, [\u043F\u043E\u0442\u043E\u043C\u0443 \u0447\u0442\u043E] \u043E\u043D\u0430 \u0438\u0437\u043D\u0430\u0447\u0430\u043B\u044C\u043D\u043E \u0432\u043E\u0437\u043D\u0438\u043A\u043B\u0430 <em>(prathamam udbh\u0101sita\u1E25)</em> \u0438\u0437 \u041D\u0435\u0433\u043E --\u0438\u0437 \u0432\u043E\u0441\u0445\u0438\u0442\u0438\u0442\u0435\u043B\u044C\u043D\u043E\u0433\u043E \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u044F-- <em>(asy\u0101\u1E25)</em> \u0431\u043B\u0430\u0433\u043E\u0434\u0430\u0440\u044F Sv\u0101tantrya --\u0415\u0433\u043E \u0410\u0431\u0441\u043E\u043B\u044E\u0442\u043D\u043E\u0439 \u0421\u0432\u043E\u0431\u043E\u0434\u0435-- <em>(sv\u0101tantry\u0101t)</em> --\u0432 \u043E\u0431\u0449\u0435\u043C, \u0441\u0432\u044F\u0437\u044C \u043C\u0435\u0436\u0434\u0443 \u0442\u0435\u043B\u043E\u043C \u0438 \u0436\u0438\u0437\u043D\u0435\u043D\u043D\u043E\u0439 \u044D\u043D\u0435\u0440\u0433\u0438\u0435\u0439 \u0435\u0441\u0442\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u0430, \u043F\u043E\u0441\u043A\u043E\u043B\u044C\u043A\u0443 \u043E\u043D\u0430 \u0431\u044B\u043B\u0430 \u043F\u0440\u043E\u044F\u0432\u043B\u0435\u043D\u0430 \u0413\u043E\u0441\u043F\u043E\u0434\u043E\u043C \u0441 \u0441\u0430\u043C\u043E\u0433\u043E \u043D\u0430\u0447\u0430\u043B\u0430 \u0432\u0441\u0435\u043B\u0435\u043D\u043D\u043E\u0439--|</p><p>\u0422\u0430\u043A\u0436\u0435 <em>(tath\u0101 ca)</em> [\u044D\u0442\u043E \u0431\u044B\u043B\u043E \u0437\u0430\u044F\u0432\u043B\u0435\u043D\u043E] \u0432 \u043F\u043E\u0447\u0442\u0435\u043D\u043D\u043E\u0439 V\u0101jasaney\u0101 <em>(\u015Br\u012B-v\u0101jasaney\u0101y\u0101m)</em>:</p><blockquote><p>&quot; \u015Aakti --\u0421\u0438\u043B\u0430 \u0413\u043E\u0441\u043F\u043E\u0434\u0430-- <em>(s\u0101 \u015Bakti\u1E25)</em>, \u043A\u043E\u0442\u043E\u0440\u0430\u044F <em>(y\u0101)</em> [\u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F] \u0432\u044B\u0441\u0448\u0435\u0439 <em>(par\u0101)</em>, \u0442\u043E\u043D\u043A\u043E\u0439 <em>(s\u016Bk\u1E63m\u0101)</em>, \u0432\u0441\u0435\u043F\u0440\u043E\u043D\u0438\u043A\u0430\u044E\u0449\u0435\u0439 --\u0432\u0435\u0437\u0434\u0435\u0441\u0443\u0449\u0435\u0439-- <em>(vy\u0101pin\u012B)</em>, \u0447\u0438\u0441\u0442\u043E\u0439 <em>(nirmal\u0101)</em>, \u0431\u043B\u0430\u0433\u043E\u0439 <em>(\u015Biv\u0101)</em>, \u043C\u0430\u0442\u0435\u0440\u044C\u044E <em>(janan\u012B)</em> \u0433\u0440\u0443\u043F\u043F\u044B <em>(cakrasya)</em> \u0441\u0438\u043B <em>(\u015Bakti)</em>, \u0432\u044B\u0441\u0448\u0438\u043C \u0431\u043B\u0430\u0436\u0435\u043D\u0441\u0442\u0432\u043E\u043C <em>(para-\u0101nand\u0101)</em>, \u0447\u044C\u044F \u043F\u0440\u0438\u0440\u043E\u0434\u0430 <em>(\u0101tmik\u0101)</em> \u2014 \u043D\u0435\u043A\u0442\u0430\u0440, \u0434\u0430\u0440\u0443\u044E\u0449\u0438\u0439 \u0431\u0435\u0441\u0441\u043C\u0435\u0440\u0442\u0438\u0435 <em>(am\u1E5Bta)</em>, \u043F\u043E\u0432\u0435\u043B\u0438\u0442\u0435\u043B\u044C\u043D\u0438\u0446\u0435\u0439 <em>(\u012B\u015Bvar\u012B)</em> mah\u0101ghor\u0101-s --\u0443\u0436\u0430\u0441\u043D\u0435\u0439\u0448\u0438\u0445 \u0441\u0438\u043B, \u0441\u0432\u044F\u0437\u044B\u0432\u0430\u044E\u0449\u0438\u0445 \u0438 \u043F\u043E\u0440\u0430\u0431\u043E\u0449\u0430\u044E\u0449\u0438\u0445 \u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u043D\u044B\u0445 \u0441\u0443\u0449\u0435\u0441\u0442\u0432-- <em>(mah\u0101-ghor\u0101)</em>, \u0432\u043D\u0443\u0448\u0430\u044E\u0449\u0435\u0439 \u0443\u0436\u0430\u0441 --\u0442\u0430\u043A \u043A\u0430\u043A \u041E\u043D\u0430 \u0441\u043A\u0440\u044B\u0432\u0430\u0435\u0442 \u0441\u0432\u043E\u044E \u0441\u0443\u0449\u043D\u043E\u0441\u0442\u043D\u0443\u044E \u043F\u0440\u0438\u0440\u043E\u0434\u0443-- <em>(ca\u1E47\u1E0D\u0101)</em>, [\u0438] \u0422\u043E\u0439, \u043A\u0442\u043E \u0432\u044B\u0437\u044B\u0432\u0430\u0435\u0442 <em>(k\u0101rik\u0101)</em> \u043F\u0440\u043E\u044F\u0432\u043B\u0435\u043D\u0438\u0435 <em>(s\u1E5B\u1E63\u1E6Di)</em> [\u0438] \u043F\u043E\u0433\u043B\u043E\u0449\u0435\u043D\u0438\u0435 <em>(sa\u1E41h\u0101ra)</em> [\u0432\u0441\u0435\u043B\u0435\u043D\u043D\u043E\u0439]. \u041E\u043D\u0430 \u0441\u0438\u043B\u043E\u0439 \u043F\u0440\u043E\u044F\u0432\u043B\u044F\u0435\u0442 \u0438 \u043E\u0442\u0437\u044B\u0432\u0430\u0435\u0442 <em>(bal\u0101t... prakar\u1E63ati)</em> \u0412\u0440\u0435\u043C\u044F <em>(k\u0101lam)</em>, \u043F\u043E\u044F\u0432\u043B\u044F\u044E\u0449\u0435\u0435\u0441\u044F \u043A\u0430\u043A \u0442\u0440\u0438 \u043F\u043E\u0442\u043E\u043A\u0430, \u0438\u043B\u0438 \u0442\u0435\u0447\u0435\u043D\u0438\u044F --\u0442.\u0435. \u0412\u0440\u0435\u043C\u044F \u0442\u0435\u0447\u0435\u0442 \u043F\u043E \u0442\u043E\u043D\u043A\u0438\u043C \u043A\u0430\u043D\u0430\u043B\u0430\u043C, \u0438\u0437\u0432\u0435\u0441\u0442\u043D\u044B\u043C \u043A\u0430\u043A I\u1E0D\u0101, Pi\u1E45gal\u0101 \u0438 Su\u1E63umn\u0101-- <em>(tri-vaham)</em>, \u0442\u0440\u0435\u043C\u044F \u043F\u0443\u0442\u044F\u043C\u0438 --\u0442.\u0435. \u0412\u0440\u0435\u043C\u044F \u0432\u043E\u0437\u043D\u0438\u043A\u0430\u0435\u0442 \u0432 \u0444\u043E\u0440\u043C\u0435 \u043B\u0443\u043D\u044B, \u0441\u043E\u043B\u043D\u0446\u0430 \u0438 \u043E\u0433\u043D\u044F, \u043A\u043E\u0442\u043E\u0440\u044B\u0435 \u043F\u0440\u0435\u0434\u0441\u0442\u0430\u0432\u043B\u044F\u044E\u0442 \u0441\u043E\u0431\u043E\u0439 \u043F\u043E\u0437\u043D\u0430\u0432\u0430\u0435\u043C\u043E\u0435, \u0438\u043B\u0438 \u043E\u0431\u044A\u0435\u043A\u0442, \u043F\u043E\u0437\u043D\u0430\u044E\u0449\u0435\u0433\u043E, \u0438\u043B\u0438 \u0441\u0443\u0431\u044A\u0435\u043A\u0442 \u0438 \u0437\u043D\u0430\u043D\u0438\u0435, \u0441\u043E\u043E\u0442\u0432\u0435\u0442\u0441\u0442\u0432\u0435\u043D\u043D\u043E-- <em>(trividham)</em>, [\u0438] \u0432 \u0442\u0440\u0435\u0445 \u0430\u0441\u043F\u0435\u043A\u0442\u0430\u0445 --\u0442.\u0435. \u0412\u0440\u0435\u043C\u044F \u0441\u0442\u0430\u043D\u043E\u0432\u0438\u0442\u0441\u044F \u043F\u0440\u043E\u044F\u0432\u043B\u0435\u043D\u043D\u044B\u043C \u043A\u0430\u043A \u043F\u0440\u043E\u0448\u043B\u043E\u0435, \u043D\u0430\u0441\u0442\u043E\u044F\u0449\u0435\u0435 \u0438 \u0431\u0443\u0434\u0443\u0449\u0435\u0435-- <em>(tristham... iti)</em>&quot;||</p></blockquote><p>\u0412\u044B\u0448\u0435\u0443\u043F\u043E\u043C\u044F\u043D\u0443\u0442\u043E\u0435 <em>(uktam)</em> \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435 \u0440\u0435\u0436\u0438\u0441\u0441\u0435\u0440\u0430 <em>(k\u0101ritvam)</em> [\u043E\u0431\u043E\u0438\u0445] \u0432\u043D\u0435\u0448\u043D\u0438\u0445 \u043F\u0440\u043E\u044F\u0432\u043B\u0435\u043D\u0438\u0439 <em>(ull\u0101sa)</em> [\u0438] \u0432\u043D\u0443\u0442\u0440\u0435\u043D\u043D\u0438\u0445 \u043F\u043E\u0433\u043B\u043E\u0449\u0435\u043D\u0438\u0439 <em>(vil\u0101pana)</em> \u0432 \u043E\u0442\u043D\u043E\u0448\u0435\u043D\u0438\u0438 \u0432\u043D\u0435\u0448\u043D\u0435\u0433\u043E \u0412\u0440\u0435\u043C\u0435\u043D\u0438 <em>(b\u0101hya-k\u0101la)</em> \u0432 \u0444\u043E\u0440\u043C\u0435 \u0440\u044F\u0434\u0430 <em>(krame\u1E47a)</em> \u0436\u0438\u0437\u043D\u0435\u043D\u043D\u044B\u0445 \u044D\u043D\u0435\u0440\u0433\u0438\u0439 <em>(pr\u0101\u1E47a)</em>, \u043F\u0440\u0438\u043D\u0430\u0434\u043B\u0435\u0436\u0438\u0442 \u0442\u043E\u043B\u044C\u043A\u043E <em>(eva)</em> \u0432\u043E\u0441\u0445\u0438\u0442\u0438\u0442\u0435\u043B\u044C\u043D\u043E\u043C\u0443 \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u044E <em>(sa\u1E41vida\u1E25... bhagavaty\u0101\u1E25)</em>. [\u0412\u043D\u0435\u0448\u043D\u0435\u0435 \u0412\u0440\u0435\u043C\u044F, \u0432\u043E\u0437\u043D\u0438\u043A\u0430\u044E\u0449\u0435\u0435 \u043A\u0430\u043A \u0440\u044F\u0434 \u0436\u0438\u0437\u043D\u0435\u043D\u043D\u044B\u0445 \u044D\u043D\u0435\u0440\u0433\u0438\u0439, \u0431\u044B\u043B\u043E \u043F\u043E\u043A\u0430\u0437\u0430\u043D\u043E \u0432 \u044D\u0442\u043E\u0439 \u0441\u0430\u043C\u043E\u0439 \u0441\u0442\u0440\u043E\u0444\u0435 \u0442\u0435\u0440\u043C\u0438\u043D\u0430\u043C\u0438 &quot;tristham&quot;, &quot;trividham&quot; \u0438 &quot;trivaham&quot;, \u0430 \u0438\u043C\u0435\u043D\u043D\u043E, \u0432\u043D\u0435\u0448\u043D\u0435\u0435 \u0412\u0440\u0435\u043C\u044F], \u0447\u044C\u0435\u0439 \u0444\u043E\u0440\u043C\u043E\u0439 \u044F\u0432\u043B\u044F\u044E\u0442\u0441\u044F <em>(r\u016Bpa)</em> \u043F\u0440\u043E\u0448\u043B\u043E\u0435 <em>(at\u012Bta)</em>, \u0431\u0443\u0434\u0443\u0449\u0435\u0435 <em>(an\u0101gata)</em> [\u0438] \u043D\u0430\u0441\u0442\u043E\u044F\u0449\u0435\u0435 <em>(vartam\u0101na)</em>, [\u044D\u0442\u043E \u0442\u043E, \u0447\u0442\u043E] \u043F\u0440\u0435\u0431\u044B\u0432\u0430\u0435\u0442 \u043A\u0430\u043A <em>(\u0101tma-avasthita)</em> \u043B\u0443\u043D\u0430 --\u043F\u043E\u0437\u043D\u0430\u0432\u0430\u0435\u043C\u043E\u0435, \u0438\u043B\u0438 \u043E\u0431\u044A\u0435\u043A\u0442-- <em>(soma)</em>, \u0441\u043E\u043B\u043D\u0446\u0435 --\u043F\u043E\u0437\u043D\u0430\u044E\u0449\u0438\u0439, \u0438\u043B\u0438 \u0441\u0443\u0431\u044A\u0435\u043A\u0442-- <em>(s\u016Brya)</em> [\u0438] \u043E\u0433\u043E\u043D\u044C --\u0437\u043D\u0430\u043D\u0438\u0435-- <em>(vahni)</em>, [\u0438] \u0442\u0435\u0447\u0435\u0442 <em>(v\u0101hi)</em> \u043F\u043E \u0442\u0440\u0435\u043C <em>(traya)</em> \u0442\u043E\u043D\u043A\u0438\u043C \u043A\u0430\u043D\u0430\u043B\u0430\u043C --I\u1E0D\u0101, Pi\u1E45gal\u0101 \u0438 Su\u1E63umn\u0101-- <em>(n\u0101\u1E0Di)</em><sup>1</sup>|</p><p>\u042D\u0442\u043E <em>(tad)</em> \u0431\u044B\u043B\u043E \u0442\u0430\u043A\u0436\u0435 \u0443\u043F\u043E\u043C\u044F\u043D\u0443\u0442\u043E <em>(uktam... api)</em> \u0432 Svacchandatantra <em>(svacchande)</em>:</p><blockquote><p>&quot;\u0416\u0438\u0437\u043D\u0435\u043D\u043D\u0430\u044F \u044D\u043D\u0435\u0440\u0433\u0438\u044F <em>(pr\u0101\u1E47a\u1E25)</em> \u0441\u043E\u0441\u0442\u043E\u0438\u0442 \u0438\u0437 <em>(maya\u1E25)</em> pr\u0101\u1E47a <em>(pr\u0101\u1E47a)</em> [\u0438] ap\u0101na <em>(ap\u0101na)</em> \u0432 \u043A\u0430\u0436\u0434\u043E\u043C <em>(prati)</em> \u0432\u044B\u0434\u043E\u0445\u0435 <em>(visarga)</em> [\u0438] \u0432\u0434\u043E\u0445\u0435 <em>(\u0101p\u016Bra\u1E47am)</em>, [\u0438] \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u0443\u0435\u0442 <em>(sthita\u1E25)</em> \u0432 \u0433\u0440\u0443\u0434\u0438 <em>(urasi)</em> \u0436\u0438\u0432\u044B\u0445 \u0441\u0443\u0449\u0435\u0441\u0442\u0432 <em>(pr\u0101\u1E47in\u0101m)</em> \u043A\u0430\u043A \u0442\u043E, \u0447\u0442\u043E \u043D\u0430\u043F\u043E\u043B\u043D\u0435\u043D\u043E \u0432\u043E\u0437\u0434\u0443\u0445\u043E\u043C --\u0442.\u0435. \u0436\u0438\u0437\u043D\u044C\u044E-- <em>(\u0101p\u016Brayan eva)</em> \u043F\u043E\u0441\u0442\u043E\u044F\u043D\u043D\u043E <em>(nityam... iti)</em><sup>2</sup>&quot;||<br> [\u0421\u043C. VII, 25 \u0432 Svacchandatantra]</p></blockquote><p>\u0412 \u0441\u043E\u043E\u0442\u0432\u0435\u0442\u0441\u0442\u0432\u0438\u0438 \u0441 \u0442\u0435\u043C, \u0447\u0442\u043E \u0431\u044B\u043B\u043E \u0443\u043F\u043E\u043C\u044F\u043D\u0443\u0442\u043E <em>(ukta-n\u012Bty\u0101)</em> [\u0432 \u0441\u0430\u043C\u043E\u0439 Svacchandatantra]:</p><blockquote><p>&quot;\u0411\u0443\u043A\u0432\u0430 <em>(k\u0101ra\u1E25)</em> &#39;ha&#39; <em>(ha)</em>, \u0431\u0435\u0437\u0443\u0441\u043B\u043E\u0432\u043D\u043E, \u0441\u0447\u0438\u0442\u0430\u0435\u0442\u0441\u044F <em>(tu sm\u1E5Bta\u1E25)</em> \u0436\u0438\u0437\u043D\u0435\u043D\u043D\u043E\u0439 \u044D\u043D\u0435\u0440\u0433\u0438\u0435\u0439 <em>(pr\u0101\u1E47a\u1E25)</em>, \u043A\u043E\u0442\u043E\u0440\u0430\u044F \u0432\u043E\u0437\u043D\u0438\u043A\u0430\u0435\u0442 \u0441\u0430\u043C\u0430 \u043F\u043E \u0441\u0435\u0431\u0435 --\u0430\u0432\u0442\u043E\u043C\u0430\u0442\u0438\u0447\u0435\u0441\u043A\u0438-- <em>(svaprav\u1E5Btta\u1E25)</em> [\u0438] \u0438\u043C\u0435\u0435\u0442 \u0444\u043E\u0440\u043C\u0443 <em>(\u0101k\u1E5Bti\u1E25)</em> \u043F\u043B\u0443\u0433\u0430 <em>(hala... iti)</em><sup>3</sup>&quot;||<br> [\u0421\u043C. IV, 257 \u0432 Svacchandatantra]</p></blockquote><p>\u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435 \u0440\u0435\u0436\u0438\u0441\u0441\u0435\u0440\u0430 <em>(k\u0101ritvam)</em> \u043F\u0440\u043E\u044F\u0432\u043B\u0435\u043D\u0438\u044F <em>(s\u1E5B\u1E63\u1E6Di)</em> [\u0438] \u043F\u043E\u0433\u043B\u043E\u0449\u0435\u043D\u0438\u044F <em>(sa\u1E41h\u0101ra)</em> \u0432 \u0444\u043E\u0440\u043C\u0435 \u0438\u0441\u043F\u0443\u0441\u043A\u0430\u043D\u0438\u044F \u0438 \u043D\u0430\u043F\u043E\u043B\u043D\u0435\u043D\u0438\u044F <em>(visarga-\u0101p\u016Bratay\u0101)</em>, \u043A\u0430\u043A \u0433\u043E\u0432\u043E\u0440\u0438\u0442\u0441\u044F <em>(abhihitam)</em>, \u043F\u0440\u0438\u043D\u0430\u0434\u043B\u0435\u0436\u0438\u0442 \u0436\u0438\u0437\u043D\u0435\u043D\u043D\u043E\u0439 \u044D\u043D\u0435\u0440\u0433\u0438\u0438, \u0438\u043B\u0438 pr\u0101\u1E47a <em>(pr\u0101\u1E47asya)</em>, \u043F\u043E\u0442\u043E\u043C\u0443 \u0447\u0442\u043E \u043E\u043D\u043E \u0438\u0437\u043E\u0431\u0438\u043B\u0443\u0435\u0442 <em>(mayatv\u0101t)</em> \u044D\u043D\u0435\u0440\u0433\u0438\u0435\u0439 \u0438 \u0441\u0438\u043B\u043E\u0439 <em>(pr\u0101\u1E47a)</em>, \u0447\u044C\u044F \u043F\u0440\u0438\u0440\u043E\u0434\u0430 <em>(r\u016Bpa)</em> \u2014 \u0441\u0430\u043C\u0430\u044F \u0432\u043E\u0441\u0445\u0438\u0442\u0438\u0442\u0435\u043B\u044C\u043D\u0430\u044F <em>(\u015Br\u012B... bha\u1E6D\u1E6D\u0101raka)</em> Svacchanda -- \u0410\u0431\u0441\u043E\u043B\u044E\u0442\u043D\u043E \u0421\u0432\u043E\u0431\u043E\u0434\u043D\u044B\u0439 \u0413\u043E\u0441\u043F\u043E\u0434\u044C-- <em>(svacchanda)</em>. \u0422\u0430\u043A\u0438\u043C \u043E\u0431\u0440\u0430\u0437\u043E\u043C <em>(iti)</em>, \u044D\u0442\u043E \u0431\u044B\u043B\u043E \u043F\u0440\u0430\u0432\u0438\u043B\u044C\u043D\u043E \u0441\u043A\u0430\u0437\u0430\u043D\u043E [\u0432 \u0441\u0442\u0440\u043E\u0444\u0435] <em>(yuktam uktam)</em>: &quot;\u0421\u0432\u044F\u0437\u044C, \u0438\u043B\u0438 \u0430\u0441\u0441\u043E\u0446\u0438\u0430\u0446\u0438\u044F <em>(sambandha\u1E25)</em> \u0436\u0438\u0437\u043D\u0435\u043D\u043D\u043E\u0439 \u044D\u043D\u0435\u0440\u0433\u0438\u0438 <em>(pr\u0101\u1E47a)</em> [\u0441 \u0442\u0435\u043B\u043E\u043C \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F] \u0435\u0441\u0442\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0439 <em>(naisargika\u1E25... iti)</em>&quot;|</p><p>\u041F\u043E \u044D\u0442\u043E\u0439 \u0441\u0430\u043C\u043E\u0439 \u043F\u0440\u0438\u0447\u0438\u043D\u0435 <em>(atas eva)</em>, \u043F\u043E\u0434\u0442\u0432\u0435\u0440\u0436\u0434\u0435\u043D\u0438\u0435 <em>(d\u0101r\u1E0Dhyam)</em> \u0442\u043E\u0433\u043E, \u0447\u0442\u043E \u0438\u0437\u0432\u0435\u0441\u0442\u043D\u043E \u043A\u0430\u043A <em>(\u0101khya)</em> pr\u0101\u1E47a, \u0438\u043B\u0438 \u0436\u0438\u0437\u043D\u0435\u043D\u043D\u0430\u044F \u044D\u043D\u0435\u0440\u0433\u0438\u044F <em>(pr\u0101\u1E47a)</em>, \u044F\u0432\u043B\u044F\u044E\u0449\u0430\u044F\u0441\u044F \u043F\u0440\u0438\u0447\u0438\u043D\u043E\u0439 [\u043F\u0440\u043E\u044F\u0432\u043B\u0435\u043D\u0438\u044F \u0438 \u043F\u043E\u0433\u043B\u043E\u0449\u0435\u043D\u0438\u044F] <em>(nimitta)</em>, \u0431\u044B\u043B\u043E \u0443\u043F\u043E\u043C\u044F\u043D\u0443\u0442\u043E <em>(uktam)</em> \u043F\u043E\u0447\u0442\u0435\u043D\u043D\u044B\u043C Kalla\u1E6Da <em>(\u015Br\u012B-bha\u1E6D\u1E6Da-kalla\u1E6Dena)</em> \u0432 [\u0435\u0433\u043E] Tattv\u0101rthacint\u0101ma\u1E47i <em>(tattv\u0101rthacint\u0101ma\u1E47au)</em>:</p><blockquote><p>&quot;\u0412\u043D\u0430\u0447\u0430\u043B\u0435 <em>(pr\u0101k)</em> \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u0435 <em>(sa\u1E41vid)</em> \u043F\u0440\u0435\u0432\u0440\u0430\u0449\u0430\u0435\u0442\u0441\u044F <em>(pari\u1E47at\u0101)</em> \u0432 \u0436\u0438\u0437\u043D\u0435\u043D\u043D\u0443\u044E \u044D\u043D\u0435\u0440\u0433\u0438\u044E <em>(pr\u0101\u1E47e... iti)</em>&quot;|</p></blockquote><p>||43||</p><hr><ol><li>\u041F\u043E\u0441\u043A\u043E\u043B\u044C\u043A\u0443 \u0412\u0440\u0435\u043C\u044F \u2014 \u044D\u0442\u043E \u043F\u0440\u043E\u044F\u0432\u043B\u0435\u043D\u0438\u0435 Pr\u0101\u1E47an\u0101, \u0443\u043D\u0438\u0432\u0435\u0440\u0441\u0430\u043B\u044C\u043D\u043E\u0439 \u0436\u0438\u0437\u043D\u0435\u043D\u043D\u043E\u0439 \u044D\u043D\u0435\u0440\u0433\u0438\u0438, \u0447\u044C\u0435\u0439 \u0441\u0443\u0449\u043D\u043E\u0441\u0442\u044C\u044E \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u043F\u0443\u043B\u044C\u0441\u0438\u0440\u0443\u044E\u0449\u0438\u0439 \u0421\u0432\u0435\u0442 \u0411\u043E\u0433\u0430, \u0442\u043E \u043E\u043D\u043E \u043F\u043E\u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u0432 \u0432\u0438\u0434\u0435 \u0433\u0440\u0443\u043F\u043F\u044B pr\u0101\u1E47a-s, \u0438\u043B\u0438 \u0436\u0438\u0437\u043D\u0435\u043D\u043D\u044B\u0445 \u044D\u043D\u0435\u0440\u0433\u0438\u0439. \u0414\u0430, \u043D\u0430\u0432\u0435\u0440\u043D\u043E, \u0442\u0440\u0443\u0434\u043D\u043E \u043F\u043E\u043D\u044F\u0442\u044C \u043A\u043E\u043D\u0446\u0435\u043F\u0446\u0438\u044E \u0432\u0440\u0435\u043C\u0435\u043D\u0438, \u043A\u0430\u043A \u0436\u0438\u0437\u043D\u0435\u043D\u043D\u043E\u0439 \u044D\u043D\u0435\u0440\u0433\u0438\u0438, \u043D\u043E \u044D\u0442\u043E \u043F\u0440\u0430\u0432\u0434\u0430. \u0427\u0442\u043E \u043A\u0430\u0441\u0430\u0435\u0442\u0441\u044F \u043E\u0441\u0442\u0430\u043B\u044C\u043D\u043E\u0439 \u0447\u0430\u0441\u0442\u0438 \u043C\u043E\u0435\u0433\u043E \u043F\u0435\u0440\u0435\u0432\u043E\u0434\u0430 \u044D\u0442\u043E\u0433\u043E \u0430\u0431\u0437\u0430\u0446\u0430, \u0442\u043E \u043A\u043E\u043D\u0435\u0447\u043D\u043E, \u044F \u0434\u043E\u043B\u0436\u0435\u043D \u0431\u044B\u043B \u0443\u0434\u043E\u0431\u043D\u043E \u0441\u043A\u043E\u043C\u043F\u0430\u043D\u043E\u0432\u0430\u0442\u044C \u0435\u0433\u043E, \u0438\u043D\u0430\u0447\u0435 \u044D\u0442\u043E \u043D\u0435\u0443\u0434\u043E\u0431\u043E\u0432\u0430\u0440\u0438\u043C\u043E\u0435 \u0441\u043E\u0441\u0442\u0430\u0432\u043D\u043E\u0435 \u0441\u043B\u043E\u0432\u043E (\u0434\u043B\u0438\u043D\u043D\u043E\u0435 \u0438 \u0437\u0430\u0443\u043C\u043D\u043E\u0435), \u043D\u0430\u0447\u0438\u043D\u0430\u044E\u0449\u0435\u0435\u0441\u044F \u0441 &quot;n\u0101\u1E0Ditraya&quot; \u0438 \u0437\u0430\u043A\u0430\u043D\u0447\u0438\u0432\u0430\u044E\u0449\u0435\u0435\u0441\u044F \u0432 &quot;k\u0101ritvam&quot;, \u043B\u0435\u0433\u043A\u043E \u0443\u0431\u0438\u043B\u043E \u0431\u044B \u043D\u0430\u0448 \u0438\u043D\u0442\u0435\u043B\u043B\u0435\u043A\u0442! \u0422\u0430\u043A\u043E\u0439 \u0432\u0438\u0434 \u0441\u0432\u0435\u0440\u0445\u0434\u043B\u0438\u043D\u043D\u044B\u0445 \u0441\u043E\u0441\u0442\u0430\u0432\u043D\u044B\u0445 \u0441\u043B\u043E\u0432 \u043E\u0431\u044B\u0447\u043D\u043E \u0432\u0441\u0442\u0440\u0435\u0447\u0430\u0435\u0442\u0441\u044F \u0432 \u0440\u0430\u0431\u043E\u0442\u0430\u0445 \u043D\u0435\u043A\u043E\u0442\u043E\u0440\u044B\u0445 \u043C\u0430\u0441\u0442\u0435\u0440\u043E\u0432 \u0422\u0440\u0438\u043A\u0438 (\u043D\u0430\u043F\u0440\u0438\u043C\u0435\u0440, Abhinavagupta \u0438 \u0435\u0433\u043E \u0443\u0447\u0435\u043D\u0438\u043A\u0430 K\u1E63emar\u0101ja).</li></ol><p>\u041A \u0441\u0447\u0430\u0441\u0442\u044C\u044E, \u0442\u0430\u043A\u043E\u0439 \u0441\u0442\u0438\u043B\u044C \u043D\u0430\u0433\u0440\u043E\u043C\u043E\u0436\u0434\u0435\u043D\u0438\u044F \u0441\u043B\u043E\u0432 \u043E\u0431\u044B\u0447\u043D\u043E \u043D\u0435 \u0432\u0441\u0442\u0440\u0435\u0447\u0430\u0435\u0442\u0441\u044F \u0432 \u0441\u0442\u0430\u0440\u044B\u0445 \u041F\u0438\u0441\u0430\u043D\u0438\u044F\u0445. \u041F\u0440\u043E\u0431\u043B\u0435\u043C\u0430 \u0441 \u043D\u0435\u0443\u0434\u043E\u0431\u043E\u0432\u0430\u0440\u0438\u043C\u044B\u043C\u0438 \u0441\u043E\u0441\u0442\u0430\u0432\u043D\u044B\u043C\u0438 \u0441\u043B\u043E\u0432\u0430\u043C\u0438 \u0441\u043E\u0441\u0442\u043E\u0438\u0442 \u0432 \u0442\u043E\u043C, \u0447\u0442\u043E \u0447\u0435\u043C \u0431\u043E\u043B\u044C\u0448\u0435 \u0441\u043B\u043E\u0432 \u0432 \u043D\u0438\u0445 \u0441\u043E\u0434\u0435\u0440\u0436\u0438\u0442\u0441\u044F, \u0442\u0435\u043C \u0431\u043E\u043B\u0435\u0435 \u043F\u0440\u043E\u0431\u043B\u0435\u043C\u0430\u0442\u0438\u0447\u043D\u044B\u043C \u043E\u043D\u043E \u0441\u0442\u0430\u043D\u043E\u0432\u0438\u0442\u0441\u044F \u043F\u0440\u0438 \u043F\u043E\u043F\u044B\u0442\u043A\u0435 \u0435\u0433\u043E \u043F\u0435\u0440\u0435\u0432\u043E\u0434\u0430. \u0415\u0441\u043B\u0438 \u0432\u044B \u0441\u0430\u043D\u0441\u043A\u0440\u0438\u0442\u0441\u043A\u0438\u0439 \u0441\u0442\u0443\u0434\u0435\u043D\u0442, \u0432\u044B \u0443\u0436\u0435 \u0437\u043D\u0430\u0435\u0442\u0435, \u0447\u0442\u043E \u043A\u0430\u0436\u0434\u043E\u0435 \u0441\u043B\u043E\u0432\u043E \u0432 \u0441\u0430\u043D\u0441\u043A\u0440\u0438\u0442\u0435 \u043C\u043E\u0436\u0435\u0442 \u0438\u043C\u0435\u0442\u044C \u043C\u043D\u043E\u0436\u0435\u0441\u0442\u0432\u043E \u0437\u043D\u0430\u0447\u0435\u043D\u0438\u0439 (\u0438\u043D\u043E\u0433\u0434\u0430 \u043E\u0433\u0440\u043E\u043C\u043D\u043E\u0435 \u043A\u043E\u043B\u0438\u0447\u0435\u0441\u0442\u0432\u043E). \u0422\u0430\u043A \u043D\u0430\u043F\u0440\u0438\u043C\u0435\u0440, \u0435\u0441\u043B\u0438 \u0443 \u0432\u0430\u0441 \u0438\u043C\u0435\u0435\u0442\u0441\u044F \u0441\u043E\u0441\u0442\u0430\u0432\u043D\u043E\u0435 \u0441\u043B\u043E\u0432\u043E \u0438\u0437 \u0442\u0440\u0435\u0445 \u0441\u043B\u043E\u0432, \u0438 \u043A\u0430\u0436\u0434\u043E\u0435 \u0438\u0445 \u043D\u0438\u0445 \u0438\u043C\u0435\u0435\u0442 \u043F\u044F\u0442\u044C \u0432\u043E\u0437\u043C\u043E\u0436\u043D\u044B\u0445 \u0437\u043D\u0430\u0447\u0435\u043D\u0438\u0439, \u043D\u0443, \u0443 \u0432\u0430\u0441 \u0431\u0443\u0434\u0435\u0442 \u043A\u043E\u043C\u0431\u0438\u043D\u0430\u0446\u0438\u044F \u0438\u0437 \u043F\u044F\u0442\u043D\u0430\u0434\u0446\u0430\u0442\u0438 \u0437\u043D\u0430\u0447\u0435\u043D\u0438\u0439. \u0414\u043B\u044F \u043F\u0435\u0440\u0435\u0432\u043E\u0434\u0447\u0438\u043A\u0430, \u0438\u043C\u0435\u044E\u0449\u0435\u0433\u043E \u0434\u043E\u0441\u0442\u0430\u0442\u043E\u0447\u043D\u043E \u043E\u043F\u044B\u0442\u0430 \u0438 \u0437\u043D\u0430\u043D\u0438\u0439, \u0442\u0430\u043A\u0438\u0435 \u043A\u043E\u0440\u043E\u0442\u043A\u0438\u0435 \u0441\u043E\u0441\u0442\u0430\u0432\u043D\u044B\u0435 \u0441\u043B\u043E\u0432\u0430 \u043E\u0442\u043D\u043E\u0441\u0438\u0442\u0435\u043B\u044C\u043D\u043E \u043F\u0440\u043E\u0441\u0442\u044B \u0434\u043B\u044F \u0442\u0440\u0430\u043A\u0442\u043E\u0432\u043A\u0438. \u0422\u0435\u043C \u043D\u0435 \u043C\u0435\u043D\u0435\u0435, \u0435\u0441\u043B\u0438 \u0441\u043E\u0441\u0442\u0430\u0432\u043D\u043E\u0435 \u0441\u043B\u043E\u0432\u043E \u0441\u043E\u0441\u0442\u043E\u0438\u0442 \u0438\u0437 \u0431\u043E\u043B\u0435\u0435, \u0447\u0435\u043C \u043F\u044F\u0442\u0438 \u0438\u043B\u0438 \u0448\u0435\u0441\u0442\u0438 \u0441\u043B\u043E\u0432, \u0442\u043E\u0433\u0434\u0430 \u043F\u0435\u0440\u0435\u0432\u043E\u0434\u0447\u0438\u043A\u0443 \u043F\u0440\u0438\u0434\u0435\u0442\u0441\u044F \u043F\u043E\u043F\u043E\u0442\u0435\u0442\u044C, \u043F\u043E\u0441\u043A\u043E\u043B\u044C\u043A\u0443 \u0447\u0438\u0441\u043B\u043E \u0432\u043E\u0437\u043C\u043E\u0436\u043D\u044B\u0445 \u043A\u043E\u043C\u0431\u0438\u043D\u0430\u0446\u0438\u0439 \u0443\u0432\u0435\u043B\u0438\u0447\u0438\u0432\u0430\u0435\u0442\u0441\u044F. \u0421\u043E\u0441\u0442\u0430\u0432\u043D\u043E\u0435 \u0441\u043B\u043E\u0432\u043E, \u043D\u0430\u043F\u0438\u0441\u0430\u043D\u043D\u043E\u0435 K\u1E63emar\u0101ja \u0432 \u043F\u043E\u0441\u043B\u0435\u0434\u043D\u0435\u043C \u0430\u0431\u0437\u0430\u0446\u0435, \u0438\u043C\u0435\u0435\u0442 \u0431\u043E\u043B\u0435\u0435, \u0447\u0435\u043C \u043F\u044F\u0442\u043D\u0430\u0434\u0446\u0430\u0442\u044C \u0441\u043B\u043E\u0432! \u0414\u0430, \u0431\u043E\u043B\u044C\u0448\u0438\u043D\u0441\u0442\u0432\u043E \u0438\u0437 \u043D\u0438\u0445 \u0432\u043F\u043E\u043B\u043D\u0435 \u043F\u043E\u043D\u044F\u0442\u043D\u044B \u043E\u043F\u044B\u0442\u043D\u043E\u043C\u0443 \u043F\u0435\u0440\u0435\u0432\u043E\u0434\u0447\u0438\u043A\u0443 \u0441 \u0433\u043B\u0443\u0431\u043E\u043A\u0438\u043C\u0438 \u043F\u043E\u0437\u043D\u0430\u043D\u0438\u044F\u043C\u0438 \u0432 \u0444\u0438\u043B\u043E\u0441\u043E\u0444\u0438\u0438, \u043D\u043E \u0438\u043C\u0435\u0435\u0442\u0441\u044F \u0434\u0432\u0430 \u0442\u0435\u0440\u043C\u0438\u043D\u0430, \u043A\u043E\u0442\u043E\u0440\u044B\u0435 \u0432\u043E\u043E\u0431\u0449\u0435 \u043D\u0435\u043F\u0440\u043E\u0441\u0442\u043E \u043F\u0435\u0440\u0435\u0432\u0435\u0441\u0442\u0438: &quot;ull\u0101sa&quot; \u0438 &quot;vil\u0101pana&quot;. \u0427\u0442\u043E\u0431\u044B \u0438\u0445 \u043F\u0440\u0430\u0432\u0438\u043B\u044C\u043D\u043E \u043F\u0435\u0440\u0435\u0432\u0435\u0441\u0442\u0438, \u0432\u0430\u043C \u043D\u0435\u043E\u0431\u0445\u043E\u0434\u0438\u043C\u043E \u0447\u0438\u0442\u0430\u0442\u044C \u043A\u043E\u043C\u043C\u0435\u043D\u0442\u0430\u0440\u0438\u0438 \u0443\u0447\u0435\u043D\u044B\u0445, \u0432\u043B\u0430\u0434\u0435\u044E\u0449\u0438\u0445 \u044D\u0442\u043E\u0439 \u0444\u0438\u043B\u043E\u0441\u043E\u0444\u0441\u043A\u043E\u0439 \u0441\u0438\u0441\u0442\u0435\u043C\u043E\u0439. \u0415\u0441\u043B\u0438 \u0432\u044B \u043F\u043E\u043B\u044C\u0437\u0443\u0435\u0442\u0435\u0441\u044C \u0442\u043E\u043B\u044C\u043A\u043E \u0441\u0430\u043D\u0441\u043A\u0440\u0438\u0442\u0441\u043A\u0438\u043C \u0441\u043B\u043E\u0432\u0430\u0440\u0435\u043C, \u0432\u044B \u043C\u043E\u0436\u0435\u0442\u0435 \u043F\u0440\u0438\u0439\u0442\u0438 \u043A \u0432\u044B\u0432\u043E\u0434\u0443, \u0447\u0442\u043E &quot;ull\u0101sa&quot; \u2014 \u044D\u0442\u043E \u0432\u043E\u0437\u043C\u043E\u0436\u043D\u043E, \u0447\u0442\u043E-\u0442\u043E \u0442\u0438\u043F\u0430 &quot;\u043F\u0440\u043E\u044F\u0432\u043B\u0435\u043D\u0438\u044F&quot;, \u0430 &quot;vil\u0101pana&quot; \u2014 \u0431\u043E\u043B\u0435\u0435 \u043A\u0430\u0432\u0435\u0440\u0437\u043D\u043E\u0435 \u0441\u043B\u043E\u0432\u043E, \u0438 \u0435\u0441\u043B\u0438 \u0432\u044B \u043F\u0435\u0440\u0435\u0432\u0435\u0434\u0435\u0442\u0435 \u0435\u0433\u043E \u043F\u0440\u043E\u0441\u0442\u043E \u043A\u0430\u043A &quot;\u0443\u043D\u0438\u0447\u0442\u043E\u0436\u0435\u043D\u0438\u0435, \u0441\u043C\u0435\u0440\u0442\u044C \u0438 \u0442.\u043F.&quot;, \u0432\u0430\u0448 \u043F\u0435\u0440\u0435\u0432\u043E\u0434 \u043D\u0435 \u0431\u0443\u0434\u0435\u0442 \u043E\u0447\u0435\u043D\u044C \u0445\u043E\u0440\u043E\u0448\u0438\u043C. \u041F\u0440\u0430\u0432\u0438\u043B\u044C\u043D\u043E\u0435 \u0437\u043D\u0430\u0447\u0435\u043D\u0438\u0435 \u044D\u0442\u0438\u0445 \u0442\u0435\u0440\u043C\u0438\u043D\u043E\u0432 \u0432 \u044D\u0442\u043E\u043C \u043A\u043E\u043D\u0442\u0435\u043A\u0441\u0442\u0435, \u0441\u043E\u0433\u043B\u0430\u0441\u043D\u043E \u0432\u0435\u043B\u0438\u043A\u0438\u043C \u0443\u0447\u0435\u043D\u044B\u043C, \u0431\u0443\u0434\u0435\u0442 &quot;\u0432\u043D\u0435\u0448\u043D\u0435\u0435 \u043F\u0440\u043E\u044F\u0432\u043B\u0435\u043D\u0438\u0435&quot; \u0438 &quot;\u0432\u043D\u0443\u0442\u0440\u0435\u043D\u043D\u0435\u0435 \u043F\u043E\u0433\u043B\u043E\u0449\u0435\u043D\u0438\u0435&quot;. \u0418\u0442\u0430\u043A, \u043C\u043E\u0439 \u0441\u043E\u0432\u0435\u0442 \u0441\u0430\u043D\u0441\u043A\u0440\u0438\u0442\u0441\u043A\u0438\u043C \u0441\u0442\u0443\u0434\u0435\u043D\u0442\u0430\u043C \u0432\u0441\u0435\u0433\u0434\u0430 \u0442\u0430\u043A\u043E\u0432: &quot;\u043F\u043E\u043B\u0443\u0447\u0438\u0442\u044C \u043A\u043E\u043C\u043C\u0435\u043D\u0442\u0430\u0440\u0438\u0438 \u043F\u0435\u0440\u0435\u0434 \u043D\u0430\u0447\u0430\u043B\u043E\u043C \u043F\u0435\u0440\u0435\u0432\u043E\u0434\u0430&quot;.</p><p>\u041A\u043E\u043D\u0435\u0447\u043D\u043E, \u0438\u043D\u043E\u0433\u0434\u0430 \u043D\u0435\u0442 \u043A\u043E\u043C\u043C\u0435\u043D\u0442\u0430\u0440\u0438\u0435\u0432 \u043F\u043E\u0434 \u0440\u0443\u043A\u043E\u0439, \u0438 \u0432\u044B \u0430\u0431\u0441\u043E\u043B\u044E\u0442\u043D\u043E &quot;\u0441\u0430\u043C\u0438 \u043F\u043E \u0441\u0435\u0431\u0435&quot; (\u043D\u0430\u043F\u0440\u0438\u043C\u0435\u0440, \u0442\u0430\u043A \u0431\u044B\u043B\u043E \u0441\u043E \u043C\u043D\u043E\u0439 \u043F\u0440\u0438 \u043F\u0435\u0440\u0435\u0432\u043E\u0434\u0435 Netroddyota, Svacchandoddyota, \u0438 \u0442.\u0434. , \u043A\u043E\u0433\u0434\u0430 \u043D\u0430\u0434\u043E \u0431\u044B\u043B\u043E \u043F\u0440\u043E\u043B\u0438\u0442\u044C \u0431\u043E\u043B\u044C\u0448\u0435 \u0441\u0432\u0435\u0442\u0430 \u043F\u043E \u043E\u043F\u0440\u0435\u0434\u0435\u043B\u0435\u043D\u043D\u043E\u043C\u0443 \u043F\u0440\u0435\u0434\u043C\u0435\u0442\u0443). \u0412 \u044D\u0442\u043E\u043C \u0441\u043B\u0443\u0447\u0430\u0435, \u043D\u0430\u0434\u043E \u0432\u0441\u0435\u0433\u0434\u0430 \u0432\u0432\u0435\u0440\u044F\u0442\u044C \u0441\u0435\u0431\u044F \u0411\u043E\u0433\u0443, \u043F\u043E\u0442\u043E\u043C\u0443 \u0447\u0442\u043E \u044D\u0442\u043E \u043F\u043E\u043B\u043E\u0436\u0435\u043D\u0438\u0435 (\u0431\u0435\u0437 \u043A\u043E\u043C\u043C\u0435\u043D\u0442\u0430\u0440\u0438\u0435\u0432) \u0441\u043E\u0432\u0435\u0440\u0448\u0435\u043D\u043D\u043E \u043D\u0435 \u043F\u0440\u0438\u0432\u043B\u0435\u043A\u0430\u0442\u0435\u043B\u044C\u043D\u043E\u0435. \u0422\u0435\u043A\u0441\u0442\u044B \u0442\u0430\u043A\u0438\u0445 \u043C\u0443\u0434\u0440\u0435\u0446\u043E\u0432, \u043A\u0430\u043A Abhinavagupta, K\u1E63emar\u0101ja \u0438 \u0442.\u0434. \u0441 \u043B\u0435\u0433\u043A\u043E\u0441\u0442\u044C\u044E \u043C\u043E\u0433\u0443\u0442 &quot;\u0440\u0430\u0437\u043C\u0430\u0437\u0430\u0442\u044C \u043F\u043E \u043F\u043E\u043B\u0443&quot; \u043B\u044E\u0431\u043E\u0433\u043E \u0441\u0430\u043D\u0441\u043A\u0440\u0438\u0442\u0441\u043A\u043E\u0433\u043E \u0441\u0442\u0443\u0434\u0435\u043D\u0442\u0430, \u043D\u0430\u0447\u0438\u043D\u0430\u044E\u0449\u0435\u0433\u043E \u0438\u043B\u0438 \u0434\u0430\u0436\u0435 \u0441\u0440\u0435\u0434\u043D\u0435\u0433\u043E \u0443\u0440\u043E\u0432\u043D\u044F. \u0418 \u0431\u0443\u0434\u044C\u0442\u0435 \u0443\u0432\u0435\u0440\u0435\u043D\u044B, \u0447\u0442\u043E \u043F\u0440\u043E\u0434\u0432\u0438\u043D\u0443\u0442\u044B\u043C \u0443\u0447\u0435\u043D\u0438\u043A\u0430\u043C \u043D\u0435\u043E\u0431\u0445\u043E\u0434\u0438\u043C\u043E \u0438\u043C\u0435\u0442\u044C \u0431\u043E\u043B\u044C\u0448\u043E\u0435 \u043A\u043E\u043B\u0438\u0447\u0435\u0441\u0442\u0432\u043E \u0437\u043D\u0430\u043D\u0438\u0439 \u0432 \u0422\u0440\u0438\u043A\u0435 \u043F\u043B\u044E\u0441 \u043D\u0435\u043A\u043E\u0442\u043E\u0440\u044B\u0435 \u043A\u043E\u043C\u043C\u0435\u043D\u0442\u0430\u0440\u0438\u0438 \u0432 \u043A\u0430\u0447\u0435\u0441\u0442\u0432\u0435 \u043F\u043E\u0434\u0434\u0435\u0440\u0436\u043A\u0438, \u0435\u0441\u043B\u0438 \u043E\u043D\u0438 \u0445\u043E\u0442\u044F\u0442 \u0438\u043C\u0435\u0442\u044C \u0443\u0434\u0430\u0447\u043D\u044B\u0439 \u0434\u0435\u043D\u044C. \u041D\u0430 \u0441\u0430\u043C\u043E\u043C \u0434\u0435\u043B\u0435, \u043D\u0435\u043A\u043E\u0442\u043E\u0440\u044B\u0435 \u041F\u0438\u0441\u0430\u043D\u0438\u044F Abhinavagupta (\u0435\u0441\u043B\u0438 \u043D\u0435 \u0432\u0441\u0435!) \u043D\u0443\u0436\u0434\u0430\u044E\u0442\u0441\u044F \u0432 \u0433\u0440\u0443\u043F\u043F\u0435 \u0443\u0447\u0435\u043D\u044B\u0445 \u0434\u043B\u044F \u0442\u043E\u0433\u043E, \u0447\u0442\u043E\u0431\u044B \u0441\u0434\u0435\u043B\u0430\u0442\u044C \u0445\u043E\u0440\u043E\u0448\u0438\u0439 \u043F\u0435\u0440\u0435\u0432\u043E\u0434. \u0412\u043E\u0442 \u043F\u043E\u0447\u0435\u043C\u0443 \u044F \u0432\u0441\u0435\u0433\u0434\u0430 \u043F\u043E\u0431\u0430\u0438\u0432\u0430\u044E\u0441\u044C Abhinavagupta \u0438 \u0435\u0433\u043E \u0443\u0447\u0435\u043D\u0438\u0439. \u0412\u043D\u0435 \u0432\u0441\u044F\u043A\u043E\u0433\u043E \u0441\u043E\u043C\u043D\u0435\u043D\u0438\u044F, \u043E\u043D\u0438 \u043C\u043E\u0433\u0443\u0442 \u0441 \u043B\u0435\u0433\u043A\u043E\u0441\u0442\u044C\u044E \u043F\u043E\u0442\u043E\u043F\u0438\u0442\u044C \u043C\u043E\u044E \u043C\u0430\u043B\u0435\u043D\u044C\u043A\u0443\u044E \u043B\u043E\u0434\u043A\u0443.</p><ol start="2"><li>\u0416\u0438\u0437\u043D\u0435\u043D\u043D\u0430\u044F \u044D\u043D\u0435\u0440\u0433\u0438\u044F \u0432 \u0446\u0435\u043B\u043E\u043C \u043D\u0430\u0437\u044B\u0432\u0430\u0435\u0442\u0441\u044F &quot;pr\u0101\u1E47a&quot;. \u041D\u043E \u044D\u0442\u043E \u043F\u043E\u043D\u044F\u0442\u0438\u0435 \u0440\u0430\u0437\u0434\u0435\u043B\u0435\u043D\u043E \u043D\u0430 \u0434\u0435\u0441\u044F\u0442\u044C \u043A\u0430\u0442\u0435\u0433\u043E\u0440\u0438\u0439, \u043F\u044F\u0442\u044C \u0438\u0437 \u043A\u043E\u0442\u043E\u0440\u044B\u0445 \u2014 \u0433\u043B\u0430\u0432\u043D\u044B\u0435, \u0434\u0440\u0443\u0433\u0438\u0435 \u043F\u044F\u0442\u044C \u2014 \u0432\u0442\u043E\u0440\u043E\u0441\u0442\u0435\u043F\u0435\u043D\u043D\u044B\u0435. \u041F\u0440\u043E\u0431\u043B\u0435\u043C\u0430 \u0437\u0430\u043A\u043B\u044E\u0447\u0430\u0435\u0442\u0441\u044F \u0432 \u0442\u043E\u043C, \u0447\u0442\u043E \u043E\u0434\u043D\u0430 \u0438\u0437 \u044D\u0442\u0438\u0445 \u043A\u0430\u0442\u0435\u0433\u043E\u0440\u0438\u0439 (\u043E\u0442\u043D\u043E\u0441\u044F\u0449\u0430\u044F\u0441\u044F \u043A \u043F\u044F\u0442\u0438 \u0433\u043B\u0430\u0432\u043D\u044B\u043C) \u0438\u043C\u0435\u0435\u0442 \u0442\u043E \u0436\u0435 \u0441\u0430\u043C\u043E\u0435 \u043D\u0430\u0437\u0432\u0430\u043D\u0438\u0435, \u0442.\u0435. &quot;pr\u0101\u1E47a&quot;. \u041E\u0447\u0435\u043D\u044C \u0447\u0430\u0441\u0442\u043E, \u043B\u044E\u0434\u0438 \u043F\u0440\u0438\u043D\u0438\u043C\u0430\u044E\u0442 \u044D\u0442\u0443 \u043A\u0430\u0442\u0435\u0433\u043E\u0440\u0438\u044E \u0437\u0430 pr\u0101\u1E47a, \u0438\u043B\u0438 \u0436\u0438\u0437\u043D\u0435\u043D\u043D\u0443\u044E \u044D\u043D\u0435\u0440\u0433\u0438\u044E &quot;\u0432 \u0446\u0435\u043B\u043E\u043C&quot;. \u041E\u0434\u0438\u043D \u0438\u0437 \u0441\u043F\u043E\u0441\u043E\u0431\u043E\u0432 \u043E\u0431\u043E\u0439\u0442\u0438 \u044D\u0442\u0443 \u043F\u0443\u0442\u0430\u043D\u0438\u0446\u0443 \u2014 \u043D\u0430\u0437\u0432\u0430\u0442\u044C \u0436\u0438\u0437\u043D\u0435\u043D\u043D\u0443\u044E \u044D\u043D\u0435\u0440\u0433\u0438\u044E Pr\u0101\u1E47a (\u0441 \u0437\u0430\u0433\u043B\u0430\u0432\u043D\u043E\u0439 \u043D\u0430\u0447\u0430\u043B\u044C\u043D\u043E\u0439 \u0431\u0443\u043A\u0432\u043E\u0439 &quot;p&quot;), \u0430 \u043A\u0430\u0442\u0435\u0433\u043E\u0440\u0438\u044E pr\u0101\u1E47a (\u0441\u043E \u0441\u0442\u0440\u043E\u0447\u043D\u043E\u0439 \u043D\u0430\u0447\u0430\u043B\u044C\u043D\u043E\u0439 \u0431\u0443\u043A\u0432\u043E\u0439 &quot;p&quot;), \u0438\u043B\u0438 \u0436\u0435 \u043D\u0430\u0437\u044B\u0432\u0430\u0442\u044C \u0436\u0438\u0437\u043D\u0435\u043D\u043D\u0443\u044E \u044D\u043D\u0435\u0440\u0433\u0438\u044E \u0432 \u0446\u0435\u043B\u043E\u043C \u043A\u0430\u043A &quot;mah\u0101pr\u0101\u1E47a&quot; (\u0432\u0435\u043B\u0438\u043A\u0430\u044F pr\u0101\u1E47a) \u0438 \u043E\u0441\u0442\u0430\u0432\u0438\u0442\u044C \u0441\u043B\u043E\u0432\u043E &quot;pr\u0101\u1E47a&quot; \u0434\u043B\u044F \u043F\u0440\u043E\u0441\u0442\u043E\u0439 \u043A\u0430\u0442\u0435\u0433\u043E\u0440\u0438\u0438. \u042D\u0442\u043E \u0442\u0435 \u043C\u0435\u0442\u043E\u0434\u044B, \u043A\u043E\u0442\u043E\u0440\u044B\u0435 \u043E\u0431\u044B\u0447\u043D\u043E \u0438\u0441\u043F\u043E\u043B\u044C\u0437\u0443\u044E\u0442\u0441\u044F, \u0447\u0442\u043E\u0431\u044B \u043E\u0431\u043E\u0439\u0442\u0438 \u043D\u0435\u0431\u043E\u043B\u044C\u0448\u0438\u0435 \u043F\u0440\u0435\u043F\u044F\u0442\u0441\u0442\u0432\u0438\u044F. \u041A\u0430\u043A \u0431\u044B \u0442\u043E \u043D\u0438 \u0431\u044B\u043B\u043E, \u0441\u043B\u043E\u0432\u043E &quot;pr\u0101\u1E47a&quot; \u0432\u043E \u0444\u0440\u0430\u0437\u0435 &quot;Pr\u0101\u1E47\u0101p\u0101namaya\u1E25&quot; \u0432 \u0441\u0442\u0440\u043E\u0444\u0435 \u043D\u0435\u0441\u043E\u043C\u043D\u0435\u043D\u043D\u043E \u043E\u0442\u043D\u043E\u0441\u0438\u0442\u0441\u044F \u043A \u043A\u0430\u0442\u0435\u0433\u043E\u0440\u0438\u0438, \u0430 \u043D\u0435 \u043A &quot;pr\u0101\u1E47a&quot; \u0432 \u0446\u0435\u043B\u043E\u043C. \u0422\u0435\u043C \u043D\u0435 \u043C\u0435\u043D\u0435\u0435, \u0432\u043E \u0432\u0442\u043E\u0440\u043E\u043C \u0441\u043B\u0443\u0447\u0430\u0435 (\u0442.\u0435. &quot;pr\u0101\u1E47o&quot; \u0432 \u0441\u0442\u0440\u043E\u0444\u0435) \u043E\u0442\u043D\u043E\u0441\u0438\u0442\u0441\u044F \u043A \u0436\u0438\u0437\u043D\u0435\u043D\u043D\u043E\u0439 \u044D\u043D\u0435\u0440\u0433\u0438\u0438 &quot;\u0432 \u0446\u0435\u043B\u043E\u043C&quot;.</li></ol><p>\u0412 \u0441\u0432\u043E\u044E \u043E\u0447\u0435\u0440\u0435\u0434\u044C, \u043A\u0430\u0442\u0435\u0433\u043E\u0440\u0438\u0438 &quot;pr\u0101\u1E47a&quot; \u0438 &quot;ap\u0101na&quot; \u2014 \u044D\u0442\u043E \u0434\u0432\u0435 \u0436\u0438\u0437\u043D\u0435\u043D\u043D\u044B\u0435 \u044D\u043D\u0435\u0440\u0433\u0438\u0438, \u043E\u0434\u043D\u0430 \u043F\u0440\u043E\u0445\u043E\u0434\u0438\u0442 \u0447\u0435\u0440\u0435\u0437 \u0432\u044B\u0434\u043E\u0445, \u0430 \u0434\u0440\u0443\u0433\u0430\u044F\u2014 \u0447\u0435\u0440\u0435\u0437 \u0432\u0434\u043E\u0445, \u0441\u043E\u043E\u0442\u0432\u0435\u0442\u0441\u0442\u0432\u0435\u043D\u043D\u043E. \u0421\u043B\u0435\u0434\u043E\u0432\u0430\u0442\u0435\u043B\u044C\u043D\u043E, \u0441\u0442\u0440\u043E\u0444\u0430 \u0443\u0442\u043E\u0447\u043D\u044F\u0435\u0442 &quot;\u0432 \u043A\u0430\u0436\u0434\u043E\u043C&quot; (prati).</p><p>\u0425\u043E\u0442\u044F K\u1E63emar\u0101ja \u043D\u0435 \u0443\u043F\u043E\u043C\u0438\u043D\u0430\u043B \u044D\u0442\u043E\u0433\u043E \u0437\u0434\u0435\u0441\u044C, \u044F \u043C\u043E\u0433\u0443 \u043F\u043E\u043A\u0430\u0437\u0430\u0442\u044C \u0443\u0442\u0432\u0435\u0440\u0436\u0434\u0435\u043D\u0438\u0435, \u0441\u043B\u0435\u0434\u0443\u044E\u0449\u0435\u0435 \u0437\u0430 \u0441\u0442\u0440\u043E\u0444\u043E\u0439, \u043F\u0440\u043E\u0446\u0438\u0442\u0438\u0440\u043E\u0432\u0430\u043D\u043D\u043E\u0439 \u0432 Svacchandatantra, \u043A\u043E\u0442\u043E\u0440\u043E\u0435 \u0437\u0430\u0432\u0435\u0440\u0448\u0430\u0435\u0442 \u0441\u043C\u044B\u0441\u043B: &quot;\u092A\u094D\u0930\u093E\u0923\u0928\u0902 \u0915\u0941\u0930\u0941\u0924\u0947 \u092F\u0938\u094D\u092E\u093E\u0924\u094D\u0924\u0938\u094D\u092E\u093E\u0924\u094D\u092A\u094D\u0930\u093E\u0923\u0903 \u092A\u094D\u0930\u0915\u0940\u0930\u094D\u0924\u093F\u0924\u0903\u0964&quot; - &quot;Pr\u0101\u1E47ana\u1E41 kurute yasm\u0101ttasm\u0101tpr\u0101\u1E47a\u1E25 prak\u012Brtita\u1E25|&quot; - &quot;\u041F\u043E\u0441\u043A\u043E\u043B\u044C\u043A\u0443 \u044D\u0442\u043E \u0434\u0430\u0435\u0442 \u0436\u0438\u0437\u043D\u044C, \u0441\u043B\u0435\u0434\u043E\u0432\u0430\u0442\u0435\u043B\u044C\u043D\u043E \u044D\u0442\u043E \u043D\u0430\u0437\u044B\u0432\u0430\u0435\u0442\u0441\u044F pr\u0101\u1E47a --\u0431\u0443\u043A\u0432. \u0434\u044B\u0445\u0430\u043D\u0438\u0435 \u0436\u0438\u0437\u043D\u0438--&quot;.</p><p>\u0422\u0435\u043F\u0435\u0440\u044C, \u044F \u043F\u043E\u043B\u0430\u0433\u0430\u044E, \u0432\u0441\u0435 \u043A\u0440\u0438\u0441\u0442\u0430\u043B\u044C\u043D\u043E \u044F\u0441\u043D\u043E.</p><ol start="3"><li>\u042F \u043C\u043E\u0433 \u0431\u044B \u043E\u0431\u044A\u0441\u043D\u0438\u0442\u044C \u044D\u0442\u043E \u0441\u0430\u043C, \u043D\u043E \u044F \u043F\u0440\u043E\u0446\u0438\u0442\u0438\u0440\u0443\u044E Svacchandoddyota (\u043D\u0430\u0443\u0447\u043D\u044B\u0439 \u043A\u043E\u043C\u043C\u0435\u043D\u0442\u0430\u0440\u0438\u0439 K\u1E63emar\u0101ja \u043D\u0430 Svacchandatantra), \u0447\u0442\u043E\u0431\u044B \u0432\u044B \u043F\u043E\u043B\u0443\u0447\u0438\u043B\u0438 \u043E\u0431\u044A\u044F\u0441\u043D\u0435\u043D\u0438\u0435 \u043D\u0430\u043F\u0440\u044F\u043C\u0443\u044E \u0438\u0437 \u0430\u0432\u0442\u043E\u0440\u0438\u0442\u0435\u0442\u043D\u043E\u0433\u043E \u0438\u0441\u0442\u043E\u0447\u043D\u0438\u043A\u0430. \u041D\u0435\u0441\u043C\u043E\u0442\u0440\u044F \u043D\u0430 \u0442\u043E, \u0447\u0442\u043E \u044F \u043F\u0440\u043E\u0446\u0438\u0442\u0438\u0440\u0443\u044E \u043E\u0447\u0435\u043D\u044C \u043D\u0435\u0431\u043E\u043B\u044C\u0448\u0443\u044E \u0447\u0430\u0441\u0442\u044C, \u0432\u0441\u0442\u0440\u0435\u0447\u0430\u044E\u0449\u0443\u044E\u0441\u044F \u0432 \u043D\u0430\u0447\u0430\u043B\u0435 \u0432\u0441\u0435\u0433\u043E \u043A\u043E\u043C\u043C\u0435\u043D\u0442\u0430\u0440\u0438\u044F, \u043D\u0430\u043F\u0438\u0441\u0430\u043D\u043D\u043E\u0433\u043E \u043C\u0443\u0434\u0440\u0435\u0446\u043E\u043C, \u043C\u043D\u0435 \u0432\u0441\u0435 \u0440\u0430\u0432\u043D\u043E \u043D\u0435\u043E\u0431\u0445\u043E\u0434\u0438\u043C\u043E \u043E\u0431\u044A\u044F\u0441\u043D\u044F\u0442\u044C \u044D\u0442\u043E!:</li></ol><p>&quot;\u092F\u094B\u093D\u092F\u0902 \u0939\u0932\u093E\u0915\u0943\u0924\u093F\u0930\u0928\u091A\u094D\u0915\u094B \u0939\u0915\u093E\u0930\u094B\u093D\u0928\u093E\u0939\u0924\u0927\u094D\u0935\u0928\u094D\u092F\u093E\u0924\u094D\u092E\u093E&quot; - &quot;Yo&#39;ya\u1E41 hal\u0101k\u1E5Btiranacko hak\u0101ro&#39;n\u0101hatadhvany\u0101tm\u0101&quot; - &quot;\u0422\u043E, \u0447\u0442\u043E \u0438\u043C\u0435\u0435\u0442 \u0444\u043E\u0440\u043C\u0443 \u043F\u043B\u0443\u0433\u0430, [\u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F] \u0431\u0443\u043A\u0432\u043E\u0439 &#39;ha&#39;, \u043B\u0438\u0448\u0435\u043D\u043D\u043E\u0439 \u0433\u043B\u0430\u0441\u043D\u043E\u0439 [\u0438] \u043F\u0440\u0438\u0440\u043E\u0434\u0430 \u043A\u043E\u0442\u043E\u0440\u043E\u0439 \u2014 \u043D\u0435\u043F\u0440\u043E\u0438\u0437\u0432\u0435\u0434\u0435\u043D\u043D\u044B\u0439 \u0437\u0432\u0443\u043A&quot;.</p><p>\u0425\u043E\u0440\u043E\u0448\u043E! \u041D\u0443, \u0432\u0435\u043B\u0438\u043A\u0438\u0439 \u0433\u0440\u0430\u043C\u043C\u0430\u0442\u0438\u0441\u0442 P\u0101\u1E47ini \u0441\u043E\u0437\u0434\u0430\u043B \u0442\u0435\u0445\u043D\u0438\u0447\u0435\u0441\u043A\u0438\u0439 \u0442\u0435\u0440\u043C\u0438\u043D \u0434\u043B\u044F \u043E\u0431\u043E\u0437\u043D\u0430\u0447\u0435\u043D\u0438\u044F \u0432\u0441\u0435\u0445 \u0438\u043B\u0438 \u043B\u044E\u0431\u044B\u0445 \u0433\u043B\u0430\u0441\u043D\u044B\u0445 : &quot;ac&quot;. \u0422\u0430\u043A, &quot;anacka&quot; \u043E\u0437\u043D\u0430\u0447\u0430\u0435\u0442 &quot;\u043B\u044E\u0431\u043E\u0439 \u0441\u043E\u0433\u043B\u0430\u0441\u043D\u044B\u0439 \u0431\u0435\u0437 \u0433\u043B\u0430\u0441\u043D\u043E\u0439, \u0442.\u0435. \u0438\u0437\u043E\u043B\u0438\u0440\u043E\u0432\u0430\u043D\u043D\u044B\u0439&quot;. \u041A\u0430\u043A \u044F\u0432\u0441\u0442\u0432\u0443\u0435\u0442 \u0438\u0437 \u043F\u0440\u043E\u0441\u0442\u043E\u0433\u043E \u0432\u0438\u0434\u0435\u043D\u0438\u044F &#39;h&#39; (\u0442.\u0435. &#39;ha&#39; \u0441 \u043F\u0440\u043E\u043F\u0443\u0449\u0435\u043D\u043D\u043E\u0439 \u0433\u043B\u0430\u0441\u043D\u043E\u0439 &#39;a&#39;) \u0432 \u0441\u0430\u043D\u0441\u043A\u0440\u0438\u0442\u0435 \u2014\u0441\u043C\u043E\u0442\u0440\u0438\u0442\u0435!: &quot;\u0939\u094D&quot; - &quot;h&quot;\u2014, \u044D\u0442\u0430 \u0431\u0443\u043A\u0432\u0430 \u0438\u043C\u0435\u0435\u0442 \u0444\u043E\u0440\u043C\u0443 \u043F\u043B\u0443\u0433\u0430. \u041D\u043E \u0432\u0441\u0435 \u043D\u0435 \u0442\u0430\u043A \u043F\u0440\u043E\u0441\u0442\u043E, \u043F\u043E\u0442\u043E\u043C\u0443 \u0447\u0442\u043E \u0438\u043C\u0435\u0435\u0442\u0441\u044F \u0434\u0440\u0443\u0433\u043E\u0439 \u0441\u043F\u043E\u0441\u043E\u0431 \u043F\u0440\u043E\u0447\u0442\u0435\u043D\u0438\u044F &quot;hal\u0101k\u1E5Bti&quot; (\u0438\u043C\u0435\u044E\u0449\u0438\u0439 \u0444\u043E\u0440\u043C\u0443 \u043F\u043B\u0443\u0433\u0430). \u0412\u043C\u0435\u0441\u0442\u043E \u0442\u043E\u0433\u043E, \u0447\u0442\u043E\u0431\u044B \u0440\u0430\u0441\u0441\u043C\u0430\u0442\u0440\u0438\u0432\u0430\u0442\u044C \u044D\u0442\u043E \u043A\u0430\u043A \u0441\u0444\u043E\u0440\u043C\u0438\u0440\u043E\u0432\u0430\u043D\u043D\u043E\u0435 \u0438\u0437 &quot;hala + \u0101k\u1E5Bti&quot; - &quot;\u043F\u043B\u0443\u0433 + \u0444\u043E\u0440\u043C\u0430&quot;, \u044D\u0442\u043E \u043C\u043E\u0436\u0435\u0442 \u0440\u0430\u0441\u0441\u043C\u0430\u0442\u0440\u0438\u0432\u0430\u0442\u044C\u0441\u044F \u043A\u0430\u043A \u0441\u043E\u0441\u0442\u043E\u044F\u0449\u0435\u0435 \u0438\u0437 &quot;hal + \u0101k\u1E5Bti&quot;. \u0412 \u044D\u0442\u043E\u043C \u0441\u043B\u0443\u0447\u0430\u0435, &quot;hal&quot; \u2014 \u0442\u0435\u0445\u043D\u0438\u0447\u0435\u0441\u043A\u0438\u0439 \u0442\u0435\u0440\u043C\u0438\u043D, \u0441\u043E\u0437\u0434\u0430\u043D\u043D\u044B\u0439 P\u0101\u1E47ini, \u0434\u043B\u044F \u043E\u0431\u043E\u0437\u043D\u0430\u0447\u0435\u043D\u0438\u044F \u0432\u0441\u0435\u0445 \u0438\u043B\u0438 \u043B\u044E\u0431\u044B\u0445 \u0441\u043E\u0433\u043B\u0430\u0441\u043D\u044B\u0445. \u0422\u043E\u0433\u0434\u0430, \u043F\u0435\u0440\u0435\u0432\u043E\u0434 \u044D\u0442\u043E\u0439 \u043C\u0430\u043B\u0435\u043D\u044C\u043A\u043E\u0439 \u0447\u0430\u0441\u0442\u0438 \u0432 Svacchandoddyota \u043C\u0435\u043D\u044F\u0435\u0442\u0441\u044F \u043D\u0430:</p><p>&quot;[\u0412\u044B\u0440\u0430\u0436\u0435\u043D\u0438\u0435] &#39;hak\u0101ra&#39; [\u0432 \u0441\u0442\u0440\u043E\u0444\u0435, \u0443\u043A\u0430\u0437\u044B\u0432\u0430\u0435\u0442] \u043D\u0430 \u0442\u043E, \u0447\u0442\u043E \u0438\u043C\u0435\u0435\u0442 \u0444\u043E\u0440\u043C\u0443 \u0441\u043E\u0433\u043B\u0430\u0441\u043D\u043E\u0433\u043E [&#39;ha&#39;], \u043D\u043E \u0431\u0435\u0437 \u0433\u043B\u0430\u0441\u043D\u043E\u0433\u043E, \u0438 \u0447\u044C\u044F \u0444\u043E\u0440\u043C\u0430 \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u043D\u0435\u043F\u0440\u043E\u0438\u0437\u0432\u0435\u0434\u0435\u043D\u043D\u044B\u043C \u0437\u0432\u0443\u043A\u043E\u043C&quot;.</p><p>\u0418 \u044D\u0442\u0430 \u043F\u0440\u0438\u0440\u043E\u0434\u0430 \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F &quot;\u043D\u0435\u043F\u0440\u043E\u0438\u0437\u0432\u0435\u0434\u0435\u043D\u043D\u044B\u043C&quot; \u0437\u0432\u0443\u043A\u043E\u043C, \u043F\u043E\u0442\u043E\u043C\u0443 \u0447\u0442\u043E \u044D\u0442\u043E\u0442 \u0437\u0432\u0443\u043A \u0441\u043E\u0437\u0434\u0430\u0435\u0442\u0441\u044F \u0435\u0441\u0442\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u044B\u043C \u043E\u0431\u0440\u0430\u0437\u043E\u043C \u043F\u0443\u0442\u0435\u043C \u0432\u0434\u044B\u0445\u0430\u043D\u0438\u044F, \u0431\u0435\u0437 \u043D\u0435\u043E\u0431\u0445\u043E\u0434\u0438\u043C\u043E\u0441\u0442\u0438 \u043E\u0431\u044A\u0435\u043A\u0442\u043E\u0432 \u0443\u0434\u0430\u0440\u044F\u0442\u044C\u0441\u044F \u0438\u043B\u0438 \u0431\u0438\u0442\u044C\u0441\u044F \u0434\u0440\u0443\u0433 \u043E\u0431 \u0434\u0440\u0443\u0433\u0430. \u0423 \u0432\u0441\u0435\u0445 \u0436\u0438\u0432\u044B\u0445 \u0441\u0443\u0449\u0435\u0441\u0442\u0432 \u0438\u0445 \u0434\u044B\u0445\u0430\u043D\u0438\u0435 \u043F\u0440\u043E\u0434\u043E\u043B\u0436\u0430\u0435\u0442\u0441\u044F \u0441\u043F\u043E\u043D\u0442\u0430\u043D\u043D\u043E \u0438 \u043D\u0435\u043F\u0440\u0435\u0440\u044B\u0432\u043D\u043E \u0441\u043E \u0437\u0432\u0443\u043A\u0430\u043C\u0438 &quot;ha&quot; \u0438 &quot;sa&quot; \u043F\u0440\u0438 \u043A\u0430\u0436\u0434\u043E\u043C \u0432\u0434\u043E\u0445\u0435 \u0438 \u0432\u044B\u0434\u043E\u0445\u0435. \u042D\u0442\u043E\u0442 \u043F\u0440\u043E\u0446\u0435\u0441\u0441 \u043F\u0440\u043E\u0438\u0441\u0445\u043E\u0434\u0438\u0442 \u0441\u0430\u043C \u043F\u043E \u0441\u0435\u0431\u0435, \u0430\u0432\u0442\u043E\u043C\u0430\u0442\u0438\u0447\u0435\u0441\u043A\u0438.</p></div><div class="stanza"><a href="#s3.44" id="s3.44" class="num">3.44</a><div class="sans"><p>\u0905\u0924\u0936\u094D\u091A \u0938\u094D\u0925\u093F\u0924\u0947\u093D\u092A\u093F \u0928\u0948\u0938\u0930\u094D\u0917\u093F\u0915\u0947 \u092A\u094D\u0930\u093E\u0923\u0938\u092E\u094D\u092C\u0928\u094D\u0927\u0947 \u092F\u0938\u094D\u0924\u0926\u093E\u0930\u0942\u0922 \u0906\u0928\u094D\u0924\u0930\u0940\u0902 \u0915\u0932\u093E\u0902 \u0935\u093F\u092E\u0943\u0936\u0928\u094D\u0928\u093E\u0938\u094D\u0924\u0947 \u0938 \u0932\u094B\u0915\u094B\u0924\u094D\u0924\u0930 \u090F\u0935\u0947\u0924\u094D\u092F\u093E\u0939\u2014</p><blockquote><p><strong>\u0928\u093E\u0938\u093F\u0915\u093E\u0928\u094D\u0924\u0930\u094D\u092E\u0927\u094D\u092F\u0938\u0902\u092F\u092E\u093E\u0924\u094D \u0915\u093F\u092E\u0924\u094D\u0930 \u0938\u0935\u094D\u092F\u093E\u092A\u0938\u0935\u094D\u092F\u0938\u094C\u0937\u0941\u092E\u094D\u0928\u0947\u0937\u0941\u0965\u096A\u096A\u0965</strong></p></blockquote><p>\u0938\u0930\u094D\u0935\u0928\u093E\u0921\u0940\u091A\u0915\u094D\u0930\u092A\u094D\u0930\u0927\u093E\u0928\u0930\u0942\u092A\u0947\u0937\u0941 \u0938\u0935\u094D\u092F\u093E\u092A\u0938\u0935\u094D\u092F\u0938\u094C\u0937\u0941\u092E\u094D\u0928\u0947\u0937\u0941 \u0926\u0915\u094D\u0937\u093F\u0923\u0935\u093E\u092E\u092E\u0927\u094D\u092F\u0928\u093E\u0921\u0940\u092A\u0926\u0947\u0937\u0941 \u092F\u093E \u0928\u093E\u0938\u093F\u0915\u093E \u0928\u0938\u0924\u0947 \u0915\u094C\u091F\u093F\u0932\u094D\u092F\u0947\u0928 \u0935\u0939\u0924\u0940\u0924\u093F \u0915\u0943\u0924\u094D\u0935\u093E \u0915\u0941\u091F\u093F\u0932\u0935\u093E\u0939\u093F\u0928\u0940 \u092A\u094D\u0930\u093E\u0923\u0936\u0915\u094D\u0924\u093F\u0938\u094D\u0924\u0938\u094D\u092F\u093E \u0905\u0928\u094D\u0924\u0930\u093F\u0924\u094D\u092F\u093E\u0928\u094D\u0924\u0930\u0940 \u0938\u0902\u0935\u093F\u0924\u094D \u0924\u0938\u094D\u092F\u093E \u0905\u092A\u093F \u092E\u0927\u094D\u092F\u0902 \u0938\u0930\u094D\u0935\u093E\u0928\u094D\u0924\u0930\u0924\u092E\u0924\u092F\u093E \u092A\u094D\u0930\u0927\u093E\u0928\u092E\u094D\u0964</p><blockquote><p>\u0924\u0938\u094D\u092F \u0926\u0947\u0935\u093E\u0924\u093F\u0926\u0947\u0935\u0938\u094D\u092F \u092A\u0930\u092C\u094B\u0927\u0938\u094D\u0935\u0930\u0942\u092A\u093F\u0923\u0903\u0964<br> \u0935\u093F\u092E\u0930\u094D\u0936\u0903 \u092A\u0930\u092E\u093E \u0936\u0915\u094D\u0924\u093F\u0903 \u0938\u0930\u094D\u0935\u091C\u094D\u091E\u093E \u091C\u094D\u091E\u093E\u0928\u0936\u093E\u0932\u093F\u0928\u0940\u0965</p></blockquote><p>\u0907\u0924\u093F \u0936\u094D\u0930\u0940\u0915\u093E\u0932\u093F\u0915\u093E\u0915\u094D\u0930\u092E\u094B\u0915\u094D\u0924\u0928\u0940\u0924\u094D\u092F\u093E \u092F\u0926\u094D\u0935\u093F\u092E\u0930\u094D\u0936\u092E\u092F\u0902 \u0930\u0942\u092A\u0902 \u0924\u0924\u094D\u0938\u0902\u092F\u092E\u093E\u0926\u0928\u094D\u0924\u0930\u094D\u0928\u093F\u092D\u093E\u0932\u0928\u092A\u094D\u0930\u0915\u0930\u094D\u0937\u093E\u0924\u094D\u0915\u093F\u092E\u0924\u094D\u0930\u094B\u091A\u094D\u092F\u0924 \u0905\u092F\u0902 \u0939\u093F \u0938\u0930\u094D\u0935\u0926\u0936\u093E\u0938\u0941 \u0926\u0947\u0926\u0940\u092A\u094D\u092F\u092E\u093E\u0928\u094B \u0928\u093F\u0930\u094D\u0935\u094D\u092F\u0941\u0924\u094D\u0925\u093E\u0928\u0903 \u092A\u0930\u0903 \u0938\u092E\u093E\u0927\u093F\u0903\u0964 \u0924\u0926\u0941\u0915\u094D\u0924\u0902 \u0936\u094D\u0930\u0940\u0935\u093F\u091C\u094D\u091E\u093E\u0928\u092D\u0948\u0930\u0935\u0947</p><blockquote><p>\u0917\u094D\u0930\u093E\u0939\u094D\u092F\u0917\u094D\u0930\u093E\u0939\u0915\u0938\u0902\u0935\u093F\u0924\u094D\u0924\u093F\u0903 \u0938\u093E\u092E\u093E\u0928\u094D\u092F\u093E \u0938\u0930\u094D\u0935\u0926\u0947\u0939\u093F\u0928\u093E\u092E\u094D\u0964<br> \u092F\u094B\u0917\u093F\u0928\u093E\u0902 \u0924\u0941 \u0935\u093F\u0936\u0947\u0937\u094B\u093D\u092F\u0902 \u0938\u092E\u094D\u092C\u0928\u094D\u0927\u0947 \u0938\u093E\u0935\u0927\u093E\u0928\u0924\u093E\u0965</p></blockquote><p>\u0907\u0924\u093F\u0965\u096A\u096A\u0965</p></div><hr><div class="trans"><p>Ata\u015Bca sthite&#39;pi naisargike pr\u0101\u1E47asambandhe yastad\u0101r\u016B\u1E0Dha \u0101ntar\u012B\u1E41 kal\u0101\u1E41 vim\u1E5B\u015Bann\u0101ste sa lokottara evety\u0101ha\u2014</p><blockquote><p><strong>N\u0101sik\u0101ntarmadhyasa\u1E41yam\u0101t kimatra savy\u0101pasavyasau\u1E63umne\u1E63u||44||</strong></p></blockquote><p>Sarvan\u0101\u1E0D\u012Bcakrapradh\u0101nar\u016Bpe\u1E63u savy\u0101pasavyasau\u1E63umne\u1E63u dak\u1E63i\u1E47av\u0101mamadhyan\u0101\u1E0D\u012Bpade\u1E63u y\u0101 n\u0101sik\u0101 nasate kau\u1E6Dilyena vahat\u012Bti k\u1E5Btv\u0101 ku\u1E6Dilav\u0101hin\u012B pr\u0101\u1E47a\u015Baktistasy\u0101 antarity\u0101ntar\u012B sa\u1E41vit tasy\u0101 api madhya\u1E41 sarv\u0101ntaratamatay\u0101 pradh\u0101nam|</p><blockquote><p>Tasya dev\u0101tidevasya parabodhasvar\u016Bpi\u1E47a\u1E25|<br> Vimar\u015Ba\u1E25 param\u0101 \u015Bakti\u1E25 sarvaj\xF1\u0101 j\xF1\u0101na\u015B\u0101lin\u012B||</p></blockquote><p>iti \u015Br\u012Bk\u0101lik\u0101kramoktan\u012Bty\u0101 yadvimar\u015Bamaya\u1E41 r\u016Bpa\u1E41 tatsa\u1E41yam\u0101dantarnibh\u0101lanaprakar\u1E63\u0101tkimatrocyata aya\u1E41 hi sarvada\u015B\u0101su ded\u012Bpyam\u0101no nirvyutth\u0101na\u1E25 para\u1E25 sam\u0101dhi\u1E25| Tadukta\u1E41 \u015Br\u012Bvij\xF1\u0101nabhairave</p><blockquote><p>Gr\u0101hyagr\u0101hakasa\u1E41vitti\u1E25 s\u0101m\u0101ny\u0101 sarvadehin\u0101m|<br> Yogin\u0101\u1E41 tu vi\u015Be\u1E63o&#39;ya\u1E41 sambandhe s\u0101vadh\u0101nat\u0101||</p></blockquote><p>iti||44||</p></div><hr><p>\u0421\u043B\u0435\u0434\u043E\u0432\u0430\u0442\u0435\u043B\u044C\u043D\u043E <em>(atas ca)</em>, \u0432 \u0442\u043E \u0432\u0440\u0435\u043C\u044F, \u043A\u0430\u043A \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u0443\u0435\u0442 \u0435\u0441\u0442\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u0430\u044F \u0441\u0432\u044F\u0437\u044C, \u0438\u043B\u0438 \u0430\u0441\u0441\u043E\u0446\u0438\u0430\u0446\u0438\u044F \u0436\u0438\u0437\u043D\u0435\u043D\u043D\u043E\u0439 \u044D\u043D\u0435\u0440\u0433\u0438\u0438 [\u0441 \u0442\u0435\u043B\u043E\u043C]<em>(sthite api naisargike pr\u0101\u1E47a-sambandhe)</em>, \u0442\u043E\u0442, \u043A\u0442\u043E <em>(ya\u1E25)</em>, \u0431\u0443\u0434\u0443\u0447\u0438 \u0443\u043A\u043E\u0440\u0435\u043D\u0435\u043D\u043D\u044B\u043C <em>(\u0101r\u016B\u1E0Dha\u1E25)</em> \u0432 \u044D\u0442\u043E\u043C --\u0432 \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0438 \u043F\u043E\u0437\u043D\u0430\u044E\u0449\u0435\u0433\u043E, \u043A\u0442\u043E \u0435\u0441\u0442\u044C \u0444\u043E\u0440\u043C\u0430, \u043F\u0440\u0438\u043D\u044F\u0442\u0430\u044F Pr\u0101\u1E47an\u0101, \u0443\u043D\u0438\u0432\u0435\u0440\u0441\u0430\u043B\u044C\u043D\u043E\u0439 \u0436\u0438\u0437\u043D\u0435\u043D\u043D\u043E\u0439 \u044D\u043D\u0435\u0440\u0433\u0438\u0435\u0439-- <em>(tad)</em><sup>1</sup>, \u043F\u0440\u043E\u0434\u043E\u043B\u0436\u0430\u0435\u0442 <em>(\u0101ste)</em> \u043E\u0441\u043E\u0437\u043D\u0430\u0432\u0430\u0442\u044C <em>(vim\u1E5B\u015Ban)</em> \u0432\u043D\u0443\u0442\u0440\u0435\u043D\u043D\u0435\u0435 <em>(\u0101ntar\u012Bm)</em> \u0431\u0435\u0437\u0443\u043F\u0440\u0435\u0447\u043D\u043E\u0435 \u042F-\u0421\u043E\u0437\u043D\u0430\u043D\u0438\u0435 --\u0442.\u0435. \u015Aakti-- <em>(kal\u0101m)</em>, [\u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F] \u044D\u043A\u0441\u0442\u0440\u0430\u043E\u0440\u0434\u0438\u043D\u0430\u0440\u043D\u044B\u043C --\u0442.\u0435. \u043D\u0430\u0445\u043E\u0434\u0438\u0442\u0441\u044F \u0432\u043D\u0435 \u0442\u043E\u0433\u043E, \u0447\u0442\u043E \u043E\u0431\u044B\u0447\u043D\u043E-- <em>(sa\u1E25 loka-uttara\u1E25 eva)</em>. [\u015Aiva] \u0441\u043A\u0430\u0437\u0430\u043B <em>(\u0101ha)</em> \u0442\u0430\u043A <em>(iti)</em> [\u0432 \u0441\u043B\u0435\u0434\u0443\u044E\u0449\u0435\u043C \u0430\u0444\u043E\u0440\u0438\u0437\u043C\u0435]\u2014</p><blockquote><p><strong>[\u0416\u0438\u0437\u043D\u0435\u043D\u043D\u0430\u044F \u044D\u043D\u0435\u0440\u0433\u0438\u044F --pr\u0101\u1E47a\u015Bakti, \u0438\u043B\u0438 pr\u0101\u1E47a-- \u043D\u0430\u0445\u043E\u0434\u0438\u0442\u0441\u044F] \u0432 \u043B\u0435\u0432\u043E\u043C \u0442\u043E\u043D\u043A\u043E\u043C \u043A\u0430\u043D\u0430\u043B\u0435 --I\u1E0D\u0101-- <em>(apasavya)</em>, \u0432 \u043F\u0440\u0430\u0432\u043E\u043C \u0442\u043E\u043D\u043A\u043E\u043C \u043A\u0430\u043D\u0430\u043B\u0435 --Pi\u1E45gal\u0101-- <em>(savya)</em> [\u0438] \u0432 Su\u1E63umn\u0101 --\u0432 \u0441\u0440\u0435\u0434\u043D\u0435\u043C \u043A\u0430\u043D\u0430\u043B\u0435-- <em>(sau\u1E63umne\u1E63u)</em>.</strong></p></blockquote><blockquote><p>\u0411\u043B\u0430\u0433\u043E\u0434\u0430\u0440\u044F \u0438\u043D\u0442\u0435\u043D\u0441\u0438\u0432\u043D\u043E\u043C\u0443 \u0438 \u043F\u043E\u0441\u0442\u043E\u044F\u043D\u043D\u043E\u043C\u0443 \u043E\u0441\u043E\u0437\u043D\u0430\u0432\u0430\u043D\u0438\u044E <em>(sa\u1E41yam\u0101t)</em> \u0446\u0435\u043D\u0442\u0440\u0430 --\u0442.\u0435. \u0441\u043E\u0432\u0435\u0440\u0448\u0435\u043D\u043D\u043E\u0433\u043E \u042F-\u0421\u043E\u0437\u043D\u0430\u043D\u0438\u044F-- <em>(madhya)</em> \u0432\u043D\u0443\u0442\u0440\u0435\u043D\u043D\u0435\u0433\u043E \u0430\u0441\u043F\u0435\u043A\u0442\u0430 <em>(antar)</em> [\u0432\u044B\u0448\u0435\u0443\u043F\u043E\u043C\u044F\u043D\u0443\u0442\u043E\u0439] pr\u0101\u1E47a\u015Bakti <em>(n\u0101sik\u0101)</em>, [Yog\u012B \u043D\u0430\u0432\u0441\u0435\u0433\u0434\u0430 \u043E\u0431\u0440\u0435\u0442\u0430\u0435\u0442 \u043F\u043E\u0441\u0442\u043E\u044F\u043D\u043D\u043E\u0435 \u043E\u0441\u043E\u0437\u043D\u0430\u043D\u0438\u0435 \u0432\u044B\u0441\u0448\u0435\u0433\u043E \u0438 \u0441\u043E\u0432\u0435\u0440\u0448\u0435\u043D\u043D\u043E\u0433\u043E \u042F-\u0421\u043E\u0437\u043D\u0430\u043D\u0438\u044F].</p></blockquote><blockquote><p>\u0427\u0442\u043E \u0435\u0449\u0435 [\u043C\u043E\u0436\u043D\u043E \u0441\u043A\u0430\u0437\u0430\u0442\u044C] <em>(kim)</em> \u043E\u0431 \u044D\u0442\u043E\u043C <em>(atra)</em>?||44||</p></blockquote><p>N\u0101sik\u0101 --pr\u0101\u1E47a\u015Bakti, \u0438\u043B\u0438 pr\u0101\u1E47a-- <em>(y\u0101 n\u0101sik\u0101)</em> [\u043F\u0440\u0435\u0431\u044B\u0432\u0430\u0435\u0442] \u0432 \u0433\u043B\u0430\u0432\u043D\u044B\u0445 \u043A\u0430\u043D\u0430\u043B\u0430\u0445 <em>(pradh\u0101na-r\u016Bpe\u1E63u)</em> \u0433\u0440\u0443\u043F\u043F\u044B <em>(cakra)</em>, [\u0441\u043E\u0441\u0442\u043E\u044F\u0449\u0435\u0439 \u0438\u0437] \u0432\u0441\u0435\u0445 <em>(sarva)</em> \u0442\u043E\u043D\u043A\u0438\u0445 \u043A\u0430\u043D\u0430\u043B\u043E\u0432 <em>(n\u0101\u1E0D\u012B)</em> \u2014\u0432 savya, apasavya \u0438 Su\u1E63umn\u0101 <em>(savya-apasavya-sau\u1E63umne\u1E63u)</em>\u2014, \u0442.\u0435. \u0432 \u043F\u0440\u0430\u0432\u043E\u043C, \u043B\u0435\u0432\u043E\u043C \u0438 \u0441\u0440\u0435\u0434\u0438\u043D\u043D\u043E\u043C \u0442\u043E\u043D\u043A\u0438\u0445 \u043A\u0430\u043D\u0430\u043B\u0430\u0445 <em>(dak\u1E63i\u1E47a-v\u0101ma-madhya-n\u0101\u1E0D\u012B-pade\u1E63u)</em> --\u0438\u0437\u0432\u0435\u0441\u0442\u043D\u044B\u0445 \u043A\u0430\u043A Pi\u1E45gal\u0101, I\u1E0D\u0101 \u0438 Su\u1E63umn\u0101--, [\u0441\u043E\u043E\u0442\u0432\u0435\u0442\u0441\u0442\u0432\u0435\u043D\u043D\u043E]<sup>2</sup>. [\u0418 &quot;n\u0101sik\u0101&quot; \u2014 \u044D\u0442\u043E] pr\u0101\u1E47a\u015Bakti --\u0438\u043B\u0438 pr\u0101\u1E47a-- <em>(pr\u0101\u1E47a-\u015Bakti\u1E25)</em>, \u0442\u0430, \u043A\u043E\u0442\u043E\u0440\u0430\u044F \u0442\u0435\u0447\u0435\u0442 <em>(v\u0101hin\u012B)</em> \u0437\u0438\u0433\u0437\u0430\u0433\u043E\u043E\u0431\u0440\u0430\u0437\u043D\u043E <em>(ku\u1E6Dila)</em>, \u043F\u043E\u043B\u0430\u0433\u0430\u044F, \u0447\u0442\u043E <em>(iti k\u1E5Btv\u0101)</em> [\u0442\u0435\u0440\u043C\u0438\u043D\u044B &quot;n\u0101sik\u0101&quot; \u0438 &quot;ku\u1E6Dilav\u0101hin\u012B&quot; \u043F\u0440\u043E\u0438\u0441\u0445\u043E\u0434\u044F\u0442 \u0438\u0437 &quot;nasate kau\u1E6Dilyena vahati&quot;, \u0438\u043B\u0438] &quot;\u043E\u043D\u0430 \u0434\u0432\u0438\u0433\u0430\u0435\u0442\u0441\u044F \u0437\u0438\u0433\u0437\u0430\u0433\u043E\u043E\u0431\u0440\u0430\u0437\u043D\u043E <em>(nasate)</em>, \u0430 \u0438\u043C\u0435\u043D\u043D\u043E, \u043E\u043D\u0430 \u0442\u0435\u0447\u0435\u0442 <em>(vahati)</em> \u0437\u0438\u0433\u0437\u0430\u0433\u0430\u043C\u0438 <em>(kau\u1E6Dilyena)</em>&quot;<sup>3</sup>. [\u0421\u043B\u043E\u0432\u043E] &quot;ant\xE1r&quot; <em>(antar iti)</em> [\u043E\u0437\u043D\u0430\u0447\u0430\u0435\u0442] \u0432\u043D\u0443\u0442\u0440\u0435\u043D\u043D\u0438\u0439 \u0430\u0441\u043F\u0435\u043A\u0442 <em>(\u0101ntar\u012B)</em>, [\u0438\u043B\u0438] \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u0435 <em>(sa\u1E41vid)</em> \u044D\u0442\u043E\u0439 [n\u0101sik\u0101] <em>(tasy\u0101\u1E25)</em>. [\u0418] &quot;madhya&quot;, \u0438\u043B\u0438 &quot;\u0446\u0435\u043D\u0442\u0440&quot; <em>(madhyam)</em> \u044D\u0442\u043E\u0433\u043E [\u0432\u043D\u0443\u0442\u0440\u0435\u043D\u043D\u0435\u0433\u043E \u0430\u0441\u043F\u0435\u043A\u0442\u0430 n\u0101sik\u0101] <em>(tasy\u0101\u1E25)</em> \u0442\u0430\u043A\u0436\u0435 <em>(api)</em>, \u0431\u0443\u0434\u0443\u0447\u0438 \u0441\u0430\u043C\u044B\u043C \u0441\u043E\u043A\u0440\u043E\u0432\u0435\u043D\u043D\u044B\u043C <em>(antaratamatay\u0101)</em> \u0432\u0441\u0435\u0433\u043E <em>(sarva)</em>, [\u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F] &quot;Pradh\u0101na&quot;, \u0438\u043B\u0438 &quot;\u0441\u0443\u0449\u043D\u043E\u0441\u0442\u043D\u043E\u0439 \u0420\u0435\u0430\u043B\u044C\u043D\u043E\u0441\u0442\u044C\u044E&quot; --\u043A\u043E\u0440\u043E\u0447\u0435 \u0433\u043E\u0432\u043E\u0440\u044F, \u0431\u0435\u0437\u0443\u043F\u0440\u0435\u0447\u043D\u044B\u043C \u042F-\u0421\u043E\u0437\u043D\u0430\u043D\u0438\u0435\u043C, \u043A\u043E\u0442\u043E\u0440\u043E\u0435 \u0435\u0441\u0442\u044C \u0446\u0435\u043D\u0442\u0440 \u0432\u0441\u0435\u0433\u043E-- <em>(pradh\u0101nam)</em>|</p><blockquote><p>&quot;Vimar\u015Ba --\u042F-\u0421\u043E\u0437\u043D\u0430\u043D\u0438\u0435-- <em>(vimar\u015Ba\u1E25)</em> \u0442\u043E\u0433\u043E \u0411\u043E\u0433\u0430, \u043A\u043E\u0442\u043E\u0440\u044B\u0439 \u043F\u0440\u0435\u0432\u043E\u0441\u0445\u043E\u0434\u0438\u0442 \u0432\u0441\u0435\u0445 \u0434\u0440\u0443\u0433\u0438\u0445 \u0431\u043E\u0433\u043E\u0432 <em>(deva-atidevasya)</em>, [\u0438] \u0447\u044C\u044F \u0441\u0443\u0449\u043D\u043E\u0441\u0442\u043D\u0430\u044F \u043F\u0440\u0438\u0440\u043E\u0434\u0430 <em>(sva-r\u016Bpi\u1E47a\u1E25)</em> \u2014 \u0412\u044B\u0441\u0448\u0435\u0435 <em>(para)</em> \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u0435 <em>(bodha)</em> --\u0442.\u0435. \u044D\u0442\u0438\u043C \u0411\u043E\u0433\u043E\u043C \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u015Aiva, \u0438\u043B\u0438 Prak\u0101\u015Ba--, [\u0435\u0441\u0442\u044C] \u0412\u044B\u0441\u0448\u0430\u044F <em>(param\u0101)</em> \u0421\u0438\u043B\u0430 <em>(\u015Bakti\u1E25)</em>, \u043A\u043E\u0442\u043E\u0440\u0430\u044F \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u0432\u0441\u0435\u0437\u043D\u0430\u044E\u0449\u0435\u0439 <em>(sarvaj\xF1\u0101)</em>, \u0430 \u0438\u043C\u0435\u043D\u043D\u043E, \u043F\u043E\u043B\u043D\u043E\u0439 <em>(\u015B\u0101lin\u012B)</em> \u0437\u043D\u0430\u043D\u0438\u044F <em>(j\xF1\u0101na... iti)</em>&quot;||</p></blockquote><p>\u0418\u0441\u043F\u043E\u043B\u044C\u0437\u0443\u044F \u0442\u043E, \u0447\u0442\u043E \u0431\u044B\u043B\u043E \u0432\u044B\u0440\u0430\u0436\u0435\u043D\u043E \u0432 \u043F\u043E\u0447\u0442\u0435\u043D\u043D\u043E\u043C K\u0101lik\u0101krama \u0432 \u043A\u0430\u0447\u0435\u0441\u0442\u0432\u0435 \u0440\u0443\u043A\u043E\u0432\u043E\u0434\u0441\u0442\u0432\u0430 <em>(\u015Br\u012B-k\u0101lik\u0101krama-ukta-n\u012Bty\u0101)</em>, \u043F\u043E\u0441\u0440\u0435\u0434\u0441\u0442\u0432\u043E\u043C sa\u1E41yama <em>(sa\u1E41yam\u0101t)</em>, [\u0438\u043B\u0438] \u0438\u043D\u0442\u0435\u043D\u0441\u0438\u0432\u043D\u043E\u0441\u0442\u0438 <em>(prakar\u1E63\u0101t)</em> [\u043F\u043E\u0441\u0442\u043E\u044F\u043D\u043D\u043E\u0433\u043E] \u0432\u043D\u0443\u0442\u0440\u0435\u043D\u043D\u0435\u0433\u043E <em>(antar)</em> \u043E\u0441\u043E\u0437\u043D\u0430\u0432\u0430\u043D\u0438\u044F <em>(nibh\u0101lana)</em> \u044D\u0442\u043E\u0439 <em>(tad)</em> \u0441\u0443\u0449\u043D\u043E\u0441\u0442\u043D\u043E\u0439 \u043F\u0440\u0438\u0440\u043E\u0434\u044B <em>(r\u016Bpam)</em>, \u043A\u043E\u0442\u043E\u0440\u043E\u0439 <em>(yad)</em> \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F Vimar\u015Ba --\u042F-\u0421\u043E\u0437\u043D\u0430\u043D\u0438\u0435-- <em>(vimar\u015Ba-mayam)</em>, \u0433\u043E\u0432\u043E\u0440\u0438\u0442\u0441\u044F <em>(ucyate)</em> &quot;kimatra&quot; --\u0432\u043E\u0441\u043A\u043B\u0438\u0446\u0430\u043D\u0438\u0435, \u043F\u043E\u043A\u0430\u0437\u044B\u0432\u0430\u044E\u0449\u0435\u0435 \u0432\u043E\u0441\u0442\u043E\u0440\u0433 \u0438 \u0437\u043D\u0430\u0447\u0435\u043D\u0438\u0435 \u043A\u043E\u0442\u043E\u0440\u043E\u0433\u043E \u2014 &quot;\u0427\u0442\u043E \u0435\u0449\u0435 [\u043C\u043E\u0436\u043D\u043E \u0441\u043A\u0430\u0437\u0430\u0442\u044C] \u0432 \u044D\u0442\u043E\u043C \u043E\u0442\u043D\u043E\u0448\u0435\u043D\u0438\u0438?&quot;-- <em>(kim atra)</em> [\u0432 \u0442\u043E\u043C \u0441\u043C\u044B\u0441\u043B\u0435, \u0447\u0442\u043E \u0432 \u0440\u0435\u0437\u0443\u043B\u044C\u0442\u0430\u0442\u0435 \u0442\u0430\u043A\u043E\u0439 sa\u1E41yama, \u0432\u043E\u0437\u043D\u0438\u043A\u0430\u0435\u0442] \u044D\u0442\u043E <em>(ayam hi)</em> \u0432\u044B\u0441\u0448\u0435\u0435 <em>(para\u1E25)</em> Nirvyutth\u0101nasam\u0101dhi <em>(nirvyutth\u0101na\u1E25... sam\u0101dhi\u1E25)</em>, \u043A\u043E\u0442\u043E\u0440\u043E\u0435 \u0438\u043D\u0442\u0435\u043D\u0441\u0438\u0432\u043D\u043E \u0441\u0438\u044F\u0435\u0442 <em>(ded\u012Bpyam\u0101na\u1E25)</em> \u0432\u043E \u0432\u0441\u0435\u0445 \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u044F\u0445 --\u0442.\u0435. \u043F\u0440\u0438 \u043B\u044E\u0431\u044B\u0445 \u043E\u0431\u0441\u0442\u043E\u044F\u0442\u0435\u043B\u044C\u0441\u0442\u0432\u0430\u0445-- <em>(sarva-da\u015B\u0101su)</em><sup>4</sup>|</p><p>\u0422\u0430\u043A <em>(tad)</em> \u0431\u044B\u043B\u043E \u0437\u0430\u044F\u0432\u043B\u0435\u043D\u043E <em>(uktam)</em> \u0432 \u0443\u0432\u0430\u0436\u0430\u0435\u043C\u043E\u043C Vij\xF1\u0101nabhairava <em>(\u015Br\u012B-vij\xF1\u0101nabhairave)</em>:</p><blockquote><p>&quot;\u0421\u043E\u0437\u043D\u0430\u043D\u0438\u0435 <em>(sa\u1E41vitti\u1E25)</em> \u043E\u0431\u044A\u0435\u043A\u0442\u0430 <em>(gr\u0101hya)</em> [\u0438] \u0441\u0443\u0431\u044A\u0435\u043A\u0442\u0430 <em>(gr\u0101haka)</em> \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u043E\u0431\u0449\u0438\u043C <em>(s\u0101m\u0101ny\u0101)</em> \u0434\u043B\u044F \u0432\u0441\u0435\u0445 \u0432\u043E\u043F\u043B\u043E\u0449\u0435\u043D\u043D\u044B\u0445 <em>(sarva-dehin\u0101m)</em>; \u043D\u043E <em>(tu)</em> \u0432 \u0441\u043B\u0443\u0447\u0430\u0435 Yog\u012B-s <em>(yogin\u0101m)</em> \u0432 \u044D\u0442\u043E\u043C \u0438 <em>(ayam)</em> [\u0435\u0441\u0442\u044C] \u0440\u0430\u0437\u043B\u0438\u0447\u0438\u0435 <em>(vi\u015Be\u1E63a\u1E25)</em>: \u0432\u043D\u0438\u043C\u0430\u043D\u0438\u0435 \u0443\u0434\u0435\u043B\u044F\u0435\u0442\u0441\u044F <em>(sa-avadh\u0101nat\u0101)</em> \u043E\u0442\u043D\u043E\u0448\u0435\u043D\u0438\u044E [\u043C\u0435\u0436\u0434\u0443 \u043E\u0431\u044A\u0435\u043A\u0442\u043E\u043C \u0438 \u0441\u0443\u0431\u044A\u0435\u043A\u0442\u043E\u043C] <em>(sambandhe... iti)</em>&quot;||</p></blockquote><p>||44||</p><hr><ol><li><p>\u042D\u0442\u043E \u043D\u0435 \u043C\u043E\u0435 \u0438\u0437\u043E\u0431\u0440\u0435\u0442\u0435\u043D\u0438\u0435, \u0430 \u0432\u0435\u043B\u0438\u043A\u0438\u0439 \u0443\u0447\u0435\u043D\u044B\u0435 \u043A\u043E\u043C\u043C\u0435\u043D\u0442\u0438\u0440\u0443\u044E\u0442 \u044D\u0442\u043E \u0441\u043B\u043E\u0432\u043E &quot;tad&quot; \u0432 \u0442\u0430\u043A\u043E\u043C \u043A\u043E\u043D\u0442\u0435\u043A\u0441\u0442\u0435. \u041A\u0440\u043E\u043C\u0435 \u0442\u043E\u0433\u043E, \u0432\u044B \u043C\u043E\u0436\u0435\u0442\u0435 \u043B\u0435\u0433\u043A\u043E \u043F\u0440\u043E\u0432\u0435\u0440\u0438\u0442\u044C, \u0447\u0442\u043E \u044D\u0442\u043E \u0443\u0442\u0432\u0435\u0440\u0436\u0434\u0435\u043D\u0438\u0435 \u043F\u043E\u043B\u043D\u043E\u0441\u0442\u044C\u044E \u0441\u043E\u0433\u043B\u0430\u0441\u0443\u0435\u0442\u0441\u044F \u0441 \u0442\u0435\u043C, \u0447\u0442\u043E \u0431\u044B\u043B\u043E \u043F\u043E\u0434\u0442\u0432\u0435\u0440\u0436\u0434\u0435\u043D\u043E \u0432 \u043A\u043E\u043C\u043C\u0435\u043D\u0442\u0430\u0440\u0438\u0438 \u043A \u043F\u0440\u0435\u0434\u044B\u0434\u0443\u0449\u0435\u043C\u0443 \u0430\u0444\u043E\u0440\u0438\u0437\u043C\u0443.</p></li><li><p>\u0427\u0442\u043E\u0431\u044B \u043D\u0435 \u043F\u043E\u043B\u0443\u0447\u0438\u0442\u044C \u0442\u043E\u043B\u043F\u044B \u0441\u0430\u043D\u0441\u043A\u0440\u0438\u0442\u0441\u043A\u0438\u0445 \u0441\u0442\u0443\u0434\u0435\u043D\u0442\u043E\u0432, \u043A\u043E\u0440\u0440\u0435\u043A\u0442\u0438\u0440\u0443\u044E\u0449\u0438\u0445 \u043C\u043E\u0439 \u043F\u0435\u0440\u0435\u0432\u043E\u0434 &quot;savya&quot;\u0438 &quot;apasavya&quot; \u043A\u0430\u043A &quot;\u043F\u0440\u0430\u0432\u044B\u0439&quot; \u0438 &quot;\u043B\u0435\u0432\u044B\u0439&quot;, \u0441\u043E\u043E\u0442\u0432\u0435\u0442\u0441\u0442\u0432\u0435\u043D\u043D\u043E, \u043C\u043D\u0435 \u043D\u0443\u0436\u043D\u043E \u043A\u043E\u0435-\u0447\u0442\u043E \u0441\u043A\u0430\u0437\u0430\u0442\u044C: &quot;\u0414\u0430, \u0432\u044B \u043F\u0440\u0430\u0432\u044B!&quot; \u0415\u0441\u043B\u0438 \u0432\u044B \u043E\u0431\u0440\u0430\u0442\u0438\u0442\u0435\u0441\u044C \u043A \u0441\u043B\u043E\u0432\u0430\u0440\u044E, \u0442\u043E \u0443\u0432\u0438\u0434\u0438\u0442\u0435, \u0447\u0442\u043E &quot;savya&quot; \u043E\u0437\u043D\u0430\u0447\u0430\u0435\u0442 &quot;\u043B\u0435\u0432\u044B\u0439&quot; \u0438 &quot;apasavya&quot; \u043E\u0437\u043D\u0430\u0447\u0430\u0435\u0442 &quot;\u043F\u0440\u0430\u0432\u044B\u0439&quot;. \u0422\u0435\u043C \u043D\u0435 \u043C\u0435\u043D\u0435\u0435, K\u1E63emar\u0101ja \u043B\u044E\u0431\u0438\u0442 \u0440\u0430\u0441\u0441\u043C\u0430\u0442\u0440\u0438\u0432\u0430\u0442\u044C \u0437\u043D\u0430\u0447\u0435\u043D\u0438\u044F &quot;savya&quot; \u0438 &quot;apasavya&quot;, \u043A\u0430\u043A \u0435\u0441\u043B\u0438 \u0431\u044B \u043E\u043D\u0438 \u0431\u044B\u043B\u0438 \u0432\u0441\u0435\u0433\u0434\u0430 \u043D\u0435\u0441\u043A\u043B\u043E\u043D\u044F\u0435\u043C\u044B\u043C\u0438 (\u043D\u0435\u0437\u0430\u0432\u0438\u0441\u0438\u043C\u043E \u043E\u0442 \u0442\u043E\u0433\u043E, \u0434\u0435\u0439\u0441\u0442\u0432\u0443\u044E\u0442 \u043E\u043D\u0438 \u0438\u043B\u0438 \u043D\u0435\u0442 \u043A\u0430\u043A \u043D\u0435\u0441\u043A\u043B\u043E\u043D\u044F\u0435\u043C\u044B\u0435). \u0415\u0441\u043B\u0438 \u0432\u044B \u043F\u0440\u043E\u0432\u0435\u0440\u0438\u0442\u0435 \u0441\u043B\u043E\u0432\u0430\u0440\u044C, \u0442\u043E &quot;savya&quot; \u0438 &quot;apasavya&quot;, <em>\u043A\u0430\u043A \u043D\u0435\u0441\u043A\u043B\u043E\u043D\u044F\u0435\u043C\u044B\u0435</em> --\u0442.\u0435. \u043A\u0430\u043A savyam/savyena \u0438 apasavyam/apasavyena--, \u043E\u0437\u043D\u0430\u0447\u0430\u044E\u0442 &quot;\u043D\u0430\u043F\u0440\u0430\u0432\u043E&quot; \u0438 &quot;\u043D\u0430\u043B\u0435\u0432\u043E&quot;, \u0441\u043E\u043E\u0442\u0432\u0435\u0442\u0441\u0442\u0432\u0435\u043D\u043D\u043E. \u0422\u0435\u043F\u0435\u0440\u044C, \u0432\u044B \u043C\u043E\u0436\u0435\u0442\u0435 \u0441 \u043B\u0435\u0433\u043A\u043E\u0441\u0442\u044C\u044E \u043F\u043E\u043D\u044F\u0442\u044C, \u043F\u043E\u0447\u0435\u043C\u0443 \u043E\u043D \u0438\u043D\u0442\u0435\u0440\u043F\u0440\u0435\u0442\u0438\u0440\u0443\u0435\u0442 \u0437\u043D\u0430\u0447\u0435\u043D\u0438\u044F &quot;savya&quot; \u0438 &quot;apasavya&quot; \u043F\u0440\u043E\u0442\u0438\u0432\u043E\u043F\u043E\u043B\u043E\u0436\u043D\u043E \u0442\u043E\u043C\u0443, \u0447\u0442\u043E \u043C\u043E\u0436\u043D\u043E \u0431\u044B\u043B\u043E \u0431\u044B \u043E\u0436\u0438\u0434\u0430\u0442\u044C. \u0414\u0430, \u044D\u0442\u043E \u043D\u0435\u043C\u043D\u043E\u0433\u043E \u0430\u0434\u0441\u043A\u0438 \u0438 \u0437\u0430\u043F\u0443\u0442\u0430\u043D\u043D\u043E... \u043D\u0430 \u0441\u0430\u043C\u043E\u043C \u0434\u0435\u043B\u0435, \u0443 \u043C\u0435\u043D\u044F \u0441\u0430\u043C\u043E\u0433\u043E \u043A\u0440\u0443\u0436\u0438\u0442\u0441\u044F \u0433\u043E\u043B\u043E\u0432\u0430 \u0442\u043E\u043B\u044C\u043A\u043E \u043E\u0442 \u0447\u0442\u0435\u043D\u0438\u044F savya \u0438 apasavya, \u044D\u0442\u043E \u043A\u0430\u043A \u0441\u043A\u043E\u0440\u043E\u0433\u043E\u0432\u043E\u0440\u043A\u0430!... \u043D\u043E \u043C\u044B \u043D\u0438\u0447\u0435\u0433\u043E \u043D\u0435 \u043C\u043E\u0436\u0435\u043C \u043F\u043E\u0434\u0435\u043B\u0430\u0442\u044C \u0441 \u044D\u0442\u0438\u043C, \u0432\u044B \u0437\u043D\u0430\u0435\u0442\u0435. \u0417\u0430\u043F\u043E\u043C\u043D\u0438\u0442\u0435 \u044D\u0442\u043E \u043D\u0430 \u0431\u0443\u0434\u0443\u0449\u0435\u0435, \u043F\u043E\u0436\u0430\u043B\u0443\u0439\u0441\u0442\u0430.</p></li><li><p>\u041E\u043D\u0430 (\u0442.\u0435. n\u0101sik\u0101, \u0438\u043B\u0438 pr\u0101\u1E47a\u015Bakti, \u0436\u0438\u0437\u043D\u0435\u043D\u043D\u0430\u044F \u044D\u043D\u0435\u0440\u0433\u0438\u044F) \u0434\u0432\u0438\u0436\u0435\u0442\u0441\u044F \u0437\u0438\u0433\u0437\u0430\u0433\u043E\u043E\u0431\u0440\u0430\u0437\u043D\u043E, \u043F\u043E\u0442\u043E\u043C\u0443 \u0447\u0442\u043E \u043E\u043D\u0430 \u0442\u0435\u0447\u0451\u0442 \u0447\u0435\u0440\u0435\u0437 \u0442\u043E\u043D\u043A\u0438\u0435 \u043A\u0430\u043D\u0430\u043B\u044B \u0432 \u0442\u043E\u043D\u043A\u043E\u043C \u0442\u0435\u043B\u0435, \u043A\u043E\u0442\u043E\u0440\u044B\u0435 \u043A\u0430\u043A \u043F\u0440\u0430\u0432\u0438\u043B\u043E, \u0438\u0437\u0433\u0438\u0431\u0430\u044E\u0442\u0441\u044F. \u042D\u0442\u043E \u043E\u0441\u043E\u0431\u0435\u043D\u043D\u043E \u0432\u0435\u0440\u043D\u043E \u0432 \u043E\u0442\u043D\u043E\u0448\u0435\u043D\u0438\u0438 I\u1E0D\u0101 \u0438 Pi\u1E45gal\u0101, \u043F\u043E\u0441\u043A\u043E\u043B\u044C\u043A\u0443 \u043E\u043D\u0438 \u043F\u0440\u043E\u0445\u043E\u0434\u044F\u0442 \u0437\u0438\u0433\u0437\u0430\u0433\u043E\u043E\u0431\u0440\u0430\u0437\u043D\u043E \u0441\u043B\u0435\u0432\u0430 \u0438 \u0441\u043F\u0440\u0430\u0432\u0430 \u043E\u0442 Su\u1E63umn\u0101.</p></li><li><p>\u0418\u0437 \u044D\u0442\u043E\u0439 \u0441\u0442\u0440\u043E\u0444\u044B K\u0101lik\u0101krama \u0441\u0442\u0430\u043D\u043E\u0432\u0438\u0442\u0441\u044F \u043F\u043E\u043D\u044F\u0442\u043D\u043E, \u0447\u0442\u043E \u0412\u044B\u0441\u0448\u0430\u044F \u0421\u0438\u043B\u0430 \u0413\u043E\u0441\u043F\u043E\u0434\u0430 \u0435\u0441\u0442\u044C \u043D\u0435 \u0447\u0442\u043E \u0438\u043D\u043E\u0435, \u043A\u0430\u043A \u0442\u0432\u043E\u0435 \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0435 \u042F-\u0421\u043E\u0437\u043D\u0430\u043D\u0438\u0435. \u0418\u0441\u043F\u043E\u043B\u044C\u0437\u0443\u044F \u044D\u0442\u043E \u0443\u0447\u0435\u043D\u0438\u0435 \u0432 \u043A\u0430\u0447\u0435\u0441\u0442\u0432\u0435 \u0440\u0443\u043A\u043E\u0432\u043E\u0434\u0441\u0442\u0432\u0430, \u043A\u043E\u043C\u043C\u0435\u043D\u0442\u0430\u0442\u043E\u0440 \u043E\u0431\u044A\u044F\u0441\u043D\u044F\u0435\u0442, \u0447\u0442\u043E \u0431\u043B\u0430\u0433\u043E\u0434\u0430\u0440\u044F sa\u1E41yama \u044D\u0442\u043E\u0433\u043E \u0412\u044B\u0441\u0448\u0435\u0433\u043E \u042F-\u0421\u043E\u0437\u043D\u0430\u043D\u0438\u044F \u0432\u0435\u043B\u0438\u043A\u0438\u0439 Yog\u012B \u0434\u043E\u0441\u0442\u0438\u0433\u0430\u0435\u0442 Nirvyutth\u0101nasam\u0101dhi, \u0438\u043B\u0438 \u043F\u043E\u0433\u0440\u0443\u0436\u0435\u043D\u0438\u044F \u0432 \u0441\u0432\u043E\u0451 &quot;\u042F&quot;, \u0438\u0437 \u043A\u043E\u0442\u043E\u0440\u043E\u0433\u043E \u043E\u043D \u043D\u0438\u043A\u043E\u0433\u0434\u0430 \u043D\u0435 \u0432\u0435\u0440\u043D\u0451\u0442\u0441\u044F \u0432 \u043E\u0431\u044B\u0447\u043D\u043E\u0435 \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435, \u0438\u043B\u0438 vyutth\u0101na, \u0430 \u0441\u043E\u0445\u0440\u0430\u043D\u0438\u0442 \u0442\u0430\u043A\u0443\u044E \u0440\u0435\u0430\u043B\u0438\u0437\u0430\u0446\u0438\u044E \u043F\u0440\u0438 \u043B\u044E\u0431\u044B\u0445 \u043E\u0431\u0441\u0442\u043E\u044F\u0442\u0435\u043B\u044C\u0441\u0442\u0432\u0430\u0445, \u0432\u043E \u0432\u0441\u0435\u0445 \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u044F\u0445 \u0438 \u0443\u0441\u043B\u043E\u0432\u0438\u044F\u0445. \u0421\u043B\u043E\u0432\u043E sa\u1E41yama \u0437\u0434\u0435\u0441\u044C \u043D\u0435 \u0438\u043D\u0442\u0435\u0440\u043F\u0440\u0435\u0442\u0438\u0440\u0443\u0435\u0442\u0441\u044F \u043A\u0430\u043A \u0443 \u0432\u0435\u043B\u0438\u043A\u043E\u0433\u043E \u043C\u0443\u0434\u0440\u0435\u0446\u0430 Pata\xF1jali \u0432 \u0435\u0433\u043E Yogas\u016Btra-s III, 4, \u043D\u043E \u0441\u043A\u043E\u0440\u0435\u0435 \u043A\u0430\u043A &quot;antarnibh\u0101lanaprakar\u1E63a&quot;, \u0438\u043B\u0438 &quot;\u0438\u043D\u0442\u0435\u043D\u0441\u0438\u0432\u043D\u043E\u0441\u0442\u044C [\u043F\u043E\u0441\u0442\u043E\u044F\u043D\u043D\u043E\u0433\u043E] \u0432\u043D\u0443\u0442\u0440\u0435\u043D\u043D\u0435\u0433\u043E \u043E\u0441\u043E\u0437\u043D\u0430\u0432\u0430\u043D\u0438\u044F&quot;. \u041E\u0441\u043E\u0437\u043D\u0430\u0432\u0430\u043D\u0438\u0435 \u0447\u0435\u0433\u043E? \u0415\u0433\u043E \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0433\u043E \u0432 \u0432\u044B\u0441\u0448\u0435\u0439 \u0441\u0442\u0435\u043F\u0435\u043D\u0438 \u0441\u043E\u0432\u0435\u0440\u0448\u0435\u043D\u043D\u043E\u0433\u043E \u042F-\u0421\u043E\u0437\u043D\u0430\u043D\u0438\u044F, \u0438\u043B\u0438 Vimar\u015Ba, \u043A\u043E\u0442\u043E\u0440\u0430\u044F \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u0441\u0430\u043C\u043E\u0439 \u0441\u043E\u043A\u0440\u043E\u0432\u0435\u043D\u043D\u043E\u0439 \u0433\u043B\u0430\u0432\u043D\u043E\u0439 \u0420\u0435\u0430\u043B\u044C\u043D\u043E\u0441\u0442\u044C\u044E. \u0414\u0440\u0443\u0433\u0438\u043C\u0438 \u0441\u043B\u043E\u0432\u0430\u043C\u0438, \u043E\u043D \u043E\u0441\u043E\u0437\u043D\u0430\u0435\u0442 \u0441\u0432\u043E\u044E \u0438\u0441\u0442\u0438\u043D\u043D\u0443\u044E \u043F\u0440\u0438\u0440\u043E\u0434\u0443 \u0441\u043D\u043E\u0432\u0430 \u0438 \u0441\u043D\u043E\u0432\u0430 (\u043F\u043E\u0441\u0442\u043E\u044F\u043D\u043D\u043E). \u0418\u043C\u0435\u044F \u0442\u0430\u043A\u043E\u0433\u043E \u0432\u043E\u0437\u0432\u044B\u0448\u0435\u043D\u043D\u043E\u0433\u043E Yog\u012B, \u0434\u043E\u0441\u0442\u0438\u0433\u0448\u0435\u0433\u043E \u0432\u044B\u0441\u0448\u0435\u0433\u043E \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u044F \u0441\u043E\u0437\u043D\u0430\u043D\u0438\u044F, &quot;kimatra&quot;, \u0442.\u0435. &quot;\u0427\u0442\u043E \u0435\u0449\u0435 [\u043C\u043E\u0436\u043D\u043E \u0441\u043A\u0430\u0437\u0430\u0442\u044C] \u043E\u0431 \u044D\u0442\u043E\u043C?&quot;.</p></li></ol><p>\u0422\u0435\u043C \u043D\u0435 \u043C\u0435\u043D\u0435\u0435, \u0435\u0449\u0435 \u043E\u0434\u0438\u043D \u0430\u0444\u043E\u0440\u0438\u0437\u043C \u0431\u0443\u0434\u0435\u0442 \u043D\u0430\u043F\u0438\u0441\u0430\u043D \u0413\u043E\u0441\u043F\u043E\u0434\u043E\u043C (45<sup>\u044B\u0439</sup>) \u0442\u043E\u043B\u044C\u043A\u043E \u0434\u043B\u044F \u0442\u043E\u0433\u043E, \u0447\u0442\u043E\u0431\u044B \u043E\u043F\u0438\u0441\u0430\u0442\u044C \u043A\u043E\u043D\u0435\u0447\u043D\u043E\u0435 \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435, \u0434\u043E\u0441\u0442\u0438\u0433\u043D\u0443\u0442\u043E\u0435 \u0431\u0435\u0441\u0441\u043C\u0435\u0440\u0442\u043D\u044B\u043C Yog\u012B, \u043A\u043E\u0442\u043E\u0440\u044B\u0439 \u0435\u0441\u0442\u044C \u0441\u0430\u043C\u0430 \u0421\u0430\u043C\u043E\u0441\u0442\u044C.</p></div><div class="stanza"><a href="#s3.45" id="s3.45" class="num">3.45</a><div class="sans"><p>\u090F\u0935\u092E\u0940\u0926\u0943\u0936\u0938\u094D\u092F \u092F\u094B\u0917\u092B\u0932\u0902 \u0926\u0930\u094D\u0936\u092F\u0928\u094D \u092A\u094D\u0930\u0915\u0930\u0923\u092E\u0941\u092A\u0938\u0902\u0939\u0930\u0924\u093F\u2014</p><blockquote><p><strong>\u092D\u0942\u092F\u0903 \u0938\u094D\u092F\u093E\u0924\u094D\u092A\u094D\u0930\u0924\u093F\u092E\u0940\u0932\u0928\u092E\u094D\u0965\u096A\u096B\u0965</strong></p></blockquote><p>\u091A\u0948\u0924\u0928\u094D\u092F\u093E\u0924\u094D\u092E\u0928\u0903 \u0938\u094D\u0935\u0930\u0942\u092A\u093E\u0926\u0941\u0926\u093F\u0924\u0938\u094D\u092F\u093E\u0938\u094D\u092F \u0935\u093F\u0936\u094D\u0935\u0938\u094D\u092F \u092D\u0942\u092F\u0903 \u092A\u0941\u0928\u0930\u094D\u0935\u093F\u0917\u0932\u093F\u0924\u092D\u0947\u0926\u0938\u0902\u0938\u094D\u0915\u093E\u0930\u093E\u0924\u094D\u092E\u0928\u093E \u092C\u093E\u0939\u0941\u0932\u094D\u092F\u0947\u0928 \u091A \u092A\u094D\u0930\u0924\u093F\u092E\u0940\u0932\u0928\u092E\u094D \u091A\u0948\u0924\u0928\u094D\u092F\u093E\u092D\u093F\u092E\u0941\u0916\u094D\u092F\u0947\u0928 \u0928\u093F\u092E\u0940\u0932\u0928\u0902 \u092A\u0941\u0928\u0930\u092A\u093F \u091A\u0948\u0924\u0928\u094D\u092F\u093E\u0924\u094D\u092E\u0938\u094D\u0935\u0938\u094D\u0935\u0930\u0942\u092A\u094B\u0928\u094D\u092E\u0940\u0932\u0928\u0930\u0942\u092A\u0902 \u092A\u0930\u092F\u094B\u0917\u093E\u092D\u093F\u0928\u093F\u0935\u093F\u0937\u094D\u091F\u0938\u094D\u092F \u092F\u094B\u0917\u093F\u0928\u094B \u092D\u0935\u0924\u093F\u0964 \u0924\u0926\u0941\u0915\u094D\u0924\u0902 \u0936\u094D\u0930\u0940\u0938\u094D\u0935\u091A\u094D\u091B\u0928\u094D\u0926\u0947</p><blockquote><p>\u0909\u0928\u094D\u092E\u0928\u093E\u092A\u0930\u0924\u094B \u0926\u0947\u0935\u093F \u0924\u0924\u094D\u0930\u093E\u0924\u094D\u092E\u093E\u0928\u0902 \u0928\u093F\u092F\u094B\u091C\u092F\u0947\u0924\u094D\u0964<br> \u0924\u0938\u094D\u092E\u093F\u0928\u094D\u092F\u0941\u0915\u094D\u0924\u0938\u094D\u0924\u0924\u094B \u0939\u094D\u092F\u093E\u0924\u094D\u092E\u093E \u0924\u0928\u094D\u092E\u092F\u0936\u094D\u091A \u092A\u094D\u0930\u091C\u093E\u092F\u0924\u0947\u0965</p></blockquote><p>\u0907\u0924\u093F\u0964 \u0924\u0925\u093E \u091A</p><blockquote><p>\u0909\u0926\u094D\u092C\u094B\u0927\u093F\u0924\u094B \u092F\u0925\u093E \u0935\u0939\u094D\u0928\u093F\u0930\u094D\u0928\u093F\u0930\u094D\u092E\u0932\u094B\u093D\u0924\u0940\u0935 \u092D\u093E\u0938\u094D\u0935\u0930\u0903\u0964<br> \u0928 \u092D\u0942\u092F\u0903 \u092A\u094D\u0930\u0935\u093F\u0936\u0947\u0924\u094D\u0915\u093E\u0937\u094D\u0920\u0902 \u0924\u0925\u093E\u0924\u094D\u092E\u093E\u0927\u094D\u0935\u0928 \u0909\u0926\u094D\u0927\u0943\u0924\u0903\u0965<br> \u092E\u0932\u0915\u0930\u094D\u092E\u0915\u0932\u093E\u0926\u094D\u092F\u0948\u0938\u094D\u0924\u0941 \u0928\u093F\u0930\u094D\u092E\u0941\u0915\u094D\u0924\u094B \u0935\u093F\u0917\u0924\u0915\u094D\u0932\u092E\u0903\u0964<br> \u0924\u0924\u094D\u0930\u0938\u094D\u0925\u094B\u093D\u092A\u093F \u0928 \u092C\u0927\u094D\u092F\u0947\u0924 \u092F\u0924\u094B\u093D\u0924\u0940\u0935 \u0938\u0941\u0928\u093F\u0930\u094D\u092E\u0932\u0903\u0965</p></blockquote><p>\u0907\u0924\u093F\u0964 \u092D\u0942\u092F\u0903 \u0938\u094D\u092F\u093E\u0926\u093F\u0924\u094D\u092F\u092D\u093F\u0926\u0927\u0924\u094B\u093D\u092F\u092E\u093E\u0936\u092F\u094B \u092F\u0924\u094D \u0936\u093F\u0935\u0924\u094D\u0935\u092E\u0938\u094D\u092F \u092F\u094B\u0917\u093F\u0928\u094B \u0928\u093E\u092A\u0942\u0930\u094D\u0935\u092E\u092A\u093F \u0924\u0941 \u0938\u094D\u0935\u092D\u093E\u0935 \u090F\u0935 \u0915\u0947\u0935\u0932\u0902 \u092E\u093E\u092F\u093E\u0936\u0915\u094D\u0924\u094D\u092F\u0941\u0924\u094D\u0925\u093E\u092A\u093F\u0924\u0938\u094D\u0935\u0935\u093F\u0915\u0932\u094D\u092A\u0926\u094C\u0930\u093E\u0924\u094D\u092E\u094D\u092F\u093E\u0926\u094D\u092D\u093E\u0938\u092E\u093E\u0928\u092E\u092A\u093F \u0924\u0928\u094D\u0928\u093E\u092F\u0902 \u092A\u094D\u0930\u0924\u094D\u092F\u0935\u092E\u094D\u0930\u0937\u094D\u091F\u0941\u0902 \u0915\u094D\u0937\u092E \u0907\u0924\u094D\u092F\u0938\u094D\u092F\u094B\u0915\u094D\u0924\u094B\u092A\u093E\u092F\u092A\u094D\u0930\u0926\u0930\u094D\u0936\u0928\u0915\u094D\u0930\u092E\u0947\u0923 \u0924\u0926\u0947\u0935\u093E\u092D\u093F\u0935\u094D\u092F\u091C\u094D\u092F\u0924 \u0907\u0924\u093F \u0936\u093F\u0935\u092E\u094D\u0965\u096A\u096B\u0965</p></div><hr><div class="trans"><p>Evam\u012Bd\u1E5B\u015Basya yogaphala\u1E41 dar\u015Bayan prakara\u1E47amupasa\u1E41harati\u2014</p><blockquote><p><strong>Bh\u016Bya\u1E25 sy\u0101tpratim\u012Blanam||45||</strong></p></blockquote><p>Caitany\u0101tmana\u1E25 svar\u016Bp\u0101duditasy\u0101sya vi\u015Bvasya bh\u016Bya\u1E25 punarvigalitabhedasa\u1E41sk\u0101r\u0101tman\u0101 b\u0101hulyena ca pratim\u012Blanam caitany\u0101bhimukhyena nim\u012Blana\u1E41 punarapi caitany\u0101tmasvasvar\u016Bponm\u012Blanar\u016Bpa\u1E41 parayog\u0101bhinivi\u1E63\u1E6Dasya yogino bhavati| Tadukta\u1E41 \u015Br\u012Bsvacchande</p><blockquote><p>Unman\u0101parato devi tatr\u0101tm\u0101na\u1E41 niyojayet|<br> Tasminyuktastato hy\u0101tm\u0101 tanmaya\u015Bca praj\u0101yate||</p></blockquote><p>iti| Tath\u0101 ca</p><blockquote><p>Udbodhito yath\u0101 vahnirnirmalo&#39;t\u012Bva bh\u0101svara\u1E25|<br> Na bh\u016Bya\u1E25 pravi\u015Betk\u0101\u1E63\u1E6Dha\u1E41 tath\u0101tm\u0101dhvana uddh\u1E5Bta\u1E25||<br> Malakarmakal\u0101dyaistu nirmukto vigataklama\u1E25|<br> Tatrastho&#39;pi na badhyeta yato&#39;t\u012Bva sunirmala\u1E25||</p></blockquote><p>iti| Bh\u016Bya\u1E25 sy\u0101dityabhidadhato&#39;yam\u0101\u015Bayo yat \u015Bivatvamasya yogino n\u0101p\u016Brvamapi tu svabh\u0101va eva kevala\u1E41 m\u0101y\u0101\u015Baktyutth\u0101pitasvavikalpadaur\u0101tmy\u0101dbh\u0101sam\u0101namapi tann\u0101ya\u1E41 pratyavamra\u1E63\u1E6Du\u1E41 k\u1E63ama ityasyoktop\u0101yapradar\u015Banakrame\u1E47a tadev\u0101bhivyajyata iti \u015Bivam||45||</p></div><hr><p>\u0422\u0430\u043A\u0438\u043C \u043E\u0431\u0440\u0430\u0437\u043E\u043C <em>(evam)</em>, [\u0441\u0435\u0439\u0447\u0430\u0441 \u015Aiva] \u043F\u043E\u0434\u0432\u043E\u0434\u0438\u0442 \u0438\u0442\u043E\u0433 <em>(upasa\u1E41harati)</em> \u043A\u043D\u0438\u0433\u0438 \u0438 \u0435\u0435 \u0442\u0435\u043C\u044B --\u015Aivas\u016Btra-s-- <em>(prakara\u1E47am)</em>, \u043F\u043E\u043A\u0430\u0437\u044B\u0432\u0430\u044F <em>(dar\u015Bayan)</em> \u043F\u043B\u043E\u0434 <em>(phalam)</em> \u0419\u043E\u0433\u0438 <em>(yoga)</em> \u0434\u043B\u044F \u0442\u0430\u043A\u043E\u0433\u043E [Yog\u012B] <em>(\u012Bd\u1E5B\u015Basya)</em>\u2014</p><blockquote><p><strong>[\u0412 \u0441\u043B\u0443\u0447\u0430\u0435 \u043F\u0440\u043E\u0441\u0432\u0435\u0442\u043B\u0435\u043D\u043D\u043E\u0433\u043E Yog\u012B], \u0441\u043D\u043E\u0432\u0430 \u0438 \u0441\u043D\u043E\u0432\u0430 <em>(bh\u016Byas)</em> \u043F\u0440\u043E\u0438\u0441\u0445\u043E\u0434\u0438\u0442 <em>(sy\u0101t)</em> \u043E\u0441\u043E\u0437\u043D\u0430\u043D\u0438\u0435 \u0412\u044B\u0441\u0448\u0435\u0439 \u0421\u0430\u043C\u043E\u0441\u0442\u0438 \u043A\u0430\u043A \u0432\u043D\u0443\u0442\u0440\u0435\u043D\u043D\u0435, \u0442\u0430\u043A \u0438 \u0432\u043D\u0435\u0448\u043D\u0435 <em>(pratim\u012Blanam)</em>||45||</strong></p></blockquote><p>Pratim\u012Blana <em>(pratim\u012Blanam)</em> \u044D\u0442\u043E\u0439 <em>(asya)</em> \u0432\u0441\u0435\u043B\u0435\u043D\u043D\u043E\u0439 <em>(vi\u015Bvasya)</em>, \u043A\u043E\u0442\u043E\u0440\u0430\u044F \u0432\u043E\u0437\u043D\u0438\u043A\u043B\u0430 <em>(uditasya)</em> \u0438\u0437 \u0435\u0433\u043E \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0439 \u0441\u0443\u0449\u043D\u043E\u0441\u0442\u043D\u043E\u0439 \u043F\u0440\u0438\u0440\u043E\u0434\u044B <em>(sva-r\u016Bp\u0101t)</em>, [\u0438\u043B\u0438] \u0410\u0431\u0441\u043E\u043B\u044E\u0442\u043D\u043E \u0421\u0432\u043E\u0431\u043E\u0434\u043D\u043E\u0433\u043E \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u044F <em>(caitanya-\u0101tmana\u1E25)</em>, \u2014\u0441\u043E\u0432\u0435\u0440\u0448\u0435\u043D\u043D\u043E <em>(b\u0101hulyena ca)</em> \u0441\u0432\u043E\u0431\u043E\u0434\u043D\u0430\u044F <em>(vigalita)</em> \u043E\u0442 [\u043B\u044E\u0431\u043E\u0433\u043E] \u043B\u0430\u0442\u0435\u043D\u0442\u043D\u043E\u0433\u043E \u043E\u0442\u043F\u0435\u0447\u0430\u0442\u043A\u0430 <em>(sa\u1E41sk\u0101ra-\u0101tman\u0101)</em> \u0434\u0432\u043E\u0439\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0441\u0442\u0438 <em>(bheda)</em>\u2014 \u0441\u043E\u0432\u0435\u0440\u0448\u0430\u0435\u0442\u0441\u044F <em>(bhavati)</em> \u0441\u043D\u043E\u0432\u0430 \u0438 \u0441\u043D\u043E\u0432\u0430 <em>(bh\u016Byas punar)</em> \u0432 \u0441\u043B\u0443\u0447\u0430\u0435 Yog\u012B <em>(yogina\u1E25)</em>, \u043A\u043E\u0442\u043E\u0440\u044B\u0439 \u043F\u043E\u0433\u0440\u0443\u0436\u0435\u043D <em>(abhinivi\u1E63\u1E6Dasya)</em> \u0432 \u0412\u044B\u0441\u0448\u0443\u044E <em>(para)</em> \u0419\u043E\u0433\u0443 <em>(yoga)</em>. [\u042D\u0442\u0430 pratim\u012Blana \u0441 \u043E\u0434\u043D\u043E\u0439 \u0441\u0442\u043E\u0440\u043E\u043D\u044B \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F] \u0432\u043D\u0443\u0442\u0440\u0435\u043D\u043D\u0438\u043C \u043F\u043E\u0433\u043B\u043E\u0449\u0435\u043D\u0438\u0435\u043C \u0432 \u0412\u044B\u0441\u0448\u0435\u0439 \u0421\u0430\u043C\u043E\u0441\u0442\u0438 <em>(nim\u012Blanam)</em> \u2014\u043A\u043E\u0433\u0434\u0430 [Yog\u012B] \u043E\u0440\u0438\u0435\u043D\u0442\u0438\u0440\u043E\u0432\u0430\u043D <em>(abhimukhyena)</em> \u043D\u0430 [\u0432\u043D\u0443\u0442\u0440\u0435\u043D\u043D\u0435\u0435] \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u0435 <em>(caitanya)</em>\u2014, [\u0438] \u0441 \u0434\u0440\u0443\u0433\u043E\u0439 \u0441\u0442\u043E\u0440\u043E\u043D\u044B <em>(punar api)</em>, \u0432\u043D\u0435\u0448\u043D\u0438\u043C \u043F\u043E\u0433\u043B\u043E\u0449\u0435\u043D\u0438\u0435\u043C \u0432 [\u044D\u0442\u043E\u0439 \u0436\u0435 \u0441\u0430\u043C\u043E\u0439] \u0412\u044B\u0441\u0448\u0435\u0439 \u0421\u0430\u043C\u043E\u0441\u0442\u0438 <em>(unm\u012Blana-r\u016Bpam)</em>, [\u0433\u0434\u0435 Yog\u012B \u043F\u0435\u0440\u0435\u0436\u0438\u0432\u0430\u0435\u0442 \u0432\u0441\u044E \u0432\u0441\u0435\u043B\u0435\u043D\u043D\u0443\u044E \u043A\u0430\u043A] \u0441\u0432\u043E\u044E \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u0443\u044E <em>(sva)</em> \u0421\u0443\u0449\u043D\u043E\u0441\u0442\u044C <em>(sva-r\u016Bpa)</em>, \u0447\u044C\u044F \u043F\u0440\u0438\u0440\u043E\u0434\u0430 <em>(\u0101tma)</em> \u2014 [\u0442\u0430 \u0436\u0435] Caitanya, \u0438\u043B\u0438 \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u0435 <em>(caitanya)</em><sup>1</sup>|</p><p>\u0422\u043E \u0436\u0435 <em>(tad)</em> \u0431\u044B\u043B\u043E \u043E\u043F\u0438\u0441\u0430\u043D\u043E <em>(uktam)</em> \u0432 \u043F\u043E\u0447\u0442\u0435\u043D\u043D\u043E\u043C Svacchandatantra <em>(\u015Br\u012Bsvacchande)</em>:</p><blockquote><p>&quot;\u041E \u0411\u043E\u0433\u0438\u043D\u044F <em>(devi)</em>!, Unman\u0101 <em>(unman\u0101)</em>, \u043D\u0430\u0445\u043E\u0434\u044F\u0449\u0430\u044F\u0441\u044F \u0432\u043D\u0435 [Saman\u0101] <em>(paratas)</em>; \u043D\u0443\u0436\u043D\u043E \u0441\u043E\u0435\u0434\u0438\u043D\u0438\u0442\u044C\u0441\u044F <em>(\u0101tm\u0101nam niyojayet)</em> \u0441 \u044D\u0442\u0438\u043C--\u0441 Unman\u0101-- <em>(tatra)</em>. \u0421\u043B\u0435\u0434\u043E\u0432\u0430\u0442\u0435\u043B\u044C\u043D\u043E <em>(tatas hi)</em>, \u0441\u0430\u043C\u043E\u0441\u0442\u044C <em>(\u0101tm\u0101)</em>, \u0441\u043E\u0435\u0434\u0438\u043D\u0435\u043D\u043D\u0430\u044F <em>(yukta\u1E25)</em> \u0441 \u044D\u0442\u0438\u043C <em>(tasmin)</em>, \u0441\u0442\u0430\u043D\u043E\u0432\u0438\u0442\u0441\u044F <em>(praj\u0101yate)</em> \u0442\u043E\u0436\u0434\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0439 <em>(maya\u1E25 ca)</em> \u044D\u0442\u043E\u043C\u0443 <em>(tad... iti)</em>&quot;||<br> [\u0421\u043C. IV, 332 \u0432 Svacchandatantra]</p></blockquote><p>\u0418 \u0442\u0430\u043A\u0436\u0435 <em>(tath\u0101 ca)</em>, [\u0432 \u0441\u0430\u043C\u043E\u043C Svacchandatantra, \u0441\u043A\u0430\u0437\u0430\u043D\u043E]:</p><blockquote><p>&quot;\u041F\u043E\u0434\u043E\u0431\u043D\u043E \u0442\u043E\u043C\u0443, \u043A\u0430\u043A <em>(yath\u0101)</em> \u043E\u0433\u043E\u043D\u044C <em>(vahni\u1E25)</em>, \u043A\u043E\u0442\u043E\u0440\u044B\u0439 \u0432\u043E\u0437\u043D\u0438\u043A <em>(udbodhita\u1E25)</em> \u0447\u0438\u0441\u0442\u044B\u043C <em>(nirmala\u1E25)</em> [\u0438] \u043E\u0447\u0435\u043D\u044C <em>(at\u012Bva)</em> \u043B\u0443\u0447\u0435\u0437\u0430\u0440\u043D\u044B\u043C <em>(bh\u0101svara\u1E25)</em> [\u043E\u0442 \u043A\u0443\u0441\u043A\u0430 \u0434\u0435\u0440\u0435\u0432\u0430], \u043D\u0435 <em>(na)</em> \u0432\u0445\u043E\u0434\u0438\u0442 <em>(pravi\u015Bet)</em> \u0432 \u043A\u0443\u0441\u043E\u043A \u0434\u0435\u0440\u0435\u0432\u0430 <em>(k\u0101\u1E63\u1E6Dham)</em> \u0441\u043D\u043E\u0432\u0430 <em>(bh\u016Byas)</em>, \u0442\u0430\u043A\u0436\u0435 \u0438 <em>(tath\u0101)</em> \u0421\u0430\u043C\u043E\u0441\u0442\u044C <em>(\u0101tm\u0101)</em>, \u0432\u043E\u0437\u043D\u0438\u043A\u0448\u0430\u044F <em>(uddh\u1E5Bta\u1E25)</em> \u0438\u0437 \u1E62a\u1E0Dadhv\u0101 --\u0428\u0435\u0441\u0442\u0438 \u041F\u0443\u0442\u0435\u0439 (\u043F\u0440\u043E\u044F\u0432\u043B\u0435\u043D\u0438\u044F)-- <em>(\u0101dhvana\u1E25)</em>, \u0431\u0443\u0434\u0443\u0447\u0438 \u043E\u0441\u0432\u043E\u0431\u043E\u0436\u0434\u0435\u043D\u043D\u043E\u0439 <em>(nirmukta\u1E25)</em> \u043E\u0442 \u0100\u1E47avamala, K\u0101rmamala \u0438 M\u0101y\u012Byamala, \u0438 \u0442.\u0434. <em>(mala-karma-kal\u0101-\u0101dyai\u1E25 tu)</em>, \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F vigataklama, \u0438\u043B\u0438 \u0442\u0435\u043C, \u0447\u044C\u044F \u0438\u0437\u043D\u0443\u0440\u0438\u0442\u0435\u043B\u044C\u043D\u0430\u044F \u0440\u0430\u0431\u043E\u0442\u0430 \u043F\u0440\u0435\u043A\u0440\u0430\u0442\u0438\u043B\u0430\u0441\u044C <em>(vigata-klama\u1E25)</em>. \u0425\u043E\u0442\u044F <em>(api)</em> \u043E\u043D \u043F\u0440\u0435\u0431\u044B\u0432\u0430\u0435\u0442 <em>(stha\u1E25)</em> \u0442\u0430\u043C --\u0432 \u043C\u0438\u0440\u0435-- <em>(tatra)</em>, \u043E\u043D \u043D\u0435 <em>(na)</em> \u0441\u0432\u044F\u0437\u0430\u043D [\u0443\u0434\u043E\u0432\u043E\u043B\u044C\u0441\u0442\u0432\u0438\u044F\u043C\u0438 \u044D\u0442\u043E\u0433\u043E \u043C\u0438\u0440\u0430] <em>(badhyeta)</em>, \u043F\u043E\u0441\u043A\u043E\u043B\u044C\u043A\u0443 <em>(yatas)</em> \u043E\u043D \u0447\u0440\u0435\u0437\u0432\u044B\u0447\u0430\u0439\u043D\u043E \u0431\u0435\u0437\u0443\u043F\u0440\u0435\u0447\u0435\u043D <em>(at\u012Bva sunirmala\u1E25... iti)</em><sup>3</sup>&quot;||<br> [\u0421\u043C. X, 371-372 \u0432 Svacchandatantra]</p></blockquote><p>[\u0413\u043E\u0432\u043E\u0440\u044F] &quot;Bh\u016Bya\u1E25 sy\u0101t&quot;, \u0438\u043B\u0438 &quot;\u043F\u0440\u043E\u0438\u0441\u0445\u043E\u0434\u0438\u0442 \u0441\u043D\u043E\u0432\u0430 \u0438 \u0441\u043D\u043E\u0432\u0430&quot; <em>(bh\u016Bya\u1E25 sy\u0101t iti)</em> [\u0432 \u0430\u0444\u043E\u0440\u0438\u0437\u043C\u0435], \u044D\u0442\u043E <em>(ayam)</em> [\u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F] \u043D\u0430\u043C\u0435\u0440\u0435\u043D\u0438\u0435\u043C <em>(\u0101\u015Baya\u1E25)</em> \u0422\u043E\u0433\u043E, \u041A\u0442\u043E \u043F\u0440\u043E\u0432\u043E\u0437\u0433\u043B\u0430\u0448\u0430\u0435\u0442 \u044D\u0442\u043E --\u0442.\u0435. \u015Aiva, \u0430\u0432\u0442\u043E\u0440\u0430 \u015Aivas\u016Btra-s-- <em>(abhidadhata\u1E25)</em>:</p><p>\u042D\u0442\u043E <em>(yad)</em> \u015Aiva-hood --\u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435 \u015Aiva-- <em>(\u015Bivatvam)</em> \u044D\u0442\u043E\u0433\u043E <em>(asya)</em> Yog\u012B <em>(yogina\u1E25)</em> \u043D\u0435 \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F <em>(na)</em> \u0447\u0435\u043C-\u0442\u043E \u043D\u043E\u0432\u044B\u043C <em>(ap\u016Brvam)</em>, \u0430 \u0432\u0435\u0440\u043D\u0435\u0435 (\u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F) <em>(api tu)</em> [\u0435\u0433\u043E] \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0439 \u0441\u0443\u0449\u043D\u043E\u0441\u0442\u043D\u043E\u0439 \u043F\u0440\u0438\u0440\u043E\u0434\u043E\u0439 <em>(sva-bh\u0101va\u1E25 eva)</em>! \u0422\u043E\u043B\u044C\u043A\u043E <em>(kevalam)</em> \u0438\u0437-\u0437\u0430 \u0438\u0437\u0432\u0440\u0430\u0449\u0435\u043D\u043D\u043E\u0441\u0442\u0438 <em>(daur\u0101tmy\u0101t)</em> \u0435\u0433\u043E <em>(sva)</em> \u043C\u044B\u0441\u043B\u0435\u0439 <em>(vikalpa)</em>, \u043F\u0440\u043E\u0431\u0443\u0436\u0434\u0435\u043D\u043D\u044B\u0445 <em>(utth\u0101pita)</em> m\u0101y\u0101\u015Bakti --\u0415\u0433\u043E \u0441\u0438\u043B\u044B \u043F\u043E\u0440\u043E\u0436\u0434\u0430\u0442\u044C \u0434\u0432\u043E\u0439\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0441\u0442\u044C-- <em>(m\u0101y\u0101-\u015Bakti)</em><sup>4</sup>, \u0445\u043E\u0442\u044F <em>(api)</em> \u044D\u0442\u043E --\u0442.\u0435. \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435 \u015Aiva-- <em>(tad)</em> \u0431\u044B\u043B\u043E \u043F\u0440\u043E\u044F\u0432\u043B\u0435\u043D\u043E <em>(bh\u0101sam\u0101nam)</em>, \u043E\u043D <em>(ayam)</em> \u0431\u044B\u043B \u043D\u0435 <em>(na)</em> \u0441\u043F\u043E\u0441\u043E\u0431\u0435\u043D <em>(k\u1E63ama\u1E25)</em> \u0440\u0430\u0441\u043F\u043E\u0437\u043D\u0430\u0442\u044C [\u0435\u0433\u043E] --\u0441\u043E\u043F\u0440\u0438\u043A\u043E\u0441\u043D\u0443\u0442\u044C\u0441\u044F \u0441 \u043D\u0438\u043C-- <em>(pratyavamra\u1E63\u1E6Dum)</em>. \u0422\u0430\u043A\u0438\u043C \u043E\u0431\u0440\u0430\u0437\u043E\u043C <em>(iti)</em>, \u044D\u0442\u043E [\u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435 \u015Aiva] <em>(tad eva)</em> \u0431\u044B\u043B\u043E [\u0441\u0435\u0439\u0447\u0430\u0441] \u043F\u0440\u043E\u044F\u0432\u043B\u0435\u043D\u043E <em>(abhivyajyate)</em> \u0434\u043B\u044F \u043D\u0435\u0433\u043E --\u0434\u043B\u044F \u043F\u0440\u043E\u0441\u0432\u0435\u0442\u043B\u0435\u043D\u043D\u043E\u0433\u043E Yog\u012B-- <em>(asya)</em> \u0441\u0435\u0440\u0438\u0435\u0439 [\u0430\u0444\u043E\u0440\u0438\u0437\u043C\u043E\u0432] <em>(krame\u1E47a)</em>, \u043F\u043E\u043A\u0430\u0437\u044B\u0432\u0430\u044E\u0449\u0438\u0445 \u0438 \u043E\u0431\u044A\u044F\u0441\u043D\u044F\u044E\u0449\u0438\u0445 <em>(pradar\u015Bana)</em> \u043C\u0435\u0442\u043E\u0434\u044B <em>(up\u0101ya)</em>, \u043A\u043E\u0442\u043E\u0440\u044B\u0435 \u0431\u044B\u043B\u0438 \u043E\u043F\u0438\u0441\u0430\u043D\u044B <em>(uktam)</em>. \u0414\u0430 \u0431\u0443\u0434\u0435\u0442 \u0431\u043B\u0430\u0433\u043E [\u0434\u043B\u044F \u0432\u0441\u0435\u0445 \u0441\u0443\u0449\u0435\u0441\u0442\u0432] <em>(iti \u015Bivam)</em>!||45||</p><hr><ol><li><p>\u041F\u0440\u043E\u0449\u0435 \u0433\u043E\u0432\u043E\u0440\u044F: \u042D\u0442\u043E\u0442 Yog\u012B \u043F\u0435\u0440\u0435\u0436\u0438\u0432\u0430\u0435\u0442 \u0412\u044B\u0441\u0448\u0443\u044E \u0421\u0430\u043C\u043E\u0441\u0442\u044C \u043A\u0430\u043A \u0432\u043D\u0443\u0442\u0440\u0438, \u0442\u0430\u043A \u0438 \u0441\u043D\u0430\u0440\u0443\u0436\u0438. \u0412\u043D\u0443\u0442\u0440\u0438, \u0413\u043E\u0441\u043F\u043E\u0434\u044C \u043F\u043E\u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u043A\u0430\u043A \u0435\u0433\u043E \u0432\u043D\u0443\u0442\u0440\u0435\u043D\u043D\u044F\u044F \u0421\u0430\u043C\u043E\u0441\u0442\u044C, \u0438\u043B\u0438 \u0438\u0441\u0442\u0438\u043D\u043D\u043E\u0435 &quot;\u042F&quot;, \u0430 \u0441\u043D\u0430\u0440\u0443\u0436\u0438 \u041E\u043D \u044F\u0432\u043B\u044F\u0435\u0442 \u0441\u0435\u0431\u044F \u043A\u0430\u043A \u0432\u0441\u044F \u0432\u0441\u0435\u043B\u0435\u043D\u043D\u0430\u044F. \u041F\u043E\u044D\u0442\u043E\u043C\u0443 \u0442\u0430\u043A\u043E\u0439 \u043F\u0440\u043E\u0441\u0432\u0435\u0442\u043B\u0435\u043D\u043D\u044B\u0439 Yog\u012B \u0432\u0441\u0435 \u0432\u0440\u0435\u043C\u044F \u0432\u043E\u0441\u043F\u0440\u0438\u043D\u0438\u043C\u0430\u0435\u0442 \u0442\u043E\u043B\u044C\u043A\u043E \u0411\u043E\u0433\u0430. \u042D\u0442\u043E \u0443\u0434\u0438\u0432\u0438\u0442\u0435\u043B\u044C\u043D\u043E\u0435 \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435 \u0441\u043E\u0437\u043D\u0430\u043D\u0438\u044F \u0438\u0437\u0432\u0435\u0441\u0442\u043D\u043E \u043A\u0430\u043A Pratim\u012Blana.</p></li><li><p>\u0412\u044B\u0440\u0430\u0436\u0435\u043D\u0438\u0435 &quot;\u0432\u043E\u0437\u043D\u0438\u043A\u0448\u0430\u044F \u0438\u0437 \u1E62a\u1E0Dadhv\u0101 --\u0428\u0435\u0441\u0442\u0438 \u041F\u0443\u0442\u0435\u0439--&quot; \u043E\u0437\u043D\u0430\u0447\u0430\u0435\u0442, \u0447\u0442\u043E \u0442\u0430\u043A\u0430\u044F \u043E\u0441\u0432\u043E\u0431\u043E\u0436\u0434\u0435\u043D\u043D\u0430\u044F \u0434\u0443\u0448\u0430 \u0432\u044B\u0448\u043B\u0430 \u0437\u0430 \u0438\u0445 \u043F\u0440\u0435\u0434\u0435\u043B\u044B. \u041C\u0435\u0436\u0434\u0443 \u0442\u0435\u043C, \u0441\u043B\u043E\u0432\u0430 &quot;mala, karma \u0438 kal\u0101&quot; \u0443\u043A\u0430\u0437\u044B\u0432\u0430\u044E\u0442 \u043D\u0430 &quot;\u0100\u1E47avamala, K\u0101rmamala \u0438 M\u0101y\u012Byamala&quot;. \u041F\u043E\u0447\u0435\u043C\u0443? \u0412\u043E-\u043F\u0435\u0440\u0432\u044B\u0445, \u0100\u1E47avamala \u043E\u0447\u0435\u043D\u044C \u0447\u0430\u0441\u0442\u043E \u043E\u0431\u043E\u0437\u043D\u0430\u0447\u0430\u0435\u0442\u0441\u044F \u043F\u0440\u043E\u0441\u0442\u043E \u0442\u0435\u0440\u043C\u0438\u043D\u043E\u043C &quot;mala&quot; (\u0437\u0430\u0433\u0440\u044F\u0437\u043D\u0435\u043D\u0438\u0435), \u043F\u043E\u0442\u043E\u043C\u0443 \u0447\u0442\u043E \u044D\u0442\u043E \u0441\u0430\u043C\u043E\u0435 \u0432\u0430\u0436\u043D\u043E\u0435 \u0437\u0430\u0433\u0440\u044F\u0437\u043D\u0435\u043D\u0438\u0435. \u0414\u0430\u043B\u0435\u0435, \u043F\u043E\u0441\u043A\u043E\u043B\u044C\u043A\u0443 \u0441\u043B\u043E\u0432\u043E &quot;karma&quot; \u043E\u0437\u043D\u0430\u0447\u0430\u0435\u0442 &quot;\u0434\u0435\u0439\u0441\u0442\u0432\u0438\u0435&quot;, \u0441\u0442\u0430\u043D\u043E\u0432\u0438\u0442\u0441\u044F \u043E\u0447\u0435\u0432\u0438\u0434\u043D\u043E\u0439 \u043F\u0440\u0438\u0447\u0438\u043D\u0430, \u043F\u043E\u0447\u0435\u043C\u0443 K\u0101rmamala (\u0437\u0430\u0433\u0440\u044F\u0437\u043D\u0435\u043D\u0438\u0435, \u0441\u0432\u044F\u0437\u0430\u043D\u043D\u043E\u0435 \u0441 \u0434\u0435\u043B\u0430\u0442\u0435\u043B\u0435\u043C) \u0442\u0430\u043A \u043D\u0430\u0437\u044B\u0432\u0430\u0435\u0442\u0441\u044F. \u041D\u043E \u043E\u0447\u0435\u043D\u044C \u0441\u0442\u0440\u0430\u043D\u043D\u043E, \u0447\u0442\u043E \u0432 \u0441\u0442\u0440\u043E\u0444\u0435 Svacchandatantra M\u0101y\u012Byamala \u043D\u0430\u0437\u0432\u0430\u043D\u0430 &quot;kal\u0101&quot;, \u043F\u043E\u0441\u043A\u043E\u043B\u044C\u043A\u0443 &quot;kal\u0101&quot; \u043E\u0431\u044B\u0447\u043D\u043E \u043E\u0437\u043D\u0430\u0447\u0430\u0435\u0442 &quot;\u015Bakti&quot;, \u0438\u043B\u0438 &quot;\u0441\u0438\u043B\u0443&quot;. \u0422\u0430\u043A \u0438\u043B\u0438 \u0438\u043D\u0430\u0447\u0435, \u0435\u0441\u043B\u0438 \u0432\u044B \u043F\u0440\u0438\u0431\u0435\u0433\u043D\u0435\u0442\u0435 \u043A \u0441\u043B\u043E\u0432\u0430\u0440\u044E, \u0432\u044B \u043E\u0431\u043D\u0430\u0440\u0443\u0436\u0438\u0442\u0435, \u0447\u0442\u043E \u044D\u0442\u043E \u0441\u043B\u043E\u0432\u043E \u0433\u043B\u0430\u0432\u043D\u044B\u043C \u043E\u0431\u0440\u0430\u0437\u043E\u043C \u043E\u0437\u043D\u0430\u0447\u0430\u0435\u0442 &quot;\u0447\u0430\u0441\u0442\u044C&quot;. \u0418 \u044D\u0442\u043E \u043A\u043B\u044E\u0447 \u043A \u0440\u0430\u0437\u0433\u0430\u0434\u043A\u0435 \u0442\u0430\u0439\u043D\u044B: M\u0101y\u012Byamala \u0437\u0430\u0441\u0442\u0430\u0432\u043B\u044F\u0435\u0442 \u0432\u0430\u0441 \u0441\u0447\u0438\u0442\u0430\u0442\u044C, \u0447\u0442\u043E \u0432\u0435\u0449\u0438 \u043E\u0442\u043B\u0438\u0447\u0430\u044E\u0442\u0441\u044F \u0434\u0440\u0443\u0433 \u043E\u0442 \u0434\u0440\u0443\u0433\u0430. \u0422\u0430\u043A\u0438\u043C \u043E\u0431\u0440\u0430\u0437\u043E\u043C, M\u0101y\u012Byamala \u043F\u043E\u0440\u043E\u0436\u0434\u0430\u0435\u0442 \u0432\u0441\u044E \u0432\u0441\u0435\u043B\u0435\u043D\u043D\u0443\u044E, \u0441\u043E\u0441\u0442\u043E\u044F\u0449\u0443\u044E \u0438\u0437 \u0447\u0430\u0441\u0442\u0435\u0439, \u043A\u0430\u0436\u0434\u0430\u044F \u0438\u0437 \u043A\u043E\u0442\u043E\u0440\u044B\u0445 \u043E\u0442\u043B\u0438\u0447\u043D\u0430 \u043E\u0442 \u0434\u0440\u0443\u0433\u0438\u0445. \u0422\u0435\u043F\u0435\u0440\u044C \u0437\u0430\u0433\u0430\u0434\u043A\u0430 \u0438\u0441\u0447\u0435\u0437\u043B\u0430!</p></li></ol><p>\u0418, \u043E\u0447\u0435\u0432\u0438\u0434\u043D\u043E, \u043E\u043D \u2014 \u0442\u043E\u0442, \u0447\u044C\u044F \u0438\u0437\u043D\u0443\u0440\u0438\u0442\u0435\u043B\u044C\u043D\u0430\u044F \u0440\u0430\u0431\u043E\u0442\u0430 \u043F\u0440\u0435\u043A\u0440\u0430\u0442\u0438\u043B\u0430\u0441\u044C (vigataklama), \u043F\u043E\u0441\u043A\u043E\u043B\u044C\u043A\u0443 \u043E\u043D \u043F\u043E\u043B\u043D\u043E\u0441\u0442\u044C\u044E \u0441\u0432\u043E\u0431\u043E\u0434\u0435\u043D \u043E\u0442 \u0432\u0441\u0435\u0433\u043E, \u0447\u0442\u043E \u043A\u0430\u0441\u0430\u0435\u0442\u0441\u044F \u044D\u0442\u043E\u0433\u043E \u043C\u0438\u0440\u0430. \u0423 \u043D\u0435\u0433\u043E \u0431\u043E\u043B\u0435\u0435 \u043D\u0435\u0442 \u043F\u0440\u043E\u0431\u043B\u0435\u043C, \u043F\u043E\u0442\u043E\u043C\u0443 \u0447\u0442\u043E, &quot;\u0447\u0442\u043E\u0431\u044B \u0438\u043C\u0435\u0442\u044C \u043F\u0440\u043E\u0431\u043B\u0435\u043C\u0443&quot;, \u0434\u043B\u044F \u043D\u0430\u0447\u0430\u043B\u0430 \u043D\u0443\u0436\u0435\u043D &quot;\u0438\u043D\u0434\u0438\u0432\u0438\u0434&quot;. \u041F\u043E\u0441\u043A\u043E\u043B\u044C\u043A\u0443 \u044D\u0442\u043E\u0442 \u0432\u0435\u043B\u0438\u043A\u0438\u0439 Yog\u012B \u0432\u044B\u0448\u0435\u043B \u0437\u0430 \u043F\u0440\u0435\u0434\u0435\u043B\u044B \u0441\u0432\u043E\u0435\u0439 \u0438\u043D\u0434\u0438\u0432\u0438\u0434\u0443\u0430\u043B\u044C\u043D\u043E\u0441\u0442\u0438 \u0438 \u043E\u0441\u043E\u0437\u043D\u0430\u043B \u0441\u0432\u043E\u044E \u0431\u043E\u0436\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0441\u0442\u044C, \u0432 \u043D\u0435\u043C \u0431\u043E\u043B\u044C\u0448\u0435 \u043D\u0435\u0442 &quot;\u0438\u043D\u0434\u0438\u0432\u0438\u0434\u0443\u0443\u043C\u0430&quot;. \u041F\u043E\u0441\u043A\u043E\u043B\u044C\u043A\u0443 \u0438\u043D\u0434\u0438\u0432\u0438\u0434\u0443\u0430\u043B\u044C\u043D\u043E\u0441\u0442\u044C \u043E\u0442\u0441\u0443\u0442\u0441\u0442\u0432\u0443\u0435\u0442, \u043F\u0440\u043E\u0431\u043B\u0435\u043C\u044B \u0442\u0430\u043A\u0436\u0435 \u043D\u0435 \u043C\u043E\u0433\u0443\u0442 \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u043E\u0432\u0430\u0442\u044C. \u041F\u0440\u043E\u0441\u0442\u043E \u0436\u0438\u0432\u043E\u0433\u043E \u0442\u0435\u043B\u0430 \u043D\u0435\u0434\u043E\u0441\u0442\u0430\u0442\u043E\u0447\u043D\u043E, \u0447\u0442\u043E\u0431\u044B &quot;\u0438\u043C\u0435\u0442\u044C \u043F\u0440\u043E\u0431\u043B\u0435\u043C\u0443&quot;. \u042D\u0442\u043E \u0441\u043B\u043E\u0436\u043D\u043E \u0434\u043B\u044F \u0432\u044B\u0440\u0430\u0436\u0435\u043D\u0438\u044F \u0441\u043B\u043E\u0432\u0430\u043C\u0438, \u043D\u043E \u043F\u0440\u043E\u0441\u0442\u043E, \u0435\u0441\u043B\u0438 \u0435\u0441\u0442\u044C \u044D\u0442\u043E\u0442 \u043E\u043F\u044B\u0442. \u041F\u043E\u044D\u0442\u043E\u043C\u0443, \u0432\u0441\u0435\u043C\u0438 \u0441\u0432\u043E\u0438\u043C\u0438 \u0441\u0438\u043B\u0430\u043C\u0438, \u043E\u0442 \u0432\u0441\u0435\u0433\u043E \u0441\u0435\u0440\u0434\u0446\u0430, \u0441\u0442\u0440\u0435\u043C\u0438\u0442\u0435\u0441\u044C \u0431\u044B\u0442\u044C \u043F\u043E\u0434\u043E\u0431\u043D\u044B\u043C\u0438 \u0435\u043C\u0443: \u0410\u0431\u0441\u043E\u043B\u044E\u0442\u043D\u043E \u0421\u0432\u043E\u0431\u043E\u0434\u043D\u044B\u043C\u0438!</p><ol start="4"><li>\u0417\u043D\u0430\u0447\u0435\u043D\u0438\u0435 \u044D\u0442\u043E\u0433\u043E \u0442\u0435\u0440\u043C\u0438\u043D\u0430 \u0443\u0436\u0435 \u0440\u0430\u0437\u044A\u044F\u0441\u043D\u044F\u043B\u043E\u0441\u044C .</li></ol></div><div class="stanza"><h2 id="\u043A\u043E\u043D\u0435\u0446-\u0433n\u0430\u0432\u044B-iii-\u0438-\u0441\u0432\u044F\u0449\u0435\u043D\u043D\u043E\u0433\u043E-\u043F\u0438\u0441\u0430\u043D\u0438\u044F" tabindex="-1">\u041A\u043E\u043D\u0435\u0446 \u0413\u043B\u0430\u0432\u044B III \u0438 \u0421\u0432\u044F\u0449\u0435\u043D\u043D\u043E\u0433\u043E \u041F\u0438\u0441\u0430\u043D\u0438\u044F <a class="header-anchor" href="#\u043A\u043E\u043D\u0435\u0446-\u0433n\u0430\u0432\u044B-iii-\u0438-\u0441\u0432\u044F\u0449\u0435\u043D\u043D\u043E\u0433\u043E-\u043F\u0438\u0441\u0430\u043D\u0438\u044F" aria-hidden="true">#</a></h2><div class="sans"><blockquote><p>\u0938\u0947\u092F\u092E\u093E\u0917\u092E\u0938\u0902\u0935\u093E\u0926\u0938\u094D\u092A\u0928\u094D\u0926\u0938\u0919\u094D\u0917\u0924\u093F\u0938\u0941\u0928\u094D\u0926\u0930\u093E\u0964<br> \u0935\u0943\u0924\u094D\u0924\u093F\u0903 \u0936\u0948\u0935\u0930\u0939\u0938\u094D\u092F\u093E\u0930\u094D\u0925\u0947 \u0936\u093F\u0935\u0938\u0942\u0924\u094D\u0930\u0947\u0937\u0941 \u0926\u0930\u094D\u0936\u093F\u0924\u093E\u0965\u0967\u0965</p></blockquote><blockquote><p>\u0936\u093F\u0935\u0930\u0939\u0938\u094D\u092F\u0928\u093F\u0926\u0930\u094D\u0936\u0928\u0938\u0902\u0938\u094D\u0930\u0935\u0928\u094D\u0928\u0935\u0928\u0935\u093E\u092E\u0943\u0924\u0938\u093E\u0930\u0930\u0938\u094B\u0932\u094D\u092C\u0923\u093E\u092E\u094D\u0964<br> \u0938\u0941\u0915\u0943\u0924\u093F\u0928\u094B \u0930\u0938\u092F\u0928\u094D\u0924\u0941 \u092D\u0935\u091A\u094D\u091B\u093F\u0926\u0947 \u0938\u094D\u092B\u0941\u091F\u092E\u093F\u092E\u093E\u0902 \u0936\u093F\u0935\u0938\u0942\u0924\u094D\u0930\u0935\u093F\u092E\u0930\u094D\u0936\u093F\u0928\u0940\u092E\u094D\u0965\u0968\u0965</p></blockquote><blockquote><p>\u0907\u092F\u092E\u0930\u094B\u091A\u0915\u093F\u0928\u093E\u0902 \u0930\u0941\u091A\u093F\u0935\u0930\u094D\u0927\u093F\u0928\u0940 \u092A\u0930\u093F\u0923\u0924\u093F\u0902 \u0924\u0928\u0941\u0924\u0947 \u092A\u0930\u092E\u093E\u0902 \u092E\u0924\u0947\u0903\u0964<br> \u0930\u0938\u0928\u092E\u093E\u0924\u094D\u0930\u0924 \u090F\u0935 \u0938\u0941\u0927\u094C\u0918\u0935\u0928\u094D\u092E\u0943\u0924\u093F\u091C\u0930\u093E\u091C\u0928\u0928\u093E\u0926\u093F\u092D\u092F\u093E\u092A\u0939\u0943\u0924\u094D\u0965\u0969\u0965</p></blockquote><blockquote><p>\u0926\u0947\u0939\u092A\u094D\u0930\u093E\u0923\u0938\u0941\u0916\u093E\u0926\u093F\u092D\u093F\u0903 \u092A\u0930\u093F\u092E\u093F\u0924\u093E\u0939\u0928\u094D\u0924\u093E\u0938\u094D\u092A\u0926\u0948\u0903 \u0938\u0902\u0935\u0943\u0924\u0936\u094D\u091A\u0948\u0924\u0928\u094D\u092F\u0902 \u091A\u093F\u0928\u0941\u0924\u0947 \u0928\u093F\u091C\u0902 \u0928 \u0938\u0941\u092E\u0939\u0928\u094D\u092E\u093E\u0939\u0947\u0936\u094D\u0935\u0930\u0902 \u0938\u094D\u0935\u0902 \u091C\u0928\u0903\u0964<br> \u092E\u0927\u094D\u092F\u0947 \u092C\u094B\u0927\u0938\u0941\u0927\u093E\u092C\u094D\u0927\u093F \u0935\u093F\u0936\u094D\u0935\u092E\u092D\u093F\u0924\u0938\u094D\u0924\u0924\u094D\u092B\u0947\u0928\u092A\u093F\u0923\u094D\u0921\u094B\u092A\u092E\u0902 \u092F\u0903 \u092A\u0936\u094D\u092F\u0947\u0926\u0941\u092A\u0926\u0947\u0936\u0924\u0938\u094D\u0924\u0941 \u0915\u0925\u093F\u0924\u0903 \u0938\u093E\u0915\u094D\u0937\u093E\u0924\u094D\u0938 \u090F\u0915\u0903 \u0936\u093F\u0935\u0903\u0965\u096A\u0965</p></blockquote><blockquote><p>\u0924\u0930\u0924 \u0924\u0930\u0938\u093E \u0938\u0902\u0938\u093E\u0930\u093E\u092C\u094D\u0927\u093F\u0902 \u0935\u093F\u0927\u0924\u094D\u0924 \u092A\u0930\u0947 \u092A\u0926\u0947 \u092A\u0926\u092E\u0935\u093F\u091A\u0932\u0902 \u0928\u093F\u0924\u094D\u092F\u093E\u0932\u094B\u0915\u092A\u094D\u0930\u092E\u094B\u0926\u0938\u0941\u0928\u093F\u0930\u094D\u092D\u0930\u0947\u0964<br> \u0935\u093F\u092E\u0943\u0936\u0924 \u0936\u093F\u0935\u092A\u094D\u0930\u094B\u0915\u094D\u0924\u0902 \u0938\u0942\u0924\u094D\u0930\u0902 \u0930\u0939\u0938\u094D\u092F\u0938\u092E\u0941\u091C\u094D\u091C\u094D\u0935\u0932\u0902 \u092A\u094D\u0930\u0938\u092D\u0935\u093F\u0932\u0938\u0924\u094D\u0938\u0926\u094D\u092F\u0941\u0915\u094D\u0924\u094D\u092F\u093E\u0928\u094D\u0924\u0903 \u0938\u092E\u0941\u0924\u094D\u092A\u094D\u0932\u0935\u0926\u093E\u092F\u093F \u0924\u0924\u094D\u0965\u096B\u0965</p></blockquote><p>\u0907\u0924\u093F \u0936\u094D\u0930\u0940\u092E\u0928\u094D\u092E\u0939\u093E\u092E\u093E\u0939\u0947\u0936\u094D\u0935\u0930\u093E\u091A\u093E\u0930\u094D\u092F\u0935\u0930\u094D\u092F\u093E\u092D\u093F\u0928\u0935\u0917\u0941\u092A\u094D\u0924\u092A\u093E\u0926\u092A\u0926\u094D\u092E\u094B\u092A\u091C\u0940\u0935\u093F\u0936\u094D\u0930\u0940\u0915\u094D\u0937\u0947\u092E\u0930\u093E\u091C\u0935\u093F\u0930\u091A\u093F\u0924\u093E\u092F\u093E\u0902 \u0936\u093F\u0935\u0938\u0942\u0924\u094D\u0930\u0935\u093F\u092E\u0930\u094D\u0936\u093F\u0928\u094D\u092F\u093E\u092E\u093E\u0923\u0935\u094B\u092A\u093E\u092F\u092A\u094D\u0930\u0915\u093E\u0936\u0928\u0902 \u0928\u093E\u092E \u0924\u0943\u0924\u0940\u092F \u0909\u0928\u094D\u092E\u0947\u0937\u0903\u0965\u0969\u0965</p><blockquote><p>\u0938\u092E\u093E\u092A\u094D\u0924\u093E \u091A\u0947\u092F\u0902 \u0936\u093F\u0935\u0938\u0942\u0924\u094D\u0930\u0935\u093F\u092E\u0930\u094D\u0936\u093F\u0928\u0940\u0965</p></blockquote><p>\xA0</p><blockquote><p>\u0915\u0943\u0924\u093F\u0903 \u0936\u094D\u0930\u0940\u0915\u094D\u0937\u0947\u092E\u0930\u093E\u091C\u0938\u094D\u092F \u0915\u094D\u0937\u0947\u092E\u093E\u092F\u093E\u0938\u094D\u0924\u0941 \u0935\u093F\u092E\u0930\u094D\u0936\u093F\u0928\u093E\u092E\u094D\u0964<br> \u0936\u093F\u0935\u0938\u094D\u0935\u093E\u0924\u094D\u092E\u0948\u0915\u094D\u092F\u092C\u094B\u0927\u093E\u0930\u094D\u0925\u093E \u0936\u093F\u0935\u0938\u0942\u0924\u094D\u0930\u0935\u093F\u092E\u0930\u094D\u0936\u093F\u0928\u0940\u0965 ;;;</p></blockquote><hr><div class="trans"><blockquote><p>Seyam\u0101gamasa\u1E41v\u0101daspandasa\u1E45gatisundar\u0101|<br> V\u1E5Btti\u1E25 \u015Baivarahasy\u0101rthe \u015Bivas\u016Btre\u1E63u dar\u015Bit\u0101||1||</p></blockquote><blockquote><p>\u015Aivarahasyanidar\u015Banasa\u1E41sravannavanav\u0101m\u1E5Btas\u0101rarasolba\u1E47\u0101m|<br> Suk\u1E5Btino rasayantu bhavacchide sphu\u1E6Damim\u0101\u1E41 \u015Bivas\u016Btravimar\u015Bin\u012Bm||2||</p></blockquote><blockquote><p>Iyamarocakin\u0101\u1E41 rucivardhin\u012B pari\u1E47ati\u1E41 tanute param\u0101\u1E41 mate\u1E25|<br> Rasanam\u0101trata eva sudhaughavanm\u1E5Btijar\u0101janan\u0101dibhay\u0101pah\u1E5Bt||3||</p></blockquote><blockquote><p>Dehapr\u0101\u1E47asukh\u0101dibhi\u1E25 parimit\u0101hant\u0101spadai\u1E25 sa\u1E41v\u1E5Bta\u015Bcaitanya\u1E41 cinute nija\u1E41 na sumahanm\u0101he\u015Bvara\u1E41 sva\u1E41 jana\u1E25|<br> Madhye bodhasudh\u0101bdhi vi\u015Bvamabhitastatphenapi\u1E47\u1E0Dopama\u1E41 ya\u1E25 pa\u015Byedupade\u015Batastu kathita\u1E25 s\u0101k\u1E63\u0101tsa eka\u1E25 \u015Biva\u1E25||4||</p></blockquote><blockquote><p>Tarata taras\u0101 sa\u1E41s\u0101r\u0101bdhi\u1E41 vidhatta pare pade padamavicala\u1E41 nity\u0101lokapramodasunirbhare|<br> Vim\u1E5B\u015Bata \u015Bivaprokta\u1E41 s\u016Btra\u1E41 rahasyasamujjvala\u1E41 prasabhavilasatsadyukty\u0101nta\u1E25 samutplavad\u0101yi tat||5||</p></blockquote><p>Iti \u015Br\u012Bmanmah\u0101m\u0101he\u015Bvar\u0101c\u0101ryavary\u0101bhinavaguptap\u0101dapadmopaj\u012Bvi\u015Br\u012Bk\u1E63emar\u0101javiracit\u0101y\u0101\u1E41 \u015Bivas\u016Btravimar\u015Biny\u0101m\u0101\u1E47avop\u0101yaprak\u0101\u015Bana\u1E41 n\u0101ma t\u1E5Bt\u012Bya unme\u1E63a\u1E25||3||</p><blockquote><p>Sam\u0101pt\u0101 ceya\u1E41 \u015Bivas\u016Btravimar\u015Bin\u012B||</p></blockquote><blockquote><p>K\u1E5Bti\u1E25 \u015Br\u012Bk\u1E63emar\u0101jasya k\u1E63em\u0101y\u0101stu vimar\u015Bin\u0101m|<br> \u015Aivasv\u0101tmaikyabodh\u0101rth\u0101 \u015Bivas\u016Btravimar\u015Bin\u012B||</p></blockquote></div></div><hr><blockquote><p>&quot;\u042D\u0442\u043E\u0442 \u0441\u0430\u043C\u044B\u0439 <em>(s\u0101 iyam)</em> \u043A\u043E\u043C\u043C\u0435\u043D\u0442\u0430\u0440\u0438\u0439 <em>(v\u1E5Btti\u1E25)</em> \u043D\u0430 \u015Aivas\u016Btra-s <em>(\u015Bivas\u016Btre\u1E63u)</em>, \u0443\u043A\u0440\u0430\u0448\u0435\u043D\u043D\u044B\u0439 <em>(sundar\u0101)</em> \u0441\u0432\u043E\u0435\u0439 \u0441\u0432\u044F\u0437\u044C\u044E <em>(sa\u1E45gati)</em> \u0441\u043E \u0421\u043F\u0430\u043D\u0434\u0430\u043A\u0430\u0440\u0438\u043A\u0430\u043C\u0438 (Spandak\u0101rik\u0101-s) --\u043F\u043E\u0441\u043B\u0435\u0434\u043E\u0432\u0430\u0442\u0435\u043B\u044C\u043D\u044B\u043C \u043A\u043E\u043C\u043C\u0435\u043D\u0442\u0430\u0440\u0438\u0435\u043C \u043D\u0430 \u015Aivas\u016Btra-s-- <em>(spanda)</em> [\u0438] \u0431\u043B\u0430\u0433\u043E\u0434\u0430\u0440\u044F \u0441\u0432\u043E\u0435\u0439 \u0441\u043E\u0433\u043B\u0430\u0441\u043E\u0432\u0430\u043D\u043D\u043E\u0441\u0442\u0438 <em>(sa\u1E41v\u0101da)</em> \u0441 \u0420\u0430\u0441\u043A\u0440\u044B\u0442\u044B\u043C\u0438 \u0421\u0432\u044F\u0449\u0435\u043D\u043D\u044B\u043C\u0438 \u041F\u0438\u0441\u0430\u043D\u0438\u044F\u043C\u0438 <em>(\u0101gama)</em>, \u0431\u044B\u043B \u044F\u0432\u043B\u0435\u043D <em>(dar\u015Bit\u0101)</em> \u0434\u043B\u044F [\u0440\u0430\u0441\u043A\u0440\u044B\u0442\u0438\u044F] <em>(arthe)</em> \u0442\u0430\u0439\u043D\u044B <em>(rahasya)</em> \u015Aiva <em>(\u015Baiva)</em><sup>1</sup>&quot;||1||</p></blockquote><blockquote><p>&quot;\u0427\u0442\u043E\u0431\u044B \u043D\u0435\u0441\u043E\u043C\u043D\u0435\u043D\u043D\u043E <em>(sphu\u1E6Dam)</em> \u043F\u0440\u0435\u043A\u0440\u0430\u0442\u0438\u0442\u044C <em>(chide)</em> \u0442\u0440\u0430\u043D\u0441\u043C\u0438\u0433\u0440\u0430\u0446\u0438\u043E\u043D\u043D\u043E\u0435 \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u043E\u0432\u0430\u043D\u0438\u0435 <em>(bhava)</em>, \u043F\u0443\u0441\u0442\u044C \u0434\u043E\u0431\u0440\u043E\u0434\u0435\u0442\u0435\u043B\u044C\u043D\u044B\u0435 <em>(suk\u1E5Btina\u1E25)</em> \u043D\u0430\u0441\u043B\u0430\u0434\u044F\u0442\u0441\u044F \u0432\u043A\u0443\u0441\u043E\u043C <em>(rasayantu)</em> \u044D\u0442\u043E\u0439 <em>(im\u0101m)</em> \u015Aivas\u016Btravimar\u015Bin\u012B <em>(\u015Bivas\u016Btravimar\u015Bin\u012Bm)</em>, \u043E\u0431\u0438\u043B\u044C\u043D\u043E \u0441\u043D\u0430\u0431\u0436\u0435\u043D\u043D\u043E\u0439 <em>(ulba\u1E47\u0101m)</em> \u044D\u043B\u0438\u043A\u0441\u0438\u0440\u043E\u043C <em>(rasa)</em>, \u043F\u0440\u043E\u0438\u0437\u0432\u0435\u0434\u0435\u043D\u043D\u044B\u043C \u0438\u0437 \u0441\u0443\u0449\u043D\u043E\u0441\u0442\u0438 <em>(s\u0101ra)</em> \u0432\u0435\u0447\u043D\u043E \u043D\u043E\u0432\u043E\u0433\u043E <em>(navanava)</em> \u041D\u0435\u043A\u0442\u0430\u0440\u0430 <em>(am\u1E5Bta)</em>, \u043A\u043E\u0442\u043E\u0440\u044B\u0439 \u0432\u044B\u0442\u0435\u043A\u0430\u0435\u0442 <em>(sa\u1E41sravat)</em> \u0438\u0437 \u0443\u0447\u0435\u043D\u0438\u044F <em>(nidar\u015Bana)</em> \u043E \u0442\u0430\u0439\u043D\u043E\u0439 \u0434\u043E\u043A\u0442\u0440\u0438\u043D\u0435 <em>(rahasya)</em> \u015Aiva <em>(\u015Biva)</em>!&quot;||2||</p></blockquote><blockquote><p>&quot;\u042D\u0442\u0430 [\u015Aivas\u016Btravimar\u015Bin\u012B] <em>(iyam)</em> \u0443\u0432\u0435\u043B\u0438\u0447\u0438\u0432\u0430\u0435\u0442 <em>(vardhin\u012B)</em> \u043F\u043E\u0442\u0440\u0435\u0431\u043D\u043E\u0441\u0442\u044C <em>(ruci)</em> [\u0432 \u0437\u043D\u0430\u043D\u0438\u0438 --\u0432 \u0444\u043E\u0440\u043C\u0435 \u0434\u043E\u043A\u0442\u0440\u0438\u043D\u044B \u015Aiva--] \u0443 \u0442\u0435\u0445, \u043A\u0442\u043E \u043D\u0435 \u0438\u043C\u0435\u0435\u0442 \u0435\u0451 <em>(arocakin\u0101m)</em>, [\u0438] \u043E\u0441\u0443\u0449\u0435\u0441\u0442\u0432\u043B\u044F\u0435\u0442 <em>(tanute)</em> \u0432\u044B\u0441\u0448\u0443\u044E <em>(param\u0101m)</em> \u0442\u0440\u0430\u043D\u0441\u0444\u043E\u0440\u043C\u0430\u0446\u0438\u044E <em>(pari\u1E47atim)</em> [\u0441\u0432\u043E\u0435\u0433\u043E] \u043F\u043E\u043D\u0438\u043C\u0430\u043D\u0438\u044F <em>(mate\u1E25)</em>. \u041F\u043E\u0441\u0440\u0435\u0434\u0441\u0442\u0432\u043E\u043C \u043F\u0440\u043E\u0441\u0442\u043E\u0433\u043E \u0432\u043A\u0443\u0448\u0435\u043D\u0438\u044F [\u0435\u0451] <em>(rasana-m\u0101tratas eva)</em>, \u043E\u043D\u0430 \u0443\u043D\u0438\u0447\u0442\u043E\u0436\u0430\u0435\u0442 <em>(apah\u1E5Bt)</em> \u0441\u0442\u0440\u0430\u0445 <em>(bhaya)</em> \u0441\u043C\u0435\u0440\u0442\u0438 <em>(m\u1E5Bti)</em>, \u0441\u0442\u0430\u0440\u043E\u0441\u0442\u0438 <em>(jar\u0101)</em>, \u0440\u043E\u0436\u0434\u0435\u043D\u0438\u044F <em>(janana)</em> \u0438 \u043F\u0440. <em>(\u0101di)</em>, \u043F\u043E\u0434\u043E\u0431\u043D\u043E <em>(vat)</em> \u043F\u043E\u0442\u043E\u043A\u0443 <em>(ogha)</em> \u041D\u0435\u043A\u0442\u0430\u0440\u0430 <em>(sudh\u0101)</em><sup>2</sup>&quot;||3||</p></blockquote><blockquote><p>&quot;\u041F\u043E\u043A\u0440\u044B\u0442\u044B\u0439 <em>(sa\u1E41v\u1E5Bta\u1E25)</em> \u0442\u0435\u043B\u043E\u043C, \u0436\u0438\u0437\u043D\u0435\u043D\u043D\u043E\u0439 \u044D\u043D\u0435\u0440\u0433\u0438\u0435\u0439, \u0443\u0434\u043E\u0432\u043E\u043B\u044C\u0441\u0442\u0432\u0438\u0435\u043C \u0438 \u0442.\u0434. <em>(deha-pr\u0101\u1E47a-sukha-\u0101dibhi\u1E25)</em>, \u0438\u0437-\u0437\u0430 \u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u043D\u043E\u0441\u0442\u0438 \u043C\u0435\u0441\u0442\u0430 <em>(parimita... \u0101spadai\u1E25)</em> \u0434\u043B\u044F [\u0441\u0432\u043E\u0435\u0433\u043E] \u0447\u0443\u0432\u0441\u0442\u0432\u0430 \u0421\u0430\u043C\u043E\u0441\u0442\u0438 --\u0434\u043B\u044F \u0441\u0432\u043E\u0435\u0433\u043E \u042F-\u0421\u043E\u0437\u043D\u0430\u043D\u0438\u044F-- <em>(ahant\u0101)</em>, \u0447\u0435\u043B\u043E\u0432\u0435\u043A <em>(jana\u1E25)</em> \u043D\u0435 <em>(na)</em> \u0432\u043E\u0441\u043F\u0440\u0438\u043D\u0438\u043C\u0430\u0435\u0442 <em>(cinute)</em> \u0410\u0431\u0441\u043E\u043B\u044E\u0442\u043D\u043E \u0421\u0432\u043E\u0431\u043E\u0434\u043D\u043E\u0435 \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u0435 <em>(caitanyam)</em> \u0432\u0435\u043B\u0438\u043A\u043E\u043B\u0435\u043F\u043D\u0435\u0439\u0448\u0435\u0433\u043E \u0413\u043E\u0441\u043F\u043E\u0434\u0430 <em>(sumahat-m\u0101he\u015Bvaram)</em> \u043A\u0430\u043A \u0441\u0432\u043E\u0435 \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0435 <em>(nijam... svam)</em>. \u041E\u0434\u043D\u0430\u043A\u043E <em>(tu)</em>, \u043E\u043D <em>(sa\u1E25)</em>, \u0433\u043E\u0432\u043E\u0440\u0438\u0442\u0441\u044F <em>(kathita\u1E25)</em>, [\u0435\u0441\u0442\u044C] \u0421\u0430\u043C \u015Aiva <em>(eka\u1E25 \u015Biva\u1E25)</em> \u0432 \u0447\u0435\u043B\u043E\u0432\u0435\u043A\u0435 <em>(s\u0101k\u1E63\u0101t)</em>, \u043A\u043E\u0442\u043E\u0440\u044B\u0439 <em>(ya\u1E25)</em> \u2014\u0431\u043B\u0430\u0433\u043E\u0434\u0430\u0440\u044F [\u043F\u0435\u0440\u0435\u0434\u0430\u043D\u043D\u043E\u043C\u0443] \u0443\u0447\u0435\u043D\u0438\u044E <em>(upade\u015Batas)</em>\u2014 \u0441\u043E\u0437\u0435\u0440\u0446\u0430\u0435\u0442 <em>(pa\u015Byet)</em> \u0432\u0441\u0435\u043B\u0435\u043D\u043D\u0443\u044E <em>(vi\u015Bvam)</em> \u0432 \u0441\u0435\u0440\u0435\u0434\u0438\u043D\u0435 <em>(madhye)</em> \u043E\u043A\u0435\u0430\u043D\u0430 <em>(abdhi)</em> \u041D\u0435\u043A\u0442\u0430\u0440\u0430 <em>(sudh\u0101)</em> \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u044F <em>(bodha)</em>, \u043A\u0430\u043A <em>(upamam)</em> \u043C\u0430\u0441\u0441\u0443 <em>(pi\u1E47\u1E0Da)</em> \u0435\u0433\u043E --\u044D\u0442\u043E\u0433\u043E \u043E\u043A\u0435\u0430\u043D\u0430-- <em>(tad)</em> \u043F\u0435\u043D\u044B <em>(phena)</em> \u043F\u043E\u0432\u0441\u044E\u0434\u0443 <em>(abhitas)</em><sup>3</sup>&quot;||4||</p></blockquote><blockquote><p>&quot;\u041F\u0435\u0440\u0435\u0441\u0435\u043A\u0438\u0442\u0435 <em>(tarata)</em> \u0431\u044B\u0441\u0442\u0440\u043E <em>(taras\u0101)</em> \u043E\u043A\u0435\u0430\u043D <em>(abdhim)</em> Sa\u1E41s\u0101ra --\u0422\u0440\u0430\u043D\u0441\u043C\u0438\u0433\u0440\u0430\u0446\u0438\u0438, \u043F\u043E\u043B\u043D\u043E\u0439 \u0441\u0442\u0440\u0430\u0434\u0430\u043D\u0438\u0439-- <em>(sa\u1E41s\u0101ra)</em> [\u0438] \u0443\u0442\u0432\u0435\u0440\u0434\u0438\u0442\u0435\u0441\u044C <em>(vidhatta)</em> \u043D\u0435\u043A\u043E\u043B\u0435\u0431\u0438\u043C\u043E <em>(padam avicalam)</em> \u0432 \u0432\u044B\u0441\u0448\u0435\u043C \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0438 <em>(pare pade)</em>, \u043A\u043E\u0442\u043E\u0440\u043E\u0435 \u043F\u043E\u043B\u043D\u043E\u0441\u0442\u044C\u044E \u0437\u0430\u043F\u043E\u043B\u043D\u0435\u043D\u043E <em>(sunirbhare)</em> \u0432\u0435\u0447\u043D\u044B\u043C <em>(nitya)</em> \u0421\u0432\u0435\u0442\u043E\u043C <em>(\u0101loka)</em> [\u0438] \u0411\u043B\u0430\u0436\u0435\u043D\u0441\u0442\u0432\u043E\u043C <em>(pramoda)</em>! \u0420\u0430\u0437\u043C\u044B\u0448\u043B\u044F\u0439\u0442\u0435 <em>(vim\u1E5B\u015Bata)</em> \u043E S\u016Btra --\u0430\u0444\u043E\u0440\u0438\u0437\u043C\u0430\u0445-- <em>(s\u016Btram)</em>, \u043F\u0440\u043E\u0432\u043E\u0437\u0433\u043B\u0430\u0448\u0435\u043D\u043D\u044B\u0445 <em>(proktam)</em> \u015Aiva <em>(\u015Biva)</em>, [\u043A\u043E\u0442\u043E\u0440\u044B\u0435 \u0432\u043E\u0441\u043F\u0440\u0438\u043D\u0438\u043C\u0430\u044E\u0442\u0441\u044F] \u0438\u0437\u043B\u0443\u0447\u0430\u044E\u0449\u0438\u043C\u0438 \u0441\u0432\u0435\u0442 <em>(samujjvalam)</em>, [\u0431\u043B\u0430\u0433\u043E\u0434\u0430\u0440\u044F] \u0442\u0430\u0439\u043D\u043E\u043C\u0443 \u0443\u0447\u0435\u043D\u0438\u044E, [\u0441\u043E\u0434\u0435\u0440\u0436\u0430\u0449\u0435\u043C\u0443\u0441\u044F \u0432 \u041D\u0435\u0439 --\u0432 S\u016Btra--] <em>(rahasyam)</em>! \u042D\u0442\u0430 [S\u016Btra] <em>(tad)</em> \u0432\u044B\u0437\u044B\u0432\u0430\u0435\u0442 <em>(d\u0101yi)</em> \u0432\u0441\u043F\u043B\u0435\u0441\u043A [\u0411\u043B\u0430\u0436\u0435\u043D\u0441\u0442\u0432\u0430] <em>(samutplava)</em> [\u0438] \u043C\u043E\u0449\u043D\u043E <em>(prasabha)</em> \u0441\u0438\u044F\u0435\u0442 <em>(vilasat)</em> \u0432\u043D\u0443\u0442\u0440\u0438 <em>(antar)</em>, [\u043A\u043E\u0433\u0434\u0430 \u043F\u0440\u0435\u043F\u043E\u0434\u0430\u0435\u0442\u0441\u044F] \u043C\u0443\u0434\u0440\u0435\u0446\u043E\u043C <em>(sat-yukty\u0101)</em>&quot;||5||</p></blockquote><p>\u0417\u0434\u0435\u0441\u044C \u0437\u0430\u043A\u0430\u043D\u0447\u0438\u0432\u0430\u0435\u0442\u0441\u044F <em>(iti)</em> \u0442\u0440\u0435\u0442\u044C\u044F <em>(t\u1E5Bt\u012Bya\u1E25)</em> \u0413\u043B\u0430\u0432\u0430 <em>(unme\u1E63a\u1E25)</em>, \u043D\u0430\u0437\u044B\u0432\u0430\u0435\u043C\u0430\u044F <em>(n\u0101ma)</em> \u0100\u1E47avop\u0101yaprak\u0101\u015Bana --[\u0413\u043B\u0430\u0432\u0430], \u043E\u0442\u043A\u0440\u044B\u0432\u0430\u044E\u0449\u0430\u044F \u043C\u0435\u0442\u043E\u0434\u044B, \u043F\u0440\u0435\u0434\u043D\u0430\u0437\u043D\u0430\u0447\u0435\u043D\u043D\u044B\u0435 \u0434\u043B\u044F a\u1E47u, \u0438\u043B\u0438 \u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u043D\u043E\u0433\u043E \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u0430-- <em>(\u0101\u1E47ava-up\u0101ya-prak\u0101\u015Banam)</em>, \u0432 \u015Aivas\u016Btravimar\u015Bin\u012B <em>(\u015Bivas\u016Btravimar\u015Biny\u0101m)</em>, \u043D\u0430\u043F\u0438\u0441\u0430\u043D\u043D\u043E\u0439 <em>(viracit\u0101y\u0101m)</em> \u043F\u043E\u0447\u0442\u0435\u043D\u043D\u044B\u043C <em>(\u015Br\u012B)</em> K\u1E63emar\u0101ja <em>(k\u1E63emar\u0101ja)</em>, \u0437\u0430\u0432\u0438\u0441\u0438\u043C\u043E\u0433\u043E <em>(upaj\u012Bvi)</em> \u043E\u0442 \u043B\u043E\u0442\u043E\u0441\u043D\u044B\u0445 \u0441\u0442\u043E\u043F --\u0442.\u0435. \u0441\u0442\u043E\u043F, \u043F\u0440\u0435\u043A\u0440\u0430\u0441\u043D\u044B\u0445 \u043A\u0430\u043A \u043B\u043E\u0442\u043E\u0441-- <em>(p\u0101da-padma)</em> \u0432\u044B\u0434\u0430\u044E\u0449\u0435\u0433\u043E\u0441\u044F <em>(\u015Br\u012Bmat)</em> Abhinavagupta <em>(abhinavagupta)</em>, \u043B\u0443\u0447\u0448\u0435\u0433\u043E <em>(varya)</em> \u0438\u0437 \u0434\u0443\u0445\u043E\u0432\u043D\u044B\u0445 \u043D\u0430\u0441\u0442\u0430\u0432\u043D\u0438\u043A\u043E\u0432 <em>(\u0101c\u0101rya)</em> [\u0438] \u0432\u0435\u043B\u0438\u043A\u043E\u0433\u043E <em>(mah\u0101)</em> \u043F\u0440\u0435\u0434\u0430\u043D\u043D\u043E\u0433\u043E Mahe\u015Bvara, \u0412\u0435\u043B\u0438\u043A\u043E\u0433\u043E \u0413\u043E\u0441\u043F\u043E\u0434\u0430 --\u044D\u043F\u0438\u0442\u0435\u0442 \u015Aiva-- <em>(m\u0101he\u015Bvara)</em>||3||</p><blockquote><p><strong>\u042D\u0442\u0430 <em>(iyam)</em> \u015Aivas\u016Btravimar\u015Bin\u012B <em>(\u015Bivas\u016Btra-vimar\u015Bin\u012B)</em> \u0437\u0430\u0432\u0435\u0440\u0448\u0435\u043D\u0430 <em>(sam\u0101pt\u0101)</em>||</strong></p></blockquote><blockquote><p>\u041F\u0443\u0441\u0442\u044C \u0440\u0430\u0431\u043E\u0442\u0430 \u043F\u043E\u0447\u0442\u0435\u043D\u043D\u043E\u0433\u043E K\u1E63emar\u0101ja \u043F\u043E\u0441\u043B\u0443\u0436\u0438\u0442 <em>(k\u1E5Bti\u1E25 \u015Br\u012B-k\u1E63emar\u0101jasya... astu)</em> \u043C\u0438\u0440\u0443 \u0438 \u0437\u0430\u0449\u0438\u0442\u0435 <em>(k\u1E63em\u0101ya)</em> \u0442\u0435\u0445, \u043A\u0442\u043E \u0440\u0430\u0437\u043C\u044B\u0448\u043B\u044F\u0435\u0442 [\u0433\u043B\u0443\u0431\u043E\u043A\u043E \u043D\u0430\u0434 \u0441\u043C\u044B\u0441\u043B\u043E\u043C \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u043E\u0432\u0430\u043D\u0438\u044F] <em>(vimar\u015Bin\u0101m)</em>! \u015Aivas\u016Btravimar\u015Bin\u012B <em>(\u015Bivas\u016Btravimar\u015Bin\u012B)</em> [\u0431\u044B\u043B\u0430 \u0438\u0437\u043B\u043E\u0436\u0435\u043D\u0430] \u0441 \u0446\u0435\u043B\u044C\u044E <em>(arth\u0101)</em>[\u043F\u0440\u043E\u0431\u0443\u0436\u0434\u0435\u043D\u0438\u044F] bodha, \u0438\u043B\u0438 \u043E\u0441\u043E\u0437\u043D\u0430\u043D\u0438\u044F --\u043F\u043E\u043D\u0438\u043C\u0430\u043D\u0438\u044F-- <em>(bodha)</em> [\u043D\u0435\u043E\u0442\u044A\u0435\u043C\u043B\u0435\u043C\u043E\u0433\u043E] \u0435\u0434\u0438\u043D\u0441\u0442\u0432\u0430 <em>(aikya)</em> \u043C\u0435\u0436\u0434\u0443 \u0441\u0432\u043E\u0435\u0439 \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0439 <em>(sva)</em> \u0421\u0430\u043C\u043E\u0441\u0442\u044C\u044E <em>(\u0101tma)</em> [\u0438] \u015Aiva <em>(\u015Biva)</em>||</p></blockquote><hr><ol><li>\u0412 \u0441\u0430\u043D\u0441\u043A\u0440\u0438\u0442\u0435 \u0441\u043B\u043E\u0432\u043E &quot;v\u1E5Btti&quot;, \u0438\u043B\u0438 &quot;\u043A\u043E\u043C\u043C\u0435\u043D\u0442\u0430\u0440\u0438\u0439&quot; \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u0436\u0435\u043D\u0441\u043A\u043E\u0433\u043E \u0440\u043E\u0434\u0430, \u0442\u0430\u043A\u0436\u0435 \u043A\u0430\u043A \u0438 \u0437\u0430\u0433\u043E\u043B\u043E\u0432\u043E\u043A \u044D\u0442\u043E\u0433\u043E \u043A\u043E\u043C\u043C\u0435\u043D\u0442\u0430\u0440\u0438\u044F \u043A \u015Aivas\u016Btra-s: &quot;\u015Aivas\u016Btravimar\u015Bin\u012B&quot;. \u0417\u043D\u0430\u043C\u0435\u043D\u0438\u0442\u044B\u0435 \u0421\u043F\u0430\u043D\u0434\u0430\u043A\u0430\u0440\u0438\u043A\u0438 \u0431\u044B\u043B\u0438 \u0441\u043E\u0441\u0442\u0430\u0432\u043B\u0435\u043D\u044B Vasugupta (\u043C\u0443\u0434\u0440\u0435\u0446\u043E\u043C, \u043A\u043E\u0442\u043E\u0440\u043E\u043C\u0443 \u015Aiva \u044F\u0432\u0438\u043B \u0415\u0433\u043E \u015Aivas\u016Btra-s), \u0441\u043E\u0433\u043B\u0430\u0441\u043D\u043E K\u1E63emar\u0101ja, \u0438\u043B\u0438 \u0435\u0433\u043E \u0433\u043B\u0430\u0432\u043D\u044B\u043C \u0443\u0447\u0435\u043D\u0438\u043A\u043E\u043C, \u043D\u0430\u0437\u044B\u0432\u0430\u0435\u043C\u044B\u043C Kalla\u1E6Da, \u0441\u043E\u0433\u043B\u0430\u0441\u043D\u043E \u0434\u0440\u0443\u0433\u0438\u043C \u0430\u0432\u0442\u043E\u0440\u0430\u043C.</li></ol><p>\u0420\u0430\u0441\u043A\u0440\u044B\u0442\u044B\u0435 \u0421\u0432\u044F\u0449\u0435\u043D\u043D\u044B\u0435 \u041F\u0438\u0441\u0430\u043D\u0438\u044F \u044F\u0432\u043B\u044F\u044E\u0442\u0441\u044F \u0434\u0440\u0435\u0432\u043D\u0438\u043C\u0438 \u0442\u0430\u043D\u0442\u0440\u0430\u043C\u0438 (\u043D\u0430\u043F\u0440\u0438\u043C\u0435\u0440, Svacchandatantra, M\u0101lin\u012Bvijayatantra \u0438 \u043F\u0440.). \u042D\u0442\u0430 \u0442\u0435\u043C\u0430 \u2014 \u0434\u043B\u0438\u043D\u043D\u0430\u044F \u0438 \u0441\u043B\u043E\u0436\u043D\u0430\u044F (\u043A\u0430\u043A \u0432\u0441\u0435\u0433\u0434\u0430 \u0432 \u044D\u0442\u043E\u043C \u043E\u043A\u0435\u0430\u043D\u0435 \u0441\u0430\u043D\u0441\u043A\u0440\u0438\u0442\u0430), \u043D\u043E \u0435\u0441\u043B\u0438 \u0432\u044B \u043F\u0440\u043E\u0447\u0438\u0442\u0430\u043B\u0438 \u0432\u0435\u0441\u044C \u0442\u0435\u043A\u0441\u0442 \u043A\u043E\u043C\u043C\u0435\u043D\u0442\u0430\u0440\u0438\u044F, \u0432\u044B \u043D\u0430\u0432\u0435\u0440\u043D\u044F\u043A\u0430 \u0432\u0438\u0434\u0435\u043B\u0438 \u043C\u043D\u043E\u0433\u043E \u0446\u0438\u0442\u0430\u0442, \u0438\u0437\u0432\u043B\u0435\u0447\u0435\u043D\u043D\u044B\u0445 \u0438\u0437 \u0434\u0440\u0443\u0433\u0438\u0445 \u0421\u0432\u044F\u0449\u0435\u043D\u043D\u044B\u0445 \u041F\u0438\u0441\u0430\u043D\u0438\u0439.</p><p>\u0422\u0430\u0439\u043D\u0430 \u015Aiva \u2014 \u043D\u0438\u0447\u0442\u043E \u0438\u043D\u043E\u0435, \u043A\u0430\u043A \u0442\u0430\u0439\u043D\u0430 \u015Aaivayoga, \u0438\u043B\u0438 \u0435\u0434\u0438\u043D\u0435\u043D\u0438\u044F \u0441 \u0413\u043E\u0441\u043F\u043E\u0434\u043E\u043C \u0441 \u043F\u043E\u043C\u043E\u0449\u044C\u044E \u015Baiva \u043C\u0435\u0442\u043E\u0434\u043E\u0432. \u0421\u043B\u043E\u0432\u043E &quot;\u015Baiva&quot; \u043E\u0437\u043D\u0430\u0447\u0430\u0435\u0442 &quot;\u0428\u0438\u0432\u044B, \u043E\u0442\u043D\u043E\u0441\u044F\u0449\u0438\u0445\u0441\u044F \u043A \u015Aiva, \u043F\u0440\u0438\u043D\u0430\u0434\u043B\u0435\u0436\u0430\u0449\u0438\u0445 \u015Aiva, \u0438 \u0442.\u0434.&quot;.</p><ol start="2"><li>\u0414\u043B\u044F \u043F\u0440\u043E\u044F\u0441\u043D\u0435\u043D\u0438\u044F: &quot;\u043E\u043D\u0430 \u0443\u043D\u0438\u0447\u0442\u043E\u0436\u0430\u0435\u0442 \u0441\u0442\u0440\u0430\u0445 \u0441\u043C\u0435\u0440\u0442\u0438, \u0441\u0442\u0430\u0440\u043E\u0441\u0442\u0438, \u0440\u043E\u0436\u0434\u0435\u043D\u0438\u044F \u0438 \u0442.\u043F.&quot; \u043E\u0437\u043D\u0430\u0447\u0430\u0435\u0442 &quot;\u043E\u043D\u0430 \u0443\u043D\u0438\u0447\u0442\u043E\u0436\u0430\u0435\u0442 \u0441\u0442\u0440\u0430\u0445 \u0441\u043C\u0435\u0440\u0442\u0438, \u0441\u0442\u0430\u0440\u043E\u0441\u0442\u0438, \u0440\u043E\u0436\u0434\u0435\u043D\u0438\u044F \u0438 \u0442.\u043F.&quot; \u0430 \u041D\u0415 (\u0442\u0430\u043A, \u0447\u0442\u043E): &quot;\u043E\u043D\u0430 \u0443\u043D\u0438\u0447\u0442\u043E\u0436\u0430\u0435\u0442 \u0441\u0442\u0440\u0430\u0445 \u0441\u043C\u0435\u0440\u0442\u0438, \u043E\u043D\u0430 \u0443\u043D\u0438\u0447\u0442\u043E\u0436\u0430\u0435\u0442 \u0441\u0442\u0430\u0440\u043E\u0441\u0442\u044C, \u043E\u043D\u0430 \u0443\u043D\u0438\u0447\u0442\u043E\u0436\u0430\u0435\u0442 \u0440\u043E\u0436\u0434\u0435\u043D\u0438\u0435 \u0438 \u0442.\u043F.&quot;. \u042D\u0442\u043E \u043C\u0435\u043B\u043E\u0447\u044C, \u043D\u043E \u044F \u043F\u043E\u0434\u0443\u043C\u0430\u043B, \u0447\u0442\u043E \u0431\u044B\u043B\u043E \u0432\u0430\u0436\u043D\u043E \u043F\u0440\u043E\u044F\u0441\u043D\u0438\u0442\u044C \u044D\u0442\u043E. \u0425\u043E\u0442\u044F \u0432 \u0430\u043D\u0433\u043B\u0438\u0439\u0441\u043A\u043E\u043C &quot;\u043F\u043E\u0440\u044F\u0434\u043E\u043A&quot; \u0432 \u043F\u0440\u0435\u0434\u043B\u043E\u0436\u0435\u043D\u0438\u0438 \u0438\u043C\u0435\u0435\u0442 \u0440\u0435\u0448\u0430\u044E\u0449\u0435\u0435 \u0437\u043D\u0430\u0447\u0435\u043D\u0438\u0435, \u043E\u043D \u0441\u0442\u043E\u043B\u044C \u0432\u0430\u0436\u0435\u043D \u0432 \u0441\u0430\u043D\u0441\u043A\u0440\u0438\u0442\u0435. \u0421\u043E\u0433\u043B\u0430\u0441\u043E\u0432\u0430\u043D\u0438\u0435 \u0432 \u0441\u0430\u043D\u0441\u043A\u0440\u0438\u0442\u0435 \u0437\u0430\u0432\u0438\u0441\u0438\u0442 \u0433\u043B\u0430\u0432\u043D\u044B\u043C \u043E\u0431\u0440\u0430\u0437\u043E\u043C \u043E\u0442 \u043F\u043E\u043B\u0430, \u0447\u0438\u0441\u043B\u0430, \u043B\u0438\u0447\u043D\u043E\u0441\u0442\u0438 \u0438 \u0432\u0440\u0435\u043C\u0435\u043D\u0438 (\u0438\u043B\u0438 \u043D\u0430\u043A\u043B\u043E\u043D\u0435\u043D\u0438\u044F). \u0415\u0441\u043B\u0438 \u0432\u0441\u0435 \u0432 \u043F\u043E\u0440\u044F\u0434\u043A\u0435, &quot;\u0432 \u0446\u0435\u043B\u043E\u043C&quot;, \u0432\u044B \u043C\u043E\u0436\u0435\u0442\u0435 \u0441\u0432\u043E\u0431\u043E\u0434\u043D\u043E \u043F\u0435\u0440\u0435\u043C\u0435\u0449\u0430\u0442\u044C \u0441\u043B\u043E\u0432\u0430 (\u043A\u043E\u043D\u0435\u0447\u043D\u043E, \u0438\u043C\u0435\u0435\u0442\u0441\u044F \u043D\u0435\u0441\u043A\u043E\u043B\u044C\u043A\u043E \u0438\u0441\u043A\u043B\u044E\u0447\u0435\u043D\u0438\u0439).</li></ol><p>\u041A\u0440\u043E\u043C\u0435 \u0442\u043E\u0433\u043E, \u0432\u044B\u0440\u0430\u0436\u0435\u043D\u0438\u0435 &quot;\u0443 \u0442\u0435\u0445, \u043A\u0442\u043E \u043D\u0435 \u0438\u043C\u0435\u0435\u0442 \u0435\u0451&quot; \u043E\u0437\u043D\u0430\u0447\u0430\u0435\u0442 &quot;\u0443 \u0442\u0435\u0445, \u043A\u0442\u043E \u043D\u0435 \u0438\u043C\u0435\u0435\u0442 \u043F\u043E\u0442\u0440\u0435\u0431\u043D\u043E\u0441\u0442\u0438&quot;.</p><ol start="3"><li><p>\u0412 \u044D\u0442\u043E\u0439 \u0441\u0442\u0440\u043E\u0444\u0435 \u0435\u0441\u0442\u044C &quot;\u043E\u0447\u0435\u0432\u0438\u0434\u043D\u0430\u044F&quot; \u043E\u0448\u0438\u0431\u043A\u0430 (\u0447\u0435\u0442\u0432\u0435\u0440\u0442\u0430\u044F). \u0422\u0435\u043C \u043D\u0435 \u043C\u0435\u043D\u0435\u0435, \u044D\u0442\u043E \u043D\u0435 \u043E\u0448\u0438\u0431\u043A\u0430, \u0430 \u043F\u043E\u044D\u0442\u0438\u0447\u0435\u0441\u043A\u043E\u0435 \u043E\u0442\u043A\u043B\u043E\u043D\u0435\u043D\u0438\u0435 \u043E\u0442 \u043D\u043E\u0440\u043C\u044B. \u041F\u043E\u0437\u0432\u043E\u043B\u044C\u0442\u0435 \u043E\u0431\u044A\u044F\u0441\u043D\u0438\u0442\u044C \u044D\u0442\u043E:</p><p>\u041C\u0443\u0434\u0440\u0435\u0446 K\u1E63emar\u0101ja \u0438\u0441\u043F\u043E\u043B\u044C\u0437\u0443\u0435\u0442 \u0432 \u044D\u0442\u043E\u0439 \u0441\u0442\u0430\u043D\u0446\u0435 \u0440\u0438\u0442\u043C/\u0440\u0430\u0437\u043C\u0435\u0440, \u0438\u0437\u0432\u0435\u0441\u0442\u043D\u044B\u0439 \u043A\u0430\u043A \u015A\u0101rd\u016Blavikr\u012B\u1E0Dita (\u0430 \u0438\u043C\u0435\u043D\u043D\u043E, \u0438\u0433\u0440\u0430 \u0442\u0438\u0433\u0440\u0430... \u0437\u043B\u043E\u0432\u0435\u0449\u0435\u0435 \u0438\u043C\u044F, \u043D\u0430 \u0441\u0430\u043C\u043E\u043C \u0434\u0435\u043B\u0435!), \u043A\u043E\u0442\u043E\u0440\u044B\u0439 \u0441\u043E\u0441\u0442\u043E\u0438\u0442 \u0438\u0437 19 \u0441\u043B\u043E\u0433\u043E\u0432 \u043D\u0430 p\u0101da (\u0438\u043B\u0438 \u0447\u0435\u0442\u0432\u0435\u0440\u0442\u044C). \u0412 \u043F\u0440\u0438\u0432\u0435\u0434\u0435\u043D\u043D\u043E\u043C \u0432\u044B\u0448\u0435 \u0441\u0442\u0438\u0445\u0435, \u0447\u0435\u0442\u0432\u0435\u0440\u0442\u0430\u044F \u0441\u0442\u0440\u043E\u0444\u0430 \u0432\u044B\u0433\u043B\u044F\u0434\u0438\u0442 \u0442\u0430\u043A:</p></li></ol><blockquote><p>Dehapr\u0101\u1E47asukh\u0101dibhi\u1E25 parimit\u0101hant\u0101spadai\u1E25 sa\u1E41v\u1E5Bta\u015Bcaitanya\u1E41 cinute nija\u1E41 na sumahanm\u0101he\u015Bvara\u1E41 sva\u1E41 jana\u1E25|<br> Madhye bodhasudh\u0101bdhi vi\u015Bvamabhitastatphenapi\u1E47\u1E0Dopama\u1E41 ya\u1E25 pa\u015Byedupade\u015Batastu kathita\u1E25 s\u0101k\u1E63\u0101tsa eka\u1E25 \u015Biva\u1E25||4||</p></blockquote><p>\u041D\u043E \u0434\u043B\u044F \u043F\u0440\u043E\u0441\u043B\u0435\u0436\u0438\u0432\u0430\u043D\u0438\u044F \u0440\u0438\u0442\u043C\u0430 \u0432\u0430\u043C \u043D\u0435\u043E\u0431\u0445\u043E\u0434\u0438\u043C\u043E \u0440\u0430\u0437\u0434\u0435\u043B\u0438\u0442\u044C \u0435\u0433\u043E \u043D\u0430 \u0447\u0435\u0442\u044B\u0440\u0435 \u0447\u0430\u0441\u0442\u0438 \u0441 19 \u0441\u043B\u043E\u0433\u0430\u043C\u0438 \u0432 \u043A\u0430\u0436\u0434\u043E\u0439 \u0442\u0430\u043A\u0438\u043C \u043E\u0431\u0440\u0430\u0437\u043E\u043C:</p><blockquote><p>Dehapr\u0101\u1E47asukh\u0101dibhi\u1E25 parimit\u0101hant\u0101spadai\u1E25 sa\u1E41v\u1E5Bta-<br> \u015Bcaitanya\u1E41 cinute nija\u1E41 na sumahanm\u0101he\u015Bvara\u1E41 sva\u1E41 jana\u1E25|<br> Madhye bodhasudh\u0101bdhi vi\u015Bvamabhitastatphenapi\u1E47\u1E0Dopama\u1E41<br> ya\u1E25 pa\u015Byedupade\u015Batastu kathita\u1E25 s\u0101k\u1E63\u0101tsa eka\u1E25 \u015Biva\u1E25||4||</p></blockquote><p>\u0422\u0435\u043F\u0435\u0440\u044C \u043E\u043D \u0433\u043E\u0442\u043E\u0432 \u0434\u043B\u044F \u0440\u0430\u0437\u043C\u0435\u0442\u043A\u0438 \u0441\u043B\u043E\u0433\u043E\u0432, \u043D\u043E \u0441\u043D\u0430\u0447\u0430\u043B\u0430 \u043D\u0435\u043C\u043D\u043E\u0433\u043E \u0441\u0430\u043D\u0441\u043A\u0440\u0438\u0442\u0441\u043A\u043E\u0439 \u043F\u0440\u043E\u0441\u043E\u0434\u0438\u0438:</p><p>\u0421\u043E\u0433\u043B\u0430\u0441\u043D\u043E \u0441\u0430\u043D\u0441\u043A\u0440\u0438\u0442\u0441\u043A\u043E\u0439 \u043F\u0440\u043E\u0441\u043E\u0434\u0438\u0438, \u0441\u0442\u0440\u043E\u0444\u0430, \u0438\u043B\u0438 padya \u0441\u043E\u0441\u0442\u043E\u0438\u0442 \u0438\u0437 \u0447\u0435\u0442\u044B\u0440\u0435\u0445 p\u0101da-s --\u0442\u0430\u043A\u0436\u0435 \u0438\u0437\u0432\u0435\u0441\u0442\u043D\u044B\u0445 \u043A\u0430\u043A &quot;pada-s&quot;-- \u0438\u043B\u0438 \u0447\u0435\u0442\u0432\u0435\u0440\u0442\u0435\u0439. \u0422\u0430\u043A\u0430\u044F \u0441\u0442\u0440\u043E\u0444\u0430 \u043C\u043E\u0436\u0435\u0442 \u0431\u044B\u0442\u044C \u043B\u0438\u0431\u043E v\u1E5Btta (\u0441 \u0440\u0438\u0442\u043C\u043E\u043C, \u0440\u0435\u0433\u0443\u043B\u0438\u0440\u0443\u0435\u043C\u044B\u043C \u043A\u043E\u043B\u0438\u0447\u0435\u0441\u0442\u0432\u043E\u043C \u0438 \u043F\u043E\u043B\u043E\u0436\u0435\u043D\u0438\u0435\u043C \u0441\u043B\u043E\u0433\u043E\u0432 --ak\u1E63ara-- \u0432 \u043A\u0430\u0436\u0434\u043E\u0439 p\u0101da, \u0438\u043B\u0438 \u0447\u0435\u0442\u0432\u0435\u0440\u0442\u0438), \u0438\u043B\u0438 j\u0101ti (\u0441 \u0440\u0438\u0442\u043C\u043E\u043C, \u0443\u043F\u0440\u0430\u0432\u043B\u044F\u0435\u043C\u044B\u043C \u0441\u043B\u043E\u0433\u043E\u0432\u043E\u0439 \u0434\u043B\u0438\u0442\u0435\u043B\u044C\u043D\u043E\u0441\u0442\u044C\u044E --m\u0101tr\u0101-- \u0432 \u043A\u0430\u0436\u0434\u043E\u0439 p\u0101da, \u0438\u043B\u0438 \u0447\u0435\u0442\u0432\u0435\u0440\u0442\u0438). \u0417\u0430\u0431\u0443\u0434\u044C\u0442\u0435 \u0437\u0434\u0435\u0441\u044C \u043E &quot;j\u0101ti&quot;, \u043F\u043E\u0441\u043A\u043E\u043B\u044C\u043A\u0443 \u0440\u0438\u0442\u043C \u044D\u0442\u043E\u0439 \u0441\u0442\u0440\u043E\u0444\u044B \u043E\u0442\u043D\u043E\u0441\u0438\u0442\u0441\u044F \u043A \u043A\u043B\u0430\u0441\u0441\u0443 &quot;v\u1E5Btta&quot;. \u042D\u0442\u043E\u0442 \u0432\u0438\u0434 \u0441\u043E\u0434\u0435\u0440\u0436\u0438\u0442 \u0442\u0440\u0438 \u043F\u043E\u0434\u043A\u043B\u0430\u0441\u0441\u0430: (1) samav\u1E5Btta (\u0433\u0434\u0435 \u0432\u0441\u0435 \u0447\u0435\u0442\u044B\u0440\u0435 \u0447\u0435\u0442\u0432\u0435\u0440\u0442\u0438 \u0441\u0442\u0440\u043E\u0444\u044B \u0441\u0445\u043E\u0436\u0438), (2) ardhasamav\u1E5Btta (\u0447\u0435\u0440\u0435\u0434\u0443\u044E\u0449\u0438\u0435\u0441\u044F \u0447\u0435\u0442\u0432\u0435\u0440\u0442\u0438 \u043F\u043E\u0445\u043E\u0436\u0438) \u0438 (3) vi\u1E63ama (\u0432\u0441\u0435 \u0447\u0435\u0442\u044B\u0440\u0435 \u0447\u0435\u0442\u0432\u0435\u0440\u0442\u0438 \u0440\u0430\u0437\u043D\u044B\u0435).</p><p>\u0418\u0442\u0430\u043A, \u0440\u0430\u0437\u0431\u0438\u0440\u0430\u0435\u043C\u0430\u044F \u0441\u0442\u0440\u043E\u0444\u0430 \u043E\u0442\u043D\u043E\u0441\u0438\u0442\u0441\u044F \u043A \u043F\u043E\u0434\u043A\u043B\u0430\u0441\u0441\u0443 samav\u1E5Btta (\u0432\u0441\u0435 \u0447\u0435\u0442\u0432\u0435\u0440\u0442\u0438 \u0441\u0445\u043E\u0436\u0438). \u042D\u0442\u043E\u0442 \u043F\u043E\u0434\u0432\u0438\u0434 \u0441\u043E\u0441\u0442\u043E\u0438\u0442 \u0438\u0437 26 \u0432\u0438\u0434\u043E\u0432, \u043E\u0442 \u043E\u0434\u043D\u043E\u0433\u043E \u0441\u043B\u043E\u0433\u0430 \u043D\u0430 \u0447\u0435\u0442\u0432\u0435\u0440\u0442\u044C \u0434\u043E 26-\u0442\u0438 \u0441\u043B\u043E\u0433\u043E\u0432 \u043D\u0430 \u0447\u0435\u0442\u0432\u0435\u0440\u0442\u044C. \u0412 \u0441\u0432\u043E\u044E \u043E\u0447\u0435\u0440\u0435\u0434\u044C, \u043A\u0430\u0436\u0434\u044B\u0439 \u0432\u0438\u0434 \u0434\u0435\u043B\u0438\u0442\u0441\u044F \u043D\u0430 \u043F\u043E\u0434\u0432\u0438\u0434\u044B, \u0441\u043E\u0433\u043B\u0430\u0441\u043D\u043E \u043F\u043E\u043B\u043E\u0436\u0435\u043D\u0438\u044E \u043A\u043E\u0440\u043E\u0442\u043A\u043E\u0433\u043E (\u0442.\u0435. \u043B\u0435\u0433\u043A\u043E\u0433\u043E) \u0438 \u0434\u043E\u043B\u0433\u043E\u0433\u043E (\u0442.\u0435. \u0442\u044F\u0436\u0435\u043B\u043E\u0433\u043E) \u0441\u043B\u043E\u0433\u043E\u0432 \u0438 \u0442.\u0434. \u0412 \u043F\u0440\u0435\u0434\u0435\u043B\u0430\u0445 \u0432\u0438\u0434\u0430 \u0438\u0437 19 \u0441\u043B\u043E\u0433\u043E\u0432 \u043D\u0430 \u0447\u0435\u0442\u0432\u0435\u0440\u0442\u044C, K\u1E63emar\u0101ja \u0432\u044B\u0431\u0440\u0430\u043B \u043F\u043E\u0434\u0432\u0438\u0434, \u0438\u0437\u0432\u0435\u0441\u0442\u043D\u044B\u0439 \u043A\u0430\u043A \u015A\u0101rd\u016Blavikr\u012B\u1E0Dita. \u0418\u043C\u0435\u044E\u0442\u0441\u044F \u0435\u0449\u0435 \u0434\u0432\u0430 \u0442\u0438\u043F\u0430, \u043D\u0430\u0437\u044B\u0432\u0430\u0435\u043C\u044B\u0435 Meghavisph\u016Brjit\u0101 (\u0431\u0443\u043A\u0432. \u0433\u0440\u043E\u0445\u043E\u0442 \u043E\u0431\u043B\u0430\u043A\u0430) \u0438 Sumadhur\u0101 (\u0431\u0443\u043A\u0432. \u043E\u0447\u0435\u043D\u044C \u0441\u043B\u0430\u0434\u043A\u0438\u0439), \u0432\u0441\u0435 \u043E\u043D\u0438 \u2014 \u0432 \u043F\u0440\u0435\u0434\u0435\u043B\u0430\u0445 \u0432\u0438\u0434\u0430 \u0438\u0437 19 \u0441\u043B\u043E\u0433\u043E\u0432 \u043D\u0430 \u0447\u0435\u0442\u0432\u0435\u0440\u0442\u044C. \u0425\u043E\u0440\u043E\u0448\u043E!</p><p>\u0421\u043B\u043E\u0433\u0438 \u0431\u044B\u0432\u0430\u044E\u0442 \u043A\u043E\u0440\u043E\u0442\u043A\u0438\u043C\u0438 \u0438 \u0434\u043E\u043B\u0433\u0438\u043C\u0438, \u0432 \u0437\u0430\u0432\u0438\u0441\u0438\u043C\u043E\u0441\u0442\u0438 \u043E\u0442 \u0434\u043E\u043B\u0433\u043E\u0442\u044B \u0433\u043B\u0430\u0441\u043D\u044B\u0445. \u041A\u043E\u0440\u043E\u0442\u043A\u0438\u0435 \u0433\u043B\u0430\u0441\u043D\u044B\u0435 \u2014 \u044D\u0442\u043E: a, i, u, \u1E5B, \u1E37. \u0414\u043E\u043B\u0433\u0438\u0435 \u0433\u043B\u0430\u0441\u043D\u044B\u0435 \u0431\u044B\u0432\u0430\u044E\u0442 \u0442\u0430\u043A\u043E\u0432\u044B\u043C\u0438 \u043F\u043E \u0434\u0432\u0443\u043C \u043F\u0440\u0438\u0447\u0438\u043D\u0430\u043C: (1) \u041E\u043D\u0438 \u2014 \u0435\u0441\u0442\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u043E \u0434\u043E\u043B\u0433\u0438\u0435 (\u0101, \u012B, \u016B, \u1E5D, e, ai, o, au), (2) \u043E\u043D\u0438 \u043F\u0440\u043E\u0441\u043E\u0434\u0438\u0447\u0435\u0441\u043A\u0438 \u0434\u043E\u043B\u0433\u0438\u0435 \u0438\u0437-\u0437\u0430 \u0442\u043E\u0433\u043E, \u0447\u0442\u043E \u0437\u0430 \u043D\u0438\u043C\u0438 \u0441\u043B\u0435\u0434\u0443\u044E\u0442 Anusv\u0101ra, \u0438\u043B\u0438 Visarga, \u0438\u043B\u0438 \u0434\u0432\u0430 \u0438\u043B\u0438 \u0431\u043E\u043B\u0435\u0435 \u0441\u043E\u0433\u043B\u0430\u0441\u043D\u044B\u0445 \u0437\u0432\u0443\u043A\u0430 (\u043D\u0430\u043F\u0440\u0438\u043C\u0435\u0440, a\u1E41, a\u1E25, antr). \u041F\u043E\u0441\u043B\u0435\u0434\u043D\u0438\u0439 \u0441\u043B\u043E\u0433 \u0447\u0435\u0442\u0432\u0435\u0440\u0442\u0438 \u2014 &quot;\u0432\u0441\u0435\u0433\u0434\u0430&quot; \u043A\u043E\u0440\u043E\u0442\u043A\u0438\u0439 \u0438\u043B\u0438 \u0434\u043E\u043B\u0433\u0438\u0439 \u0432 \u0437\u0430\u0432\u0438\u0441\u0438\u043C\u043E\u0441\u0442\u0438 \u043E\u0442 \u0442\u0440\u0435\u0431\u043E\u0432\u0430\u043D\u0438\u044F \u043A \u0440\u0430\u0437\u043C\u0435\u0440\u0443, \u043D\u0435\u0437\u0430\u0432\u0438\u0441\u0438\u043C\u043E \u043E\u0442 \u0442\u043E\u0433\u043E, \u043A\u043E\u0440\u043E\u0442\u043A\u0438\u0439 \u043E\u043D \u0438\u043B\u0438 \u0435\u0441\u0442\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u043E/\u043F\u0440\u043E\u0441\u043E\u0434\u0438\u0447\u0435\u0441\u043A\u0438 \u0434\u043E\u043B\u0433\u0438\u0439, \u0442.\u0435. \u0430\u0432\u0442\u043E\u0440\u044B \u0432\u0441\u0435\u0433\u0434\u0430 \u0432\u043E\u043B\u044C\u043D\u044B \u0438\u0441\u043F\u043E\u043B\u044C\u0437\u043E\u0432\u0430\u0442\u044C \u043B\u044E\u0431\u043E\u0439 \u0441\u043B\u043E\u0433 (\u043A\u043E\u0440\u043E\u0442\u043A\u0438\u0439 \u0438\u043B\u0438 \u0434\u043E\u043B\u0433\u0438\u0439) \u0432 \u043A\u0430\u0447\u0435\u0441\u0442\u0432\u0435 \u043F\u043E\u0441\u043B\u0435\u0434\u043D\u0435\u0433\u043E \u0432 \u0447\u0435\u0442\u0432\u0435\u0440\u0442\u0438 \u0438 \u044D\u0442\u043E &quot;\u0432\u0441\u0435\u0433\u0434\u0430&quot; \u0431\u0443\u0434\u0435\u0442 \u0441\u043E\u0433\u043B\u0430\u0441\u043E\u0432\u044B\u0432\u0430\u0442\u044C\u0441\u044F \u0441 \u0442\u0440\u0435\u0431\u043E\u0432\u0430\u043D\u0438\u044F\u043C\u0438 \u0440\u0438\u0442\u043C\u0430/\u0440\u0430\u0437\u043C\u0435\u0440\u0430. \u041F\u043E\u043C\u043D\u0438\u0442\u0435 \u043E\u0431 \u044D\u0442\u043E\u043C!</p><p>\u0412 \u0441\u0432\u043E\u044E \u043E\u0447\u0435\u0440\u0435\u0434\u044C, \u0447\u0442\u043E\u0431\u044B \u0432\u0441\u0435 \u044D\u0442\u043E \u0443\u043F\u0440\u043E\u0441\u0442\u0438\u0442\u044C (\u044D\u0442\u043E \u043D\u0435 \u0448\u0443\u0442\u043A\u0430), \u0432 \u0441\u0430\u043D\u0441\u043A\u0440\u0438\u0442\u0441\u043A\u043E\u0439 \u043F\u0440\u043E\u0441\u043E\u0434\u0438\u0438 \u043A\u0430\u0436\u0434\u043E\u043C\u0443 \u043A\u043E\u043D\u043A\u0440\u0435\u0442\u043D\u043E\u043C\u0443 \u0440\u044F\u0434\u0443 \u0438\u0437 \u0442\u0440\u0435\u0445 \u0441\u043B\u043E\u0433\u043E\u0432 \u0432 \u0447\u0435\u0442\u0432\u0435\u0440\u0442\u0438 \u0434\u0430\u0435\u0442\u0441\u044F \u043E\u043F\u0440\u0435\u0434\u0435\u043B\u0435\u043D\u043D\u043E\u0435 \u0438\u043C\u044F. \u042D\u0442\u0438 \u0433\u0440\u0443\u043F\u043F\u044B \u0438\u0437 \u0442\u0440\u0435\u0445 \u0441\u043B\u043E\u0433\u043E\u0432 \u0438\u0437\u0432\u0435\u0441\u0442\u043D\u044B \u043A\u0430\u043A &quot;ga\u1E47a-s&quot; (\u043D\u0435 \u043F\u0443\u0442\u0430\u0439\u0442\u0435 \u0438\u0445 \u0441 \u0445\u043E\u0440\u043E\u0448\u043E \u0438\u0437\u0432\u0435\u0441\u0442\u043D\u044B\u043C\u0438 ga\u1E47a-s, \u0438\u043B\u0438 \u0434\u043E\u043C\u0430\u043C\u0438, \u0438\u0441\u043F\u043E\u043B\u044C\u0437\u0443\u0435\u043C\u044B\u043C\u0438 \u0434\u043B\u044F \u043A\u043B\u0430\u0441\u0441\u0438\u0444\u0438\u043A\u0430\u0446\u0438\u0438 \u0433\u043B\u0430\u0433\u043E\u043B\u043E\u0432) \u0438 \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u0443\u044E\u0442 \u0442\u043E\u043B\u044C\u043A\u043E \u0432 \u0442\u0430\u043A\u043E\u043C \u0432\u0438\u0434\u0435 \u0432 \u0441\u0442\u0440\u043E\u0444\u0430\u0445 \u043A\u043B\u0430\u0441\u0441\u0430 v\u1E5Btta (\u0441 \u0440\u0430\u0437\u043C\u0435\u0440\u043E\u043C, \u0440\u0435\u0433\u0443\u043B\u0438\u0440\u0443\u0435\u043C\u044B\u043C \u0447\u0438\u0441\u043B\u043E\u043C \u0438 \u043F\u043E\u043B\u043E\u0436\u0435\u043D\u0438\u0435\u043C \u0441\u043B\u043E\u0433\u043E\u0432 --ak\u1E63ara-- \u0432 \u043A\u0430\u0436\u0434\u043E\u0439 p\u0101da, \u0438\u043B\u0438 \u0447\u0435\u0442\u0432\u0435\u0440\u0442\u0438) \u043A\u0430\u043A \u0432 \u0442\u0435\u0445, \u043A\u043E\u0442\u043E\u0440\u044B\u0435 \u044F \u0441\u0435\u0439\u0447\u0430\u0441 \u0430\u043D\u0430\u043B\u0438\u0437\u0438\u0440\u0443\u044E. \u041A\u0430\u0436\u0434\u044B\u0439 ga\u1E47a \u0444\u043E\u0440\u043C\u0438\u0440\u0443\u0435\u0442\u0441\u044F \u0438\u0437 \u0442\u0440\u0435\u0445 \u0441\u043B\u043E\u0433\u043E\u0432, \u043D\u043E \u0441\u043B\u0435\u0434\u0443\u044E\u0449\u0438\u043C \u043E\u0441\u043E\u0431\u044B\u043C \u043E\u0431\u0440\u0430\u0437\u043E\u043C:</p><p>\u042D\u0442\u0438 \u0442\u0440\u0438 \u0441\u043B\u043E\u0433\u0430 \u043C\u043E\u0433\u0443\u0442 \u0431\u044B\u0442\u044C \u043A\u043E\u0440\u043E\u0442\u043A\u0438\u043C\u0438, \u0434\u043E\u043B\u0433\u0438\u043C\u0438, \u043B\u0438\u0431\u043E \u0441\u043C\u0435\u0448\u0430\u043D\u043D\u044B\u043C\u0438 (\u043F\u0440\u0435\u0434\u0441\u0442\u0430\u0432\u043B\u044F\u0442\u044C \u0441\u043E\u0431\u043E\u0439 \u043D\u0435\u0441\u043A\u043E\u043B\u044C\u043A\u043E \u043A\u043E\u043C\u0431\u0438\u043D\u0430\u0446\u0438\u0439 \u043A\u043E\u0440\u043E\u0442\u043A\u0438\u0445 \u0438 \u0434\u043E\u043B\u0433\u0438\u0445 \u0441\u043B\u043E\u0433\u043E\u0432). \u041F\u043E\u0441\u043C\u043E\u0442\u0440\u0438\u0442\u0435:</p><pre><code>- ma**: \u0434\u043E\u043B\u0433\u0438\u0439-\u0434\u043E\u043B\u0433\u0438\u0439-\u0434\u043E\u043B\u0433\u0438\u0439
- na**: \u043A\u043E\u0440\u043E\u0442\u043A\u0438\u0439-\u043A\u043E\u0440\u043E\u0442\u043A\u0438\u0439-\u043A\u043E\u0440\u043E\u0442\u043A\u0438\u0439
- bha**: \u0434\u043E\u043B\u0433\u0438\u0439-\u043A\u043E\u0440\u043E\u0442\u043A\u0438\u0439-\u043A\u043E\u0440\u043E\u0442\u043A\u0438\u0439
- ya**: \u043A\u043E\u0440\u043E\u0442\u043A\u0438\u0439-\u0434\u043E\u043B\u0433\u0438\u0439-\u0434\u043E\u043B\u0433\u0438\u0439
- ja**: \u043A\u043E\u0440\u043E\u0442\u043A\u0438\u0439-\u0434\u043E\u043B\u0433\u0438\u0439-\u043A\u043E\u0440\u043E\u0442\u043A\u0438\u0439
- ra**: \u0434\u043E\u043B\u0433\u0438\u0439-\u043A\u043E\u0440\u043E\u0442\u043A\u0438\u0439-\u0434\u043E\u043B\u0433\u0438\u0439
- sa**: \u043A\u043E\u0440\u043E\u0442\u043A\u0438\u0439-\u043A\u043E\u0440\u043E\u0442\u043A\u0438\u0439-\u0434\u043E\u043B\u0433\u0438\u0439
- ta**: \u0434\u043E\u043B\u0433\u0438\u0439-\u0434\u043E\u043B\u0433\u0438\u0439-\u043A\u043E\u0440\u043E\u0442\u043A\u0438\u0439
</code></pre><p>\u0412 \u043A\u043E\u043D\u0446\u0435 \u0447\u0435\u0442\u0432\u0435\u0440\u0442\u0438 \u0434\u043B\u044F \u043E\u0431\u043E\u0437\u043D\u0430\u0447\u0435\u043D\u0438\u044F \u043A\u043E\u0440\u043E\u0442\u043A\u043E\u0433\u043E \u0441\u043B\u043E\u0433\u0430 \u0438\u0441\u043F\u043E\u043B\u044C\u0437\u0443\u0435\u0442\u0441\u044F \u043D\u0430\u0437\u0432\u0430\u043D\u0438\u0435 &quot;<strong>la</strong>&quot;, \u0430 \u0434\u043B\u044F \u043E\u0431\u043E\u0437\u043D\u0430\u0447\u0435\u043D\u0438\u044F \u0434\u043E\u043B\u0433\u043E\u0433\u043E \u2014 \u043D\u0430\u0437\u0432\u0430\u043D\u0438\u0435 &quot;<strong>ga</strong>&quot;. \u041E, \u0411\u043E\u0436\u0435, \u0434\u0430, \u044D\u0442\u043E \u0441\u043B\u043E\u0436\u043D\u043E, \u043D\u043E \u0435\u0441\u043B\u0438 \u044F \u043D\u0435 \u043E\u0431\u044A\u0441\u043D\u044E \u044D\u0442\u043E, \u0432\u044B \u043D\u0435 \u043F\u043E\u0439\u043C\u0435\u0442\u0435, \u0447\u0442\u043E \u044F \u0431\u0443\u0434\u0443 \u0433\u043E\u0432\u043E\u0440\u0438\u0442\u044C \u043F\u043E\u0437\u0436\u0435. \u0418 \u0435\u0449\u0451, \u043F\u043E\u0434\u0432\u0438\u0434, \u043D\u0430\u0437\u044B\u0432\u0430\u0435\u043C\u044B\u0439 \u015A\u0101rd\u016Blavikr\u012B\u1E0Dita (\u0432\u044B\u0431\u0440\u0430\u043D\u043D\u044B\u0439 \u043C\u0443\u0434\u0440\u0435\u0446\u043E\u043C \u0434\u043B\u044F \u0441\u043E\u0441\u0442\u0430\u0432\u043B\u0435\u043D\u0438\u044F \u044D\u0442\u043E\u0439 \u0441\u0442\u0440\u043E\u0444\u044B) \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u044D\u0442\u043E\u043C\u0443 \u0448\u0430\u0431\u043B\u043E\u043D\u0443 ga\u1E47a \u0432 \u043A\u0430\u0436\u0434\u043E\u0439 \u0438\u0437 \u0441\u0432\u043E\u0438\u0445 \u0447\u0435\u0442\u0432\u0435\u0440\u0442\u0435\u0439:</p><p><strong>ma</strong>, <strong>sa</strong>, <strong>ja</strong>, <strong>sa</strong>, <strong>ta</strong>, <strong>ta</strong>, <strong>ga</strong> \u2014 \u0431\u0443\u043A\u0432. \u0434\u043E\u043B\u0433\u0438\u0439-\u0434\u043E\u043B\u0433\u0438\u0439-\u0434\u043E\u043B\u0433\u0438\u0439, \u043A\u043E\u0440\u043E\u0442\u043A\u0438\u0439-\u043A\u043E\u0440\u043E\u0442\u043A\u0438\u0439-\u0434\u043E\u043B\u0433\u0438\u0439, \u043A\u043E\u0440\u043E\u0442\u043A\u0438\u0439--\u043A\u043E\u0440\u043E\u0442\u043A\u0438\u0439, \u043A\u043E\u0440\u043E\u0442\u043A\u0438\u0439-\u043A\u043E\u0440\u043E\u0442\u043A\u0438\u0439-\u0434\u043E\u043B\u0433\u0438\u0439, \u0434\u043E\u043B\u0433\u0438\u0439-\u0434\u043E\u043B\u0433\u0438\u0439-\u043A\u043E\u0440\u043E\u0442\u043A\u0438\u0439, \u0434\u043E\u043B\u0433\u0438\u0439-\u0434\u043E\u043B\u0433\u0438\u0439-\u043A\u043E\u0440\u043E\u0442\u043A\u0438\u0439, \u0434\u043E\u043B\u0433\u0438\u0439 (\u0432 \u044D\u0442\u043E\u043C \u0441\u043B\u0443\u0447\u0430\u0435, \u043F\u043E\u0441\u043B\u0435\u0434\u043D\u0438\u0439 \u0441\u043B\u043E\u0433 \u2014 \u0434\u043E\u043B\u0433\u0438\u0439, \u043D\u043E \u043F\u043E\u043C\u043D\u0438\u0442\u0435, \u0447\u0442\u043E \u043F\u043E\u0441\u043B\u0435\u0434\u043D\u0438\u0439 \u0441\u043B\u043E\u0433 &quot;\u0432\u0441\u0435\u0433\u0434\u0430&quot; \u0441\u043E\u043E\u0442\u0432\u0435\u0442\u0441\u0442\u0432\u0443\u0435\u0442 \u0442\u0440\u0435\u0431\u043E\u0432\u0430\u043D\u0438\u044F\u043C \u0440\u0430\u0437\u043C\u0435\u0440\u0430, \u0431\u0443\u0434\u044C \u0442\u043E \u043A\u043E\u0440\u043E\u0442\u043A\u0438\u0439 \u0438\u043B\u0438 \u0434\u043E\u043B\u0433\u0438\u0439, \u0442.\u0435. \u0430\u0432\u0442\u043E\u0440 \u0432\u043E\u043B\u0435\u043D \u0438\u0441\u043F\u043E\u043B\u044C\u0437\u043E\u0432\u0430\u0442\u044C \u043A\u043E\u0440\u043E\u0442\u043A\u0438\u0439 \u0438\u043B\u0438 \u0434\u043E\u043B\u0433\u0438\u0439 \u0441\u043B\u043E\u0433 \u0432 \u043A\u043E\u043D\u0446\u0435 \u0447\u0435\u0442\u0432\u0435\u0440\u0442\u0438).</p><p>\u0414\u0430\u0432\u0430\u0439\u0442\u0435 \u043E\u0442\u043C\u0435\u0442\u0438\u043C \u0441\u043B\u043E\u0433\u0438 \u0432 \u043E\u0440\u0438\u0433\u0438\u043D\u0430\u043B\u044C\u043D\u043E\u043C \u0441\u0442\u0438\u0445\u0435, \u0447\u0442\u043E\u0431\u044B \u043F\u0440\u043E\u0432\u0435\u0440\u0438\u0442\u044C, \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u043B\u0438 \u0441\u0442\u0440\u043E\u0444\u0430 (\u043A\u0430\u043A \u043E\u043D\u0430 \u0431\u044B\u043B\u0430 \u0441\u0444\u043E\u0440\u043C\u0443\u043B\u0438\u0440\u043E\u0432\u0430\u043D\u0430 \u0438\u0437\u043D\u0430\u0447\u0430\u043B\u044C\u043D\u043E) \u0448\u0430\u0431\u043B\u043E\u043D\u0443 ga\u1E47a:</p><blockquote><p>De-ha-pr\u0101-\u1E47a-su-kh\u0101-di-bhi\u1E25-pa-ri-mi-t\u0101-ha-nt\u0101-spa-dai\u1E25-sa\u1E41-v\u1E5B-ta-<br> \u015Bcai-ta-nya\u1E41-ci-nu-te-ni-ja\u1E41-na-su-ma-ha-nm\u0101-he-\u015Bva-ra\u1E41-sva\u1E41-ja-na\u1E25|<br> Ma-dhye-bo-dha-su-dh\u0101-bdhi-vi-\u015Bva-ma-bhi-ta-sta-tphe-na-pi-\u1E47\u1E0Do-pa-ma\u1E41<br> ya\u1E25-pa-\u015Bye-du-pa-de-\u015Ba-ta-stu-ka-thi-ta\u1E25-s\u0101-k\u1E63\u0101-tsa-e-ka\u1E25-\u015Bi-va\u1E25||4||</p></blockquote><blockquote><p>\u0434\u043E\u043B\u0433\u0438\u0439-\u0434\u043E\u043B\u0433\u0438\u0439-\u0434\u043E\u043B\u0433\u0438\u0439, \u043A\u043E\u0440\u043E\u0442\u043A\u0438\u0439-\u043A\u043E\u0440\u043E\u0442\u043A\u0438\u0439-\u0434\u043E\u043B\u0433\u0438\u0439, \u043A\u043E\u0440\u043E\u0442\u043A\u0438\u0439-\u0434\u043E\u043B\u0433\u0438\u0439-\u043A\u043E\u0440\u043E\u0442\u043A\u0438\u0439, \u043A\u043E\u0440\u043E\u0442\u043A\u0438\u0439-\u043A\u043E\u0440\u043E\u0442\u043A\u0438\u0439-\u0434\u043E\u043B\u0433\u0438\u0439, \u0434\u043E\u043B\u0433\u0438\u0439-\u0434\u043E\u043B\u0433\u0438\u0439-\u043A\u043E\u0440\u043E\u0442\u043A\u0438\u0439, \u0434\u043E\u043B\u0433\u0438\u0439-\u0434\u043E\u043B\u0433\u0438\u0439-\u043A\u043E\u0440\u043E\u0442\u043A\u0438\u0439, \u0434\u043E\u043B\u0433\u0438\u0439<br> \u0434\u043E\u043B\u0433\u0438\u0439-\u0434\u043E\u043B\u0433\u0438\u0439-\u0434\u043E\u043B\u0433\u0438\u0439, \u043A\u043E\u0440\u043E\u0442\u043A\u0438\u0439-\u043A\u043E\u0440\u043E\u0442\u043A\u0438\u0439-\u0434\u043E\u043B\u0433\u0438\u0439, \u043A\u043E\u0440\u043E\u0442\u043A\u0438\u0439-\u0434\u043E\u043B\u0433\u0438\u0439-\u043A\u043E\u0440\u043E\u0442\u043A\u0438\u0439, \u043A\u043E\u0440\u043E\u0442\u043A\u0438\u0439-\u043A\u043E\u0440\u043E\u0442\u043A\u0438\u0439-\u0434\u043E\u043B\u0433\u0438\u0439, \u0434\u043E\u043B\u0433\u0438\u0439-\u0434\u043E\u043B\u0433\u0438\u0439-\u043A\u043E\u0440\u043E\u0442\u043A\u0438\u0439, \u0434\u043E\u043B\u0433\u0438\u0439-\u0434\u043E\u043B\u0433\u0438\u0439-\u043A\u043E\u0440\u043E\u0442\u043A\u0438\u0439, \u0434\u043E\u043B\u0433\u0438\u0439<br> \u0434\u043E\u043B\u0433\u0438\u0439-\u0434\u043E\u043B\u0433\u0438\u0439-\u0434\u043E\u043B\u0433\u0438\u0439, \u043A\u043E\u0440\u043E\u0442\u043A\u0438\u0439-\u043A\u043E\u0440\u043E\u0442\u043A\u0438\u0439-\u0434\u043E\u043B\u0433\u0438\u0439, \u043A\u043E\u0440\u043E\u0442\u043A\u0438\u0439-\u0434\u043E\u043B\u0433\u0438\u0439-\u043A\u043E\u0440\u043E\u0442\u043A\u0438\u0439, \u043A\u043E\u0440\u043E\u0442\u043A\u0438\u0439-\u043A\u043E\u0440\u043E\u0442\u043A\u0438\u0439-\u0434\u043E\u043B\u0433\u0438\u0439, \u0434\u043E\u043B\u0433\u0438\u0439-\u0434\u043E\u043B\u0433\u0438\u0439-\u043A\u043E\u0440\u043E\u0442\u043A\u0438\u0439, \u0434\u043E\u043B\u0433\u0438\u0439-\u0434\u043E\u043B\u0433\u0438\u0439-\u043A\u043E\u0440\u043E\u0442\u043A\u0438\u0439, \u0434\u043E\u043B\u0433\u0438\u0439<br> \u0434\u043E\u043B\u0433\u0438\u0439-\u0434\u043E\u043B\u0433\u0438\u0439-\u0434\u043E\u043B\u0433\u0438\u0439, \u043A\u043E\u0440\u043E\u0442\u043A\u0438\u0439-\u043A\u043E\u0440\u043E\u0442\u043A\u0438\u0439-\u0434\u043E\u043B\u0433\u0438\u0439, \u043A\u043E\u0440\u043E\u0442\u043A\u0438\u0439-\u0434\u043E\u043B\u0433\u0438\u0439-\u043A\u043E\u0440\u043E\u0442\u043A\u0438\u0439, \u043A\u043E\u0440\u043E\u0442\u043A\u0438\u0439-\u043A\u043E\u0440\u043E\u0442\u043A\u0438\u0439-\u0434\u043E\u043B\u0433\u0438\u0439, \u0434\u043E\u043B\u0433\u0438\u0439-\u0434\u043E\u043B\u0433\u0438\u0439-\u043A\u043E\u0440\u043E\u0442\u043A\u0438\u0439, \u0434\u043E\u043B\u0433\u0438\u0439-\u0434\u043E\u043B\u0433\u0438\u0439-\u043A\u043E\u0440\u043E\u0442\u043A\u0438\u0439, \u0434\u043E\u043B\u0433\u0438\u0439</p></blockquote><p>\u041E\u0442\u043B\u0438\u0447\u043D\u043E, K\u1E63emar\u0101ja! \u041E\u0447\u0435\u0432\u0438\u0434\u043D\u043E, \u043E\u043D \u0437\u043D\u0430\u0435\u0442 \u043E \u0441\u0430\u043D\u0441\u043A\u0440\u0438\u0442\u0441\u043A\u043E\u0439 \u043F\u0440\u043E\u0441\u043E\u0434\u0438\u0438! (\u0448\u0443\u0447\u0443). \u041D\u0443, \u043A\u0430\u043A \u0432\u044B \u043C\u043E\u0436\u0435\u0442\u0435 \u0432\u0438\u0434\u0435\u0442\u044C, \u043C\u0443\u0434\u0440\u0435\u0446 \u043F\u043E\u043B\u043D\u043E\u0441\u0442\u044C\u044E \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u0442\u0440\u0435\u0431\u043E\u0432\u0430\u043D\u0438\u044F\u043C \u0440\u0430\u0437\u043C\u0435\u0440\u0430. \u0422\u0435\u043C \u043D\u0435 \u043C\u0435\u043D\u0435\u0435, \u043A\u043E\u0433\u0434\u0430 \u0432\u044B \u0430\u043D\u0430\u043B\u0438\u0437\u0438\u0440\u0443\u0435\u0442\u0435 \u0441\u0442\u0440\u043E\u0444\u0443 \u0441 \u0433\u0440\u0430\u043C\u043C\u0430\u0442\u0438\u0447\u0435\u0441\u043A\u043E\u0439 \u0442\u043E\u0447\u043A\u0438 \u0437\u0440\u0435\u043D\u0438\u044F, \u0432\u044B \u0437\u0430\u043C\u0435\u0447\u0430\u0435\u0442\u0435 \u043D\u0435\u0447\u0442\u043E \u0441\u0442\u0440\u0430\u043D\u043D\u043E\u0435. \u041F\u043E\u0441\u043C\u043E\u0442\u0440\u0438\u0442\u0435 \u043D\u0430 \u043F\u0435\u0440\u0432\u043E\u0435 \u0432\u044B\u0440\u0430\u0436\u0435\u043D\u0438\u0435 \u0442\u0440\u0435\u0442\u044C\u0435\u0439 \u0447\u0435\u0442\u0432\u0435\u0440\u0442\u0438: &quot;Madhye bodhasudh\u0101bdhi&quot; (\u0412 \u0441\u0435\u0440\u0435\u0434\u0438\u043D\u0435... \u043E\u043A\u0435\u0430\u043D\u0430 \u041D\u0435\u043A\u0442\u0430\u0440\u0430 \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u044F?!). \u041A\u043E\u0433\u0434\u0430 \u0432\u044B \u0441\u0442\u0430\u0440\u0430\u0435\u0442\u0435\u0441\u044C \u043F\u0435\u0440\u0435\u0432\u0435\u0441\u0442\u0438, \u0432\u044B \u043E\u0441\u043E\u0437\u043D\u0430\u0435\u0442\u0435, \u0447\u0442\u043E &quot;abdhi&quot; (\u043E\u043A\u0435\u0430\u043D) \u041D\u0415 \u043F\u0440\u0430\u0432\u0438\u043B\u044C\u043D\u043E \u0441\u043A\u043B\u043E\u043D\u044F\u0435\u0442\u0441\u044F \u043A\u0430\u043A \u0432 \u0420\u043E\u0434\u0438\u0442\u0435\u043B\u044C\u043D\u043E\u043C \u043F\u0430\u0434\u0435\u0436\u0435 (abdhe\u1E25), \u0442\u0430\u043A \u0438 \u0432 \u041C\u0435\u0441\u0442\u043D\u043E\u043C \u043F\u0430\u0434\u0435\u0436\u0435 (abdhau), \u0442.\u043A. &quot;abdhi&quot; \u2014 \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u0438\u0442\u0435\u043B\u044C\u043D\u043E\u0435 \u043C\u0443\u0436\u0441\u043A\u043E\u0433\u043E \u0440\u043E\u0434\u0430, \u043E\u043A\u0430\u043D\u0447\u0438\u0432\u0430\u044E\u0449\u0435\u0435\u0441\u044F \u043D\u0430 &quot;i&quot;. \u041A\u0430\u043A \u0432\u044B \u0437\u043D\u0430\u0435\u0442\u0435, \u0441\u043B\u043E\u0432\u0430, \u0441\u0432\u044F\u0437\u0430\u043D\u043D\u044B\u0435 \u0441 \u043D\u0435\u0441\u043A\u043B\u043E\u043D\u044F\u0435\u043C\u044B\u043C &quot;madhye&quot; (\u0432 \u0441\u0435\u0440\u0435\u0434\u0438\u043D\u0435), \u043E\u0431\u044B\u0447\u043D\u043E \u043D\u0435\u043E\u0431\u0445\u043E\u0434\u0438\u043C\u043E \u043F\u0440\u043E\u0441\u043A\u043B\u043E\u043D\u044F\u0442\u044C \u0432 \u0440\u043E\u0434\u0438\u0442\u0435\u043B\u044C\u043D\u043E\u043C \u043F\u0430\u0434\u0435\u0436\u0435, \u0430 \u0438\u043D\u043E\u0433\u0434\u0430 \u2014 \u0434\u0430\u0436\u0435 \u0432 \u043C\u0435\u0441\u0442\u043D\u043E\u043C (\u043B\u043E\u043A\u0430\u0442\u0438\u0432\u043D\u043E\u043C) \u043F\u0430\u0434\u0435\u0436\u0435, \u043A\u043E\u0433\u0434\u0430 \u043E\u043D\u0438 \u043D\u0435 \u043E\u0431\u0440\u0430\u0437\u0443\u044E\u0442 \u0441\u043E\u0441\u0442\u0430\u0432\u043D\u043E\u0433\u043E (\u0441\u043B\u043E\u0432\u0430), \u0432\u0430\u043C \u0438\u043D\u0442\u0435\u0440\u0435\u0441\u043D\u043E, \u0447\u0442\u043E \u0436\u0435 \u043F\u0440\u043E\u0438\u0437\u043E\u0448\u043B\u043E \u0442\u0430\u043C. \u0412\u0441\u0435 \u043F\u0440\u043E\u0441\u0442\u043E: \u0415\u0441\u043B\u0438 \u0431\u044B \u043C\u0443\u0434\u0440\u0435\u0446 \u043F\u0440\u0430\u0432\u0438\u043B\u044C\u043D\u043E \u043F\u0440\u043E\u0441\u043A\u043B\u043E\u043D\u044F\u043B \u0441\u043B\u043E\u0432\u043E \u0432 \u0440\u043E\u0434\u0438\u0442\u0435\u043B\u044C\u043D\u043E\u043C \u0438\u043B\u0438 \u043C\u0435\u0441\u0442\u043D\u043E\u043C \u043F\u0430\u0434\u0435\u0436\u0430\u0445 (abdhe\u1E25 \u0438\u0437\u043C\u0435\u043D\u0438\u043B\u0441\u044F \u0431\u044B \u043D\u0430 abdher \u0441\u043E\u0433\u043B\u0430\u0441\u043D\u043E 7<sup>\u043E\u043C\u0443</sup> \u041F\u0440\u0430\u0432\u0438\u043B\u0443 Visarga \u0421\u0430\u043D\u0434\u0445\u0438, \u0438 abdhau \u043E\u0441\u0442\u0430\u043B\u0441\u044F \u0431\u044B \u043F\u0440\u0435\u0436\u043D\u0438\u043C), \u0444\u0440\u0430\u0437\u0430 \u0432\u044B\u0433\u043B\u044F\u0434\u0435\u043B\u0430 \u0431\u044B: &quot;Madhye bodhasudh\u0101bdher&quot; \u0438\u043B\u0438 &quot;Madhye bodhasudh\u0101bdhau&quot;, \u0438 \u0442\u0435\u043F\u0435\u0440\u044C \u0432\u044B \u043C\u043E\u0433\u043B\u0438 \u0431\u044B \u0431\u0435\u0437 \u043F\u0440\u043E\u0431\u043B\u0435\u043C \u043F\u0435\u0440\u0435\u0432\u0435\u0441\u0442\u0438 \u044D\u0442\u043E \u043A\u0430\u043A &quot;\u0412 \u0441\u0435\u0440\u0435\u0434\u0438\u043D\u0435 \u043E\u043A\u0435\u0430\u043D\u0430 \u041D\u0435\u043A\u0442\u0430\u0440\u0430 \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u044F&quot;. \u0418 p\u0101da, \u0438\u043B\u0438 \u0447\u0435\u0442\u0432\u0435\u0440\u0442\u044C \u0432\u044B\u0433\u043B\u044F\u0434\u0435\u043B\u0430 \u0431\u044B \u0442\u0430\u043A\u0438\u043C \u043E\u0431\u0440\u0430\u0437\u043E\u043C:</p><blockquote><p>Ma-dhye-bo-dha-su-dh\u0101-bdhe-rvi-\u015Bva-ma-bhi-ta-sta-tphe-na-pi-\u1E47\u1E0Do-pa-ma\u1E41<br> \u0438\u043B\u0438 \u0435\u0449\u0451<br> Ma-dhye-bo-dha-su-dh\u0101-bdhau-vi-\u015Bva-ma-bhi-ta-sta-tphe-na-pi-\u1E47\u1E0Do-pa-ma\u1E41</p></blockquote><p>\u042D\u0442\u043E \u0431\u044B\u043B\u043E \u0431\u044B \u0445\u043E\u0440\u043E\u0448\u043E \u0441 \u0433\u0440\u0430\u043C\u043C\u0430\u0442\u0438\u0447\u0435\u0441\u043A\u043E\u0439 \u0442\u043E\u0447\u043A\u0438 \u0437\u0440\u0435\u043D\u0438\u044F, \u043D\u043E \u043A\u0430\u043A \u043D\u0430\u0441\u0447\u0435\u0442 \u0442\u043E\u0433\u043E, \u0447\u0442\u043E\u0431\u044B \u0441\u043E\u043E\u0442\u0432\u0435\u0442\u0441\u0442\u0432\u043E\u0432\u0430\u0442\u044C \u0442\u0440\u0435\u0431\u043E\u0432\u0430\u043D\u0438\u044F\u043C \u0440\u0430\u0437\u043C\u0435\u0440\u0430? \u0414\u0430\u0432\u0430\u0439\u0442\u0435 \u043F\u043E\u0441\u043C\u043E\u0442\u0440\u0438\u043C:</p><blockquote><p>\u0434\u043E\u043B\u0433\u0438\u0439-\u0434\u043E\u043B\u0433\u0438\u0439-\u0434\u043E\u043B\u0433\u0438\u0439, \u043A\u043E\u0440\u043E\u0442\u043A\u0438\u0439-\u043A\u043E\u0440\u043E\u0442\u043A\u0438\u0439-\u0434\u043E\u043B\u0433\u0438\u0439, <strong>\u0434\u043E\u043B\u0433\u0438\u0439</strong>-\u0434\u043E\u043B\u0433\u0438\u0439-\u043A\u043E\u0440\u043E\u0442\u043A\u0438\u0439, \u043A\u043E\u0440\u043E\u0442\u043A\u0438\u0439-\u043A\u043E\u0440\u043E\u0442\u043A\u0438\u0439-\u0434\u043E\u043B\u0433\u0438\u0439, \u0434\u043E\u043B\u0433\u0438\u0439-\u0434\u043E\u043B\u0433\u0438\u0439-\u043A\u043E\u0440\u043E\u0442\u043A\u0438\u0439, \u0434\u043E\u043B\u0433\u0438\u0439-\u0434\u043E\u043B\u0433\u0438\u0439-\u043A\u043E\u0440\u043E\u0442\u043A\u0438\u0439, \u0434\u043E\u043B\u0433\u0438\u0439<br> \u0438\u043B\u0438 \u0434\u043E\u043B\u0433\u0438\u0439-\u0434\u043E\u043B\u0433\u0438\u0439-\u0434\u043E\u043B\u0433\u0438\u0439, \u043A\u043E\u0440\u043E\u0442\u043A\u0438\u0439-\u043A\u043E\u0440\u043E\u0442\u043A\u0438\u0439-\u0434\u043E\u043B\u0433\u0438\u0439, <strong>\u0434\u043E\u043B\u0433\u0438\u0439</strong>-\u0434\u043E\u043B\u0433\u0438\u0439-\u043A\u043E\u0440\u043E\u0442\u043A\u0438\u0439, \u043A\u043E\u0440\u043E\u0442\u043A\u0438\u0439-\u043A\u043E\u0440\u043E\u0442\u043A\u0438\u0439-\u0434\u043E\u043B\u0433\u0438\u0439, \u0434\u043E\u043B\u0433\u0438\u0439-\u0434\u043E\u043B\u0433\u0438\u0439-\u043A\u043E\u0440\u043E\u0442\u043A\u0438\u0439, \u0434\u043E\u043B\u0433\u0438\u0439-\u0434\u043E\u043B\u0433\u0438\u0439-\u043A\u043E\u0440\u043E\u0442\u043A\u0438\u0439, \u0434\u043E\u043B\u0433\u0438\u0439</p></blockquote><p>\u041E \u043D\u0435\u0442, \u044D\u0442\u043E \u0434\u043E\u043B\u0436\u0435\u043D \u0431\u044B\u0442\u044C &quot;\u043A\u043E\u0440\u043E\u0442\u043A\u0438\u0439&quot; \u0441\u043B\u043E\u0433! \u042D\u0442\u043E \u043D\u0435 \u0441\u043E\u043E\u0442\u0432\u0435\u0442\u0441\u0442\u0432\u0443\u0435\u0442 \u0442\u0440\u0435\u0431\u043E\u0432\u0430\u043D\u0438\u044F\u043C \u0440\u0430\u0437\u043C\u0435\u0440\u0430 (\u043A\u0430\u043A &quot;abdher&quot;, \u0442\u0430\u043A \u0438 &quot;abdhau&quot;!). \u0412\u043E\u0442 \u043F\u043E\u0447\u0435\u043C\u0443 K\u1E63emar\u0101ja \u0440\u0435\u0448\u0438\u043B \u043E\u0441\u0442\u0430\u0432\u0438\u0442\u044C \u0441\u043B\u043E\u0432\u043E &quot;abdhi&quot; \u0442\u0430\u043A\u0438\u043C, \u0432 \u043D\u0435\u0438\u0437\u043C\u0435\u043D\u0435\u043D\u043D\u043E\u0439 \u0444\u043E\u0440\u043C\u0435 (\u0432 \u043D\u0435\u0438\u0437\u043C\u0435\u043D\u0435\u043D\u043D\u043E\u043C \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0438, \u0438\u043B\u0438 pr\u0101tipadika), \u0442\u0430\u043A\u0438\u043C, \u043A\u0430\u043A\u0438\u043C \u0441\u043B\u043E\u0432\u043E&quot;abdhi&quot; \u0432\u0441\u0442\u0440\u0435\u0447\u0430\u0435\u0442\u0441\u044F \u0432 \u0441\u043B\u043E\u0432\u0430\u0440\u044F\u0445. \u0422\u0435\u043C \u0441\u0430\u043C\u044B\u043C, \u043E\u043D \u044F\u0441\u043D\u043E \u0434\u0430\u0435\u0442 \u043F\u043E\u043D\u044F\u0442\u044C, \u0447\u0442\u043E \u044D\u0442\u043E \u043D\u0435 \u0433\u0440\u0430\u043C\u043C\u0430\u0442\u0438\u0447\u0435\u0441\u043A\u0430\u044F \u043E\u0448\u0438\u0431\u043A\u0430, \u0430 \u043F\u043E\u044D\u0442\u0438\u0447\u0435\u0441\u043A\u043E\u0435 \u043E\u0442\u043A\u043B\u043E\u043D\u0435\u043D\u0438\u0435, \u043A\u043E\u0442\u043E\u0440\u043E\u0435 \u043E\u043D \u043E\u0441\u0443\u0449\u0435\u0441\u0442\u0432\u0438\u043B, \u0447\u0442\u043E\u0431\u044B \u043F\u043E\u043B\u043D\u043E\u0441\u0442\u044C\u044E \u0441\u043E\u043E\u0442\u0432\u0435\u0442\u0441\u0442\u0432\u043E\u0432\u0430\u0442\u044C \u0442\u0440\u0435\u0431\u043E\u0432\u0430\u043D\u0438\u044F\u043C \u0440\u0430\u0437\u043C\u0435\u0440\u0430 \u015A\u0101rd\u016Blavikr\u012B\u1E0Dita .</p></div>`,7),r=[o];function p(u,s,n,v,h,k){return e(),m("div",null,r)}var b=a(i,[["render",p]]);export{q as __pageData,b as default};
